window.HADITH_CACHE["bukhari_3"] = {"1501":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ سَلَامٍ حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا فُلَيْحٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَعَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ أَشْوَاطٍ وَمَشَى أَرْبَعَةً فِي الْحَجِّ وَالْعُمْرَةِتَابَعَهُ اللَّيْثُ قَالَ حَدَّثَنِي كَثِيرُ بْنُ فَرْقَدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada saya [Muhammad bin Salam] telah menceritakan kepada kami [Suraij bin An-Nu'man] telah menceritakan kepada kami [Fulaih] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata: \"Rasulullah Shallallahu'alaihiwasallam melaksanakan sa'iy dengan berlari-lari kecil pada tiga putaran dan berjalan biasa pada empat putaran sisanya dalam pelaksanaan hajji maupun 'umrah\". Hadits ini diikuti pula oleh [Al Laits], dia berkata; telah menceritakan kepada saya [Katsir bin Farqad] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] dari Nabi Shallallahu'alaihiwasallam."},"1502":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرِ بْنِ أَبِي كَثِيرٍ قَالَ أَخْبَرَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ أَبِيهِ أَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُقَالَ لِلرُّكْنِ أَمَا وَاللَّهِ إِنِّي لَأَعْلَمُ أَنَّكَ حَجَرٌ لَا تَضُرُّ وَلَا تَنْفَعُ وَلَوْلَا أَنِّي رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَلَمَكَ مَا اسْتَلَمْتُكَ فَاسْتَلَمَهُ ثُمَّ قَالَ فَمَا لَنَا وَلِلرَّمَلِ إِنَّمَا كُنَّا رَاءَيْنَا بِهِ الْمُشْرِكِينَ وَقَدْ أَهْلَكَهُمْ اللَّهُ ثُمَّ قَالَ شَيْءٌ صَنَعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا نُحِبُّ أَنْ نَتْرُكَهُ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah mengabarkan kepada kami [Muhammad bin Ja'far bin Abu Katsir] berkata, telah mengabarkan kepada saya [Zaid bin Aslam] dari [bapaknya] bahwa ['Umar bin Al Khaththob radliallahu 'anhu] berkata kepada rukun (Al Hajar AL Aswad): \"Sungguh aku mengetahui bahwa kamu hanyalah batu yang tidak bisa mendatangkan madharat maupun manfa'at. Namun kalau bukan karena aku telah melihat Nabi Shallallahu'alaihiwasallam menciummu tentu aku tidak akan menciummu\". Maka dia menciumnya lalu berkata: \"Kenapa pula kita harus berlari-lari kecil?. Sungguh kami telah menyaksikan orang-orang musyrikin melakukannya namun kemudian mereka dibinasakan oleh Allah subhanahu wata'ala\". Dia berkata: \"Berlari-lari kecil ini adalah sesuatu sunnah yang telah dikerjakan oleh Nabi Shallallahu'alaihiwasallam dan kami tidak suka bila meninggalkannya\"."},"1503":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَمَا تَرَكْتُ اسْتِلَامَ هَذَيْنِ الرُّكْنَيْنِ فِي شِدَّةٍ وَلَا رَخَاءٍ مُنْذُ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَلِمُهُمَا قُلْتُ لِنَافِعٍ أَكَانَ ابْنُ عُمَرَ يَمْشِي بَيْنَ الرُّكْنَيْنِ قَالَ إِنَّمَا كَانَ يَمْشِي لِيَكُونَ أَيْسَرَ لِاسْتِلَامِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata: \"Tidak pernah aku meninggalkan dari menyentuh (mengusap) dua rukun ini (yang ada Al Hajar Al Aswad) baik dalam keadaan sulit maupun mudah semenjak aku melihat Nabi Shallallahu'alaihiwasallam mengusap keduanya\". Aku bertanya klepada Nafi': \"Apakah Ibnu 'Umar radliallahu 'anhuma berjalan diantara dua rukun itu?\". Dia berkata: \"Dia berjalan agar dapat lebih mudah untuk mengusapnya\"."},"1504":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ وَيَحْيَى بْنُ سُلَيْمَانَ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَطَافَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ عَلَى بَعِيرٍ يَسْتَلِمُ الرُّكْنَ بِمِحْجَنٍتَابَعَهُ الدَّرَاوَرْدِيُّ عَنْ ابْنِ أَخِي الزُّهْرِيِّ عَنْ عَمِّهِ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] dan [Yahya bin Sulaiman] keduanya berkata, telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepada saya [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi Shallallahu'alaihiwasallam melaksanakan thawaf ketika hajji wada' (perpisahan) diatas untanya dan Beliau menyentuh Ar-Rukun (Al Hajar Al Aswad) menggunakan tongkat\". Hadits ini juga diikuti oleh [Ad-Darawardiy] dari anak saudara laki-laki [Az Zuhriy] dari pamannya."},"1505":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمْ أَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَلِمُ مِنْ الْبَيْتِ إِلَّا الرُّكْنَيْنِ الْيَمَانِيَيْنِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Laits] dari [Ibnu Syihab] dari [Salim bin 'Abdullah] dari [bapaknya] radliallahu 'anhuma berkata: \"Aku tidak melihat Nabi Shallallahu'alaihiwasallam menyentuh sesuatu dari Ka'bah kecuali dua rukun Yamani\"."},"1506":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ سِنَانٍ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا وَرْقَاءُ أَخْبَرَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ أَبِيهِ قَالَ رَأَيْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُقَبَّلَ الْحَجَرَ وَقَالَ لَوْلَا أَنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبَّلَكَ مَا قَبَّلْتُكَ","id":"Telah menceritakan kepada kami [Ahmad bin Sinan] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Warqa'] telah mengabarkan kepada kami [Zaid bin Aslam] dari [bapaknya] berkata; Aku melihat ['Umar bin Al Khaththob radliallahu 'anhu] mencium Al Hajar Al Aswad lalu berkata: \"Kalau bukan karena aku melihat Rasulullah Shallallahu'alaihiwasallam menciummu tentu aku tidak akan menciummu\"."},"1507":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ الزُّبَيْرِ بْنِ عَرَبِيٍّ قَالَ سَأَلَ رَجُلٌ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ اسْتِلَامِ الْحَجَرِ فَقَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَلِمُهُ وَيُقَبِّلُهُ قَالَ قُلْتُ أَرَأَيْتَ إِنْ زُحِمْتُ أَرَأَيْتَ إِنْ غُلِبْتُ قَالَ اجْعَلْ أَرَأَيْتَ بِالْيَمَنِ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَلِمُهُ وَيُقَبِّلُهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dari [Az Zubair bin 'Arabiy] berkata; Ada seseorang bertanya kepada [Ibnu'Umar radliallahu 'anhuma] tentang mengusap Al Hajar Al Aswad. Maka dia berkata: \"Aku melihat Rasulullah Shallallahu'alaihiwasallam mengusap dan menciumnya\". Dia berkata; Aku bertanya lagi: \"Bagaimana kalau berdesakan atau aku gagal menggapainya?\". Dia menjawab: \"Tetap laksanakanlah\". Bagaimana kalau kamu berada di Yaman?.\"Aku melihat Rasulullah Shallallahu'alaihiwasallam mengusap dan menciumnya\". "},"1508":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَطَافَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَيْتِ عَلَى بَعِيرٍ كُلَّمَا أَتَى عَلَى الرُّكْنِ أَشَارَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi Shallallahu'alaihiwasallam melaksanakan thawaf di Ka'bah Baitullah diatas untanya dan setiap kali Beliau melewati Ar-Rukun (Al Hajar Al Aswad) Beliau memberi isyarat kepadanya\"."},"1509":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَطَافَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَيْتِ عَلَى بَعِيرٍ كُلَّمَا أَتَى الرُّكْنَ أَشَارَ إِلَيْهِ بِشَيْءٍ كَانَ عِنْدَهُ وَكَبَّرَتَابَعَهُ إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ خَالِدٍ الْحَذَّاءِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Khalid bin 'Abdullah] telah menceritakan kepada kami [Khalid Al Hadzdza'] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi Shallallahu'alaihiwasallam melaksanakan thawaf di Ka'bah Baitullah diatas untanya dan setiap kali Beliau melewati Ar-Rukun (Al Hajar Al Aswad) Beliau memberi isyarat kepadanya dengan sesuatu yang ada pada Beliau lalu bertakbir\". Hadits ini juga diikuti oleh [Ibrahim bin Thahran] dari [Khalid Al Hadzdza']."},"1510":{"ar":"حَدَّثَنَا أَصْبَغُ عَنْ ابْنِ وَهْبٍ أَخْبَرَنِي عَمْرٌو عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ ذَكَرْتُ لِعُرْوَةَ قَالَ فَأَخْبَرَتْنِي عَائِشَةُ رَضِيَ اللَّهُ عَنْهَاأَنَّ أَوَّلَ شَيْءٍ بَدَأَ بِهِ حِينَ قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ تَوَضَّأَ ثُمَّ طَافَ ثُمَّ لَمْ تَكُنْ عُمْرَةً ثُمَّ حَجَّ أَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا مِثْلَهُ ثُمَّ حَجَجْتُ مَعَ أَبِي الزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُ فَأَوَّلُ شَيْءٍ بَدَأَ بِهِ الطَّوَافُ ثُمَّ رَأَيْتُ الْمُهَاجِرِينَ وَالْأَنْصَارَ يَفْعَلُونَهُ وَقَدْ أَخْبَرَتْنِي أُمِّي أَنَّهَا أَهَلَّتْ هِيَ وَأُخْتُهَا وَالزُّبَيْرُ وَفُلَانٌ وَفُلَانٌ بِعُمْرَةٍ فَلَمَّا مَسَحُوا الرُّكْنَ حَلُّوا","id":"Telah menceritakan kepada kami [Ashbagh] dari [Ibnu Wahb] telah mengabarkan kepada saya ['Amru] dari [Muhammad bin 'Abdurrahman]; aku menyebutkan sesuatu kepada ['Urwah], maka ia berkata: ['Aisyah radliallahu 'anha] berkata kepadaku bahwa yang pertama kali dilakukan oleh Nabi Shallallahu'alaihiwasallam ketika Beliau sampai (di Makkah) adalah berwudhu kemudian thawaf dan tidak ber'umrah. Kemudian Abu Bakar dan 'Umar radliallahu 'anhuma melakukan hajji seperti beliau, lalu aku berhajji bersama Abu Zubair radliallahu 'anhu dan yang pertama kali ia lakukan adalah thawaf. Kemudian aku melihat orang-orang Muhajirin dan Anshar melakukan seperti itu. Dan sungguh ibuku mengabarkan kepadaku bahwa ia, saudara perempuannya, Az Zubair, fulan dan fulan berniat ihram untuk umrah, dan setelah mereka mengusap Ar-Rukun (Al Hajar Al Aswad) maka mereka bertahallul."},"1511":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَبُو ضَمْرَةَ أَنَسٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا طَافَ فِي الْحَجِّ أَوْ الْعُمْرَةِ أَوَّلَ مَا يَقْدَمُ سَعَى ثَلَاثَةَ أَطْوَافٍ وَمَشَى أَرْبَعَةً ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ يَطُوفُ بَيْنَ الصَّفَا وَالْمَرْوَةِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Abu Dhamrah Anas] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhua] bahwa Rasulullah Shallallahu'alaihiwasallam apabila thawaf dalam pelaksanaan hajji atau 'umrah, yang pertama kali dilakukan adalah bersa'iy (berlari kecil) mengelilingi Ka'bah tiga kali putaran dan berjalan pada empat putaran lainnya kemudian shalat dua raka'at lalu berjalan bolak balik antara bukit Ash-Shafa dan Al Marwah\". "},"1512":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا طَافَ بِالْبَيْتِ الطَّوَافَ الْأَوَّلَ يَخُبُّ ثَلَاثَةَ أَطْوَافٍ وَيَمْشِي أَرْبَعَةً وَأَنَّهُ كَانَ يَسْعَى بَطْنَ الْمَسِيلِ إِذَا طَافَ بَيْنَ الصَّفَا وَالْمَرْوَةِ","id":"Telah menceritakan kepada kami [Ibrahin bin Al Mundzir] telah menceritakan kepada kami [Anas bin 'Iyadh] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa Nabi Shallallahu'alaihiwasallam apabila thawaf di Ka'bah Baitullah berjalan cepat pada tiga putaran dan berjalan biasa pada empat putaran lainnya dan berjalan pada dasar aliran air ketika sa'iy antara bukit Ash-Shafa dan Al Marwah\". "},"1513":{"ar":"و قَالَ لِي عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنَا قَالَ أَخْبَرَنِي عَطَاءٌإِذْ مَنَعَ ابْنُ هِشَامٍ النِّسَاءَ الطَّوَافَ مَعَ الرِّجَالِ قَالَ كَيْفَ يَمْنَعُهُنَّ وَقَدْ طَافَ نِسَاءُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ الرِّجَالِ قُلْتُ أَبَعْدَ الْحِجَابِ أَوْ قَبْلُ قَالَ إِي لَعَمْرِي لَقَدْ أَدْرَكْتُهُ بَعْدَ الْحِجَابِ قُلْتُ كَيْفَ يُخَالِطْنَ الرِّجَالَ قَالَ لَمْ يَكُنَّ يُخَالِطْنَ كَانَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا تَطُوفُ حَجْرَةً مِنْ الرِّجَالِ لَا تُخَالِطُهُمْ فَقَالَتْ امْرَأَةٌ انْطَلِقِي نَسْتَلِمْ يَا أُمَّ الْمُؤْمِنِينَ قَالَتْ انْطَلِقِي عَنْكِ وَأَبَتْ يَخْرُجْنَ مُتَنَكِّرَاتٍ بِاللَّيْلِ فَيَطُفْنَ مَعَ الرِّجَالِ وَلَكِنَّهُنَّ كُنَّ إِذَا دَخَلْنَ الْبَيْتَ قُمْنَ حَتَّى يَدْخُلْنَ وَأُخْرِجَ الرِّجَالُ وَكُنْتُ آتِي عَائِشَةَ أَنَا وَعُبَيْدُ بْنُ عُمَيْرٍ وَهِيَ مُجَاوِرَةٌ فِي جَوْفِ ثَبِيرٍ قُلْتُ وَمَا حِجَابُهَا قَالَ هِيَ فِي قُبَّةٍ تُرْكِيَّةٍ لَهَا غِشَاءٌ وَمَا بَيْنَنَا وَبَيْنَهَا غَيْرُ ذَلِكَ وَرَأَيْتُ عَلَيْهَا دِرْعًا مُوَرَّدًا","id":"Dan berkata, kepadaku ['Amru bin 'Ali] telah menceritakan kepada kami [Abu 'Ashim] berkata, [Ibnu Juraij] telah mengabarkan kepada kami, berkata,, telah mengabarkan kepada saya ['Atho'] ketika Ibnu Hisyam melarang para wanita untuk thawaf bersama kaum lelaki, ia ('Atho') berkata; \"Bagaimana kalian melarang mereka sedangkan para isteri Nabi Shallallahu'alaihiwasallam melakukan tawaf bersama kaum lelaki?\". Aku bertanya: \"Apakah setelah turun ayat hijab atau sebelumnya?\". Ia menjawab: \"Benar, sungguh aku mendapatinya setelah turun ayat hijab\". Aku berkata: \"Bagaimana mereka berbaur dengan kaum lelaki?\". Ia menjawab: \"Mereka tidak berbaur dengan kaum lelaki, dan ['Aisyah radliallahu 'anha] thawaf dengan menyendiri dan tidak berbaur dengan kaum lelaki\". Lalu ada seorang wanita berkata, kepadanya: \"Beranjaklah wahai Ummul Mukminin, mari kita mencium hajar aswad\". 'Aisyah radliallahu 'anha menjawab: \"Engkau saja yang pergi\". Sedangkan ia enggan untuk pergi. Dahulu kaum wanita keluar pada malam hari tanpa diketahui keberadaannya, lalu mereka thawaf bersama kaum lelaki. Namun mereka jika memasuki masjid, mereka berdiri hingga mereka masuk saat para lelaki telah keluar. Dan aku bersama 'Ubaid bin 'Umair pernah menemui 'Aisyah radliallahu 'anha yang sedang berada disisi gunung Tsabir. Aku bertanya: \"Hijabnya apa? Ia menjawab: \"Ia berada di dalam tenda kecil buatan Turki. Tenda itu memiliki penutup yang tipis dan tidak ada pembatas antara kami dan beliau selain tenda itu, dan aku melihat beliau mengenakan gamis bermotif mawar\"."},"1514":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَتْ شَكَوْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي أَشْتَكِي فَقَالَ طُوفِي مِنْ وَرَاءِ النَّاسِ وَأَنْتِ رَاكِبَةٌ فَطُفْتُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَئِذٍ يُصَلِّي إِلَى جَنْبِ الْبَيْتِ وَهُوَ يَقْرَأُ وَالطُّورِ وَكِتَابٍ مَسْطُورٍ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Malik] dari [Muhammad bin 'Abdurrahman bin Nawfal] dari ['Urwah bin Az Zubair] dari [Zainab binti Abu Salamah] dari [Ummu Salamah radliallahu 'anhaa] isteri Nabi Shallallahu'alaihiwasallam berkata: \"Aku mengadu kepada Rasulullah Shallallahu'alaihiwasallam bahwa kondisiku sedang lemah, maka Beliau berkata: \"Thawaflah dari belakang orang banyak dengan mengendarai tunggangan\". Maka aku thawaf sedang Rasulullah Shallallahu'alaihiwasallam saat itu shalat disisi Ka'bah Baitullah dan Beliau membaca Surah Ath-Thur (Surah ke 52)."},"1515":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا هِشَامٌ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي سُلَيْمَانُ الْأَحْوَلُ أَنَّ طَاوُسًا أَخْبَرَهُ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ وَهُوَ يَطُوفُ بِالْكَعْبَةِ بِإِنْسَانٍ رَبَطَ يَدَهُ إِلَى إِنْسَانٍ بِسَيْرٍ أَوْ بِخَيْطٍ أَوْ بِشَيْءٍ غَيْرِ ذَلِكَ فَقَطَعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ ثُمَّ قَالَ قُدْهُ بِيَدِهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah menceritakan kepada kami [Hisyam] bahwa [Ibnu Juraij] mengabarkan kepada mereka, katanya telah mengabarkan kepada saya [Sulaiman Al Ahwal] bahwa [Thowus] nemgabarkan kepadanya dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Nabi Shallallahu'alaihiwasallam ketika sedang thawaf, Beliau melewati seorang yang mengikat tangannya kepada orang lain dengan tali atau benang atau selain itu. Maka Nabi Shallallahu'alaihiwasallam memutuskannya dengan tangan Beliau sendiri dan berkata, (kepada orang lainnya): \"Tuntunlah dia dengan tangannya\"."},"1516":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَطُوفُ بِالْكَعْبَةِ بِزِمَامٍ أَوْ غَيْرِهِ فَقَطَعَهُ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari wa [Ibnu Juraij] dari [Sulaiman Al Ahwal] dari [Thowus] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Nabi Shallallahu'alaihiwasallam melihat seseorang thawaf di Ka'bah dengan mengikat (tangannya kepada orang lain) dengan tali kekang atau selainnya lalu Beliau memotongnya. "},"1517":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ قَالَ يُونُسُ قَالَ ابْنُ شِهَابٍ حَدَّثَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُأَنَّ أَبَا بَكْرٍ الصِّدِّيقَ رَضِيَ اللَّهُ عَنْهُ بَعَثَهُ فِي الْحَجَّةِ الَّتِي أَمَّرَهُ عَلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ حَجَّةِ الْوَدَاعِ يَوْمَ النَّحْرِ فِي رَهْطٍ يُؤَذِّنُ فِي النَّاسِ أَلَا لَا يَحُجُّ بَعْدَ الْعَامِ مُشْرِكٌ وَلَا يَطُوفُ بِالْبَيْتِ عُرْيَانٌ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] berkata, [Yunus] berkata, [Ibnu Syihab] telah menceritakan kepada saya [Humaid bin 'Abdurrahman] bahwa [Abu Hurairah radliallahu 'anhu] mengabarkan kepadanya bahwa Abu Bakar Ash-Shidiq radliallahu 'anhu mengutusnya dalam urusan yang dia diperuntahkan oleh Rasulullah Shallallahu'alaihiwasallam sebelum hajji wada' pada hari Nahar dalam satu rambongan kecil untuk mengumumkan kepada manusia bahwa; \"Setelah tahun ini tidak boleh seorang musyrikpun ang melaksanakan hajji dan tidak boleh thawaf di Ka'bah dengan telanjang\"."},"1518":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَأَلْنَا ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَيَقَعُ الرَّجُلُ عَلَى امْرَأَتِهِ فِي الْعُمْرَةِ قَبْلَ أَنْ يَطُوفَ بَيْنَ الصَّفَا وَالْمَرْوَةِ قَالَ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَافَ بِالْبَيْتِ سَبْعًا ثُمَّ صَلَّى خَلْفَ الْمَقَامِ رَكْعَتَيْنِ وَطَافَ بَيْنَ الصَّفَا وَالْمَرْوَةِ وَقَالَ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ إِسْوَةٌ حَسَنَةٌ }قَالَ وَسَأَلْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ لَا يَقْرَبُ امْرَأَتَهُ حَتَّى يَطُوفَ بَيْنَ الصَّفَا وَالْمَرْوَةِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Sufyan] dari ['Amru]: \"Kami pernah bertanya kepada [Ibnu'Umar radliallahu 'anhuma]: \"Apakah seorang suami boleh berhubungan dengan isterinya dalam pelaksanaan 'umrah sebelum dia melaksanakan sa'iy antara bukit Shafaa dan Marwah?\". Dia menjawab: \"Nabi Shallallahu'alaihiwasallam pernah datang ke Baitullah untuk hajji, Beliau thawaf di Baitullah tujuh kali putaran kemudian shalat dua raka'at di belakang Maqam (Ibrahim) lalu melakukan sa'iy antara bukit Shafaa dan Marwah. Kemudian dia membaca QS Al Ahzab ayat 21 yang artinya: (\"Sungguh bagi kalian ada suri tauladan yang baik pada diri Rasulullah\"). Dan aku ('Amru) pernah pula bertanya kepada [Jabir bin 'Abdullah radliallahu 'anhu] tentang hal ini. Maka katanya: \"Janganlah orang itu mendekati isterinya hingga dia melaksanakan sa'iy antara bukit Shafaa dan Marwah. "},"1519":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا فُضَيْلٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ أَخْبَرَنِي كُرَيْبٌ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ فَطَافَ وَسَعَى بَيْنَ الصَّفَا وَالْمَرْوَةِ وَلَمْ يَقْرَبْ الْكَعْبَةَ بَعْدَ طَوَافِهِ بِهَا حَتَّى رَجَعَ مِنْ عَرَفَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar] telah menceritakan kepada kami [Fudhail] telah menceritakan kepada kami [Musa bin 'Uqbah] telah mengabarkan kepada saya [Kuraib] dari ['Abdullah bin 'Abbas radliallahu 'anhuma] berkata: \"Nabi Shallallahu'alaihiwasallam tiba di Makkah lalu Beliau thawaf dan sa'iy antara bukit Shafaa dan Marwah dan Beliau tidak mendekati Ka'bah setelah melaksanakan thawafnya hingga Beliau kembali dari 'Arafah."},"1520":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عُرْوَةَ عَنْ زَيْنَبَ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا شَكَوْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنِي مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنَا أَبُو مَرْوَانَ يَحْيَى بْنُ أَبِي زَكَرِيَّاءَ الْغَسَّانِيُّ عَنْ هِشَامٍ عَنْ عُرْوَةَ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ رَضِيَ اللَّهُ عَنْهَا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهُوَ بِمَكَّةَ وَأَرَادَ الْخُرُوجَ وَلَمْ تَكُنْ أُمُّ سَلَمَةَ طَافَتْ بِالْبَيْتِ وَأَرَادَتْ الْخُرُوجَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُقِيمَتْ صَلَاةُ الصُّبْحِ فَطُوفِي عَلَى بَعِيرِكِ وَالنَّاسُ يُصَلُّونَ فَفَعَلَتْ ذَلِكَ فَلَمْ تُصَلِّ حَتَّى خَرَجَتْ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Muhammad bin 'Abdurrahman] dari ['Urwah] dari [Zainab] dari [Ummu Salamah radliallahu 'anha]; \"Aku mengadu kepada Rasulullah Shallallahu'alaihiwasallam \". Dan diriwayatkan pula, telah menceritakan kepada saya [Muhammad bin Harb] telah menceritakan kepada kami [Abu Marwan Yahya bin Abu Zakariya' Al Ghossaniy] dari [Hisyam] dari ['Urwah] dari [Ummu Salamah radliallahu 'anhah], isteri Nabi Shallallahu'alaihiwasallam, bahwa Rasulullah Shallallahu'alaihiwasallam berkata, ketika Beliau berada di Makkah dan hendak keluar darinya, sedangkan Ummu Salamah belum melaksanakan thawaf di Ka'bah Baitullah dan dia juga hendak keluar (dari Makkah), Rasulullah Shallallahu'alaihiwasallam berkata kepadanya: \"Jika shalat Shubuh sudah dibacakan iqamatnya maka thawaf lah kamu diatas untamu saat orang-orang sedang melaksanakan shalat\". Maka aku laksanakan perintah itu dan aku tidak shalat (sunnah thawaf) hingga aku keluar (dari Baitullah) \"."},"1521":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَافَ بِالْبَيْتِ سَبْعًا وَصَلَّى خَلْفَ الْمَقَامِ رَكْعَتَيْنِ ثُمَّ خَرَجَ إِلَى الصَّفَا وَقَدْ قَالَ اللَّهُ تَعَالَى{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Amru bin Dinar] berkata; Aku mendengar [Ibnu'Umar radliallahu 'anhuma] berkata: \"Nabi Shallallahu'alaihiwasallam datang (ke Baitullah untuk hajji) maka Beliau thawaf di Baitullah tujuh kali putaran kemudian shalat dua raka'at di belakang Maqam (Ibrahim) lalu keluar menuju bukit Ash-Shafa dan Al Marwah. Dan sungguh Allah Ta'ala telah berfirman dalam QS Al Ahzab ayat 21 yang artinya: (\"Sungguh bagi kalian ada suri tauladan yang baik pada diri Rasulullah\"). "},"1522":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عُمَرَ الْبَصْرِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ حَبِيبٍ عَنْ عَطَاءٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ نَاسًا طَافُوا بِالْبَيْتِ بَعْدَ صَلَاةِ الصُّبْحِ ثُمَّ قَعَدُوا إِلَى الْمُذَكِّرِ حَتَّى إِذَا طَلَعَتْ الشَّمْسُ قَامُوا يُصَلُّونَ فَقَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا قَعَدُوا حَتَّى إِذَا كَانَتْ السَّاعَةُ الَّتِي تُكْرَهُ فِيهَا الصَّلَاةُ قَامُوا يُصَلُّونَ","id":"Telah menceritakan kepada kami [Al Hasan bin 'Umar Al Bashriy] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Habib] dari ['Atho'] dari ['Urwah] dari ['Aisyah radliallahu 'anha] bahwa orang-orang thawaf di Ka'bah setelah shalat Shubuh kemudian mereka duduk untuk berdzikir hingga ketika matahari telah terbit mereka mendirikan shalat. Maka 'Aisyah radliallahu 'anha berkata: \"Mereka duduk hingga waktu yang dilarang untuk shalat telah berlalu, mereka mendirikan shalat\""},"1523":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَبُو ضَمْرَةَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عِنِ الصَّلَاةِ عِنْدَ طُلُوعِ الشَّمْسِ وَعِنْدَ غُرُوبِهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Abu Dhamrah] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] bahwa ['Abdullah radliallahu 'anhu] berkata; \"Aku mendengar Nabi Shallallahu'alaihiwasallam melarang shalat ketika matahari sedang terbit dan ketika sedang terbenam\"."},"1524":{"ar":"حَدَّثَنِي الْحَسَنُ بْنُ مُحَمَّدٍ هُوَ الزَّعْفَرَانِيُّ حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ رُفَيْعٍ قَالَ رَأَيْتُ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُمَا يَطُوفُ بَعْدَ الْفَجْرِ وَيُصَلِّي رَكْعَتَيْنِ قَالَ عَبْدُ الْعَزِيزِ وَرَأَيْتُ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِيُصَلِّي رَكْعَتَيْنِ بَعْدَ الْعَصْرِ وَيُخْبِرُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا حَدَّثَتْهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَدْخُلْ بَيْتَهَا إِلَّا صَلَّاهُمَا","id":"Telah menceritakan kepada saya [Al Hasan bin Muhammad] dia adalah Az Za'faraniy telah menceritakan kepada kami ['Ubaidah bin Humaid] telah menceritakan kepada saya ['Abdul 'Aziz bin Rufai'] berkata: \"Aku melihat ['Abdullah bin Az Zubair radliallahu 'anhuma] melaksanakan thawaf setelah Fajar (Shubuh) lalu shalat dua raka'at\". Berkata, ['Abdul 'Aziz]; \"Dan aku juga pernah melihat ['Abdullah bin Az Zubair radliallahu 'anhuma] mendirikan shalat dua raka'at setelah 'Ashar dan dia mengabarkan bahwa ['Aisyah radliallahu 'anha] menceritakan kepadanya bahwa Nabi Shallallahu'alaihiwasallam tidaklah memasuki rumahnya kecuali mengerjakan shalat keduanya (setelah Shubuh dan 'Ashar)."},"1525":{"ar":"حَدَّثَنِي إِسْحَاقُ الْوَاسِطِيُّ حَدَّثَنَا خَالِدٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَافَ بِالْبَيْتِ وَهُوَ عَلَى بَعِيرٍ كُلَّمَا أَتَى عَلَى الرُّكْنِ أَشَارَ إِلَيْهِ بِشَيْءٍ فِي يَدِهِ وَكَبَّرَ","id":"Telah menceritakan kepada saya [Ishaq Al Wasitiy] telah menceritakan kepada kami [Khalid] dari [Khalid Al Hadzdza'] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Rasulullah Shallallahu'alaihiwasallam melaksanakan thawaf di Ka'bah Baitullah di atas untanya dan setiap kali sampai pada Ar-rukun (Al Hajar Al Aswad) Beliau memberi isyarat kepadanya dengan sesuatu yang ada di tangan Beliau lalu bertakbir."},"1526":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ عَنْ عُرْوَةَ عَنْ زَيْنَبَ ابْنَةِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْشَكَوْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي أَشْتَكِي فَقَالَ طُوفِي مِنْ وَرَاءِ النَّاسِ وَأَنْتِ رَاكِبَةٌ فَطُفْتُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي إِلَى جَنْبِ الْبَيْتِ وَهُوَ يَقْرَأُ بِالطُّورِ وَكِتَابٍ مَسْطُورٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamahl] telah menceritakan kepada kami [Malik] dari [Muhammad bin 'Abdurrahman bin Nawfal] dari ['Urwah] dari [Zainab binti Ummu Salamah] dari [Ummu Salamah radliallahu 'anha] berkata: \"Aku mengadu kepada Rasulullah Shallallahu'alaihiwasallam bahwa kondisiku sedang lemah, maka Beliau berkata: \"Thowaflah dari belakang orang banyak dengan mengendarai tunggangan\". Maka aku thawaf sedang Rasulullah Shallallahu'alaihiwasallam saat itu shalat disisi Ka'bah Baitullah dan Beliau membaca Surah Ath-Thur (Surah ke 52)."},"1527":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا أَبُو ضَمْرَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَاسْتَأْذَنَ الْعَبَّاسُ بْنُ عَبْدِ الْمُطَّلِبِ رَضِيَ اللَّهُ عَنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيتَ بِمَكَّةَ لَيَالِيَ مِنًى مِنْ أَجْلِ سِقَايَتِهِ فَأَذِنَ لَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Abu Al Aswad] telah menceritakan kepada kami [Abu Dhamrah] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata; Al 'Abbas bin 'Abdul Mutholib radliallahu 'anhuma meminta ijin kepada Rasulullah Shallallahu'alaihiwasallam untuk bermalam di Makkah selama malam-malam Mina untuk (melayani) menyediakan minum buat Beliau. Maka Beliau mengizinkannya. "},"1528":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا خَالِدٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ إِلَى السِّقَايَةِ فَاسْتَسْقَى فَقَالَ الْعَبَّاسُ يَا فَضْلُ اذْهَبْ إِلَى أُمِّكَ فَأْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَرَابٍ مِنْ عِنْدِهَا فَقَالَ اسْقِنِي قَالَ يَا رَسُولَ اللَّهِ إِنَّهُمْ يَجْعَلُونَ أَيْدِيَهُمْ فِيهِ قَالَ اسْقِنِي فَشَرِبَ مِنْهُ ثُمَّ أَتَى زَمْزَمَ وَهُمْ يَسْقُونَ وَيَعْمَلُونَ فِيهَا فَقَالَ اعْمَلُوا فَإِنَّكُمْ عَلَى عَمَلٍ صَالِحٍ ثُمَّ قَالَ لَوْلَا أَنْ تُغْلَبُوا لَنَزَلْتُ حَتَّى أَضَعَ الْحَبْلَ عَلَى هَذِهِ يَعْنِي عَاتِقَهُ وَأَشَارَ إِلَى عَاتِقِهِ","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Khalid] dari [Khalid Al Hadzdza'] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Rasulullah Shallallahu'alaihiwasallam datang menemui orang-orang yang menyediakan minuman dalam pelayanan hajji, lalu Beliau meminta minum. Maka Al 'Abbas berkata: \"Wahai Fadhal, pergilah kepada ibumu dan berikan Rasulullah Shallallahu'alaihiwasallam minuman darinya. Maka Beliau berkata: \"Berilah aku air minum\". Maka dia (Al 'Abbas) berkata: \"Wahai Rasulullah, mereka membuat dengan tangan mereka sendiri. Beliau berkata: \"Berilah aku air minum\". Maka Beliau meminumnya lalu menghampiri air zamzam yang ketika itu orang-orang sedang meminum dan bekerja disana. Maka Beliau berkata: \"Bekerjalah, karena kalian sedang beramal shalih\". Kemudian Beliau berkata: \"Seandainya bukan karena kalian akan tersingkirkan tentu aku akan turun ikut bekerja hingga aku ikatkan tali disini\", yaitu bahu. Beliau menunjuk kepada bahu Beliau\". "},"1529":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَامٍ أَخْبَرَنَا الْفَزَارِيُّ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا حَدَّثَهُ قَالَسَقَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ زَمْزَمَ فَشَرِبَ وَهُوَ قَائِمٌ قَالَ عَاصِمٌ فَحَلَفَ عِكْرِمَةُ مَا كَانَ يَوْمَئِذٍ إِلَّا عَلَى بَعِيرٍ","id":"Telah menceritakan kepada kami [Muhammad] dia adalah Ibnu Salam telah mengabarkan kepada kami [Al Fazariy] dari ['Ashim] dari [Asy-Sya'biy] bahwa [Ibnu 'Abbas radliallahu 'anhuma] menceritakan kepadanya, dia berkata: \"Aku memberi minum Rasulullah Shallallahu'alaihiwasallam dengan air zamzam. Maka Beliau meminumnya sambil berdiri\". Berkata, 'Ashim: 'Ikrimah bersumpah bahwa saat itu Beliau tidak lain kecuali berada diatas untanya. "},"1530":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ فَأَهْلَلْنَا بِعُمْرَةٍ ثُمَّ قَالَ مَنْ كَانَ مَعَهُ هَدْيٌ فَلْيُهِلَّ بِالْحَجِّ وَالْعُمْرَةِ ثُمَّ لَا يَحِلُّ حَتَّى يَحِلَّ مِنْهُمَا فَقَدِمْتُ مَكَّةَ وَأَنَا حَائِضٌ فَلَمَّا قَضَيْنَا حَجَّنَا أَرْسَلَنِي مَعَ عَبْدِ الرَّحْمَنِ إِلَى التَّنْعِيمِ فَاعْتَمَرْتُ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ مَكَانَ عُمْرَتِكِ فَطَافَ الَّذِينَ أَهَلُّوا بِالْعُمْرَةِ ثُمَّ حَلُّوا ثُمَّ طَافُوا طَوَافًا آخَرَ بَعْدَ أَنْ رَجَعُوا مِنْ مِنًى وَأَمَّا الَّذِينَ جَمَعُوا بَيْنَ الْحَجِّ وَالْعُمْرَةِ فَإِنَّمَا طَافُوا طَوَافًا وَاحِدًا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnui Syihab] dari ['Urwah] dari ['Aisyah radliallahu 'anha]: \"Kami berangkat bersama Nabi Shallallahu'alaihiwasallam saat hajji wada' lalu kami berihram untuk 'umrah, kemudian Beliau berkata: \"Barangsiapa yang membawa hewan sembelihan hendaklah dia berihram untukhajji sekaligus 'umrah kemudian dia tidak bertahallul hingga bertahallul untuk keduanya (hajji dan 'umrah). Maka aku tiba di Makkah sedang aku dalam keadaan mengalami haidh. Setelah kami selesai melaksanakan manasik hajji, Beliau mengutusku bersama 'Abdurrahman bin Abu Bakar menuju Tan'im. Maka dari tempat itu aku memulai 'umrah. Beliau Shallallahu'alaihiwasallam berkata: \"Ini pengganti 'umrahmu\".\"Maka orang-orang yang berihram untuk 'umrah melakukan thawaf di Baitullah lalu bertahallul lalu thawaf lagi thawaf yang lain setelah mereka kembali dari Mina. Adapun orang-orang yang menggabungkan hajji dan 'umrah mereka hanya melakukan thawaf satu kali\"."},"1531":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَادَخَلَ ابْنُهُ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ وَظَهْرُهُ فِي الدَّارِ فَقَالَ إِنِّي لَا آمَنُ أَنْ يَكُونَ الْعَامَ بَيْنَ النَّاسِ قِتَالٌ فَيَصُدُّوكَ عَنْ الْبَيْتِ فَلَوْ أَقَمْتَ فَقَالَ قَدْ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَالَ كُفَّارُ قُرَيْشٍ بَيْنهُ وَبَيْنَ الْبَيْتِ فَإِنْ حِيلَ بَيْنِي وَبَيْنَهُ أَفْعَلُ كَمَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ إِسْوَةٌ حَسَنَةٌ }ثُمَّ قَالَ أُشْهِدُكُمْ أَنِّي قَدْ أَوْجَبْتُ مَعَ عُمْرَتِي حَجًّا قَالَ ثُمَّ قَدِمَ فَطَافَ لَهُمَا طَوَافًا وَاحِدًا","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Ayyub] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma]: Anaknya 'Abdullah bin 'Abdullah bin 'Umar masuk menemuinya sedang dia ketika itu sedang berada didalam rumah, berkata: \"Aku tidak menjamin keamanan seandainya kamu berangkat pada tahun yang sedang terjadi peperangan diantara manusia ini\". Maka 'Abdullah bin 'Umar radliallahu 'anhua berkata: \"Rasulullah shallallahu 'alaihi wasallam pernah keluar untuk menunaikan 'ibadah ke Baitullah padahal saat itu tengah terjadi permusuhan antara Beliau dan Kaum Kafir Quraisy. Seandainya terjadi hari ini antara aku dengannya tentu aku akan tetap melakukannya seperti pernah dilakukan oleh Rasulullah Shallallahu'alaihiwasallam. (Selanjutnya dia membaca ayat); (\"Sungguh bagi kalian ada suri tauladan yang baik pada diri Rasulullah\"). Lalu dia berkata: \"Aku bersaksi kepada kalian bahwa aku telah mewajibkan hajji atas diriku bersama dengan 'umrahku ini\". Dia (Nafi') berkata: \"Kemdian dia mengunjungi Makkah lalu thawaf untuk keduanya (hajji dan 'umrah) dengan satu kali thawaf \". "},"1532":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَرَادَ الْحَجَّ عَامَ نَزَلَ الْحَجَّاجُ بِابْنِ الزُّبَيْرِ فَقِيلَ لَهُ إِنَّ النَّاسَ كَائِنٌ بَيْنَهُمْ قِتَالٌ وَإِنَّا نَخَافُ أَنْ يَصُدُّوكَ فَقَالَ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ إِسْوَةٌ حَسَنَةٌ }إِذًا أَصْنَعَ كَمَا صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أُشْهِدُكُمْ أَنِّي قَدْ أَوْجَبْتُ عُمْرَةً ثُمَّ خَرَجَ حَتَّى إِذَا كَانَ بِظَاهِرِ الْبَيْدَاءِ قَالَ مَا شَأْنُ الْحَجِّ وَالْعُمْرَةِ إِلَّا وَاحِدٌ أُشْهِدُكُمْ أَنِّي قَدْ أَوْجَبْتُ حَجًّا مَعَ عُمْرَتِي وَأَهْدَى هَدْيًا اشْتَرَاهُ بِقُدَيْدٍ وَلَمْ يَزِدْ عَلَى ذَلِكَ فَلَمْ يَنْحَرْ وَلَمْ يَحِلَّ مِنْ شَيْءٍ حَرُمَ مِنْهُ وَلَمْ يَحْلِقْ وَلَمْ يُقَصِّرْ حَتَّى كَانَ يَوْمُ النَّحْرِ فَنَحَرَ وَحَلَقَ وَرَأَى أَنْ قَدْ قَضَى طَوَافَ الْحَجِّ وَالْعُمْرَةِ بِطَوَافِهِ الْأَوَّلِ وَقَالَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا كَذَلِكَ فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Nafi'] bahwa [Ibnu'Umar radliallahu 'anhuma] hendak melaksanakan hajji pada tahun turunnya Al Hajjaj (dari kekuasaan) oleh Ibnu Az Zubair lalu dikatakan kepadanya: \"Seungguhnya telah terjadi peprangan di tengah manusia dan aku khawatir mereka akan menghalangimu\". Maka dia berkata, (\"Sungguh bagi kalian ada suri tauladan yang baik pada diri Rasulullah\"). Maka aku akan melakukan sebagaimana Rasulullah Shallallahu'alaihiwasallam telah melakukannya dan sungguh aku bersaksi kepada kalian bahwa aku sudah mewajibkan (meniatkan) diriku untuk 'umrah\":. Kemudian dia keluar hingga ketika tiba di Al Baida (padang sahara) dia berkata: \"Tidaklah pelaksanaan hajji dan 'umrah itu kecuali satu dan aku bersaksi kepada kalian bahwa aku sudah meniatkan hajji bersama 'umrahku dan aku membawa hewan qurban yang aku beli di Qudaid dan tidak lebih dari itu\". Maka dia tidak menyembelih qurban, tidak bertahallul dari sesuatu yang diharamkan dan tidak mencukur tambut hingga tiba hari Nahar. Maka pada hari Nahar itu dia mencukur rambutnya dan memandang bahwa dia telah menyelesaikan thawaf hajji dan 'umrahnya cukup dengan thawaf nya yang pertama. Dan berkata, Ibnu'Umar radliallahu 'anhuma: \"Begitulah apa yang dikerjakan Rasulullah Shallallahu'alaihiwasallam \"."},"1533":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ الْقُرَشِيِّ أَنَّهُ سَأَلَ عُرْوَةَ بْنَ الزُّبَيْرِ فَقَالَقَدْ حَجَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَتْنِي عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا أَنَّهُ أَوَّلُ شَيْءٍ بَدَأَ بِهِ حِينَ قَدِمَ أَنَّهُ تَوَضَّأَ ثُمَّ طَافَ بِالْبَيْتِ ثُمَّ لَمْ تَكُنْ عُمْرَةً ثُمَّ حَجَّ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَكَانَ أَوَّلَ شَيْءٍ بَدَأَ بِهِ الطَّوَافُ بِالْبَيْتِ ثُمَّ لَمْ تَكُنْ عُمْرَةً ثُمَّ عُمَرُ رَضِيَ اللَّهُ عَنْهُ مِثْلُ ذَلِكَ ثُمَّ حَجَّ عُثْمَانُ رَضِيَ اللَّهُ عَنْهُ فَرَأَيْتُهُ أَوَّلُ شَيْءٍ بَدَأَ بِهِ الطَّوَافُ بِالْبَيْتِ ثُمَّ لَمْ تَكُنْ عُمْرَةً ثُمَّ مُعَاوِيَةُ وَعَبْدُ اللَّهِ بْنُ عُمَرَ ثُمَّ حَجَجْتُ مَعَ أَبِي الزُّبَيْرِ بْنِ الْعَوَّامِ فَكَانَ أَوَّلَ شَيْءٍ بَدَأَ بِهِ الطَّوَافُ بِالْبَيْتِ ثُمَّ لَمْ تَكُنْ عُمْرَةً ثُمَّ رَأَيْتُ الْمُهَاجِرِينَ وَالْأَنْصَارَ يَفْعَلُونَ ذَلِكَ ثُمَّ لَمْ تَكُنْ عُمْرَةً ثُمَّ آخِرُ مَنْ رَأَيْتُ فَعَلَ ذَلِكَ ابْنُ عُمَرَ ثُمَّ لَمْ يَنْقُضْهَا عُمْرَةً وَهَذَا ابْنُ عُمَرَ عِنْدَهُمْ فَلَا يَسْأَلُونَهُ وَلَا أَحَدٌ مِمَّنْ مَضَى مَا كَانُوا يَبْدَءُونَ بِشَيْءٍ حَتَّى يَضَعُوا أَقْدَامَهُمْ مِنْ الطَّوَافِ بِالْبَيْتِ ثُمَّ لَا يَحِلُّونَ وَقَدْ رَأَيْتُ أُمِّي وَخَالَتِي حِينَ تَقْدَمَانِ لَا تَبْتَدِئَانِ بِشَيْءٍ أَوَّلَ مِنْ الْبَيْتِ تَطُوفَانِ بِهِ ثُمَّ إِنَّهُمَا لَا تَحِلَّانِ وَقَدْ أَخْبَرَتْنِي أُمِّي أَنَّهَا أَهَلَّتْ هِيَ وَأُخْتُهَا وَالزُّبَيْرُ وَفُلَانٌ وَفُلَانٌ بِعُمْرَةٍ فَلَمَّا مَسَحُوا الرُّكْنَ حَلُّوا","id":"Telah menceritakan kepada kami [Ahmad bin 'Isa] telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepada saya ['Amru bin Al Harits] dari [Muhammad bin 'Abdurrahman bin Nawfal Al Furasyi] bahwa dia bertanya kepada ['Urwah bin Az Zubair], maka ia berkata: \"Nabi Shallallahu'alaihiwasallam pernah melaksanakan hajji, dan ['Aisyah radliallahu 'anha] berkata kepadaku bahwa yang pertama kali dilakukan oleh Nabi Shallallahu'alaihiwasallam ketika Beliau sampai (di Makkah) adalah thawaf di Ka'bah Baitullah dan tidak melaksanakan 'umrah. Kemudian Abu Bakar radliallahu 'anhu melaksanakan haji dan yang pertama dilakukannya adalah thawaf di Ka'bah Baitullah dan tidak melaksanakan 'umrah. Kemudian 'Umar radliallahu 'anhu melaksanakan hajji dan melakukannya seperti itu. Kemudian 'Utsman melaksanakan hajji dan aku melihatnya apa yang dilakukannya pertama kali adalah thawaf di Ka'bah Baitullah dan tidak melaksanakan 'umrah. Kemudian Mu'awiyah dan 'Abdullah bin 'Umar juga melaksanakan haji seperti itu. Kemudian aku melaksanakan hajji bersama bapakku Az Zubair bin Al 'Awam dan yang pertama dilakukannya adalah thawaf di Ka'bah Baitullah dan tidak melaksanakan 'umrah. Kemudian aku melihat Kaum Muhajirin dan Anshar melaksanakan haji seperti itu juga, tidak melaksanakan 'umrah. Dan orang yang terakhir aku lihat melakukan seperti itu adalah Ibnu 'Umar, dia tidak mengubahnya menjadi 'umrah', Dan inilah Ibnu 'Umar, orang-orang tidak bertanya kepadanya, tidak pula seorangpun (yang masih hidup) dari orang-orang yang terdahulu, mereka tidak memulai sesuatu manasik hingga mereka menginjakkan kaki untuk melaksanakan thawaf di Ka'bah Baitullah, lalu mereka tidak bertahallul setelah itu. Sungguh aku telah melihat ibu dan bibiku ketika keduanya melaksanakan hajji, keduanya tidak memulai mengerjakan sesuatu melainkan thawaf di Ka'bah Baitullah kemudian keduanya tidak bertahallul\". Dan ibuku telah mengabarkan kepada saya bahwa dia dan saudara perempuannya dan Az Zubair serta fulan dan fulan berniat ihram untuk umrah, setelah mereka mengusap Ar-Rukun (Al Hajar Al Aswad) maka mereka bertahallul."},"1534":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ عُرْوَةُ سَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا فَقُلْتُ لَهَاأَرَأَيْتِ قَوْلَ اللَّهِ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }فَوَاللَّهِ مَا عَلَى أَحَدٍ جُنَاحٌ أَنْ لَا يَطُوفَ بِالصَّفَا وَالْمَرْوَةِ قَالَتْ بِئْسَ مَا قُلْتَ يَا ابْنَ أُخْتِي إِنَّ هَذِهِ لَوْ كَانَتْ كَمَا أَوَّلْتَهَا عَلَيْهِ كَانَتْ لَا جُنَاحَ عَلَيْهِ أَنْ لَا يَتَطَوَّفَ بِهِمَا وَلَكِنَّهَا أُنْزِلَتْ فِي الْأَنْصَارِ كَانُوا قَبْلَ أَنْ يُسْلِمُوا يُهِلُّونَ لِمَنَاةَ الطَّاغِيَةِ الَّتِي كَانُوا يَعْبُدُونَهَا عِنْدَ الْمُشَلَّلِ فَكَانَ مَنْ أَهَلَّ يَتَحَرَّجُ أَنْ يَطُوفَ بِالصَّفَا وَالْمَرْوَةِ فَلَمَّا أَسْلَمُوا سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ قَالُوا يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَتَحَرَّجُ أَنْ نَطُوفَ بَيْنَ الصَّفَا وَالْمَرْوَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ }الْآيَةَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا وَقَدْ سَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطَّوَافَ بَيْنَهُمَا فَلَيْسَ لِأَحَدٍ أَنْ يَتْرُكَ الطَّوَافَ بَيْنَهُمَا ثُمَّ أَخْبَرْتُ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِ فَقَالَ إِنَّ هَذَا لَعِلْمٌ مَا كُنْتُ سَمِعْتُهُ وَلَقَدْ سَمِعْتُ رِجَالًا مِنْ أَهْلِ الْعِلْمِ يَذْكُرُونَ أَنَّ النَّاسَ إِلَّا مَنْ ذَكَرَتْ عَائِشَةُ مِمَّنْ كَانَ يُهِلُّ بِمَنَاةَ كَانُوا يَطُوفُونَ كُلُّهُمْ بِالصَّفَا وَالْمَرْوَةِ فَلَمَّا ذَكَرَ اللَّهُ تَعَالَى الطَّوَافَ بِالْبَيْتِ وَلَمْ يَذْكُرْ الصَّفَا وَالْمَرْوَةَ فِي الْقُرْآنِ قَالُوا يَا رَسُولَ اللَّهِ كُنَّا نَطُوفُ بِالصَّفَا وَالْمَرْوَةِ وَإِنَّ اللَّهَ أَنْزَلَ الطَّوَافَ بِالْبَيْتِ فَلَمْ يَذْكُرْ الصَّفَا فَهَلْ عَلَيْنَا مِنْ حَرَجٍ أَنْ نَطَّوَّفَ بِالصَّفَا وَالْمَرْوَةِ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ }الْآيَةَ قَالَ أَبُو بَكْرٍ فَأَسْمَعُ هَذِهِ الْآيَةَ نَزَلَتْ فِي الْفَرِيقَيْنِ كِلَيْهِمَا فِي الَّذِينَ كَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بِالْجَاهِلِيَّةِ بِالصَّفَا وَالْمَرْوَةِ وَالَّذِينَ يَطُوفُونَ ثُمَّ تَحَرَّجُوا أَنْ يَطُوفُوا بِهِمَا فِي الْإِسْلَامِ مِنْ أَجْلِ أَنَّ اللَّهَ تَعَالَى أَمَرَ بِالطَّوَافِ بِالْبَيْتِ وَلَمْ يَذْكُرْ الصَّفَا حَتَّى ذَكَرَ ذَلِكَ بَعْدَ مَا ذَكَرَ الطَّوَافَ بِالْبَيْتِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy], berkata, ['Urwah]: Aku bertanya kepada ['Aisyah radliallahu 'anha], kataku kepadanya: \"Bagaimana pendapatmu tentang firman Allah Ta'ala (QS Al Baqarah 158) yang artinya: (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah, maka barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\"), dan demi Allah tidak ada dosa bagi seseorang untuk tidak ber thawaf (sa'iy) antara bukit Ash-Shafaa dan Al Marwah\". 'Aisyah radliallahu 'anha berkata: \"Buruk sekali apa yang kamu katakan itu wahai putra saudariku. Sesungguhnya ayat ini bila tafsirannya menurut pendapatmu tadi berarti tidak berdosa bila ada orang yang tidak melaksanakan sa'iy antara keduanya. Akan tetapi ayat ini turun berkenaan dengan Kaum Anshar, yang ketika mereka belum masuk Islam, mereka berniat hajji untuk patung Manat Sang Thoghut yang mereka sembah di daerah Al Musyallal. Waktu itu, barangsiapa yang berniat hajji, dia merasa berdosa bila harus sa'iy antara bukit Ash-Shafaa dan Al Marwah (karena demi menghormatii patung mereka itu). Setelah mereka masuk Islam, mereka bertanya kepada Rasulullah Shallallahu'alaihiwasallam tentang masalah itu, mereka berkata: \"Wahai Rasulullah, kami merasa berdosa bila melaksanakan sa'iy antara bukit Ash-Shafaa dan Al Marwah\". Maka kemudian Allah Ta'ala menurunkan ayat (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah\"). 'Aisyah radliallahu 'anha berkata: \"Sungguh Rasulullah Shallallahu'alaihiwasallam telah mencontohkan sa'iy antara kedua bukit tersebut dan tidak boleh seorangpun untuk meninggalkannya\". Kemudian aku kabarkan hal ini kepada Abu Bakar bin 'Abdurrahman, maka katanya: \"Sungguh ini suatu ilmu yang aku belum pernah mendengar sebelumnya, padahal aku sudah mendengar dari orang-orang ahli ilmu yang menyebutkan bahwa diantara manusia, selain orang-orang yang diterangkan oleh 'Aisyah radliallahu 'anha itu, ada yang dahulu melaksanakan ihram untuk Manat, mereka juga melaksanakan sa'iy antara bukit Ash-Shafaa dan Al Marwah. Ketika Allah menyebutkan thawaf di Ka'bah Baitullah tapi tidak menyebut sa'iy antara bukit Ash-Shafaa dan Al Marwah dalam Al Qur'an, mereka bertanya kepada: \"Wahai Rasulullah, dahulu kami melaksanakan thawaf (sa'iy) antara bukit Ash-Shafaa dan Al Marwah dan Allah telah menurunkan ayat tentang thawaf di Ka'bah Baitullah tanpa menyebut Ash-Shafaa, apakah berdosa bagi kami bila kami sa'iy antara bukit Ash-Shafaa dan Al Marwah?\". Maka Allah Ta'ala menurunkan ayat (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar Allah\"). Abu Bakar bin 'Abdurrahman berkata: \"Maka aku mendengar bahwa ayat ini turun untuk dua golongan orang yaitu golongan orang-orang yang merasa berdosa karena pernah melaksanakan sa'i antara bukit Ash-Shafaa dan Al Marwah saat mereka masih jahiliyyah (karena pernah melaksanakan untuk patung Manat), dan golongan orang-orang yang pernah melaksanakannya namun merasa berdosa bila melaksanakannya kembali setelah masuk Islam karena Allah pada mulanya hanya menyebutkan thawaf di Ka'bah Baitullah dan tidak menyebut Ash-Shafaa hingga kemudian Dia menyebutkannya setelah memerintahkan thawaf di Ka'bah Baitullah\"."},"1535":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا طَافَ الطَّوَافَ الْأَوَّلَ خَبَّ ثَلَاثًا وَمَشَى أَرْبَعًا وَكَانَ يَسْعَى بَطْنَ الْمَسِيلِ إِذَا طَافَ بَيْنَ الصَّفَا وَالْمَرْوَةِ فَقُلْتُ لِنَافِعٍ أَكَانَ عَبْدُ اللَّهِ يَمْشِي إِذَا بَلَغَ الرُّكْنَ الْيَمَانِيَ قَالَ لَا إِلَّا أَنْ يُزَاحَمَ عَلَى الرُّكْنِ فَإِنَّهُ كَانَ لَا يَدَعُهُ حَتَّى يَسْتَلِمَهُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid bin Maimun] telah menceritakan kepada kami ['Isa bin Yunus] dari ['Ubaidullah bin 'Umar] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata: \"Rasulullah Shallallahu'alaihiwasallam bila melakukan thawaf yang pertamanya (qudum) di Ka'bah Baitullah Beliau berjalan cepat pada tiga putaran, dan berjalan biasa pada empat putaran lainnya dan melakukan berjalan di dasar aliran air bila melakukan sa'iy antara bukit Ash-Shafaa dan Al Marwah\". Aku berkata, kepada Nafi': \"Apakah 'Abdullah berjalan biasa bila telah sampai di Rukun Yamani?\". Dia menjawab: \"Tidak, kecuali bila sudah merapat dengan Ar-Rukun (Al Hajar Al Aswad), dia tidak akan meninggalkannya sebelum mengusapnya\"."},"1536":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَأَلْنَا ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُعَنْ رَجُلٍ طَافَ بِالْبَيْتِ فِي عُمْرَةٍ وَلَمْ يَطُفْ بَيْنَ الصَّفَا وَالْمَرْوَةِ أَيَأْتِي امْرَأَتَهُ فَقَالَ قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَافَ بِالْبَيْتِ سَبْعًا وَصَلَّى خَلْفَ الْمَقَامِ رَكْعَتَيْنِ فَطَافَ بَيْنَ الصَّفَا وَالْمَرْوَةِ سَبْعًا{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }وَسَأَلْنَا جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ لَا يَقْرَبَنَّهَا حَتَّى يَطُوفَ بَيْنَ الصَّفَا وَالْمَرْوَةِ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] berkata: \"Kami pernah bertanya kepada [Ibnu'Umar radliallahu 'anhuma] tentang seseorang yang thawaf di Ka'bah Baitullah keetika melaksanakan 'umrah namun belum melakukan sa'iy antara bukit Ash-Shafaa dan Al Marwah, apakah dia boleh berhubungan dengan isterinya?\". Dia menjawab: \"Nabi Shallallahu'alaihiwasallam pernah datang ke Baitullah untuk haji, Beliau thawaf di Baitullah tujuh kali putaran kemudian shalat dua raka'at di belakang Maqam (Ibrahim) lalu melakukan sa'iy antara bukit Shafa dan Marwah tujuh kali. (\"Sungguh bagi kalian ada suri tauladan yang baik pada diri Rasulullah\"). Dan kami pernah pula bertanya kepada [Jabir bin 'Abdullah radliallahu 'anhua] tentang hal ini. katanya: \"Janganlah orang itu mendekati isterinya hingga dia melaksanakan sa'iy antara bukit Shafa dan Marwah."},"1537":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ فَطَافَ بِالْبَيْتِ ثُمَّ صَلَّى رَكْعَتَيْنِ ثُمَّ سَعَى بَيْنَ الصَّفَا وَالْمَرْوَةِ ثُمَّ تَلَا{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ إِسْوَةٌ حَسَنَةٌ }","id":"Telah menceritakan kepada kami [Al Makkiy bin Ibrahim] dari [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Amru bin Dinar] berkata: \"Aku mendengar [Ibnu'Umar radliallahu 'anhuma] berkata: \"Nabi Shallallahu'alaihiwasallam pernah datang ke Makkah untuk menunaikan haji lalu Beliau thawaf di Baitullah kemudian shalat dua raka'at lalu melakukan sa'iy antara bukit Shafa dan Marwah\". Kemudian dia membaca firman Allah Ta'ala (QS al Ahzab ayat 21 yang artinya): (\"Sungguh bagi kalian ada suri tauladan yang baik pada diri Rasulullah\"). "},"1538":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا عَاصِمٌ قَالَ قُلْتُ لِأَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَكُنْتُمْ تَكْرَهُونَ السَّعْيَ بَيْنَ الصَّفَا وَالْمَرْوَةِ قَالَ نَعَمْ لِأَنَّهَا كَانَتْ مِنْ شَعَائِرِ الْجَاهِلِيَّةِ حَتَّى أَنْزَلَ اللَّهُ{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami ['Ashim] berkata; Aku berkata, kepada [Anas bin Malik radliallahu 'anhu]: \"Apakah kalian tidak menyukai melaksanakan sa'iy antara bukit Shafaa dan Marwah? '. Dia menjawab: \"Ya benar, karena itu bagian dari syi'ar-syi'ar jahiliyyah hingga kemudian Allah menurunkan (QS Al Baqarah ayat 158) yang artinya (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah bahagian dari syi'ar-syi'ar Allah, barangsiapa yang beribadah haji ke Baitullah atau ber-'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\")."},"1539":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَإِنَّمَا سَعَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ لِيُرِيَ الْمُشْرِكِينَ قُوَّتَهُزَادَ الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو سَمِعْتُ عَطَاءً عَنْ ابْنِ عَبَّاسٍ مِثْلَهُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari ['Atho'] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Rasulullah Shallallahu'alaihiwasallam melaksanakan thawaf di Ka'bah Baitullah dan sa'iy antara bukit Shafaa dan Marwah untuk menunjukkan kepada kaum musyrikin kekuatan Beliau\". [Al Humaidiy] menambahkan telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru]; aku mendengar ['Atho'] dari [Ibnu 'Abbas radliallahu 'anhuma] seperti ini juga\". "},"1540":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا قَالَتْقَدِمْتُ مَكَّةَ وَأَنَا حَائِضٌ وَلَمْ أَطُفْ بِالْبَيْتِ وَلَا بَيْنَ الصَّفَا وَالْمَرْوَةِ قَالَتْ فَشَكَوْتُ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ افْعَلِي كَمَا يَفْعَلُ الْحَاجُّ غَيْرَ أَنْ لَا تَطُوفِي بِالْبَيْتِ حَتَّى تَطْهُرِي","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Abdurrahman bin Al Qasim] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa dia berkata: \"Aku mengunjungi Makkah (untuk menunaikan hajji) sedang aku mengalami haidh sehingga aku tidak melakukan thawaf di Ka'bah Baitullah dan juga tidak sa'iy antara bukit Shafaa dan Marwah\". Dia berkata: \"Kemudian hal ini aku adukan kepada Rasulullah Shallallahu'alaihiwasallam maka Beliau bersabda: \"Lakukanlah semua manasik seperti yang dilakukan para hujjaj selain thawaf di Ka'bah Baitullah hingga kamu suci\"."},"1541":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ ح وَقَالَ لِي خَلِيفَةُ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا حَبِيبٌ الْمُعَلِّمُ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَهَلَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ وَأَصْحَابُهُ بِالْحَجِّ وَلَيْسَ مَعَ أَحَدٍ مِنْهُمْ هَدْيٌ غَيْرَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَطَلْحَةَ وَقَدِمَ عَلِيٌّ مِنْ الْيَمَنِ وَمَعَهُ هَدْيٌ فَقَالَ أَهْلَلْتُ بِمَا أَهَلَّ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصْحَابَهُ أَنْ يَجْعَلُوهَا عُمْرَةً وَيَطُوفُوا ثُمَّ يُقَصِّرُوا وَيَحِلُّوا إِلَّا مَنْ كَانَ مَعَهُ الْهَدْيُ فَقَالُوا نَنْطَلِقُ إِلَى مِنًى وَذَكَرُ أَحَدِنَا يَقْطُرُ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ مَا أَهْدَيْتُ وَلَوْلَا أَنَّ مَعِي الْهَدْيَ لَأَحْلَلْتُ وَحَاضَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا فَنَسَكَتْ الْمَنَاسِكَ كُلَّهَا غَيْرَ أَنَّهَا لَمْ تَطُفْ بِالْبَيْتِ فَلَمَّا طَهُرَتْ طَافَتْ بِالْبَيْتِ قَالَتْ يَا رَسُولَ اللَّهِ تَنْطَلِقُونَ بِحَجَّةٍ وَعُمْرَةٍ وَأَنْطَلِقُ بِحَجٍّ فَأَمَرَ عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرٍ أَنْ يَخْرُجَ مَعَهَا إِلَى التَّنْعِيمِ فَاعْتَمَرَتْ بَعْدَ الْحَجِّ","id":"Telah menceritakan kepada kami [Muhammad bin AL Mutsanna] telah menceritakan kepada kami ['Abdul Wahhab] berkata,. Dan diriwayatkan pula, telah berkata kepadaku [Khalifah] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Habib Al Mu'allim] dari ['Atho'] dari [Jabir bin 'Abdullah radliallahu 'anhua] berkata: \"Nabi Shallallahu'alaihiwasallam dan para sahabatnya berihram untuk hajji dan tidak ada seorangpun dari mereka yang membawa Al Hadyu (hewan qurban) kecuali Nabi Shallallahu'alaihiwasallam dan Tholhah. Sementara itu 'Ali baru saja datang dari negeri Yaman dengan membawa Al Hadyu, dia berkata: Aku berihram (berniat hajji) sebagaimana Nabi Shallallahu'alaihiwasallam berihram. Maka Nabi Shallallahu'alaihiwasallam memerintahkan para sahabatnya agar menjadikan ihram mereka sebagai 'umrah lalu melaksanakan thawaf kemudian mencukur rambut lalu bertahallul kecuali mereka yang membawa Al Hadyu. Maka mereka berkata: \"Maka kami berangkat menuju Mina lalu diantara kami ada yang menyebut bahwa dia menarik diri. Hal ini kemudian sampai kepada Nabi Shallallahu'alaihiwasallam, maka Beliau berkata: \"Kalau aku bisa mengulang kembali apa yang telah lewat, aku tidak akan menyembelih, dan seandainya aku tidak membawa Al Hadyu, sudah pasti aku akan bertahallul\". Kemudian 'Aisyah radliallahu 'anha mengalami haidh sedangkan dia telah menuntaskan seluruh manasik kecuali thawaf di Ka'bah Baitullah. Ketika dia sudah suci, dia melaksanakan thawaf di Ka'bah Baitullah. Dia berkata: 'Wahai Rasulullah, kalian berangkat dengan niat hajji dan 'umrah sedangkan aku dengan niat hajji saja\". Maka Beliau perintahkan 'Abdurrahman bin Abu Bakar agar keluar bersama 'Aisyah radliallahu 'anha ke Tan'im. Maka 'Aisyah radliallahu 'anha melaksanakan 'umrah setelah melaksanakan manasik hajji\"."},"1542":{"ar":"حَدَّثَنَا مُؤَمَّلُ بْنُ هِشَامٍ حَدَّثَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ حَفْصَةَ قَالَتْكُنَّا نَمْنَعُ عَوَاتِقَنَا أَنْ يَخْرُجْنَ فَقَدِمَتْ امْرَأَةٌ فَنَزَلَتْ قَصْرَ بَنِي خَلَفٍ فَحَدَّثَتْ أَنَّ أُخْتَهَا كَانَتْ تَحْتَ رَجُلٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ غَزَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثِنْتَيْ عَشْرَةَ غَزْوَةً وَكَانَتْ أُخْتِي مَعَهُ فِي سِتِّ غَزَوَاتٍ قَالَتْ كُنَّا نُدَاوِي الْكَلْمَى وَنَقُومُ عَلَى الْمَرْضَى فَسَأَلَتْ أُخْتِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ هَلْ عَلَى إِحْدَانَا بَأْسٌ إِنْ لَمْ يَكُنْ لَهَا جِلْبَابٌ أَنْ لَا تَخْرُجَ قَالَ لِتُلْبِسْهَا صَاحِبَتُهَا مِنْ جِلْبَابِهَا وَلْتَشْهَدْ الْخَيْرَ وَدَعْوَةَ الْمُؤْمِنِينَ فَلَمَّا قَدِمَتْ أُمُّ عَطِيَّةَ رَضِيَ اللَّهُ عَنْهَا سَأَلْنَهَا أَوْ قَالَتْ سَأَلْنَاهَا فَقَالَتْ وَكَانَتْ لَا تَذْكُرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبَدًا إِلَّا قَالَتْ بِأَبِي فَقُلْنَا أَسَمِعْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كَذَا وَكَذَا قَالَتْ نَعَمْ بِأَبِي فَقَالَ لِتَخْرُجْ الْعَوَاتِقُ ذَوَاتُ الْخُدُورِ أَوْ الْعَوَاتِقُ وَذَوَاتُ الْخُدُورِ وَالْحُيَّضُ فَيَشْهَدْنَ الْخَيْرَ وَدَعْوَةَ الْمُسْلِمِينَ وَيَعْتَزِلُ الْحُيَّضُ الْمُصَلَّى فَقُلْتُ أَالْحَائِضُ فَقَالَتْ أَوَلَيْسَ تَشْهَدُ عَرَفَةَ وَتَشْهَدُ كَذَا وَتَشْهَدُ كَذَا","id":"Telah menceritakan kepada kami [Mu'ammal bin Hisyam] telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Hafshah] berkata: \"Dahulu kami melarang anak-anak gadis remaja kami keluar rumah\", hingga datang seorang wanita lalu mendatangi Qashra Banu Khalaf lalu aku menemuinya. Kemudian dia menceritakan tentang saudara perempuannya yang menjadi suami seorang dari sahabat Rasulullah Shallallahu'alaihiwasallam yang pernah ikut berperang bersama Nabi Shallallahu'alaihiwasallam sebanyak dua belas peperangan, dan saudaranya telah mendampingi suaminya dalam enam kali peperangan. Saudara perempuannya berkata: \"Maka (dalam peperangan itu) kami sering mengurus orang yang sakit dan mengobati orang-orang yang terluka. Saudaraku bertanya kepada Nabi Shallallahu'alaihiwasallam.: \"Wahai Rasulullah, apakah berdosa bila seorang dari kami tidak keluar rumah karena tidak memiliki jilbab?\" Beliau Shallallahu'alaihiwasallam menjawab: \"Hendaklah temannya meminjamkan jilbabnya dan agar mereka dapat menyaksikan kebaikan dan mendo'akan Kaum Muslimin\". Berkata, Hafshah: \"Ketika [Ummu 'Athiyah] datang aku menemuinya lalu aku bertanya atau dia berkata, lalu kami bertanya kepadanya. Dan setiap kali dia menceritakan tentang Rasulullah Shallallahu'alaihiwasallam dia selalu mengatakan demi bapakku. Kami bertanya: \"Apakah kamu pernah mendengar Rasulullah Shallallahu'alaihiwasallam berkata, tentang ini dan ini?\". Dia menjawab: \"Iya, demi bapakku\". Beliau bersabda: \"Keluarkanlah para gadis remaja dan wanita-wanita yang dipingit di rumah dan wanita yang sedang haidh agar mereka dapat menyaksikan kebaikah dan mendo'akan Kaum Muslimin namun para wanita yang sedang haidh harus dijauhkan dari tempat shalat\". Aku (Hafshah) bertanya: \"Juga wanita yang sedang haidh?\" Dia berkata: \"Bukankah mereka juga hadir di 'Arafah, dan menyaksikan ini dan itu?\""},"1543":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا إِسْحَاقُ الْأَزْرَقُ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قُلْتُأَخْبِرْنِي بِشَيْءٍ عَقَلْتَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ صَلَّى الظُّهْرَ وَالْعَصْرَ يَوْمَ التَّرْوِيَةِ قَالَ بِمِنًى قُلْتُ فَأَيْنَ صَلَّى الْعَصْرَ يَوْمَ النَّفْرِ قَالَ بِالْأَبْطَحِ ثُمَّ قَالَ افْعَلْ كَمَا يَفْعَلُ أُمَرَاؤُكَ","id":"Telah menceritakan kepada saya ['Abdullah bin Muhammad] telah menceritakan kepada kami [Ishaq Al Azraq] telah menceritakan kepada kami [Sufyan] dari ['Abdul 'Aziz bin Rufai'] berkata; Aku bertanya kepada [Anas bin Malik radliallahu 'anhu], kataku: \"Kabarkan kepadaku sesuatu yang kamu ingat dari Nabi Shallallahu'alaihiwasallam, dimanakah beliau melaksanakan shalat Zhuhur dan 'Ashar pada hari Tarwiyah?\". Dia berkata: \"Di Mina\". Aku tanyakan lagi: \"Dimana Beliau shalat 'Ashar pada hari Nafar?\". Dia menjawab: \"Di Al Abthoh (Al Bathha') \". Lalu dia berkata: \"Kerjakanlah (manasik) sebagaimana para pemimpin, kamu telah mengerjakannya\"."},"1544":{"ar":"حَدَّثَنَا عَلِيٌّ سَمِعَ أَبَا بَكْرِ بْنَ عَيَّاشٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ لَقِيتُ أَنَسًا ح و حَدَّثَنِي إِسْمَاعِيلُ بْنُ أَبَانَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ عَبْدِ الْعَزِيزِ قَالَخَرَجْتُ إِلَى مِنًى يَوْمَ التَّرْوِيَةِ فَلَقِيتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ ذَاهِبًا عَلَى حِمَارٍ فَقُلْتُ أَيْنَ صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا الْيَوْمَ الظُّهْرَ فَقَالَ انْظُرْ حَيْثُ يُصَلِّي أُمَرَاؤُكَ فَصَلِّ","id":"Telah menceritakan kepada saya ['Ali] dia nebdebgar [Abu Bakar 'Ayyasy] telah menceritakan kepada kami ['Abdul 'Aziz]; Aku menemui [Anas radliallahu 'anhu]. Dan diriwaatkan pula, telah menceritakan kepada saya [Isma'il bin Aban] telah menceritakan kepada kami [Abu Bakar] dari ['Abdul 'Aziz] berkata: \"Aku keluar menuju Mina pada hari Tarwiyah lalu aku menemui [Anas] radliallahu 'anhu yang juga sedang berangkat dengan menunggang keledai. Aku bertanya kepadanya: \"Dimana Nabi Shallallahu'alaihiwasallam melaksanakan shalat Zhuhur pada hari ini?\". Maka dia menjawab: \"Perhatikanlah dimana para pemimpin kamu shalat lalu shalatlah (disana) \"."},"1545":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى رَكْعَتَيْنِ وَأَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ صَدْرًا مِنْ خِلَافَتِهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepada saya [Yunus] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya ['Ubaidullah bin 'Abdullah bin 'Umar] dari [bapaknya] berkata; Nabi Shallallahu'alaihiwasallam shalat dua raka'at di Mina. Begitiu pula Abu Bakar, 'Umar dan 'Utsman pada awal kekhilafahannya."},"1546":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ الْهَمْدَانِيِّ عَنْ حَارِثَةَ بْنِ وَهْبٍ الْخُزَاعِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ أَكْثَرُ مَا كُنَّا قَطُّ وَآمَنُهُ بِمِنًى رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq Al Hamdaniy] dari [Haritsah bin Wahb Al Akhza'iy radliallahu 'anhu] berkata: \"Nabi Shallallahu'alaihiwasallam shalat bersama kami, saat itu jumlah kami belum pernah sebanyak itu, sebagaimana Beliau selalu lakukan seperti saat di Mina hanya dua raka'at\"."},"1547":{"ar":"حَدَّثَنَا قَبِيصَةُ بْنُ عُقْبَةَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ وَمَعَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ رَكْعَتَيْنِ وَمَعَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ رَكْعَتَيْنِ ثُمَّ تَفَرَّقَتْ بِكُمْ الطُّرُقُ فَيَا لَيْتَ حَظِّي مِنْ أَرْبَعٍ رَكْعَتَانِ مُتَقَبَّلَتَانِ","id":"Telah menceritakan kepada kami [Qabishah bin 'Uqbah] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari ['Abdurrahman bin Yazid] dari ['Abdullah radliallahu 'anhu] berkata; 'Aku shalat bersama Nabi Shallallahu'alaihiwasallam dua raka'at, bersama Abu Bakar radliallahu 'anhu dua raka'at dan bersama 'Umar radliallahu 'anhu dua raka'at. Kemudian banyak jalan telah menjadikan kalian berbeda pendapat. Namun aku berharap shalat yang empat raka'at maupun dua raka'at keduanya dapat diterima\"."},"1548":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ حَدَّثَنَا سَالِمٌ قَالَ سَمِعْتُ عُمَيْرًا مَوْلَى أُمِّ الْفَضْلِ عَنْ أُمِّ الْفَضْلِشَكَّ النَّاسُ يَوْمَ عَرَفَةَ فِي صَوْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَرَابٍ فَشَرِبَهُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari [Az Zuhriy] telah menceritakan kepada kami [Salim] berkata; Aku mendengar ['Umair], maula Ummu Al Fadhal dari [Ummu Al Fadhal]; 'Orang-orang ragu apakah Nabi Shallallahu'alaihiwasallam shaum pada hari 'Arafah. Maka aku utus seseorang membawakan minuman, lalu Beliau meminumnya\"."},"1549":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ أَبِي بَكْرٍ الثَّقَفِيِّ أَنَّهُ سَأَلَ أَنَسَ بْنَ مَالِكٍوَهُمَا غَادِيَانِ مِنْ مِنًى إِلَى عَرَفَةَ كَيْفَ كُنْتُمْ تَصْنَعُونَ فِي هَذَا الْيَوْمِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَانَ يُهِلُّ مِنَّا الْمُهِلُّ فَلَا يُنْكِرُ عَلَيْهِ وَيُكَبِّرُ مِنَّا الْمُكَبِّرُ فَلَا يُنْكِرُ عَلَيْهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Muhammad bin Abu Bakar Ats-Tsaqafiy] bahwa dia bertanya kepada [Anas bin Malik] saat keduanya berangkat dari Mina menuju 'Arafah: \"Apa yang kalian kerjakan pada hari ini bersama Rasulullah Shallallahu'alaihiwasallam?\" Dia menjawab: \"Diantara kami ada orang yang membaca talbiyyah, Beliau tidak mengingkarinya dan juga ada orang yang bertakbir namun Beliau juga tidak mengingkarinya\"."},"1550":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ قَالَكَتَبَ عَبْدُ الْمَلِكِ إِلَى الْحَجَّاجِ أَنْ لَا يُخَالِفَ ابْنَ عُمَرَ فِي الْحَجِّ فَجَاءَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُ وَأَنَا مَعَهُ يَوْمَ عَرَفَةَ حِينَ زَالَتْ الشَّمْسُ فَصَاحَ عِنْدَ سُرَادِقِ الْحَجَّاجِ فَخَرَجَ وَعَلَيْهِ مِلْحَفَةٌ مُعَصْفَرَةٌ فَقَالَ مَا لَكَ يَا أَبَا عَبْدِ الرَّحْمَنِ فَقَالَ الرَّوَاحَ إِنْ كُنْتَ تُرِيدُ السُّنَّةَ قَالَ هَذِهِ السَّاعَةَ قَالَ نَعَمْ قَالَ فَأَنْظِرْنِي حَتَّى أُفِيضَ عَلَى رَأْسِي ثُمَّ أَخْرُجُ فَنَزَلَ حَتَّى خَرَجَ الْحَجَّاجُ فَسَارَ بَيْنِي وَبَيْنَ أَبِي فَقُلْتُ إِنْ كُنْتَ تُرِيدُ السُّنَّةَ فَاقْصُرْ الْخُطْبَةَ وَعَجِّلْ الْوُقُوفَ فَجَعَلَ يَنْظُرُ إِلَى عَبْدِ اللَّهِ فَلَمَّا رَأَى ذَلِكَ عَبْدُ اللَّهِ قَالَ صَدَقَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Salim] berkata; \"'Abdul Malik menulis surat kepada Al Hajjaj agar tidak berbeda pendapat dengan [Ibnu 'Umar] tentang masalah haji. Lalu datanglah Ibnu 'Umar radliallahu 'anhu ketika aku bersamanya pada hari Arafah setelah matahari condong, lalu dia berteriak kepada pengawal Al Hajjaj. Maka ia (Al Hajjaj) keluar dengan mengenakan mantel kuning lalu berkata; \"Ada apa denganmu wahai Abu 'Abdurrahman?\". Ia menjawab: \"Pergilah diakhir siang jika engkau ingin mengikuti sunnah\". Ia bertanya: \"Apakah harus waktu ini?\". Ia menjawab: \"Ya, benar\". Dia berkata: \"Tunggulah aku hingga aku membasahi kepalaku, lalu aku akan keluar\". Lalu ia ('Abdullah) berhenti hingga Al Hajjaj keluar, kemudian ia berjalan diantara aku dan bapakku. Aku berkata, kepadanya (Al Hajjaj): \"Jika kamu ingin mengikuti sunah maka pendekkanlah khutbah, dan percepatlah wukuf\". Kemudian ia melihat 'Abdullah. Ketika 'Abdullah melihat hal itu, ia berkata: \"Dia benar\"."},"1551":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي النَّضْرِ عَنْ عُمَيْرٍ مَوْلَى عَبْدِ اللَّهِ بْنِ الْعَبَّاسِ عَنْ أُمِّ الْفَضْلِ بِنْتِ الْحَارِثِأَنَّ نَاسًا اخْتَلَفُوا عِنْدَهَا يَوْمَ عَرَفَةَ فِي صَوْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَعْضُهُمْ هُوَ صَائِمٌ وَقَالَ بَعْضُهُمْ لَيْسَ بِصَائِمٍ فَأَرْسَلْتُ إِلَيْهِ بِقَدَحِ لَبَنٍ وَهُوَ وَاقِفٌ عَلَى بَعِيرِهِ فَشَرِبَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Abu An-Nadhar] dari ['Umair], maula Ibnu 'Abbas radliallahu 'anhu dari [Ummu Al Fadhal binti Al Harits] bahwa; \"Orang-orang ragu tentang puasa Nabi Shallallahu'alaihiwasallam pada hari 'Arafah. Sebagian dari mereka mengatakan Beliau berpuasa, sebagian yang lain mengatakan tidak, Lalu aku utus seseorang membawakan segelas susu ketika Beliau sedang wuquf, maka Beliau meminumnya\"."},"1552":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِأَنَّ عَبْدَ الْمَلِكِ بْنَ مَرْوَانَ كَتَبَ إِلَى الْحَجَّاجِ أَنْ يَأْتَمَّ بِعَبْدِ اللَّهِ بْنِ عُمَرَ فِي الْحَجِّ فَلَمَّا كَانَ يَوْمُ عَرَفَةَ جَاءَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا وَأَنَا مَعَهُ حِينَ زَاغَتْ الشَّمْسُ أَوْ زَالَتْ فَصَاحَ عِنْدَ فُسْطَاطِهِ أَيْنَ هَذَا فَخَرَجَ إِلَيْهِ فَقَالَ ابْنُ عُمَرَ الرَّوَاحَ فَقَالَ الْآنَ قَالَ نَعَمْ قَالَ أَنْظِرْنِي أُفِيضُ عَلَيَّ مَاءً فَنَزَلَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا حَتَّى خَرَجَ فَسَارَ بَيْنِي وَبَيْنَ أَبِي فَقُلْتُ إِنْ كُنْتَ تُرِيدُ أَنْ تُصِيبَ السُّنَّةَ الْيَوْمَ فَاقْصُرْ الْخُطْبَةَ وَعَجِّلْ الْوُقُوفَ فَقَالَ ابْنُ عُمَرَ صَدَقَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Salim bin 'Abdullah] berkata; \"'Abdul Malik menulis surat kepada Al Hajjaj agar mengikuti ['Abdullah bin 'Umar] tentang pelaksanaan manasik hajji. Ketika hari 'Arafah, Ibnu'Umar radliallahu 'anhuma datang saat aku bersamanya setelah matahari condong atau siang hari, lalu dia berteriak di depan kemahnya: \"Mana dia?\". Lantas ia (Al Hajjaj) keluar menemuinya. Ibnu 'Umar radliallahu 'anhuma: \"Pergilah diakhir siang\". Ia bertanya: \"Apakah sekarang?\". Ia menjawab: \"Ya, benar\". Dia berkata: \"Tunggulah aku hingga aku membasahi kepalaku\". Lalu ia ('Abdullah) berhenti hingga Al Hajjaj keluar, kemudian ia berjalan diantara aku dan bapakku. Aku berkata, kepadanya (Al Hajjaj): \"Jika kamu ingin mendapatkan sunah hari ini maka pendekkanlah khutbah, dan percepatlah wukuf\". Kemudian Ibnu'Umar radliallahu 'anhuma berkata: \"Dia benar\"."},"1553":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو حَدَّثَنَا مُحَمَّدُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِيهِ كُنْتُ أَطْلُبُ بَعِيرًا لِي ح و حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ مُحَمَّدَ بْنَ جُبَيْرٍ عَنْ أَبِيهِ جُبَيْرِ بْنِ مُطْعِمٍ قَالَأَضْلَلْتُ بَعِيرًا لِي فَذَهَبْتُ أَطْلُبُهُ يَوْمَ عَرَفَةَ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاقِفًا بِعَرَفَةَ فَقُلْتُ هَذَا وَاللَّهِ مِنْ الْحُمْسِ فَمَا شَأْنُهُ هَا هُنَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru] telah menceritakan kepada kami [Muhammad bin Jubair bin Muth'im] dari [bapaknya]: \"Aku mencari seekor unta milikku\". Dan diriwayatkan pula, telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari ['Amru] dia mendangar [Muhammad bin Jubair] dari bapaknya, [Jabir bin Muth'im] berkata: \"Aku kehilangan seekor unta milikku, maka aku keluar mencarinya pada hari 'Arafah. Disana aku melihat Nabi Shallallahu'alaihiwasallam sedang wuquf di 'Arafah. Aku berkata: \"Demi Allah, dia dari Al Humus (Quraisy), apa yang dilakukannya disini?\"."},"1554":{"ar":"حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ عُرْوَةُ كَانَ النَّاسُ يَطُوفُونَ فِي الْجَاهِلِيَّةِ عُرَاةً إِلَّا الْحُمْسَ وَالْحُمْسُ قُرَيْشٌ وَمَا وَلَدَتْ وَكَانَتْ الْحُمْسُ يَحْتَسِبُونَ عَلَى النَّاسِ يُعْطِي الرَّجُلُ الرَّجُلَ الثِّيَابَ يَطُوفُ فِيهَا وَتُعْطِي الْمَرْأَةُ الْمَرْأَةَ الثِّيَابَ تَطُوفُ فِيهَا فَمَنْ لَمْ يُعْطِهِ الْحُمْسُ طَافَ بِالْبَيْتِ عُرْيَانًا وَكَانَ يُفِيضُ جَمَاعَةُ النَّاسِ مِنْ عَرَفَاتٍ وَيُفِيضُ الْحُمْسُ مِنْ جَمْعٍ قَالَ وَأَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ هَذِهِ الْآيَةَ نَزَلَتْ فِي الْحُمْسِ{ ثُمَّ أَفِيضُوا مِنْ حَيْثُ أَفَاضَ النَّاسُ }قَالَ كَانُوا يُفِيضُونَ مِنْ جَمْعٍ فَدُفِعُوا إِلَى عَرَفَاتٍ","id":"Telah menceritakan kepada kami [Farwah bin Abu Al Maghra'] telah menceritakan kepada kami ['Ali bin Mushir] dari [Hisyam bin 'Urwah], ['Urwah] berkata: \"Pada masa Jahiliyah orang-orang melakukan thawaf dengan telanjang kecuali Al Humus dan istilah Al Humus adalah orang-orang Quraisy dan keturunan mereka. Dahulu Al Humus membeda-bedakan manusia, diantara kaum lelakinya ada yang memberi pakaian kepada kaum lelaki sehingga dia thawaf mengenakan pakaian, begitu juga diantara wanitanya memberi pakaian kepada para wanita sehingga dia thawaf dengan pakaian itu. Sedangkan bagi orang yang tidak diberi pakaian oleh Al Humus (quraisy) maka dia thawaf dengan telanjang. Rambongan orang-orang biasanya bertolak dari 'Arafah sedangkan Al Humus (quraisy) dari Jama', atau Muzdalifah. Dia berkata; bapakku telah mengabarkan kepada saya dari ['Aisyah radliallahu 'anha] bahwa ayat ini (QS Al Baqarah ayat 199) turun tentang Al Humus (yang artinya): (\"Kemudian bertolaklah kamu dari tempat bertolaknya orang banyak\"). 'Urwah berkata: \"Awalnya mereka selalu bertolak dari Jama', kemudian diperintahkan bertolak dari 'Arafah\". "},"1555":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَ سُئِلَ أُسَامَةُوَأَنَا جَالِسٌ كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسِيرُ فِي حَجَّةِ الْوَدَاعِ حِينَ دَفَعَ قَالَ كَانَ يَسِيرُ الْعَنَقَ فَإِذَا وَجَدَ فَجْوَةً نَصَّقَالَ هِشَامٌ وَالنَّصُّ فَوْقَ الْعَنَقِ قَالَ أَبُو عَبْد اللَّهِ فَجْوَةٌ مُتَّسَعٌ وَالْجَمِيعُ فَجَوَاتٌ وَفِجَاءٌ وَكَذَلِكَ رَكْوَةٌ وَرِكَاءٌ مَنَاصٌ لَيْسَ حِينَ فِرَارٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya], berkata; [Usamah] ditanya saat aku duduk disisinya: \"Bagaimana dahulu Rasulullah Shallallahu'alaihiwasallam berjalan saat hajji wada' ketika bertolak dari 'Arafah?\" Dia menjawab: \"Beliau berjalan dengan 'anaq (makna 'anaq, sedang, tidak lambat tidak cepat) dan apabila sampai di daerah dataran yang luas Beliau berjalan dengan nashsh. Hisyam berkata: istilah nash adalah lebih cepat daripada 'anaq. Abu 'Abdullah Al Bukhariy berkata: makna fajwat adalah dataran yang luas, jama'nya fajawaat atau fijaa'. seperti kata rikwat jamaknya rika'. Dan manash tidak sampai makna berlari."},"1556":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيْثُ أَفَاضَ مِنْ عَرَفَةَ مَالَ إِلَى الشِّعْبِ فَقَضَى حَاجَتَهُ فَتَوَضَّأَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتُصَلِّي فَقَالَ الصَّلَاةُ أَمَامَكَ","id":"Telah menceritakan kepada saya [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Musa bin 'Uqbah] dari [Kuraib] maulanya Ibnu 'Abbas dari [Usamah bin Zaid radliallahu 'anhuma] bahwa tatkala Nabi Shallallahu'alaihiwasallam bertolak meninggalkan 'Arafah Beliau menuju bukit (Asy-Syi'ib) untuk menunaikan hajatnya, kemudian Beliau Shallallahu'alaihiwasallam berwudhu'. Aku bertanya: \"Wahai Rasulullah apakah kita shalat disini (sekarang)?\". Beliau Shallallahu'alaihiwasallam menjawab: \"Shalat nanti saja di depan\"."},"1557":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ قَالَ كَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَايَجْمَعُ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ بِجَمْعٍ غَيْرَ أَنَّهُ يَمُرُّ بِالشِّعْبِ الَّذِي أَخَذَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَدْخُلُ فَيَنْتَفِضُ وَيَتَوَضَّأُ وَلَا يُصَلِّي حَتَّى يُصَلِّيَ بِجَمْعٍ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] berkata: \"Dahulu ['Abdullah bin 'Umar radliallahu 'anhua] biasa menjama' antara shalat Maghrib dan 'Isya' di daerah Jama' (Muzdalifah) padahal dia melewati bukit (Asy-Syi'ib) yang juga pernah dilewati poleh Rasulullah Shallallahu'alaihiwasallam. Maka dia mendatangi bukit itu lalu beristinja' dengan batu kemudian berwudhu dan tidak shalat hingga dia shalat di daerah Jama'."},"1558":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ أَبِي حَرْمَلَةَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ قَالَرَدِفْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عَرَفَاتٍ فَلَمَّا بَلَغَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشِّعْبَ الْأَيْسَرَ الَّذِي دُونَ الْمُزْدَلِفَةِ أَنَاخَ فَبَالَ ثُمَّ جَاءَ فَصَبَبْتُ عَلَيْهِ الْوَضُوءَ فَتَوَضَّأَ وُضُوءًا خَفِيفًا فَقُلْتُ الصَّلَاةُ يَا رَسُولَ اللَّهِ قَالَ الصَّلَاةُ أَمَامَكَ فَرَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَتَى الْمُزْدَلِفَةَ فَصَلَّى ثُمَّ رَدِفَ الْفَضْلُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدَاةَ جَمْعٍقَالَ كُرَيْبٌ فَأَخْبَرَنِي عَبْدُ اللَّهِ بْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عَنْ الْفَضْلِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَزَلْ يُلَبِّي حَتَّى بَلَغَ الْجَمْرَةَ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Muhammad bin Abu Harmalah] dari [Kuraib, maulanya Ibnu 'Abbas] dari [Usamah bin Zaid radliallahu 'anhuma] bahwa dia berkata: \"Aku membonceng Rasulullah Shallallahu'alaihiwasallam dari 'Arafah. Ketika Beliau sampai dim bukit (Asy-Syi'ib) sebelah kiri yang dekat dengan Muzdalifah Beliau singgah, lalu buang air kecil. Setelah selesai Beliau datang lalu aku sodorkan kepadanya wadah air untuk wudhu'. Maka Beliau berwudhu' dengan wudhu' yang ringan (tidak sempurna). Lalu aku bertanya: \"Wahai Rasulullah, apakah kita shalat disini?\". Beliau menjawab: \"Shalat nanti saja\". Maka Rasulullah Shallallahu'alaihiwasallam menunggang tunggangannya hingga sampai di Muzdalifah lalu Beliau shalat disana. Kemudian pagi harinya Al Fadhal membonceng Rasulullah Shallallahu'alaihiwasallam di daerah Jama'. [Kuraib] berkata: \"Maka ['Abdullah bin 'Abbas radliallahu 'anhuma] mengabarkan kepada saya dari [Al Fadhal] bahwa Rasulullah Shallallahu'alaihiwasallam senantiasa membaca talbiyah hingga sampai di jamarah (tempat melempar Jumrah)."},"1559":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سُوَيْدٍ حَدَّثَنِي عَمْرُو بْنُ أَبِي عَمْرٍو مَوْلَى الْمُطَّلِبِ أَخْبَرَنِي سَعِيدُ بْنُ جُبَيْرٍ مَوْلَى وَالِبَةَ الْكُوفِيُّ حَدَّثَنِي ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ دَفَعَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَرَفَةَ فَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَاءَهُ زَجْرًا شَدِيدًا وَضَرْبًا وَصَوْتًا لِلْإِبِلِ فَأَشَارَ بِسَوْطِهِ إِلَيْهِمْ وَقَالَ أَيُّهَا النَّاسُ عَلَيْكُمْ بِالسَّكِينَةِ فَإِنَّ الْبِرَّ لَيْسَ بِالْإِيضَاعِأَوْضَعُوا أَسْرَعُوا{ خِلَالَكُمْ }مِنْ التَّخَلُّلِ بَيْنَكُمْ{ وَفَجَّرْنَا خِلَالَهُمَا }بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah menceritakan kepada kami [Ibrahim bin Suwaid] telah menceritakan kepada saya ['Amru bin Abu 'Amru, Maula Al Muththolib] telah mengabarkan kepada saya [Sa'id bin Jubair, maula Walibah AL Kuwfiy] telah menceritakan kepada saya [Ibnu 'Abbas radliallahu 'anhuma] bahwasanya dia bertolak bersama Nabi Shallallahu'alaihiwasallam pada hari 'Arafah. Kemudian Nabi Shallallahu'alaihiwasallam mendengar dari arah belakang Beliau suara yang keras dan bentakan serta pukulan terhadap unta. Maka Beliau memberi isyarat kepada mereka dengan cambuknya agar tenang. Beliau berkata: \"Wahai manusia, kalian harus tenang, karena kebaikan bukan dengan tergesa-gesa\". Kata audho'uu sama artinya dengan asro'uu yang berarti bercepat-cepat. Kata khilaalakum berasal dari kata takhallul bainakum yang artinya diantara kalian, seperti firman Allah Ta'ala Qs Al Kahfi ayat 33 yang artinya dan Kami pancarkan diantara keduanya."},"1560":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ كُرَيْبٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا أَنَّهُ سَمِعَهُ يَقُولُدَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عَرَفَةَ فَنَزَلَ الشِّعْبَ فَبَالَ ثُمَّ تَوَضَّأَ وَلَمْ يُسْبِغْ الْوُضُوءَ فَقُلْتُ لَهُ الصَّلَاةُ فَقَالَ الصَّلَاةُ أَمَامَكَ فَجَاءَ الْمُزْدَلِفَةَ فَتَوَضَّأَ فَأَسْبَغَ ثُمَّ أُقِيمَتْ الصَّلَاةُ فَصَلَّى الْمَغْرِبَ ثُمَّ أَنَاخَ كُلُّ إِنْسَانٍ بَعِيرَهُ فِي مَنْزِلِهِ ثُمَّ أُقِيمَتْ الصَّلَاةُ فَصَلَّى وَلَمْ يُصَلِّ بَيْنَهُمَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Musa bin 'Uqbah] dari [Kuraib] dari [Usamah bin Zaid radliallahu 'anhuma] bahwa dia mendengarnya berkata: \"Rasulullah Shallallahu'alaihiwasallam bertolak dari 'Arafah kemudian berhenti di bukit (Asy-Syi'ib) lalu buang air kecil kemudian berwudhu' dengan wudhu' yang tidak sempurna. Lalu Aku bertanya kepada Beliau: \" Ayo dirikan Shalat!\". Beliau menjawab: \"Shalat nanti saja\". Lalu Beliau sampai di Muzdalifah kemudian berwudhu' dengan sempurna lalu shalat dibacakan iqamatnya. Beliau melaksanakan shalat Maghrib. Kemudian setiap orang menambatkan untanya masing-masing pada tempat tambatannya, kemudian iqamat shalat dikumandangkan, maka Beliau shalat dan tidak shalat diantara keduanya\". "},"1561":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَجَمَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ بِجَمْعٍ كُلُّ وَاحِدَةٍ مِنْهُمَا بِإِقَامَةٍ وَلَمْ يُسَبِّحْ بَيْنَهُمَا وَلَا عَلَى إِثْرِ كُلِّ وَاحِدَةٍ مِنْهُمَا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Ibnu Abu Dza'bi] dari [Az Zuhriy] dari [Salim bin 'Abdullah] dari [Ibnu'Umar radliallahu 'anhuma] berkata; \"Nabi Shallallahu'alaihiwasallam menjama' shalat Maghrib dan 'Isya' di Jama' (Muzdalifah), pada setiap shalat tersebut dibacakan iqamat namun beliau tidak shalat sunnat diantara keduanya dan juga tidak setelah keduanya\"."},"1562":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ أَخْبَرَنِي عَدِيُّ بْنُ ثَابِتٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ يَزِيدَ الْخَطْمِيُّ قَالَ حَدَّثَنِي أَبُو أَيُّوبَ الْأَنْصَارِيُّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ فِي حَجَّةِ الْوَدَاعِ الْمَغْرِبَ وَالْعِشَاءَ بِالْمُزْدَلِفَةِ","id":"Telah menceritakan kepada kami [Khalid bin Mukhallad] telah menceritakan kepada kami [Sulaiman bin Bilal] telah menceritakan kepada kami [Yahya bin Sa'id] berkata, telah mengabarkan kepada saya ['Adiy bin Tsabit] berkata, telah menceritakan kepada saya ['Abdullah bin Yazid Al Khaththomiy] berkata, telah menceritakan kepada saya [Abu Ayyub Al Anshariy] bahwa Rasulullah Shallallahu'alaihiwasallam menjama' shalat Maghrib dan 'Isya' ketika hajji wada' di Muzdalifah\"."},"1563":{"ar":"حَدَّثَنَا عَمْرُو بْنُ خَالِدٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَاقَ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ يَقُولُ حَجَّ عَبْدُ اللَّهِ رَضِيَ اللَّهُ عَنْهُفَأَتَيْنَا الْمُزْدَلِفَةَ حِينَ الْأَذَانِ بِالْعَتَمَةِ أَوْ قَرِيبًا مِنْ ذَلِكَ فَأَمَرَ رَجُلًا فَأَذَّنَ وَأَقَامَ ثُمَّ صَلَّى الْمَغْرِبَ وَصَلَّى بَعْدَهَا رَكْعَتَيْنِ ثُمَّ دَعَا بِعَشَائِهِ فَتَعَشَّى ثُمَّ أَمَرَ أُرَى فَأَذَّنَ وَأَقَامَ قَالَ عَمْرٌو لَا أَعْلَمُ الشَّكَّ إِلَّا مِنْ زُهَيْرٍ ثُمَّ صَلَّى الْعِشَاءَ رَكْعَتَيْنِ فَلَمَّا طَلَعَ الْفَجْرُ قَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يُصَلِّي هَذِهِ السَّاعَةَ إِلَّا هَذِهِ الصَّلَاةَ فِي هَذَا الْمَكَانِ مِنْ هَذَا الْيَوْمِ قَالَ عَبْدُ اللَّهِ هُمَا صَلَاتَانِ تُحَوَّلَانِ عَنْ وَقْتِهِمَا صَلَاةُ الْمَغْرِبِ بَعْدَ مَا يَأْتِي النَّاسُ الْمُزْدَلِفَةَ وَالْفَجْرُ حِينَ يَبْزُغُ الْفَجْرُ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُ","id":"Telah menceritakan kepada kami ['Amru bin Khalid] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq] berkata; Aku mendengar ['Abdurrahman bin Yazid] berkata: \" ['Abdullah] (bin Mas'ud) radliallahu 'anhu melaksanakan hajji dan kami tiba di Muzdalifah ketika terdengar adzan tanda masuk waktu 'Isya' atau sekitar itu. Maka dia memerintahkan seseorang untuk mengumandangkan adzan lalu iqamat, lalu dia shalat Maghrib, lalu shalat sunnat dua raka'at sesudahnya, lalu dia mengajak makan malam, lalu dia menikmati makannya kemudian memerintahkan seseorang, aku kira dia memerintahkan seseorang untuk adzan dan iqamat, 'Amru berkata: Aku tidak mengetahui adanya keraguan kecuali dari Zuhair, kemudian dia shalat 'Isya' dua raka'at. Ketika fajar telah terbit dia berkata: \"Sesungguhnya Nabi Shallallahu'alaihiwasallam tidak pernah shalat kecuali pada waktu seperti ini, di tempat ini (saat berada di Muzdalifah dan pada hari ini\". Berkata, 'Abdullah (bin Mas'ud) radliallahu 'anhu: \"Itulah dua shalat yang ditangguhkan waktu pelaksanaannya, yaitu shalat Maghrib dilaksanakan setelah orang-orang tiba di Al Muzdalifah dan shalat Shubuh ketika fajar telah terbit\". Dia berkata: \"Aku melihat Nabi Shallallahu'alaihiwasallam melaksanaknnya seperti itu\". "},"1564":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ سَالِمٌ وَكَانَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَايُقَدِّمُ ضَعَفَةَ أَهْلِهِ فَيَقِفُونَ عِنْدَ الْمَشْعَرِ الْحَرَامِ بِالْمُزْدَلِفَةِ بِلَيْلٍ فَيَذْكُرُونَ اللَّهَ مَا بَدَا لَهُمْ ثُمَّ يَرْجِعُونَ قَبْلَ أَنْ يَقِفَ الْإِمَامُ وَقَبْلَ أَنْ يَدْفَعَ فَمِنْهُمْ مَنْ يَقْدَمُ مِنًى لِصَلَاةِ الْفَجْرِ وَمِنْهُمْ مَنْ يَقْدَمُ بَعْدَ ذَلِكَ فَإِذَا قَدِمُوا رَمَوْا الْجَمْرَةَ وَكَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُ أَرْخَصَ فِي أُولَئِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab], [Salim] berkata; \" ['Abdullah bin 'Umar radliallahu 'anhua] mendahulukan orang-orang yang lemah dari keluarganya lalu mereka berdiam (wuquf) di Al Masy'aril Haram di Muzdalifah pada malam hari. Disana mereka berdzikir (mengingat) semampu mereka kemudian mereka kembali sebelum imam berhenti (wuquf) dan sebelum bertolak. Diantara mereka ada yang menuju Mina untuk shalat Shubuh disana dan diantara mereka ada yang menuju kesana setelah shalat Shubuh. Jika mereka sudah sampai, mereka melempar jumrah. Kemudian Ibnu'Umar radliallahu 'anhuma berkata: \"Rasulullah Shallallahu'alaihiwasallam telah memberi keringanan kepada mereka\"."},"1565":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ جَمْعٍ بِلَيْلٍ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Rasulullah Shallallahu'alaihiwasallam mengutusku dari Jama' pada malam hari\". "},"1566":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ سَمِعَ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُأَنَا مِمَّنْ قَدَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ الْمُزْدَلِفَةِ فِي ضَعَفَةِ أَهْلِهِ","id":"telah menceritakan kepada kami ['Ali] telah menceritakan kepada kami [Sufyan] berkata, telah menceritakan kepada saya ['Ubaidullah bin Abu Yazid] bahewa dia mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Aku termasuk orang yang didahulukan berangkat menuju Muzdalifah diantara keluarga Beliau yang lemah\"."},"1567":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ مَوْلَى أَسْمَاءَ عَنْ أَسْمَاءَأَنَّهَا نَزَلَتْ لَيْلَةَ جَمْعٍ عِنْدَ الْمُزْدَلِفَةِ فَقَامَتْ تُصَلِّي فَصَلَّتْ سَاعَةً ثُمَّ قَالَتْ يَا بُنَيَّ هَلْ غَابَ الْقَمَرُ قُلْتُ لَا فَصَلَّتْ سَاعَةً ثُمَّ قَالَتْ يَا بُنَيَّ هَلْ غَابَ الْقَمَرُ قُلْت نَعَمْ قَالَتْ فَارْتَحِلُوا فَارْتَحَلْنَا وَمَضَيْنَا حَتَّى رَمَتْ الْجَمْرَةَ ثُمَّ رَجَعَتْ فَصَلَّتْ الصُّبْحَ فِي مَنْزِلِهَا فَقُلْتُ لَهَا يَا هَنْتَاهُ مَا أُرَانَا إِلَّا قَدْ غَلَّسْنَا قَالَتْ يَا بُنَيَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَذِنَ لِلظُّعُنِ","id":"Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari [Ibnu Juraij] berkata, telah menceritakan kepada saya ['Abdullah, maula Asma'] dari [Asma'] bahwasanya dia berhenti di daerah Jama' pada malam hari di Muzdalifah lalu dia mendirikan shalat sejenak lalu berkata; \"Wahai anakku, apakah bulan sudah menghilang?\". Aku jawab: \"Belum\". Maka dia kembali shalat sejenak lalu berkata; \"Wahai anakku, apakah bulan sudah menghilang?\". Aku jawab: \"Ya sudah\". Lalu dia berkata: \"Bersiap-siaplah untuk berangkat\". Kami pun berangkat dan berjalan (bersamanya meninggalkan Muzdalifah) hingga (sampai di tempat) melempar jumrah. Kemudian dia kembali lalu melaksanakan shalat Shubuh di tempat tinggalnya. Aku bertanya: \"Wahai gerangan, tidaklah aku melihat kecuali hari masih gelap (malam) \". Dia berkata: \"Wahai anakku, Rasulullah Shallallahu'alaihiwasallam telah mengizinkan bagi wanita yang sedang bepergian (untuk berada dalam sekedup/tandu) \"."},"1568":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ هُوَ ابْنُ الْقَاسِمِ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاسْتَأْذَنَتْ سَوْدَةُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ جَمْعٍ وَكَانَتْ ثَقِيلَةً ثَبْطَةً فَأَذِنَ لَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] telah menceritakan kepada kami ['Abdurrahman] dia adalah Ibnu Al Qasim dari [Al Qasim] dari ['Aisyah radliallahu 'anha] berkata: \"Saudah radliallahu 'anha meminta izin kepada Nabi Shallallahu'alaihiwasallam pada malam ketika berada di Jama' (Muzdalifah) untuk berangkat terlebih dahulu, karena dia termasuk wanita yang lambat, maka Beliau mengizinkannya\"."},"1569":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَفْلَحُ بْنُ حُمَيْدٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْنَزَلْنَا الْمُزْدَلِفَةَ فَاسْتَأْذَنَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَوْدَةُ أَنْ تَدْفَعَ قَبْلَ حَطْمَةِ النَّاسِ وَكَانَتْ امْرَأَةً بَطِيئَةً فَأَذِنَ لَهَا فَدَفَعَتْ قَبْلَ حَطْمَةِ النَّاسِ وَأَقَمْنَا حَتَّى أَصْبَحْنَا نَحْنُ ثُمَّ دَفَعْنَا بِدَفْعِهِ فَلَأَنْ أَكُونَ اسْتَأْذَنْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا اسْتَأْذَنَتْ سَوْدَةُ أَحَبُّ إِلَيَّ مِنْ مَفْرُوحٍ بِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Aflah bin Humaid] dari [Al Qasim bin Muhammad] dari ['Aisyah radliallahu 'anha] berkata: \"Kami berhenti di Muzdalifah, lalu Saudah radliallahu 'anhu meminta izin kepada Nabi Shallallahu'alaihiwasallam untuk berangkat terlebih dahulu sebelum sesak oleh orang-orang yang berangkat, karena dia termasuk wanita yang lambat jalannya, dan Beliau mengijinkan. Maka dia bertolak sebelum manusia berdesak-desakan sedangkan kami tetap berdiam disana hingga pagi hari. Kemudian kami bertolak menuju jumrah bersama Beliau. Sungguh bagiku meminta izin kepada Rasulullah Shallallahu'alaihiwasallam seperti yang dilakukan oleh Saudah radliallahu 'anha lebih aku sukai dari apapun yang menyenangkan\"."},"1570":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي عُمَارَةُ عَنْ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى صَلَاةً بِغَيْرِ مِيقَاتِهَا إِلَّا صَلَاتَيْنِ جَمَعَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ وَصَلَّى الْفَجْرَ قَبْلَ مِيقَاتِهَا","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepada saya ['Umarah] dari ['Abdur Rahman] dari ['Abdullah] radliallahu 'anhu berkata: \"Tidaklah pernah aku melihat Rasulullah Shallallahu'alaihiwasallam shalat bukan pada waktunya kecuali dua shalat ini, yaitu Beliau menjama' shalat Maghrib dan 'Isya' dan melaksanakan shalat fajar sebelum waktunya\". "},"1571":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ رَجَاءٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ خَرَجْنَا مَعَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ إِلَى مَكَّةَ ثُمَّ قَدِمْنَا جَمْعًا فَصَلَّى الصَّلَاتَيْنِ كُلَّ صَلَاةٍ وَحْدَهَا بِأَذَانٍ وَإِقَامَةٍ وَالْعَشَاءُ بَيْنَهُمَا ثُمَّ صَلَّى الْفَجْرَ حِينَ طَلَعَ الْفَجْرُ قَائِلٌ يَقُولُ طَلَعَ الْفَجْرُ وَقَائِلٌ يَقُولُ لَمْ يَطْلُعْ الْفَجْرُثُمَّ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ هَاتَيْنِ الصَّلَاتَيْنِ حُوِّلَتَا عَنْ وَقْتِهِمَا فِي هَذَا الْمَكَانِ الْمَغْرِبَ وَالْعِشَاءَ فَلَا يَقْدَمُ النَّاسُ جَمْعًا حَتَّى يُع��تِمُوا وَصَلَاةَ الْفَجْرِ هَذِهِ السَّاعَةَثُمَّ وَقَفَ حَتَّى أَسْفَرَ ثُمَّ قَالَ لَوْ أَنَّ أَمِيرَ الْمُؤْمِنِينَ أَفَاضَ الْآنَ أَصَابَ السُّنَّةَ فَمَا أَدْرِي أَقَوْلُهُ كَانَ أَسْرَعَ أَمْ دَفْعُ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ فَلَمْ يَزَلْ يُلَبِّي حَتَّى رَمَى جَمْرَةَ الْعَقَبَةِ يَوْمَ النَّحْرِ","id":"Telah menceritakan kepada kami ['Abdullah bin Raja'] telah menceritakan kepada kami [Isra'il] dari [Abu Ishaq] dari ['Abdurrahman bin Yazid] berkata; \"Kami keluar bersama ['Abdullah] radliallahu 'anhu menuju Makkah kemudian kami tiba di Jama', lalu dia shalat dua kali, yang pada masing-masing shalat itu dia mengumandangkan adzan dan iqamat serta menikmati makan malam diantara dua shalat itu. Lalu dia shalat Shubuh ketika fajar telah terbit. Ada seseorang berkata: \"Fajar telah terbit\". Ada yang lain berkata: \"Fajar belum terbit\". Kemudian dia ('Abdullah radliallahu 'anhu) berkata; \"Sesungguhnya Rasulullah Shallallahu'alaihiwasallam telah bersabda: \"Inilah dua shalat yang dimundurkan pelaksanaannya dari waktunya, di tempat ini, yaitu shalat Maghrib dan 'Isya', karenanya janganlah orang-orang tiba di Jama' (Muzdalifah) kecuali mereka shalat 'Isya' dan Shubuh disana, dan pada waktu ini\". Kemudian dia wuquf disana hingga langit tampak kekuningan (pagi hari) kemudian dia berkata: \"Seandainya Amiril Mu'minin bertolak sekarang (pagi hari), maka sesuai dengan (dia mendapatkan) sunnah\". 'Abdurrahman bin Zaid berkata: \"Aku tidak tahu apakah ucapannya itu agar 'Utsman radliallahu 'anhu bersegera atau 'Utsman radliallahu 'anhu bertolak dari sana senantiasa bertalbiyah hingga melempar jumrah 'Aqabah pada hari Nahar\"."},"1572":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ سَمِعْتُ عَمْرَو بْنَ مَيْمُونٍ يَقُولُ شَهِدْتُ عُمَرَ رَضِيَ اللَّهُ عَنْهُصَلَّى بِجَمْعٍ الصُّبْحَ ثُمَّ وَقَفَ فَقَالَ إِنَّ الْمُشْرِكِينَ كَانُوا لَا يُفِيضُونَ حَتَّى تَطْلُعَ الشَّمْسُ وَيَقُولُونَ أَشْرِقْ ثَبِيرُ وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَالَفَهُمْ ثُمَّ أَفَاضَ قَبْلَ أَنْ تَطْلُعَ الشَّمْسُ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] aku mendengar ['Amru bin Maimun] berkata: \"Aku menyaksikan ['Umar] radliallahu 'anhu shalat Shubuh di Jama' (Muzdalifah) lalu wuquf disana kemudian berkata: \"Sesungguhnya orang-orang musyrik tidak bertolak hingga terbit matahari dan mereka berkata: \"Terbitkanlah (matahari), wahai gunung Tsabir\". Dan Nabi Shallallahu'alaihiwasallam kemudian menyelisih mereka maka Beliau bertolak sebelum matahari terbit\". "},"1573":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ الضَّحَّاكُ بْنُ مَخْلَدٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْدَفَ الْفَضْلَ فَأَخْبَرَ الْفَضْلُ أَنَّهُ لَمْ يَزَلْ يُلَبِّي حَتَّى رَمَى الْجَمْرَةَ","id":"Telah menceritakan kepada kami [Abu 'Ashim Adh-Dhahhak bin Mukhallad] telah mengabarkan kepada kami [Ibnu Juraij] dari ['Atho'] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Nabi Shallallahu'alaihiwasallam membonceng Al Fadhal lalu [Al Fadhal] mengabarkan bahwa Beliau senantiasa bertalbiyah hingga melempar jumrah\". "},"1574":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي عَنْ يُونُسَ الْأَيْلِيِّ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ أُسَامَةَ بْنَ زَيْدٍ رَضِيَ اللَّهُ عَنْهُمَا كَانَ رِدْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عَرَفَةَ إِلَى الْمُزْدَلِفَةِ ثُمَّ أَرْدَفَ الْفَضْلَ مِنْ الْمُزْدَلِفَةِ إِلَى مِنًى قَالَ فَكِلَاهُمَا قَالَا لَمْ يَزَلْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُلَبِّي حَتَّى رَمَى جَمْرَةَ الْعَقَبَةِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [bapakku] dari [Yunus Al Ailiy] dari [Az Zuhriy] dari ['Ubaidullah bin Abdullah] dari [Ibnu 'Abbas] radliallahu 'anhuma bahwa [Usamah bin Zaid radliallahu 'anhuma] pernah diboncengkan oleh Nabi Shallallahu'alaihiwasallam dari 'Arafah menuju Muzdalifah lalu Beliau membonceng [Al Fadhal] dari Muzdalifah menuju Mina. Dia berkata: \"Selama dalam dua perjalanan itu Beliau senantiasa bertalbiyah hingga melempar jumrah 'Aqabah\"."},"1575":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ مَنْصُورٍ أَخْبَرَنَا النَّضْرُ أَخْبَرَنَا شُعْبَةُ حَدَّثَنَا أَبُو جَمْرَةَ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ الْمُتْعَةِ فَأَمَرَنِي بِهَا وَسَأَلْتُهُ عَنْ الْهَدْيِ فَقَالَ فِيهَا جَزُورٌ أَوْ بَقَرَةٌ أَوْ شَاةٌ أَوْ شِرْكٌ فِي دَمٍ قَالَ وَكَأَنَّ نَاسًا كَرِهُوهَا فَنِمْتُ فَرَأَيْتُ فِي الْمَنَامِ كَأَنَّ إِنْسَانًا يُنَادِي حَجٌّ مَبْرُورٌ وَمُتْعَةٌ مُتَقَبَّلَةٌ فَأَتَيْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَحَدَّثْتُهُ فَقَالَ اللَّهُ أَكْبَرُ سُنَّةُ أَبِي الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ وَقَالَ آدَمُ وَوَهْبُ بْنُ جَرِيرٍ وَغُنْدَرٌ عَنْ شُعْبَةَ عُمْرَةٌ مُتَقَبَّلَةٌ وَحَجٌّ مَبْرُورٌ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [An-Nadhar] telah mengabarkan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Jamrah] berkata; Aku bertanya kepada [Ibnu 'Abbas radliallahu 'anhuma] tentang muth'ah (hajji tamattu'), maka dia memerintahkan aku untuk melaksanakannya. Dan aku bertanya pula kepadanya tentang Al Hadyu (hewan qurban), maka dia berkata: 'Untuk Al Hadyu boleh unta, sapi atau kambing atau bersekutu dalam darahnya (kolektif dalam penyembilahannya). Dia berkata: \"Seakan orang-orang tidak menyukainya. Kemudian aku tidur lalu aku bermimpi seakan ada orang yang menyeru: \"Hajji mabrur dan tamattu' yang diterima\". Kemudian aku menemui Ibnu 'Abbas radliallahu 'anhuma lalu aku ceritakan mimpiku itu, maka dia berkata: \"Allahu Akbar, ini sunnah Abu Al Qasim Shallallahu'alaihiwasallam\". Dia berkata; Dan berkata, [Adam], [Wahb bin Jarir] dan [Ghundar] dari [Syu'bah] dengan redaksi: \"'Umrah mutaqabbalah (Umrah yang diterima) dan hajji mabrur\"."},"1576":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَسُوقُ بَدَنَةً فَقَالَ ارْكَبْهَا فَقَالَ إِنَّهَا بَدَنَةٌ فَقَالَ ارْكَبْهَا قَالَ إِنَّهَا بَدَنَةٌ قَالَ ارْكَبْهَا وَيْلَكَ فِي الثَّالِثَةِ أَوْ فِي الثَّانِيَةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah Shallallahu'alaihiwasallam melihat seseorang sedang menggiring untanya, maka Beliau berkata: \"Kendarailah unta itu\". Orang itu menjawab: \"Unta ini untuk qurban\". Maka Beliau Shallallahu'alaihiwasallam mengulangi perintahnya: \"Kendarailah unta itu\". Orang itu kembali menjawab: \"Unta ini untuk qurban\". Lalu Beliau berkata: \"Kendarailah unta itu, celakalah kau!\" Kalimat ini Beliau ucapkan pada ucapan Beliau yang ketiga atau kedua\"."},"1577":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ وَشُعْبَةُ قَالَا حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَسُوقُ بَدَنَةً فَقَالَ ارْكَبْهَا قَالَ إِنَّهَا بَدَنَةٌ قَالَ ارْكَبْهَا قَالَ إِنَّهَا بَدَنَةٌ قَالَ ارْكَبْهَا ثَلَاثًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] dan [Syu'bah] keduanya berkata; telah menceritakan kepada kami [Qatadah] dari [Anas radliallahu 'anhu] bahwa Nabi Shallallahu'alaihiwasallam melihat seseorang sedang menggiring untanya, maka Beliau berkata: \"Kendarailah unta itu\". Orang itu menjawab: \"Unta ini untuk qurban\". Maka Beliau Shallallahu'alaihiwasallam mengulangi perintahnya: \"Kendarailah unta itu\", sampai tiga kali. "},"1578":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَتَمَتَّعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ بِالْعُمْرَةِ إِلَى الْحَجِّ وَأَهْدَى فَسَاقَ مَعَهُ الْهَدْيَ مِنْ ذِي الْحُلَيْفَةِ وَبَدَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَهَلَّ بِالْعُمْرَةِ ثُمَّ أَهَلَّ بِالْحَجِّ فَتَمَتَّعَ النَّاسُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْعُمْرَةِ إِلَى الْحَجِّ فَكَانَ مِنْ النَّاسِ مَنْ أَهْدَى فَسَاقَ الْهَدْيَ وَمِنْهُمْ مَنْ لَمْ يُهْدِ فَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ قَالَ لِلنَّاسِ مَنْ كَانَ مِنْكُمْ أَهْدَى فَإِنَّهُ لَا يَحِلُّ لِشَيْءٍ حَرُمَ مِنْهُ حَتَّى يَقْضِيَ حَجَّهُ وَمَنْ لَمْ يَكُنْ مِنْكُمْ أَهْدَى فَلْيَطُفْ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ وَلْيُقَصِّرْ وَلْيَحْلِلْ ثُمَّ لِيُهِلَّ بِالْحَجِّ فَمَنْ لَمْ يَجِدْ هَدْيًا فَلْيَصُمْ ثَلَاثَةَ أَيَّامٍ فِي الْحَجِّ وَسَبْعَةً إِذَا رَجَعَ إِلَى أَهْلِهِ فَطَافَ حِينَ قَدِمَ مَكَّةَ وَاسْتَلَمَ الرُّكْنَ أَوَّلَ شَيْءٍ ثُمَّ خَبَّ ثَلَاثَةَ أَطْوَافٍ وَمَشَى أَرْبَعًا فَرَكَعَ حِينَ قَضَى طَوَافَهُ بِالْبَيْتِ عِنْدَ الْمَقَامِ رَكْعَتَيْنِ ثُمَّ سَلَّمَ فَانْصَرَفَ فَأَتَى الصَّفَا فَطَافَ بِالصَّفَا وَالْمَرْوَةِ سَبْعَةَ أَطْوَافٍ ثُمَّ لَمْ يَحْلِلْ مِنْ شَيْءٍ حَرُمَ مِنْهُ حَتَّى قَضَى حَجَّهُ وَنَحَرَ هَدْيَهُ يَوْمَ النَّحْرِ وَأَفَاضَ فَطَافَ بِالْبَيْتِ ثُمَّ حَلَّ مِنْ كُلِّ شَيْءٍ حَرُمَ مِنْهُ وَفَعَلَ مِثْلَ مَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَهْدَى وَسَاقَ الْهَدْيَ مِنْ النَّاسِوَعَنْ عُرْوَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي تَمَتُّعِهِ بِالْعُمْرَةِ إِلَى الْحَجِّ فَتَمَتَّعَ النَّاسُ مَعَهُ بِمِثْلِ الَّذِي أَخْبَرَنِي سَالِمٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Salim bin 'Abdullah] bahwa [Ibnu'Umar radliallahu 'anhuma] berkata; Rasulullah Shallallahu'alaihiwasallam melaksanakan hajji tamattu saat hajii wada' dengan dengan menggabungkan niat (berihram) 'umrah dan hajjinya dan Beliau membawa hewan qurban. Beliau menggiring hewan qurbannya dari Dzul Hulaifah lalu Beliau memulai berihram dengan niat 'umrah lalu berihram untuk hajji. Sedangkan orang-orang berhajji tamattu' bersama Nabi Shallallahu'alaihiwasallam dengan niat ihram 'umrah untuk pelaksanaan hajji mereka. Diantara mereka ada yang membawa hewan qurban dan ada yang tidak membawa hewan qurban. Ketika Nabi Shallallahu'alaihiwasallam tiba di Makkah, Beliau berkata, kepada orang banyak: \"Barangsiapa dari kalian yang membawa hewan qurban maka baginya tidak halal suatu apapun yang diharamkan baginya hingga dia menyelesaikan seluruh manasik hajjinya dan siapa dari kalian yang tidak membawa hewan qurban hendaklah dia thawaf di Ka'bah Baitullah dan sa'iy antara bukit Shafaa dan Marwah kemudian dia memotong rambutnya lalu bertahallul. Kemudian dia berihram untuk hajji. Dan siapa yang tidak memiliki hewan qurban hendaklah dia shaum (puasa) selama tiga hari pada masa pelaksanaan hajji dan tujuh hari jika telah kembali kepada keluarganya. Sesuatu yang harus dilakukannya ketika tiba di Makkah adalah thawaf mencium Ar-Rukun (Al Hajar Al Aswad) yang thawaf nya itu dengan berjalan cepat pada tiga putaran dan berjalan biasa pada empat putaran lainnya, kemudian setelah menyelesaikan thawaf nya di Ka'bah Baitullah itu supaya dia shalat dua raka'at dibelakang maqam Ibrahim, kemudian salam dan setelah selesai hendaklah dia menuju bukit Ash-Shafaa lalu melaksanakan sa'iy antara bukit Shafaa dan Marwah tujuh putaran, lalu tidak menghalalkan apa yang diharamkan baginya hingga menyelesaikan manasaik hajjinya dan menyembelih hewan qurban pada hari Nahar. Setelah itu dia bertolak menuju Makkah, lalu thawaf, maka menjadi halallah segala sesuatu yang sebelumnya diharamkan baginya. Maka mereka yang berqurban dan membawa hewan qurban melakukan seperti yang Rasulullah Shallallahu'alaihiwasallam lakukan\". Dan dari ['Urwah] bahwa ['Aisyah radliallahu 'anha] mengabarkannya dari Nabi Shallallahu'alaihiwasallam dalam pelaksanaan haji tamattu' dengan niat 'umrah dalam pelaksanaan hajji Beliau, maka orang-orang berhajji tamattu' bersama Beliau sebagaimana yang dikabarkan kepadaku oleh Salim dari Ibnu'Umar radliallahu 'anhuma dari Rasulullah Shallallahu'alaihiwasallam."},"1579":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمْ لِأَبِيهِأَقِمْ فَإِنِّي لَا آمَنُهَا أَنْ سَتُصَدُّ عَنْ الْبَيْتِ قَالَ إِذًا أَفْعَلُ كَمَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ قَالَ اللَّهُ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }فَأَنَا أُشْهِدُكُمْ أَنِّي قَدْ أَوْجَبْتُ عَلَى نَفْسِي الْعُمْرَةَ فَأَهَلَّ بِالْعُمْرَةِ مِنْ الدَّارِ قَالَ ثُمَّ خَرَجَ حَتَّى إِذَا كَانَ بِالْبَيْدَاءِ أَهَلَّ بِالْحَجِّ وَالْعُمْرَةِ وَقَالَ مَا شَأْنُ الْحَجِّ وَالْعُمْرَةِ إِلَّا وَاحِدٌ ثُمَّ اشْتَرَى الْهَدْيَ مِنْ قُدَيْدٍ ثُمَّ قَدِمَ فَطَافَ لَهُمَا طَوَافًا وَاحِدًا فَلَمْ يَحِلَّ حَتَّى حَلَّ مِنْهُمَا جَمِيعًا","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Nafi'] berkata; ['Abdullah bin 'Abdullah bin 'Umar radliallahu 'anhum] berkata, kepada [bapaknya]: \"Bangkitlah karena aku tidak dapat menjamin bahwa kamu tidak akan dihalangi untuk thawaf di Ka'bah Baitullah\". Maka dia berkata: \"Kerjakanlah seperti apa yang telah dilakukan Rasulullah Shallallahu'alaihiwasallam karena Allah subhanahu wata'ala telah berfirman: (\"Sungguh bagi kalian ada suri tauladan yang baik pada diri Rasulullah\"). Dan aku bersaksi kepada kalian bahwa aku telah mewajibkan diriku sendiri untuk melaksanakan 'umrah lalu aku berihram untuk 'umrah dari rumah\". Dia berkata: \"Tidaklah pelaksanaan hajji dan 'umrah itu kecuali satu\". Lalu dia membeli hewan qurban di Qudaid lalu masuk (makkah) dan thawaf utnuk hajji dan 'umrah sejali thawaf dan tifdak bertahallul hingga telah selesai (tahallul) dari keduanya\". "},"1580":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ وَمَرْوَانَ قَالَاخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ الْحُدَيْبِيَةِ مِنْ الْمَدِينَةِ فِي بِضْعَ عَشْرَةَ مِائَةً مِنْ أَصْحَابِهِ حَتَّى إِذَا كَانُوا بِذِي الْحُلَيْفَةِ قَلَّدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْهَدْيَ وَأَشْعَرَ وَأَحْرَمَ بِالْعُمْرَةِ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] dari ['Urwah bin Az Zubair] dari [Al Miswar bin Makhramah] dan [Marwan] keduanya berkata: \"Nabi Shallallahu'alaihiwasallam berangkat saat perjanjian Al Hudaibiyah dari Madinah bersama sekitar seribu orang sahabat Beliau hingga ketika sampai di Dzul Hulaifah, Nabi Shallallahu'alaihiwasallam mengikatnya dan menandai hewan qurban Beliau, lalu berihram untuk 'umrah\"."},"1581":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَفْلَحُ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْفَتَلْتُ قَلَائِدَ بُدْنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدَيَّ ثُمَّ قَلَّدَهَا وَأَشْعَرَهَا وَأَهْدَاهَا فَمَا حَرُمَ عَلَيْهِ شَيْءٌ كَانَ أُحِلَّ لَهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Aflah] dari [Al Qasim] dari ['Aisyah radliallahu 'anha] berkata; \"Aku mengikatkan kalung pada hewan qurban Nabi Shallallahu'alaihiwasallam dengan tanganku sendiri lalu Beliau mengikatnya, manandainya dan menyembelihnya. Maka apa-apa yang diharamkan setelah itu menjadi halal baginya\"."},"1582":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ رَضِيَ اللَّهُ عَنْهُمْ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ مَا شَأْنُ النَّاسِ حَلُّوا وَلَمْ تَحْلِلْ أَنْتَ قَالَ إِنِّي لَبَّدْتُ رَأْسِي وَقَلَّدْتُ هَدْيِي فَلَا أَحِلُّ حَتَّى أَحِلَّ مِنْ الْحَجِّ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] berkata, telah mengabarkan kepada saya [Nafi'] dari [Ibnu 'Umar] dari [Hafshoh radliallahu 'anhu] berkata; Aku berkata: \"Wahai Rasulullah, apa yang telah diperbuat oleh orang-orang itu mereka bertahallul sedangkan anda tidak?\". Beliau berkata: \"Aku telah mengikat rambutku, telah aku tandai hewan qurbanku, maka tidak halal bagiku segala sesuatu hingga aku menyelesaikan seluruh manasik hajji\". "},"1583":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ عُرْوَةَ وَعَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهْدِي مِنْ الْمَدِينَةِ فَأَفْتِلُ قَلَائِدَ هَدْيِهِ ثُمَّ لَا يَجْتَنِبُ شَيْئًا مِمَّا يَجْتَنِبُهُ الْمُحْرِمُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Al Laits] telah menceritakan kepada kami [Ibnu Syihab] dari ['Urwah] dan dari ['Amrah binti 'Abdurrahman] bahwa ['Aisyah radliallahu 'anha] berkata; \"Adalah Rasulullah Shallallahu'alaihiwasallam membawa hewan qurbannya dari Madinah lalu aku mengikatkan kalung pada hewan qurban Beliau maka Beliau tidak menjauhi sesuatu apa-apa yang harus diijauhi oleh orang yang berihram\"."},"1584":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا أَفْلَحُ بْنُ حُمَيْدٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْفَتَلْتُ قَلَائِدَ هَدْيِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَشْعَرَهَا وَقَلَّدَهَا أَوْ قَلَّدْتُهَا ثُمَّ بَعَثَ بِهَا إِلَى الْبَيْتِ وَأَقَامَ بِالْمَدِينَةِ فَمَا حَرُمَ عَلَيْهِ شَيْءٌ كَانَ لَهُ حِلٌّ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami [Aflah bin Humaid] dari [Al Qasim] dari ['Aisyah radliallahu 'anha] berkata; \"Aku mengikatkan kalung pada hewan qurban Nabi Shallallahu'alaihiwasallam, lalu Beliau menandainya dan mengikatnya atau aku mengikatnya kemudian Beliau mengirim hewan qurbannya itu ke Baitullah dan Beliau tinggal di Madinah. Maka apa-apa yang diharamkan bagi Beliau setelah itu menjadi halal baginya\"."},"1585":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّهَا أَخْبَرَتْهُأَنَّ زِيَادَ بْنَ أَبِي سُفْيَانَ كَتَبَ إِلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا إِنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَ مَنْ أَهْدَى هَدْيًا حَرُمَ عَلَيْهِ مَا يَحْرُمُ عَلَى الْحَاجِّ حَتَّى يُنْحَرَ هَدْيُهُ قَالَتْ عَمْرَةُ فَقَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا لَيْسَ كَمَا قَالَ ابْنُ عَبَّاسٍ أَنَا فَتَلْتُ قَلَائِدَ هَدْيِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدَيَّ ثُمَّ قَلَّدَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدَيْهِ ثُمَّ بَعَثَ بِهَا مَعَ أَبِي فَلَمْ يَحْرُمْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْءٌ أَحَلَّهُ اللَّهُ لَهُ حَتَّى نُحِرَ الْهَدْيُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Abdullah bin Abu Bakar bin 'Amru bin Hazm] dari ['Amrah binti 'Abdurrahman] bahwasanya dia mengabarkan bahwa Ziyad bin Abu Sufyan menulis surat kepada ['Aisyah radliallahu 'anha] bahwa 'Abdullah bin 'Abbas radliallahu 'anhuma berkata: \"Barangsiapa yang membawa hewan qurban maka haram baginya sebagaimana diharamkan terhadap orang yang berhajji hingga dia menyembelih hewan qurbannya\". 'Amrah berkata; Maka dia ('Aisyah radliallahu 'anha) berkata: \"Bukan begitu halnya sebagaimana yang dikatakan Ibnu 'Abbas radliallahu 'anhu. Sungguh aku telah mengikatkan kalung (sebagai tanda) pada hewan qurban Rasulullah Shallallahu'alaihiwasallam dengan tanganku sendiri lalu Rasulullah Shallallahu' alaihi wasallam mengikatnya dengan tangan Beliau lalu mengirimnya bersama bapakku. Dan tidak menjadi diharamkan bagi Rasulullah Shallallahu'alaihiwasallam sesuatu yang Allah halalkan hingga hewan qurbannya disembelih\". "},"1586":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْأَهْدَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّةً غَنَمًا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] berkata: \"Suatu kali Nabi Shallallahu'alaihiwasallam mempersembahkan hewan qurbannya berupa seekor kambing\"."},"1587":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا إِبْرَاهِيمُ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أَفْتِلُ الْقَلَائِدَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُقَلِّدُ الْغَنَمَ وَيُقِيمُ فِي أَهْلِهِ حَلَالًا","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] berkata: \"Aku telah mengikatkan kalung (sebagai tanda) pada hewan qurban Nabi Shallallahu'alaihiwasallam lalu Beliau mengikat kambingnya kemudian tingal bersama keluarganya secara halal\". "},"1588":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا مَنْصُورُ بْنُ الْمُعْتَمِرِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكُنْتُ أَفْتِلُ قَلَائِدَ الْغَنَمِ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَبْعَثُ بِهَا ثُمَّ يَمْكُثُ حَلَالًا","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Manshur bin Al Mu'tamir]. Dan telah diriwayatkan pula, telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] berkata: \"Aku telah mengikatkan kalung (sebagai tanda) pada kambing (hewan qurban) milik Nabi Shallallahu'alaihiwasallam lalu Beliau mengirimnya kemudian Beliau tinggal (bersama keluarganya) secara halal\". "},"1589":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّاءُ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْفَتَلْتُ لِهَدْيِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعْنِي الْقَلَائِدَ قَبْلَ أَنْ يُحْرِمَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakariya'] dari ['Amir] dari [Masruq] dari ['Aisyah radliallahu 'anha] berkata: \"Aku telah mengikatkan kalung (sebagai tanda) pada hewan qurban milik Nabi Shallallahu'alaihiwasallam, yang dia maksud adalah hewan qalaid (hewan yang ditandai sebagai hewan hadyu), sebelum Beliau berihram\". "},"1590":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ الْقَاسِمِ عَنْ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا قَالَتْفَتَلْتُ قَلَائِدَهَا مِنْ عِهْنٍ كَانَ عِنْدِي","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] telah menceritakan kepada kami [Mu'adz bin Mui'adz] telah menceritakan kepada kami [Ibnu 'Aun] dari [Al Qasim] dari [Ummul Mu'minin radliallahu 'anha] berkata: \"Aku telah mengalungkan (pada hewan qurban) dengan kalung terbuat dari benang wol yang ada padaku\". "},"1591":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَّامٍ أَخْبَرَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ نَبِيَّ اللَّهِ صَلَّى اللّ��هُ عَلَيْهِ وَسَلَّمَ رَأَى رَجُلًا يَسُوقُ بَدَنَةً قَالَ ارْكَبْهَا قَالَ إِنَّهَا بَدَنَةٌ قَالَ ارْكَبْهَا قَالَ فَلَقَدْ رَأَيْتُهُ رَاكِبَهَا يُسَايِرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّعْلُ فِي عُنُقِهَاتَابَعَهُ مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad], dia adalah Ibnu Salam telah mengabarkan kepada kami ['Abdul A'laa bin 'Abdul A'laa] dari [Ma'mar] dari [Yahya bin Abu Katsir] dari ['Ikrimah] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi Shallallahu'alaihiwasallam melihat seseorang sedang menggiring untanya, maka Beliau berkata: \"Kendarailah unta itu\". Orang itu menjawab: \"Unta ini untuk qurban\". Maka Beliau Shallallahu'alaihiwasallam mengulangi perintahnya: \"Kendarailah unta itu\". Abu Hurairah radliallahu 'anhu berkata: \"Aku melihat kemudian orang itu mengendarai untanya berjalan disamping kiri Nabi Shallallahu'alaihiwasallam sedangkan sandalnya digantungnya pada lehernya\". Hadits ini dikuatkan pula oleh [Muhammad bin Basysyar] telah menceritakan kepada kami ['Utsman bin 'Umar] telah mengabarkan kepada kami ['Ali bin Al Mubarak] dari [Yahya] dari ['Ikrimah] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi Shallallahu'alaihiwasallam. "},"1592":{"ar":"حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَتَصَدَّقَ بِجِلَالِ الْبُدْنِ الَّتِي نَحَرْتُ وَبِجُلُودِهَا","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [Mujahid] dari ['Abdurrahman bin Abu Laila] dari ['Ali radliallahu 'anhu] berkata: \"Rasulullah Shallallahu'alaihiwasallam memerintahkan aku agar menshadaqahkan pelana unta yang aku sembelih sebagai qurban dan juga kulitnya\". "},"1593":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَبُو ضَمْرَةَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ قَالَ أَرَادَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاالْحَجَّ عَامَ حَجَّةِ الْحَرُورِيَّةِ فِي عَهْدِ ابْنِ الزُّبَيْرِ رَضِيَ اللَّهُ عَنْهُمَا فَقِيلَ لَهُ إِنَّ النَّاسَ كَائِنٌ بَيْنَهُمْ قِتَالٌ وَنَخَافُ أَنْ يَصُدُّوكَ فَقَالَ{ لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ }إِذًا أَصْنَعَ كَمَا صَنَعَ أُشْهِدُكُمْ أَنِّي أَوْجَبْتُ عُمْرَةً حَتَّى إِذَا كَانَ بِظَاهِرِ الْبَيْدَاءِ قَالَ مَا شَأْنُ الْحَجِّ وَالْعُمْرَةِ إِلَّا وَاحِدٌ أُشْهِدُكُمْ أَنِّي قَدْ جَمَعْتُ حَجَّةً مَعَ عُمْرَةٍ وَأَهْدَى هَدْيًا مُقَلَّدًا اشْتَرَاهُ حَتَّى قَدِمَ فَطَافَ بِالْبَيْتِ وَبِالصَّفَا وَلَمْ يَزِدْ عَلَى ذَلِكَ وَلَمْ يَحْلِلْ مِنْ شَيْءٍ حَرُمَ مِنْهُ حَتَّى يَوْمِ النَّحْرِ فَحَلَقَ وَنَحَرَ وَرَأَى أَنْ قَدْ قَضَى طَوَافَهُ الْحَجَّ وَالْعُمْرَةَ بِطَوَافِهِ الْأَوَّلِ ثُمَّ قَالَ كَذَلِكَ صَنَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Abu Dhamrah] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] berkata; Bahwa [Ibnu'Umar radliallahu 'anhuma] hendak melaksanakan hajji pada tahun hajinya Kauk Al Haruriyyah pada zaman kekuasaan Ibnu Az Zubair radliallahu 'anhuma lalu dikatakan kepadanya: \"Seungguhnya telah terjadi peperangan di tengah manusia dan aku khawatir mereka akan menghalangimu\". Maka dia berkata, (\"Sungguh bagi kalian ada suri tauladan yang baik pada diri Rasulullah\"). Maka aku akan melakukan sebagaimana Rasulullah Shallallahu'alaihiwasallam telah melakukannya dan sungguh aku bersaksi kepada kalian bahwa aku sudah mewajibkan (meniatkan) diriku untuk 'umrah\":. Kemudian ketika dia tiba di Al Baida' (padang sahara) dia berkata: \"Tidaklah pelaksanaan hajji dan 'umrah itu kecuali satu dan aku bersaksi kepada kalian bahwa aku telah menggabungkan hajji dan 'umrahku dan aku membawa hewan qurban yang aku beli dan telah aku ikat dan tandai. Maka dia ber thawaf di Ka'bah Baitullah dan sa'iy di bukit Ash-Shafaa dan tidak lebih dari itu, tidak bertahallul dari sesuatu yang diharamkan hingga hari Nahar. Maka pada hari Nahar itu dia mencukur rambutnya lalu menyembelih hewan qurbannya dan dia memandang telah menyelesaikan thawaf hajji dan 'umrahnya cukup dengan thawaf nya yang pertama, kemudian dia berkata: \"Begitulah apa yang dikerjakan Rasulullah Shallallahu'alaihiwasallam \"."},"1594":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ قَالَتْ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِخَمْسٍ بَقِينَ مِنْ ذِي الْقَعْدَةِ لَا نُرَى إِلَّا الْحَجَّ فَلَمَّا دَنَوْنَا مِنْ مَكَّةَ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَكُنْ مَعَهُ هَدْيٌ إِذَا طَافَ وَسَعَى بَيْنَ الصَّفَا وَالْمَرْوَةِ أَنْ يَحِلَّ قَالَتْ فَدُخِلَ عَلَيْنَا يَوْمَ النَّحْرِ بِلَحْمِ بَقَرٍ فَقُلْتُ مَا هَذَا قَالَ نَحَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَزْوَاجِهِ قَالَ يَحْيَى فَذَكَرْتُهُ لِلْقَاسِمِ فَقَالَ أَتَتْكَ بِالْحَدِيثِ عَلَى وَجْهِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Yahya bin Sa'id] dari ['Amrah binti 'Abdurrahman] berkata; Aku mendengar ['Aisyah radliallahu 'anha] berkata: \"Kami keluar bersama Rasulullah Shallallahu'alaihiwasallam pada lima hari terakhir bulan Dzul Qa'dah yang tujuan kami tidak lain kecuali untuk menunaikan hajji. Ketika kami sudah dekat dengan kota Makkah, Rasulullah Shallallahu'alaihiwasallam memerintahkan: \"Barangsiapa yang tidak membawa Hadyu (hewan qurban) apabila telah thawaf di Ka'bah Baitullah dan sa'iy di bukit Shafaa dan Marwah hendaklah dia bertahallul\". 'Aisyah radliallahu 'anha berkata: \"Ketika hari Nahar kami dikirimi daging sapi lalu aku bertanya; \"Apa ini?. Dia menjawab: \"Ini kurban Rasulullah Shallallahu'alaihiwasallam atas nama isteri-isteri Beliau\". Yahya berkata; Lalu aku ceritakan kepada Al Qasim, maka dia berkata: \"Dia menyampaikan hadis kepadamu secara langsung?\"."},"1595":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ سَمِعَ خَالِدَ بْنَ الْحَارِثِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ رَضِيَ اللَّهُ عَنْهُكَانَ يَنْحَرُ فِي الْمَنْحَرِ قَالَ عُبَيْدُ اللَّهِ مَنْحَرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dia mendengar [Khalid bin Al Harits] telah menceritakan kepada kami ['Ubaidullah bin 'Umar] dari [Nafi'] bahwa ['Abdullah radliallahu 'anhu] menyembelih hewan qurban pada tempat penyembelihannya\". Berkata, 'Ubaidullah: Yaitu tempat penyembelihan hewan qurban Rasulullah Shallallahu'alaihiwasallam."},"1596":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاكَانَ يَبْعَثُ بِهَدْيِهِ مِنْ جَمْعٍ مِنْ آخِرِ اللَّيْلِ حَتَّى يُدْخَلَ بِهِ مَنْحَرُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ حُجَّاجٍ فِيهِمْ الْحُرُّ وَالْمَمْلُوكُ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Anas bin 'Iyadh] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] bahwa [Ibnu'Umar radliallahu 'anhuma] mengirim hewan qurbannya dari Jama' pada akhir malam hingga dibawa masuk pada tempat penyembelihan hewan qurban Nabi Shallallahu'alaihiwasallam, bersama para jama'ah hajji yang terdiri dari orang-orang merdeka dan para budak\". "},"1597":{"ar":"حَدَّثَنَا سَهْلُ بْنُ بَكَّارٍ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ وَذَكَرَ الْحَدِيثَ قَالَوَنَحَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ سَبْعَ بُدْنٍ قِيَامًا وَضَحَّى بِالْمَدِينَةِ كَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ مُخْتَصَرًا","id":"Telah menceritakan kepada kami [Sahal bin Bakar] telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Abu Qalabah] dari [Anas] lalu menyebutkan hadits, katanya: \"Nabi Shallallahu'alaihiwasallam menyembelih tujuh ekor unta dengan tangannya sendiri dalam keadaan berdiri dan di Madinah Beliau berqurban dua ekor kambing yang gemuk dan bertanduk pendek."},"1598":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ يُونُسَ عَنْ زِيَادِ بْنِ جُبَيْرٍ قَالَ رَأَيْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَتَى عَلَى رَجُلٍ قَدْ أَنَاخَ بَدَنَتَهُ يَنْحَرُهَا قَالَ ابْعَثْهَا قِيَامًا مُقَيَّدَةً سُنَّةَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَقَالَ شُعْبَةُ عَنْ يُونُسَ أَخْبَرَنِي زِيَادٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Yunus] dari [Ziyad bin Jubair] berkata: Aku melihat [Ibnu 'Umar radliallahu 'anhu] mendatangi seseorang yang tengah membaringkan unta yang akan disembelihnya lalu berkata: \"Jadikanlah dia dalam keadaan berdiri dan terikat sebagai sunnah Muhammad Shallallahu'alaihiwasallam\". Dan berkata, [Syu'bah] dari [Yunus] telah mengabarkan kepada saya [Ziyad]. "},"1599":{"ar":"حَدَّثَنَا سَهْلُ بْنُ بَكَّارٍ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ بِالْمَدِينَةِ أَرْبَعًا وَالْعَصْرَ بِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ فَبَاتَ بِهَا فَلَمَّا أَصْبَحَ رَكِبَ رَاحِلَتَهُ فَجَعَلَ يُهَلِّلُ وَيُسَبِّحُ فَلَمَّا عَلَا عَلَى الْبَيْدَاءِ لَبَّى بِهِمَا جَمِيعًا فَلَمَّا دَخَلَ مَكَّةَ أَمَرَهُمْ أَنْ يَحِلُّوا وَنَحَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِهِ سَبْعَ بُدْنٍ قِيَامًا وَضَحَّى بِالْمَدِينَةِ كَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ","id":"Telah menceritakan kepada kami [Sahal bin Bakar] telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Abu Qalabah] dari [Anas radliallahu 'anhu] berkata; Nabi Shallallahu'alaihiwasallam melaksanakan shalat Zhuhur di Madinah empat raka'at dan shalat 'Ashar di Dzu Hulaifah dua raka'at lalu Beliau bermalam disana. Ketika pagi harinya Beliau mengendarai tunggangannya lalu Beliau membaca tahlil (Laa ilaaha illallah) dan tasbih (Subhaanallah). Ketika sampai di Al Baida' (padang sahara) Beliau membaca tahlil dan tasbih (dengan suara keras) bersama-sama. Dan ketika memasuki kota Makkah Beliau memerintahkan mereka agar bertahallul dan Nabi Shallallahu'alaihiwasallam menyembelih tujuh ekor unta dengan tangannya sendiri dalam keadaan berdiri, dan di Madinah Beliau berqurban dua ekor kambing yang gemuk dan bertanduk."},"1600":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ بِالْمَدِينَةِ أَرْبَعًا وَالْعَصْرَ بِذِي الْحُلَيْفَةِ رَكْعَتَيْنِوَعَنْ أَيُّوبَ عَنْ رَجُلٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ ثُمَّ بَاتَ حَتَّى أَصْبَحَ فَصَلَّى الصُّبْحَ ثُمَّ رَكِبَ رَاحِلَتَهُ حَتَّى إِذَا اسْتَوَتْ بِهِ الْبَيْدَاءَ أَهَلَّ بِعُمْرَةٍ وَحَجَّةٍ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Abu Qalabah] dari [Anas bin Malik radliallahu 'anhu] berkata; Nabi Shallallahu'alaihiwasallam melaksanakan shalat Zhuhur di Madinah empat raka'at dan shalat 'Ashar di Dzu Hulaifah dua raka'at. Dan dari Ayyub dari seseorang dari Anas radliallahu 'anhu; Kemudian Beliau bermalam sampai pagi lalu shalat Shubuh, lalu mengendarai tunggangannya hingga sampai di Al Baida', Beliau berihram untuk 'umrah sekaligus hajinya (menggabungkannya) \"."},"1601":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ قَالَ أَخْبَرَنِي ابْنُ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَبَعَثَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُمْتُ عَلَى الْبُدْنِ فَأَمَرَنِي فَقَسَمْتُ لُحُومَهَا ثُمَّ أَمَرَنِي فَقَسَمْتُ جِلَالَهَا وَجُلُودَهَاقَالَ سُفْيَانُ وَحَدَّثَنِي عَبْدُ الْكَرِيمِ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَ أَمَرَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَقُومَ عَلَى الْبُدْنِ وَلَا أُعْطِيَ عَلَيْهَا شَيْئًا فِي جِزَارَتِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] berkata, telah mengabarkan kepada saya [Ibnu Abu Najih] dari [Mujahid] dari ['Abdurrahman bin Abu Laila] dari ['Ali radliallahu 'anhu] berkata: \"Rasulullah shallallahu 'alaihi wasallam mengutusku, lalu aku sampai pada hewan qurbanku, maka beliau memerintahkan aku, kemudian aku membagi-bagikan daging qurban tersebut. Kemudian Beliau memerintahkanku pula agar membagikan pelana unta qurban dan juga kulitnya\". [Sufyan] berkata; dan telah menceritakan kepada saya ['Abdul Karim] dari [Mujahid] dari ['Abdurrahman bin Abu Laila] dari ['Ali radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam memerintahkanku agar aku berada (menyaksikan hewan qurbannya) dan membagi-bagikan qurban namun aku tidak boleh memberikan apapun dari hewan qurban itu kepada tukang jagalnya\"."},"1602":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي الْحَسَنُ بْنُ مُسْلِمٍ وَعَبْدُ الْكَرِيمِ الْجَزَرِيُّ أَنَّ مُجَاهِدًا أَخْبَرَهُمَا أَنَّ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى أَخْبَرَهُ أَنَّ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يَقُومَ عَلَى بُدْنِهِ وَأَنْ يَقْسِمَ بُدْنَهُ كُلَّهَا لُحُومَهَا وَجُلُودَهَا وَجِلَالَهَا وَلَا يُعْطِيَ فِي جِزَارَتِهَا شَيْئًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] berkata, telah mengabarkan kepada saya [Al Hasan bin Muslim] dan ['Abdul Karim Al Jazariy] bahwa [Mujahid] telah mengabarkan kepada keduanya bahwa ['Abdurrahman bin Abu Laila] mengabarkan kepadanya bahwa ['Ali radliallahu 'anhu] mengabarkan kepadanya bahwa; \"Nabi shallallahu 'alaihi wasallam memerintahkan kepadanya agar dia berada (menyaksikan hewan qurbannya) dan membagi-bagikan qurban semuanya dari dagingnya, kulitnya dan pelananya dan agar tidak memberikan apapun dari hewan qurban itu kepada tukang jagalnya\"."},"1603":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سَيْفُ بْنُ أَبِي سُلَيْمَانَ قَالَ سَمِعْتُ مُجَاهِدًا يَقُولُ حَدَّثَنِي ابْنُ أَبِي لَيْلَى أَنَّ عَلِيًّا رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُ قَالَأَهْدَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِائَةَ بَدَنَةٍ فَأَمَرَنِي بِلُحُومِهَا فَقَسَمْتُهَا ثُمَّ أَمَرَنِي بِجِلَالِهَا فَقَسَمْتُهَا ثُمَّ بِجُلُودِهَا فَقَسَمْتُهَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sayf bin Abu Sulaiman] berkata; Aku mendengar [Mujahid] berkata; telah menceritakan kepada saya [Ibnu Abu Laila] bahwa ['Ali radliallahu 'anhu] menceritakan kepadanya, katanya: Nabi shallallahu 'alaihi wasallam berqurban dengan seratus unta lalu Beliau memerintahkanku tentang daging-dagingnya, maka aku membagi-bagikannya, kemudian memerintahkanku tentang pelana-pelananya maka aku membagi-bagikannya kemudian memerintahkan aku tentang kulit-kulitnya maka aku membagi-bagikannya\"."},"1604":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ حَدَّثَنَا عَطَاءٌ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُكُنَّا لَا نَأْكُلُ مِنْ لُحُومِ بُدْنِنَا فَوْقَ ثَلَاثِ مِنًى فَرَخَّصَ لَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كُلُوا وَتَزَوَّدُوا فَأَكَلْنَا وَتَزَوَّدْنَا قُلْتُ لِعَطَاءٍ أَقَالَ حَتَّى جِئْنَا الْمَدِينَةَ قَالَ لَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] telah menceritakan kepada kami ['Atho'] dia mendengar [Jabir bin 'Abdullah radliallahu 'anhu] berkata: \"Kami tidak memakan daging dari hewan qurban kami melebihi tiga hari Mina (Tasyriq) kemudian Nabi shallallahu 'alaihi wasallam memberi keringanan kepada kami, sabda Beliau: \"Makanlah dan sisakanlah sebagai bekal kalian?\". Aku bertanya kepada 'Atho': \"Apakah Beliau berkata: \"Hingga kita tiba di Madinah?\". Dia menjawab: \"Tidak\"."},"1605":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ قَالَ حَدَّثَنِي يَحْيَى قَالَ حَدَّثَتْنِي عَمْرَةُ قَالَتْ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِخَمْسٍ بَقِينَ مِنْ ذِي الْقَعْدَةِ وَلَا نُرَى إِلَّا الْحَجَّ حَتَّى إِذَا دَنَوْنَا مِنْ مَكَّةَ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَكُنْ مَعَهُ هَدْيٌ إِذَا طَافَ بِالْبَيْتِ ثُمَّ يَحِلُّ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا فَدُخِلَ عَلَيْنَا يَوْمَ النَّحْرِ بِلَحْمِ بَقَرٍ فَقُلْتُ مَا هَذَا فَقِيلَ ذَبَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَزْوَاجِهِ قَالَ يَحْيَى فَذَكَرْتُ هَذَا الْحَدِيثَ لِلْقَاسِمِ فَقَالَ أَتَتْكَ بِالْحَدِيثِ عَلَى وَجْهِهِ","id":"Telah menceritakan kepada kami [Khalid bin Mukhalad] telah menceritakan kepada kami [Sulaiman bin Bilal] berkata, telah menceritakan kepada saya [Yahya] berkata, telah menceritakan kepada saya ['Amrah] berkata; Aku mendengar ['Aisyah radliallahu 'anha] berkata: \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam pada lima hari terakhir bulan Dzul Qa'dah yang tujuan kami tidak lain kecuali untuk menunaikan haji. Hingga ketika kami sudah dekat dengan kota Makkah, Rasulullah shallallahu 'alaihi wasallam memerintahkan: \"Barangsiapa yang tidak membawa Hadyu (hewan qurban) apabila telah thawaf di Ka'bah Baitullah hendaklah dia bertahallul\". 'Aisyah radliallahu 'anha berkata: \"Ketika hari Nahar kami dikirimi daging sapi lalu aku bertanya; \"Apa ini?. Dijawab: \"Ini kurban Rasulullah shallallahu 'alaihi wasallam atas nama isteri-isteri Beliau\". Yahya berkata; Lalu aku ceritakan hadits ini kepada Al Qasim, maka dia berkata: \"Dia menyampaikan hadis kepadamu secara langsung?\"."},"1606":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَوْشَبٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا مَنْصُورُ بْنُ زَاذَانَ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمَّنْ حَلَقَ قَبْلَ أَنْ يَذْبَحَ وَنَحْوِهِ فَقَالَ لَا حَرَجَ لَا حَرَجَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Hawsyab] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Manshur bin Zadzan] dari ['Atho'] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam ditanya tentang mencukur rambut sebelum menyembelih hewan qurban dan pertanyaan yang sejenis itu\". Maka Beliau bersabda: Tidak apa, tidak dosa\"."},"1607":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ أَخْبَرَنَا أَبُو بَكْرٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاقَالَ رَجُلٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زُرْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ لَا حَرَجَ قَالَ حَلَقْتُ قَبْلَ أَنْ أَذْبَحَ قَالَ لَا حَرَجَ قَالَ ذَبَحْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ لَا حَرَجَوَقَالَ عَبْدُ الرَّحِيمِ الرَّازِيُّ عَنْ ابْنِ خُثَيْمٍ أَخْبَرَنِي عَطَاءٌ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ الْقَاسِمُ بْنُ يَحْيَى حَدَّثَنِي ابْنُ خُثَيْمٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عَفَّانُ أُرَاهُ عَنْ وُهَيْبٍ حَدَّثَنَا ابْنُ خُثَيْمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ حَمَّادٌ عَنْ قَيْسِ بْنِ سَعْدٍ وَعَبَّادِ بْنِ مَنْصُورٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah mengabarkan kepada kami [Abu Bakar] dari ['Abdul 'Aziz bin Rufai'] dari ['Atho'] dari [Ibnu 'Abbas radliallahu 'anhuma]; Ada seorang laki-laki berkata, kepada Nabi shallallahu 'alaihi wasallam: \"Aku berziarah (ke Ka'bah untuk thawaf) sebelum aku melempar jumrah?\". Beliau bersabda: \"Tidak dosa\". Orang itu berkata, lagi: \"Aku mencukur rambut sebelum aku menyembelih hewan qurban?\". Beliau bersabda: \"Tidak dosa\". Orang itu berkata, lagi: \"Aku menyembelih hewan qurban sebelum aku melempar jumrah?\". Beliau bersabda: \"Tidak dosa\". Dan berkata, ['Abdur Rahim Ar-Raziy] dari [Ibnu Khutsaim] telah mengabarkan kepada saya ['Atho'] dari [Ibnu 'Abbas radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam. Dan berkata, [Al Qosim bin Yahya] telah menceritakan kepadaku [Ibnu Khutsaim] dari ['Atha] dari [Ibnu 'Abbas] dari Nabi shallallahu 'alaihi wasallam, Dan berkata, ['Affan], (Abu 'Abdullah Al Bukhariy berkata,): \"Aku mengira\", dia mendapatkan kabar dari [Wuhaib] telah menceritakan kepada kami [Ibnu Khutsaim] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam. Dan berkata, [Hammad] dari [Qais bin Sa'ad] dan ['Abbad bin Manshur] dari ['Atho'] dari [Jabir radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam. "},"1608":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَمَيْتُ بَعْدَ مَا أَمْسَيْتُ فَقَالَ لَا حَرَجَ قَالَ حَلَقْتُ قَبْلَ أَنْ أَنْحَرَ قَالَ لَا حَرَجَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami ['Abdul A'laa] telah menceritakan kepada kami [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam ditanya, kata orang itu: \"Aku melempar jumrah setelah sore\". Beliau bersabda: \"Tidak dosa\". Orang itu berkata, lagi: \"Aku mencukur rambut sebelum menyembelih hewan qurban\". Beliau bersabda: \"Tidak dosa\". "},"1609":{"ar":"حَدَّثَنَا عَبْدَانُ قَالَ أَخْبَرَنِي أَبِي عَنْ شُعْبَةَ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِالْبَطْحَاءِ فَقَالَ أَحَجَجْتَ قُلْتُ نَعَمْ قَالَ بِمَا أَهْلَلْتَ قُلْتُ لَبَّيْكَ بِإِهْلَالٍ كَإِهْلَالِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحْسَنْتَ انْطَلِقْ فَطُفْ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ أَتَيْتُ امْرَأَةً مِنْ نِسَاءِ بَنِي قَيْسٍ فَفَلَتْ رَأْسِي ثُمَّ أَهْلَلْتُ بِالْحَجِّ فَكُنْتُ أُفْتِي بِهِ النَّاسَ حَتَّى خِلَافَةِ عُمَرَ رَضِيَ اللَّهُ عَنْهُ فَذَكَرْتُهُ لَهُ فَقَالَ إِنْ نَأْخُذْ بِكِتَابِ اللَّهِ فَإِنَّهُ يَأْمُرُنَا بِالتَّمَامِ وَإِنْ نَأْخُذْ بِسُنَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَحِلَّ حَتَّى بَلَغَ الْهَدْيُ مَحِلَّهُ","id":"Telah menceritakan kepada kami ['Abdan] berkata, telah mengabarkan kepada saya [bapakku] dari [Syu'bah] dari [Qais bin Muslim] dari [Thoriq bin Syihab] dari [Abu Musa radliallahu 'anhu] berkata; \"Aku menemui Rasulullah shallallahu 'alaihi wasallam ketika Beliau berada di Bathha', lalu Beliau berkata: \"Apakah kamu sudah berniat (berihram) untuk haji?\". Aku jawab: \"Ya, sudah\". Beliau bertanya lagi: \"Bagaimana cara kamu berihram?\". Aku jawab: \"Aku berihram dengan bertalbiyah (berniat memulai haji) sebagaimana Nabi shallallahu 'alaihi wasallam berihram\". Maka Beliau berkata: \"Kamu sudah berbuat dengan baik, maka berangkatlah dan thawaflah di Ka'bah Baitullah dan sa'iy antara bukit Shafaa dan Marwah\". Kemudian aku menemui seorang wanita dari Banu Qais lalu dia mencari kutu kepalaku. Kemudian aku berihram untuk haji. Setelah itu aku selalu memberi fatwa kepada orang tentang manasik ini hingga masa khilafah 'Umar radliallahu 'anhu yang aku menceritakan kepadanya, maka dia berkata: \"Jika kita mengambil pelajaran dari Kitab Allah maka Dia memerintahkan kita untuk menyempurnakannya dan apabila kita mengambil sunnah Rasulullah shallallahu 'alaihi wasallam, sesungguhnya Rasulullah shallallahu 'alaihi wasallam tidak bertahallul hingga Al Hadyu samapai pada tempat penyembelihannya\". "},"1610":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ رَضِيَ اللَّهُ عَنْهُمْ أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ مَا شَأْنُ النَّاسِ حَلُّوا بِعُمْرَةٍ وَلَمْ تَحْلِلْ أَنْتَ مِنْ عُمْرَتِكَ قَالَ إِنِّي لَبَّدْتُ رَأْسِي وَقَلَّدْتُ هَدْيِي فَلَا أَحِلُّ حَتَّى أَنْحَرَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Ibnu 'Umar] dari [Hafsoh radliallahu 'anhum] bahwa dia berkata; \"Wahai Rasulullah, apa yang telah diperbuat oleh orang-orang itu, mereka bertahallul sedangkan anda tidak bertahallul dari 'umrah anda?\". Beliau berkata: \"Aku telah mengikat rambutku dan telah aku tandai hewan qurbanku, maka aku tidak bertahallul hingga aku menyembelih hewan qurban\". "},"1611":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ قَالَ نَافِعٌ كَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُحَلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّتِهِ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib bin Abu Hamzah], [Nafi'] berkata; [Ibnu'Umar radliallahu 'anhuma] pernah berkata: \"Rasulullah shallallahu 'alaihi wasallam mencukur rambut pada pelaksanaan haji Beliau\"."},"1612":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ ارْحَمْ الْمُحَلِّقِينَ قَالُوا وَالْمُقَصِّرِينَ يَا رَسُولَ اللَّهِ قَالَ اللَّهُمَّ ارْحَمْ الْمُحَلِّقِينَ قَالُوا وَالْمُقَصِّرِينَ يَا رَسُولَ اللَّهِ قَالَ وَالْمُقَصِّرِينَوَقَالَ اللَّيْثُ حَدَّثَنِي نَافِعٌ رَحِمَ اللَّهُ الْمُحَلِّقِينَ مَرَّةً أَوْ مَرَّتَيْنِ قَالَ وَقَالَ عُبَيْدُ اللَّهِ حَدَّثَنِي نَافِعٌ وَقَالَ فِي الرَّابِعَةِ وَالْمُقَصِّرِينَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, rahmatilah orang-orang yang mencukur rambutnya\". Orang-orang berkata: \"Dan juga bagi orang-orang yang hanya memendekkan rambutnya, wahai Rasulullah?\". Beliau tetap berkata: \"Ya Allah, rahmatilah orang-orang yang mencukur rambutnya\". Orang-orang berkata, lagi: \"Dan juga bagi orang-orang yang hanya memendekkan rambutnya, wahai Rasulullah?\". Beliau baru bersabda: \"Ya, juga bagi orang-orang yang hanya memendekkan rambutnya\". Dan [Al Laits] berkata, telah menceritakan kepada saya (Nafi'), katanya; Beliau shallallahu 'alaihi wasallambersabda: \"Allah merahmati orang-orang yang mencukur rambutnya\", sekali atau dua kali. Dia berkata,, dan berkata, ['Ubaidullah] telah menceritakan kepada saya [Nafi']; dan Beliau shallallahu 'alaihi wasallamberkata, pada ucapan yang keempat: \"Dan bagi orang-orang yang hanya memendekkan rambutnya\". "},"1613":{"ar":"حَدَّثَنَا عَيَّاشُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ حَدَّثَنَا عُمَارَةُ بْنُ الْقَعْقَاعِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ اغْفِرْ لِلْمُحَلِّقِينَ قَالُوا وَلِلْمُقَصِّرِينَ قَالَ اللَّهُمَّ اغْفِرْ لِلْمُحَلِّقِينَ قَالُوا وَلِلْمُقَصِّرِينَ قَالَهَا ثَلَاثًا قَالَ وَلِلْمُقَصِّرِينَ","id":"Telah menceritakan kepada kami ['Ayyasy bin Al Walid] telah menceritakan kepada kami [Muhammad bin Fudhail] telah menceritakan kepada kami ['Umarah bin Al Qa'qa'] dari [Abu Zur'ah] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, ampunilah orang-orang yang mencukur rambutnya\". Orang-orang berkata: \"Dan juga bagi orang-orang yang hanya memendekkan rambutnya?\". Beliau tetap berkata: \"Ya Allah, ampunilah orang-orang yang mencukur rambutnya\". Beliau mengucapkannya hingga tiga kali, baru kemudian bersabda: Dan juga orang-orang yang hanya memendekkan rambutnya\". "},"1614":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ حَدَّثَنَا جُوَيْرِيَةُ بْنُ أَسْمَاءَ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَحَلَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَطَائِفَةٌ مِنْ أَصْحَابِهِ وَقَصَّرَ بَعْضُهُمْ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad bin Asma'] telah menceritakan kepada kami [Juwairiyah bin Asma'] dari [Nafi'] bahwa ['Abdullah bin 'Umar radliallahu 'anhu] berkata; \"Rasulullah shallallahu 'alaihi wasallam mencukur rambut (pada pelaksanaan haji Beliau) dan sebagian dari para sahabat Beliau dan diantara mereka ada juga yang hanya memendekkan rambutnya\".\"."},"1615":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ عَنْ مُعَاوِيَةَ رَضِيَ اللَّهُ عَنْهُمْ قَالَقَصَّرْتُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِشْقَصٍ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Al Hasan bin Muslim] dari [Thowus] dari [Ibnu 'Abbas] dari [Mu'awiyah radliallahu 'anhu] berkata: \"Aku memotong rambut Rasulullah shallallahu 'alaihi wasallam dengan menggunakan ujung pedang yang panjang\". "},"1616":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ حَدَّثَنَا فُضَيْلُ بْنُ سُلَيْمَانَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ أَخْبَرَنِي كُرَيْبٌ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ أَمَرَ أَصْحَابَهُ أَنْ يَطُوفُوا بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ يَحِلُّوا وَيَحْلِقُوا أَوْ يُقَصِّرُوا","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakar'] telah menceritakan kepada kami [Fudhail bin Sulaiman] telah menceritakan kepada kami [Musa bin 'Uqbah] telah mengabarkan kepada saya [Kuraib] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Ketika Nabi shallallahu 'alaihi wasallam tiba di Makkah Beliau memerintahkan para sahabat Beliau agar thawaf di Ka'bah Baitullah dan sa'iy di bulkit Shafaa dan Marwah kemudian agar mereka bertahallul lalu mencukur rambut mereka atau memendekkannya\". "},"1617":{"ar":"وَقَالَ لَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ طَافَ طَوَافًا وَاحِدًا ثُمَّ يَقِيلُ ثُمَّ يَأْتِي مِنًى يَعْنِي يَوْمَ النَّحْرِوَرَفَعَهُ عَبْدُ الرَّزَّاقِ أَخْبَرَنَا عُبَيْدُ اللَّهِ","id":"Dan telah berkata, kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa dia melaksanakan thawaf satu kali saja kemudian qailulah (tidur sebentar di siang hari) kemudian mendatangi Mina pada hari Nahar\". Hadits ini dimarfu'kan oleh ['Abdur Razaq], telah mengabarkan kepada kami ['Ubaidullah]. "},"1618":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ الْأَعْرَجِ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْحَجَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَفَضْنَا يَوْمَ النَّحْرِ فَحَاضَتْ صَفِيَّةُ فَأَرَادَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهَا مَا يُرِيدُ الرَّجُلُ مِنْ أَهْلِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهَا حَائِضٌ قَالَ حَابِسَتُنَا هِيَ قَالُوا يَا رَسُولَ اللَّهِ أَفَاضَتْ يَوْمَ النَّحْرِ قَالَ اخْرُجُواوَيُذْكَرُ عَنْ الْقَاسِمِ وَعُرْوَةَ وَالْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَفَاضَتْ صَفِيَّةُ يَوْمَ النَّحْرِ","id":"Telah menceritakan kepada kami [Yahya bun Bukair] telah menceritakan kepada kami [Al Laits] dari [Ja'far bin Rabi'ah] dari [Al A'raj] berkata, telah menceritakan kepada saya [Abu Salamah bin 'Abdurrahman] bahwa ['Aisyah radliallahu 'anha] berkata: \"Kami pergi menunaikan haji bersama Nabi shallallahu 'alaihi wasallam lalu kami bertolak pada hari Nahar (untuk thawaf ifadhah)). Kemudian Shafiyyah mengalami haidh. Lalu Nabi shallallahu 'alaihi wasallam ingin mendatanginya sebagaimana seorang suami mendatangi isterinya, maka aku katakan: \"Wahai Rasulullah, dia sedang mengalami haidh\". Lalu Beliau berkata: \"Dia telah menyusahkan kita!\". Orang-orang berkata: \"Wahai Rasulullah, dia telah ikut bertolak pada hari Nahar (untuk thawaf) \". Maka Beliau berkata: \"Keluarlah kalian\". Dan disebutkan dari [Al Qasim] dan ['Urwah] dan [Al Aswad] dari ['Aisyah radliallahu 'anha]: \"Shafiyyah ikut bertolak (thawaf ifadhah) pada hari Nahar\". "},"1619":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِيلَ لَهُ فِي الذَّبْحِ وَالْحَلْقِ وَالرَّمْيِ وَالتَّقْدِيمِ وَالتَّأْخِيرِ فَقَالَ لَا حَرَجَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thowus] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam ditanya tentang menyembelih hewan qurban, mencukur rambut dan melempar jumrah antara mendahului atau mengakhirkan amal amal tersebut satu sama lain. Beliau menjawab: \"Tidak dosa\"."},"1620":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسْأَلُ يَوْمَ النَّحْرِ بِمِنًى فَيَقُولُ لَا حَرَجَ فَسَأَلَهُ رَجُلٌ فَقَالَ حَلَقْتُ قَبْلَ أَنْ أَذْبَحَ قَالَ اذْبَحْ وَلَا حَرَجَ وَقَالَ رَمَيْتُ بَعْدَ مَا أَمْسَيْتُ فَقَالَ لَا حَرَجَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: Nabi shallallahu 'alaihi wasallam ditanya pada hari Nahar di Mina, Beliau menjawab: \"Tidak dosa\". Ada seorang yang bertanya: \"Aku mencukur rambut sebelum aku menyembelih hewan qurban?\". Beliau menjawab: \"Sembelihlah dan tidak dosa\". Dan ada yang bertanya: \"Aku melempar jumrah setelah sore\". Beliau menjawab: \"Tidak dosa\". "},"1621":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عِيسَى بْنِ طَلْحَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَفَ فِي حَجَّةِ الْوَدَاعِ فَجَعَلُوا يَسْأَلُونَهُ فَقَالَ رَجُلٌ لَمْ أَشْعُرْ فَحَلَقْتُ قَبْلَ أَنْ أَذْبَحَ قَالَ اذْبَحْ وَلَا حَرَجَ فَجَاءَ آخَرُ فَقَالَ لَمْ أَشْعُرْ فَنَحَرْتُ قَبْلَ أَنْ أَرْمِيَ قَالَ ارْمِ وَلَا حَرَجَ فَمَا سُئِلَ يَوْمَئِذٍ عَنْ شَيْءٍ قُدِّمَ وَلَا أُخِّرَ إِلَّا قَالَ افْعَلْ وَلَا حَرَجَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Isa bin Tholhah] dari ['Abdullah bin 'Amru] bahwa Rasulullah shallallahu 'alaihi wasallam ketika sedang wuquf pada saat haji Wada' orang-orang pada bertanya kepada Beliau. Berkata, seorang laki-laki: \"Aku belum mengerti sehingga aku mencukur rambut sebelum aku menyembelih hewan qurban?\". Beliau menjawab: \"Sembelihlah dan tidak dosa\". Lalu datang orang lain, seraya berkata: \"Aku belum mengerti sehingga aku menyembelih qurban sebelum aku melempar jumrah\". Beliau menjawab: \"Melemparlah dan tidak dosa\". Dan tidaklah Beliau ditanya pada hari itu tentang sesuatu apakah didahulukan atau diakhirkan melainkan Beliau selalau berkata: \"Lakukanlah dan tidak dosa\"."},"1622":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ حَدَّثَنَا أَبِي حَدَّثَنَا ابْنُ جُرَيْجٍ حَدَّثَنِي الزُّهْرِيُّ عَنْ عِيسَى بْنِ طَلْحَةَ ��َنَّ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُأَنَّهُ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ النَّحْرِ فَقَامَ إِلَيْهِ رَجُلٌ فَقَالَ كُنْتُ أَحْسِبُ أَنَّ كَذَا قَبْلَ كَذَا ثُمَّ قَامَ آخَرُ فَقَالَ كُنْتُ أَحْسِبُ أَنَّ كَذَا قَبْلَ كَذَا حَلَقْتُ قَبْلَ أَنْ أَنْحَرَ نَحَرْتُ قَبْلَ أَنْ أَرْمِيَ وَأَشْبَاهَ ذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْعَلْ وَلَا حَرَجَ لَهُنَّ كُلِّهِنَّ فَمَا سُئِلَ يَوْمَئِذٍ عَنْ شَيْءٍ إِلَّا قَالَ افْعَلْ وَلَا حَرَجَحَدَّثَنَا إِسْحَاقُ قَالَ أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عِيسَى بْنُ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ رَضِيَ اللَّهُ عَنْهُمَا قَالَ وَقَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى نَاقَتِهِ فَذَكَرَ الْحَدِيثَ تَابَعَهُ مَعْمَرٌ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami [Sa'id bin Yahya bin Sa'id] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ibnu Juraij] telah menceritakan kepada saya [Az Zuhriy] dari ['Isa bin Tholhah] bahwa ['Abdullah bin 'Amru bin Al 'Ash] radliallahu 'anhu menceritakan kepadanya bahwa ketika Nabi shallallahu 'alaihi wasallam sedang menampaikan khathbah pada hari Nahar, datang seorang laki-laki berdiri di hadapan Beliau lalu berkata: \"Aku mengira amal ini sebelum ini\". Kemudian datang orang lain dan berkata: \"Aku mengira amal ini sebelum ini, yaitu aku mencukur rambut sebelum aku menyembelih hewan qurban, dan aku menyembelih qurban sebelum aku melempar jumrah dan hal hal serupa itu\". Maka Nabi shallallahu 'alaihi wasallam berkata: \"Lakukanlah dan tidak dosa\", kepada mereka semua. Dan tidaklah Beliau ditanya pada hari itu tentang sesuatu melainkan Beliau selalu menjawab: \"Lakukanlah dan tidak dosa\". Telah menceritakan kepada kami [Ishaq] berkata, telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [bapakku] dari [Shalih] dari [Ibnu Syihab] telah menceritakan kepada saya ['Isa bin Tholhah bin 'Ubaidullah] bahwa dia mendengar ['Abdullah bin 'Amru bin Al 'Ash radliallahu 'anhuma] berkata: \"Rasulullah shallallahu 'alaihi wasallam berhenti diatas unta Beliau\" Lalu dia menceritakan hadits ini. Ini dikuatkan pula oleh [Ma'mar] dari [Az Zuhriy]."},"1623":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا فُضَيْلُ بْنُ غَزْوَانَ حَدَّثَنَا عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ النَّاسَ يَوْمَ النَّحْرِ فَقَالَ يَا أَيُّهَا النَّاسُ أَيُّ يَوْمٍ هَذَا قَالُوا يَوْمٌ حَرَامٌ قَالَ فَأَيُّ بَلَدٍ هَذَا قَالُوا بَلَدٌ حَرَامٌ قَالَ فَأَيُّ شَهْرٍ هَذَا قَالُوا شَهْرٌ حَرَامٌ قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فَأَعَادَهَا مِرَارًا ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ اللَّهُمَّ هَلْ بَلَّغْتُ اللَّهُمَّ هَلْ بَلَّغْتُ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا فَوَالَّذِي نَفْسِي بِيَدِهِ إِنَّهَا لَوَصِيَّتُهُ إِلَى أُمَّتِهِ فَلْيُبْلِغْ الشَّاهِدُ الْغَائِبَ لَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada saya [Yahya bin Sa'id] telah menceritakan kepada kami [Fudhail bin Ghozwan] telah menceritakan kepada kami ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam menyampaikan khuthbah pada hari Nahar, Beliau bertanya: \"Wahai sekalian manuisa, hari apakah ini? Mereka menjawab: \"Hari ini hari haram (suci) \". Beliau bertanya lagi: \"Negeri apakah ini?\". Mereka menjawab: \"Ini negeri (tanah) haram (suci) \". Beliau bertanya lagi: \"Bulan apakah ini?\". Mereka menjawab: \"Ini bulan haram (suci) \". Beliau bersabda: \"Sesungguhnya darah kalian, harta-harta kalian dan kehormatan kalian, haram atas kalian sebagaimana haramnya hari kalian ini di negeri kalian ini dan pada bulan kalian ini\". Beliau mengulang kalimatnya ini berulang-ulang lalu setelah itu Beliau mengangkat kepalanya seraya berkata: \"Ya Allah, apakah aku sudah sampaikan?, Ya Allah, apakah aku sudah sampaikan?. Ibnu 'Abbas radliallahu 'anhuma berkata: \"Maka demi Dzat yang jiwaku berada di tanganNya, sungguh itu suatu wasiat Beliau untuk ummatnya. (Sabda Beliau selanjutnya): \"Maka hendaklah yang menyaksikan menyampaikannya kepada yang tidak hadir, dan janganlah kalian kembali menjadi kafir sepeninggalku, kalian saling memukul tengkuk kalian satu sama lain (saling membunuh) \"."},"1624":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَمْرٌو قَالَ سَمِعْتُ جَابِرَ بْنَ زَيْدٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ بِعَرَفَاتٍتَابَعَهُ ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepada saya ['Amru] berkata; Aku mendengar [Jabir bin Zaid] berkata; Aku mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata: Aku mendengar Nabi shallallahu 'alaihi wasallam menyampaikan khuthbah di 'Arafah\". Hadits ini dikuatkan pula oleh [Ibnu 'Uyainah] dari ['Amru]."},"1625":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا أَبُو عَامِرٍ حَدَّثَنَا قُرَّةُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرَةَ عَنْ أَبِي بَكْرَةَ وَرَجُلٌ أَفْضَلُ فِي نَفْسِي مِنْ عَبْدِ الرَّحْمَنِ حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي بَكْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَخَطَبَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ قَالَ أَتَدْرُونَ أَيُّ يَوْمٍ هَذَا قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ فَسَكَتَ حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ قَالَ أَلَيْسَ يَوْمَ النَّحْرِ قُلْنَا بَلَى قَالَ أَيُّ شَهْرٍ هَذَا قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ فَسَكَتَ حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ فَقَالَ أَلَيْسَ ذُو الْحَجَّةِ قُلْنَا بَلَى قَالَ أَيُّ بَلَدٍ هَذَا قُلْنَا اللَّهُ وَرَسُولُهُ أَعْلَمُ فَسَكَتَ حَتَّى ظَنَنَّا أَنَّهُ سَيُسَمِّيهِ بِغَيْرِ اسْمِهِ قَالَ أَلَيْسَتْ بِالْبَلْدَةِ الْحَرَامِ قُلْنَا بَلَى قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا إِلَى يَوْمِ تَلْقَوْنَ رَبَّكُمْ أَلَا هَلْ بَلَّغْتُ قَالُوا نَعَمْ قَالَ اللَّهُمَّ اشْهَدْ فَلْيُبَلِّغْ الشَّاهِدُ الْغَائِبَ فَرُبَّ مُبَلَّغٍ أَوْعَى مِنْ سَامِعٍ فَلَا تَرْجِعُوا بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada saya [Abu 'Amir] telah menceritakan kepada kami [Qurrah] dari [Muhammad bin Sirin] berkata, telah mengabarkan kepada saya ['Abdurrahman bin Abu Bakrah] dari [Abu Bakrah] dan dari orang-orang yang lebih utama, dari 'Abdurrahman [Humaid bin 'Abdurrahman] dari [Abu Bakrah] radliallahu 'anhu berkata: Nabi shallallahu 'alaihi wasallam menyampaikan khathbah kepada kami pada hari Nahar, Beliau bertanya: \"Apakah kalian mengetahui, hari apakah ini?\". Kami menjawab: \"Allah dan rasulNya yang lebih mengetahui\". Sejenak Beliau terdiam sehingga kami menduga bahwa Beliau akan menamakannya bukan dengan namanya (yang sudah kami kenal) \". Beliau bersabda: \"Bukankah sekarang ini hari Nahar?\". Kami menjawab: \"Benar\". Beliau bertanya lagi: \"Bulan apakah ini?\". Kami menjawab: \"Allah dan rasulNya yang lebih mengetahui\". Sejenak Beliau terdiam lagi sehingga kami menduga bahwa Beliau akan menamakannya bukan dengan namanya (yang sudah kami kenal) \". Beliau bersabda: \"Bukankah ini bulan Dzul Hijjah?\". Kami menjawab: \"Benar\". Kemudian Beliau bertanya lagi: \"Negeri apakah ini?\". Kami menjawab: \"Allah dan rasulNya yang lebih mengetahui\". Sejenak Beliau kembali terdiam sehingga sekali lagi kamipun menduga bahwa Beliau akan menamakannya bukan dengan namanya (yang sudah kami kenal) \". Beliau bersabda: \"Bukankah ini negeri haram?\". Kami menjawab: \"Benar\". Lalu Beliau bersabda: \"Sesungguhnya darah kalian, harta-harta kalian haram atas kalian sebagaimana haramnya hari kalian ini, pada bulan kalian ini dan di negeri kalian ini hingga hari kalian berjumpa dengan Rabb kalian. Bukankah aku telah menyampaikannya?\". Mereka menjawab: Ya, sudah\". Kemudian Beliau melanjutkan: \"Ya Allah, saksikanlah. Maka hendaklah yang menyaksikan menyampaikannya kepada yang tidak hadir, karena betapa banyak orang yang disampaikan dapat lebih mengerti dari pada orang yang mendengar. Dan janganlah kalian kembali menjadi kafir sepeninggalku, kalian saling memukul tengkuk kalian satu sama lain (saling membunuh).\""},"1626":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَاصِمُ بْنُ مُحَمَّدِ بْنِ زَيْدٍ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى أَتَدْرُونَ أَيُّ يَوْمٍ هَذَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ فَقَالَ فَإِنَّ هَذَا يَوْمٌ حَرَامٌ أَفَتَدْرُونَ أَيُّ بَلَدٍ هَذَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ بَلَدٌ حَرَامٌ أَفَتَدْرُونَ أَيُّ شَهْرٍ هَذَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ شَهْرٌ حَرَامٌ قَالَ فَإِنَّ اللَّهَ حَرَّمَ عَلَيْكُمْ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَاوَقَالَ هِشَامُ بْنُ الْغَازِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاوَقَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ النَّحْرِ بَيْنَ الْجَمَرَاتِ فِي الْحَجَّةِ الَّتِي حَجَّ بِهَذَا وَقَالَ هَذَا يَوْمُ الْحَجِّ الْأَكْبَرِ فَطَفِقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ اشْهَدْ وَوَدَّعَ النَّاسَ فَقَالُوا هَذِهِ حَجَّةُ الْوَدَاعِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada saya [Yazid bin Harun] telah mengabarkan kepada kami ['Ashim bin Muhammad bin Zaid] dari [bapaknya] dari [Ibnu'Umar radliallahu 'anhuma] berkata: Nabi shallallahu 'alaihi wasallam bersabda ketika berada di Mina:: \"Apakah kalian mengetahui, hari apakah ini?\". Orang-orang menjawab: \"Allah dan rasulNya yang lebih mengetahui\". Beliau bersabda: \"Ini adalah hari haram (suci) \". Beliau bertanya lagi: \"Apakah kalian mengetahui, negeri apakah ini?\". Mereka menjawab: \"Allah dan rasulNya yang lebih mengetahui\". Beliau berkata: \"Ini adalah negeri haram\". Beliau bertanya lagi: \"Apakah kalian mengetahui, bulan apakah ini?\". Mereka menjawab: \"Allah dan rasulNya yang lebih mengetahui\". Beliau berkata: \"Ini adalah bulan haram. Sungguh Allah telah mengharamkan darah kalian, harta-harta kalian dan kehormatan kalian sebagaimana haramnya hari kalian ini, pada bulan kalian ini dan di negeri kalian ini\". Berkata, [Hisyam bin Al Ghor] telah mengabarkan kepada saya [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma]: \"Nabi wuquf pada hari Nahar diantara tempat-tempat melempar jumrah pada pelaksanaan haji yang Beliau laksanakan sebagaimana hadits ini. Maka Nabi shallallahu 'alaihi wasallam segera bersabda: \"Ya Allah saksikanlah\". Maka orang-orang menjadi tenang. Mereka berkata: \"Ini adalah haji wada'."},"1627":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مَيْمُونٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا رَخَّصَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَذِنَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عُبَيْدُ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ الْعَبَّاسَ رَضِيَ اللَّهُ عَنْهُ اسْتَأْذَنَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَبِيتَ بِمَكَّةَ لَيَالِيَ مِنًى مِنْ أَجْلِ سِقَايَتِهِ فَأَذِنَ لَهُتَابَعَهُ أَبُو أُسَامَةَ وَعُقْبَةُ بْنُ خَالِدٍ وَأَبُو ضَمْرَةَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid bin Maimun] telah menceritakan kepada kami ['Isa bin Yunus] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma]: Nabi shallallahu 'alaihi wasallam memberi keringanan\". Dan diriwayatkan pula, telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Muhammad bin Bakar] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepada saya ['Ubaidullah] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam memberikan izin. Dan diriwayatkan pula, telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami ['Ubaidullah] berkata, telah menceritakan kepada saya [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa; \"Al 'Abbas Radhiyallahu meminta izin kepada Rasulullah Nabi shallallahu 'alaihi wasallam untuk bermalam di Makkah selama malam-malam Mina untuk (melayani) menyediakan minum buat Beliau. Maka Beliau mengizinkannya'. Haditsa ini dikuatkan oleh [Abu Usamah], ['Uqbah bin Khalid] dan [Abu Dhamrah]."},"1628":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مِسْعَرٌ عَنْ وَبَرَةَ قَالَ سَأَلْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَامَتَى أَرْمِي الْجِمَارَ قَالَ إِذَا رَمَى إِمَامُكَ فَارْمِهْ فَأَعَدْتُ عَلَيْهِ الْمَسْأَلَةَ قَالَ كُنَّا نَتَحَيَّنُ فَإِذَا زَالَتْ الشَّمْسُ رَمَيْنَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Mis'ar] dari [Wabarah] berkata; Aku bertanya kepada [Ibnu'Umar radliallahu 'anhuma] kapan melempar jumrah dilaksanakan? Dia menjawab: \"Jika pemimpinmu telah melemparnya maka lemparlah\". Lalu aku mengulangi pertanyaan itu, ia berkata: \"Dulu kami menunggu waktu dan apabila matahari sudah condong (siang hari), maka kami baru melempar\"."},"1629":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ رَمَى عَبْدُ اللَّهِمِنْ بَطْنِ الْوَادِي فَقُلْتُ يَا أَبَا عَبْدِ الرَّحْمَنِ إِنَّ نَاسًا يَرْمُونَهَا مِنْ فَوْقِهَا فَقَالَ وَالَّذِي لَا إِلَهَ غَيْرُهُ هَذَا مَقَامُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَقَالَ عَبْدُ اللَّهِ بْنُ الْوَلِيدِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الْأَعْمَشُ بِهَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari ['Abdurrahman bin Yazid] berkata: \" ['Abdullah] melempar jumrah dari dasar lembah, lalu aku bertanya: \"Wahai 'Abdurrahman, orang-orang melempar dari atas (lembah)?\". Maka dia berkata: \"Demi Dzat yang tidak ada ilah selain Dia, tempat ini adalah tempat seseorang yang diturunkan kepadanya surah Al Baqarah, yaitu Muhammad shallallahu 'alaihi wasallam\". Dan berkata, ['Abdullah bin Al Walid] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Al A'masy] sepeti hadits ini\". "},"1630":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّهُ انْتَهَى إِلَى الْجَمْرَةِ الْكُبْرَى جَعَلَ الْبَيْتَ عَنْ يَسَارِهِ وَمِنًى عَنْ يَمِينِهِ وَرَمَى بِسَبْعٍ وَقَالَ هَكَذَا رَمَى الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari ['Abdurrahman bin Yazid] dari ['Abdullah radliallahu 'anhu] bahwa dia berhenti hingga Al Jumrah Al Kubra (Al 'Aqabah), yang Ka'bah Baitullah berada disisi kirinya sedangkan Mina disisi kanannya lalu dia melempar dengan tujuh (batu), lalu berkata; \"Beginilah cara melempar seseorang yang telah diturunkan kepadanya surah Al Baqarah, yaitu Muhammad shallallahu 'alaihi wasallam\"."},"1631":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْحَكَمُ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ أَنَّهُ حَجَّ مَعَ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُفَرَآهُ يَرْمِي الْجَمْرَةَ الْكُبْرَى بِسَبْعِ حَصَيَاتٍ فَجَعَلَ الْبَيْتَ عَنْ يَسَارِهِ وَمِنًى عَنْ يَمِينِهِ ثُمَّ قَالَ هَذَا مَقَامُ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Al Hakam] dari [Ibrahim] dari ['Abdurrahman bin Yazid] bahwa dia menunaikan haji bersama [Ibnu Mas'ud radliallahu 'anhu] lalu dia melihat Ibnu Mas'ud radliallahu 'anhu melempar Al Jumrah Al Kubra dengan tujuh kerikil yang posisi Ka'bah Baitullah berada disisi kirinya sedangkan Mina disisi kanannya lalu dia berkata; \"Inilah tempat melempar seseorang yang telah diturunkan kepadanya surah Al Baqarah, yaitu Muhammad shallallahu 'alaihi wasallam\"."},"1632":{"ar":"حَدَّثَنَا مُسَدَّدٌ عَنْ عَبْدِ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ قَالَ سَمِعْتُ الْحَجَّاجَ يَقُولُ عَلَى الْمِنْبَرِ السُّورَةُ الَّتِي يُذْكَرُ فِيهَا الْبَقَرَةُ وَالسُّورَةُ الَّتِي يُذْكَرُ فِيهَا آلُ عِمْرَانَ وَالسُّورَةُ الَّتِي يُذْكَرُ فِيهَا النِّسَاءُ قَالَ فَذَكَرْتُ ذَلِكَ لِإِبْرَاهِيمَ فَقَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ يَزِيدَ أَنَّهُ كَانَ مَعَ ابْنِ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُحِينَ رَمَى جَمْرَةَ الْعَقَبَةِ فَاسْتَبْطَنَ الْوَادِيَ حَتَّى إِذَا حَاذَى بِالشَّجَرَةِ اعْتَرَضَهَا فَرَمَى بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ مَعَ كُلِّ حَصَاةٍ ثُمَّ قَالَ مِنْ هَا هُنَا وَالَّذِي لَا إِلَهَ غَيْرُهُ قَامَ الَّذِي أُنْزِلَتْ عَلَيْهِ سُورَةُ الْبَقَرَةِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] dari ['Abdul Wahid] telah menceritakan kepada kami [Al A'masy] berkata; Aku mendengar Al Hajjaj berkata, dari atas mimbar: \"Surah yang disebut didalamnya Al Baqarah dan surah yang disebut didalamnya Ali 'Imran dan surah yang didalamnya disebut tentang para wanita\". Dia (Al A'masy) berkata: \"Lalu aku sampaikan hal ini kepada [Ibrahim], maka dia berkata; telah menceritakan kepada saya ['Abdurrahman bin Yazid] bahwa dia pernah bersama [Ibnu Mas'ud radliallahu 'anhu] ketika melempar jumrah Al 'Aqabah, dia menuruni lembah hingga ketika sampai di sebuah pohon, dia berhenti dan dari situ melempar dengan tujuh kerikil dengan bertakbir pada setiap kerikil lemparannya lalu berkata: \"Demi Dzat yang tidak ada ilah selain Dia, dari sinilah berdiri melempar seseorang yang diturunkan kepadanya surah Al Baqarah, yaitu Muhammad shallallahu 'alaihi wasallam\"."},"1633":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا طَلْحَةُ بْنُ يَحْيَى حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ كَانَ يَرْمِي الْجَمْرَةَ الدُّنْيَا بِسَبْعِ حَصَيَاتٍ يُكَبِّرُ عَلَى إِثْرِ كُلِّ حَصَاةٍ ثُمَّ يَتَقَدَّمُ حَتَّى يُسْهِلَ فَيَقُومَ مُسْتَقْبِلَ الْقِبْلَةِ فَيَقُومُ طَوِيلًا وَيَدْعُو وَيَرْفَعُ يَدَيْهِ ثُمَّ يَرْمِي الْوُسْطَى ثُمَّ يَأْخُذُ ذَاتَ الشِّمَالِ فَيَسْتَهِلُ وَيَقُومُ مُسْتَقْبِلَ الْقِبْلَةِ فَيَقُومُ طَوِيلًا وَيَدْعُو وَيَرْفَعُ يَدَيْهِ وَيَقُومُ طَوِيلًا ثُمَّ يَرْمِي جَمْرَةَ ذَاتِ الْعَقَبَةِ مِنْ بَطْنِ الْوَادِي وَلَا يَقِفُ عِنْدَهَا ثُمَّ يَنْصَرِفُ فَيَقُولُ هَكَذَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Tholhah bin Abu Yahya] telah menceritakan kepada kami [Yunus] dari [Az Zuhriy] dari [Salim] dari [Ibnu'Umar radliallahu 'anhuma] bahwa dia melempar Al Jumrah Ad-Dunya (Al Ulaa, awal) dengan tujuh kerikil dengan bertakbir pada setiap kali lemparannya, kemudian dia maju hingga sampai pada permukaan yang datar dia berdiri menghadap qiblat dengan agak lama, lalu berdo'a dengan mengangkat kedua tangannya kemudian melempar jumrah Al Wustho lalu dia mengambil jalan sebelah kiri pada dataran yang rata lalu berdiri menghadap qiblat dengan agak lama lalu berdo'a dengan mengangkat kedua tangannya dan tetap berdiri agak lama, kemudian dia melempar jumrah Al 'Aqabah dari dasar lembah dan dia tidak berhenti disitu, lalu segera pergi dan berkata: \"Begitulah aku melihat Nabi shallallahu 'alaihi wasallam mengerjakannya\". "},"1634":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاكَانَ يَرْمِي الْجَمْرَةَ الدُّنْيَا بِسَبْعِ حَصَيَاتٍ ثُمَّ يُكَبِّرُ عَلَى إِثْرِ كُلِّ حَصَاةٍ ثُمَّ يَتَقَدَّمُ فَيُسْهِلُ فَيَقُومُ مُسْتَقْبِلَ الْقِبْلَةِ قِيَامًا طَوِيلًا فَيَدْعُو وَيَرْفَعُ يَدَيْهِ ثُمَّ يَرْمِي الْجَمْرَةَ الْوُسْطَى كَذَلِكَ فَيَأْخُذُ ذَاتَ الشِّمَالِ فَيُسْهِلُ وَيَقُومُ مُسْتَقْبِلَ الْقِبْلَةِ قِيَامًا طَوِيلًا فَيَدْعُو وَيَرْفَعُ يَدَيْهِ ثُمَّ يَرْمِي الْجَمْرَةَ ذَاتَ الْعَقَبَةِ مِنْ بَطْنِ الْوَادِي وَلَا يَقِفُ عِنْدَهَا وَيَقُولُ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] berkata, telah menceritakan kepada saya [saudaraku] dari [Sulaiman] dari [Yunus bin Yazid] dari [Ibnu Syihab] dari [Salim bin 'Abdullah] bahwa ['Abdullah bin 'Umar radliallahu 'anhu] melempar Al Jumrah Ad-Dunya (Al Ulaa, awal) dengan tujuh kerikil kemudian bertakbir pada setiap kali lemparannya, kemudian dia maju hingga sampai pada permukaan yang datar dia berdiri menghadap qiblat dengan agak lama, lalu berdo'a dengan mengangkat kedua tangannya, kemudian melempar jumrah Al Wustho seperti itu pula, dia mengambil jalan sebelah kiri pada dataran yang rata lalu berdiri menghadap qiblat dengan agak lama, lalu berdo'a dengan mengangkat kedua tangannya, kemudian melempar jumrah Al 'Aqabah dari dasar lembah dan dia tidak berhenti disitu lalu berkata: \"Begitulah aku melihat Nabi shallallahu 'alaihi wasallam mengerjakannya\". "},"1635":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ أَنَّهُ سَمِعَ أَبَاهُ وَكَانَ أَفْضَلَ أَهْلِ زَمَانِهِ يَقُولُ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُطَيَّبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدَيَّ هَاتَيْنِ حِينَ أَحْرَمَ وَلِحِلِّهِ حِينَ أَحَلَّ قَبْلَ أَنْ يَطُوفَ وَبَسَطَتْ يَدَيْهَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Abdurrahman bin Al Qasim] bahwa dia mendengar [bapaknya] yang merupakan orang yang paling utama pada zamannya berkata; Aku mendengar ['Aisyah radliallahu 'anha] berkata: \"Aku memakaikan wewangian kepada Rasulullah shallallahu 'alaihi wasallam dengan kedua tanganku ini ketika beliau ihram dan ketika bertahallul sebelum Beliau thawaf\". Dan 'Aisyah radliallahu 'anha membuka kedua telapak tangannya. "},"1636":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأُمِرَ النَّاسُ أَنْ يَكُونَ آخِرُ عَهْدِهِمْ بِالْبَيْتِ إِلَّا أَنَّهُ خُفِّفَ عَنْ الْحَائِضِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Sufyan] dari [Ibnu thowus] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: Orang-orang diperintahkan agar menjadikan akhir dari perjalanan haji mereka adalah thawaf di Ka'bah Baitullah. Namun perintah ini diringankan bagi para wanita yang sedang mengalami haidh. "},"1637":{"ar":"حَدَّثَنَا أَصْبَغُ بْنُ الْفَرَجِ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ وَالْعَصْرَ وَالْمَغْرِبَ وَالْعِشَاءَ ثُمَّ رَقَدَ رَقْدَةً بِالْمُحَصَّبِ ثُمَّ رَكِبَ إِلَى الْبَيْتِ فَطَافَ بِهِتَابَعَهُ اللَّيْثُ حَدَّثَنِي خَالِدٌ عَنْ سَعِيدٍ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ashbagh bin Al Faraj] telah mengabarkan kepada kami [Ibnu Wahb] dari ['Amru bin Al Harits] dari [Qatadah] bahwa [Anas bin Malik radliallahu 'anhu] menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam melaksanakan shalat Zhuhur, 'Ashar, Maghrib dan 'Isya' kemudian Beliau tidur sejenak di Al Muhashib (tempat melempar jumrah di Mina) lalu Beliau menunggang tunggangannya menuju ke Ka'bah Baitullah lalu thawaf disana\". Hadits ini dikuatkan pula oleh [Al Laits] telah menceritakan kepada saya [Khalid] dari [Sa'id] dari [Qatadah] bahwa [Anas bin Malik radliallahu 'anhu] menceritakan kepadanya dari Nabi shallallahu 'alaihi wasallam."},"1638":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ صَفِيَّةَ بِنْتَ حُيَيٍّ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاضَتْ فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحَابِسَتُنَا هِيَ قَالُوا إِنَّهَا قَدْ أَفَاضَتْ قَالَ فَلَا إِذًا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Abdurrahman bin Al Qasim] dari [bapaknya] dari ['Aisyah radliallahu 'anha]; bahwa Shafiyyah binti Huyay, isteri Nabi shallallahu 'alaihi wasallam mengalami haidh. Berita itu lantas disampaikan kepada Rasulullah shallallahu 'alaihi wasallam, maka Beliau berkata: \"Apakah dia akan menyusahkan kita?\". Orang-orang berkata: \"Dia telah ikut bertolak pada hari Nahar (untuk thawaf) \". Maka Beliau berkata: \"Kalau begitu tidak\"."},"1639":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ أَنَّ أَهْلَ الْمَدِينَةِ سَأَلُوا ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ امْرَأَةٍ طَافَتْ ثُمَّ حَاضَتْ قَالَ لَهُمْ تَنْفِرُ قَالُوا لَا نَأْخُذُ بِقَوْلِكَ وَنَدَعُ قَوْلَ زَيْدٍ قَالَ إِذَا قَدِمْتُمْ الْمَدِينَةَ فَسَلُوا فَقَدِمُوا الْمَدِينَةَ فَسَأَلُوا فَكَانَ فِيمَنْ سَأَلُوا أُمُّ سُلَيْمٍ فَذَكَرَتْ حَدِيثَ صَفِيَّةَرَوَاهُ خَالِدٌ وَقَتَادَةُ عَنْ عِكْرِمَةَ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari ['Ikrimah] bahwa sebagian penduduk Madinah bertanya kepada [Ibnu 'Abbas radliallahu 'anhuma] tentang seorang wanita yang melaksanakan thawaf kemudian mengalami haidh. Dia berkata, kepada mereka: \"Dia boleh berangkat (pulang) \". Mereka berkata: \"Kami tidak mengambil pendapatmu namun kami mengambil pendapat Zaid\". Ibnu 'Abbas radliallahu 'anhuma berkata: \"Jika kalian telah sampai di Madinah bertanyalah?\". Ketika telah tiba di Madinah mereka bertanya dan diantara orang yang mereka tanya adalah Ummu Sulaim. Lalu Ummu Sulaim menyebutkan hadits Shafiyah yang diriwayatkan oleh [Khalid] dan [Qatadah] dari ['Ikrimah]. "},"1640":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَرُخِّصَ لِلْحَائِضِ أَنْ تَنْفِرَ إِذَا أَفَاضَتْقَالَ وَسَمِعْتُ ابْنَ عُمَرَ يَقُولُ إِنَّهَا لَا تَنْفِرُ ثُمَّ سَمِعْتُهُ يَقُولُ بَعْدُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَخَّصَ لَهُنَّ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thawus] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: Telah diberi keringanan bagi para wanita yang sedang mengalami haidh untuk bertolak (pulang) apabila telah melaksanakan (thawaf ifadhah). Dia (Ibnu 'Abbas radliallahu 'anhum) berkata; \"Dan aku telah mendengar [Ibnu 'Umar radliallahu 'anhuma] berkata: \"Dia tidak boleh pulang (sebelum dia thawaf wada'). Kemudian setelah itu aku mendengar dia berkata: \"Nabi shallallahu 'alaihi wasallam telah memberikan keringanan buat mereka\"."},"1641":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا نَرَى إِلَّا الْحَجَّ فَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَافَ بِالْبَيْتِ وَبَيْنَ الصَّفَا وَالْمَرْوَةِ وَلَمْ يَحِلَّ وَكَانَ مَعَهُ الْهَدْيُ فَطَافَ مَنْ كَانَ مَعَهُ مِنْ نِسَائِهِ وَأَصْحَابِهِ وَحَلَّ مِنْهُمْ مَنْ لَمْ يَكُنْ مَعَهُ الْهَدْيُ فَحَاضَتْ هِيَ فَنَسَكْنَا مَنَاسِكَنَا مِنْ حَجِّنَا فَلَمَّا كَانَ لَيْلَةَ الْحَصْبَةِ لَيْلَةُ النَّفْرِ قَالَتْ يَا رَسُولَ اللَّهِ كُلُّ أَصْحَابِكَ يَرْجِعُ بِحَجٍّ وَعُمْرَةٍ غَيْرِي قَالَ مَا كُنْتِ تَطُوفِينَ بِالْبَيْتِ لَيَالِيَ قَدِمْنَا قُلْتُ لَا قَالَ فَاخْرُجِي مَعَ أَخِيكِ إِلَى التَّنْعِيمِ فَأَهِلِّي بِعُمْرَةٍ وَمَوْعِدُكِ مَكَانَ كَذَا وَكَذَا فَخَرَجْتُ مَعَ عَبْدِ الرَّحْمَنِ إِلَى التَّنْعِيمِ فَأَهْلَلْتُ بِعُمْرَةٍ وَحَاضَتْ صَفِيَّةُ بِنْتُ حُيَيٍّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَقْرَى حَلْقَى إِنَّكِ لَحَابِسَتُنَا أَمَا كُنْتِ طُفْتِ يَوْمَ النَّحْرِ قَالَتْ بَلَى قَالَ فَلَا بَأْسَ انْفِرِي فَلَقِيتُهُ مُصْعِدًا عَلَى أَهْلِ مَكَّةَ وَأَنَا مُنْهَبِطَةٌ أَوْ أَنَا مُصْعِدَةٌ وَهُوَ مُنْهَبِطٌوَقَالَ مُسَدَّدٌ قُلْتُ لَا تَابَعَهُ جَرِيرٌ عَنْ مَنْصُورٍ فِي قَوْلِهِ لَا","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha]; \"Kami keluar bersama Nabi shallallahu 'alaihi wasallam dan tidaklah kami diperlihatkan melainkan Beliau keluar untuk melaksanakan haji. Ketika Nabi shallallahu 'alaihi wasallam tiba (di Makkah), Beliau melaksanakan thawaf di Ka'bah Baitullah dan sa'iy antara bukit Shafaa dan Marwah dan Beliau tidak bertahallul karena Beliau membawa Al Hadyu (hewan qurban), begitu pula ikut thawaf orang-orang yang bersama Beliau baik isteri-isteri Beliau maupun sahabat dan diantara mereka bertahallul bagi yang tidak membawa Al Hadyu. Kemudian 'Aisyah radliallahu 'anha mengalami haid. Maka kami pun menyelesaikan seluruh manasik haji kami. Ketika malam Jumrah (di Mina) saat orang-orang harus nafar (pulang), dia berkata: \"Wahai Rasulullah, seluruh sahabat-sahabat anda akan kembali pulang dengan 'umrah dan haji sedangkan aku tidak\". Beliau bertanya: \"Apakah kamu tidak ikut thawaf di Ka'bah Baitullah pada malam-malam ketika kita tiba di Makkah?\". Aku menjawab: \"Tidak\". Beliau berkata: \"Pergilah kamu bersama saudaramu ke Tan'im dan mulailah dari sana berihram untuk 'umrah kemudian tempat kamu begini begini\". Maka aku keluar bersama 'Abdurrahman ke Tan'im lalu aku berihram untuk 'umrah. Dan kemudian Shafiyyah binti Huyay mengalami haidh, maka Nabi shallallahu 'alaihi wasallam berkata: \"Celaka, kamu telah membuat kami tertahan, apakah kamu melaksanakan thawaf pada hari Nahar\". Dia (Shafiyyah) menjawab: \"Ya\". Beliau berkata: \"Kalau begitu tidak apa, pulanglah\". 'Aisyah radliallahu 'anha berkata: \"Kemudian aku menemui Beliau shallallahu 'alaihi wasallam saat Beliau tiba dari Makkah sedangkan aku sudah lebih dulu singgah atau aku baru tiba sedang Beliau sudah singgah dari Makkah\". Dan berkata, [Musaddad], Perkataan 'Aisyah radliallahu 'anha: aku berkata: \"Tidak\". Hadits ini dikuatkan pula oleh [Jarir] dari [Manshur] pada ucapan 'Aisyah radliallahu 'anha: \"Tidak\". "},"1642":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا إِسْحَاقُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍأَخْبِرْنِي بِشَيْءٍ عَقَلْتَهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ صَلَّى الظُّهْرَ يَوْمَ التَّرْوِيَةِ قَالَ بِمِنًى قُلْتُ فَأَيْنَ صَلَّى الْعَصْرَ يَوْمَ النَّفْرِ قَالَ بِالْأَبْطَحِ افْعَلْ كَمَا يَفْعَلُ أُمَرَاؤُكَ","id":"Telah menceritakan kepada saya [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ishaq bin Yusuf] telah menceritakan kepada kami [Sufyan Ats-Tsauriy] dari ['Abdul 'Aziz bin Rufai'] berkata; Aku bertanya kepada [Anas bin Malik radliallahu 'anhu]: \"Kabarkan kepadaku sesuatu yang kamu ingat dari Nabi shallallahu 'alaihi wasallam, dimana Beliau melaksanakan shalat Zhuhur pada hari Tarwiyah?\" Dia menjawab: \" Di Mina\". Aku bertanya lagi, dimana Beliau melaksanakan shalat 'Ashar pada hari Nafar?\" Dia menjawab: \" Di Al Abthoh (Al Bathha'). Kerjakanlah (manasik) sebagaimana para pemimpin kamu telah mengerjakannya\"."},"1643":{"ar":"حَدَّثَنَا عَبْدُ الْمُتَعَالِ بْنُ طَالِبٍ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ قَتَادَةَ حَدَّثَهُ أَنَّ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى الظُّهْرَ وَالْعَصْرَ وَالْمَغْرِبَ وَالْعِشَاءَ وَرَقَدَ رَقْدَةً بِالْمُحَصَّبِ ثُمَّ رَكِبَ إِلَى الْبَيْتِ فَطَافَ بِهِ","id":"Telah menceritakan kepada kami ['Abdul Muta'al bin Tholib] telah menceritakan kepada kami [Ibnu Wahb] berkata, telah mengabarkan kepada saya ['Amru bin Al Harits] bahwa [Qatadah] menceritakan kepadanya bahwa [Anas bin Malik radliallahu 'anhu] menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam melaksanakan shalat Zhuhur, 'Ashar, Maghrib dan 'Isya' kemudian Beliau tidur sejenak di Al Muhashib (tempat melempar jumrah di Mina), lalu Beliau menunggang tunggangannya menuju ke Ka'bah Baitullah lalu thawaf disana\"."},"1644":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْإِنَّمَا كَانَ مَنْزِلٌ يَنْزِلُهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَكُونَ أَسْمَحَ لِخُرُوجِهِيَعْنِي بِالْأَبْطَحِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata: \"Sesungguhnya tempat yang dipergunakan Nabi shallallahu 'alaihi wasallam untuk singgah adalah yang paling mudah untuk jalan keluarnya (pulangnya), yakni di Al Abthah (Al Bathha')."},"1645":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَيْسَ التَّحْصِيبُ بِشَيْءٍ إِنَّمَا هُوَ مَنْزِلٌ نَزَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah berkata, ['Amru] dari ['Atho'] dari [Ibnu 'Abbas radliallahu 'anhuma]: At-Tahshib (tempat singgah menjelang jumrah) bukanlah sesuatu bagian dari manasik, tapi dia hanyalah tempat yang pernah digunakan Rasulullah shallallahu 'alaihi wasallam untuk singgah\". "},"1646":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَبُو ضَمْرَةَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاكَانَ يَبِيتُ بِذِي طُوًى بَيْنَ الثَّنِيَّتَيْنِ ثُمَّ يَدْخُلُ مِنْ الثَّنِيَّةِ الَّتِي بِأَعْلَى مَكَّةَ وَكَانَ إِذَا قَدِمَ مَكَّةَ حَاجًّا أَوْ مُعْتَمِرًا لَمْ يُنِخْ نَاقَتَهُ إِلَّا عِنْدَ بَابِ الْمَسْجِدِ ثُمَّ يَدْخُلُ فَيَأْتِي الرُّكْنَ الْأَسْوَدَ فَيَبْدَأُ بِهِ ثُمَّ يَطُوفُ سَبْعًا ثَلَاثًا سَعْيًا وَأَرْبَعًا مَشْيًا ثُمَّ يَنْصَرِفُ فَيُصَلِّي رَكْعَتَيْنِ ثُمَّ يَنْطَلِقُ قَبْلَ أَنْ يَرْجِعَ إِلَى مَنْزِلِهِ فَيَطُوفُ بَيْنَ الصَّفَا وَالْمَرْوَةِ وَكَانَ إِذَا صَدَرَ عَنْ الْحَجِّ أَوْ الْعُمْرَةِ أَنَاخَ بِالْبَطْحَاءِ الَّتِي بِذِي الْحُلَيْفَةِ الَّتِي كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُنِيخُ بِهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Abu Dhamrah] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] bahwa [Ibnu'Umar radliallahu 'anhuma] bermalam di Dzu Thuwa diantara dua jalan dataran tinggi, lalu dia masuk melalui salah satu dari dataran itu yang berada di sebelah atas kota Makkah. Dan apabila sudah sampai di Makkah baik untuk menunaikan haji atau 'umrah, dia tidak singgah menambatkan untanya kecuali di (tempat) dekat pintu masjid (Al Masjidil Haram). Kemudian dia masuk dan mendatangi Rukun Hajar Aswad, lalu dia memulai thawaf dari sana sebanyak tujuh kali putaran dengan tiga kali berjalan cepat dan empat kalinya berjalan biasa, kemudian apabila telah selesai, dia shalat dua raka'at. Sebelum dia kembali ke tempat tinggalnya, dia melaksanakan sa'iy antara bukit Shafaa dan Marwah. Dan apabila dia telah menyelesaikan seluruh manasik haji atau 'umrahnya, dia singgah beristirahat di Al Bathha' yang terletak di DzulHulaifah, tempat yang pernah digunakan Rasulullah shallallahu 'alaihi wasallam untuk singgah\"."},"1647":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ سُئِلَ عُبَيْدُ اللَّهِ عَنْ الْمُحَصَّبِ فَحَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ قَالَ نَزَلَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعُمَرُ وَابْنُ عُمَرَ وَعَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاكَانَ يُصَلِّي بِهَا يَعْنِي الْمُحَصَّبَ الظُّهْرَ وَالْعَصْرَ أَحْسِبُهُ قَالَ وَالْمَغْرِبَ قَالَ خَالِدٌ لَا أَشُكُّ فِي الْعِشَاءِ وَيَهْجَعُ هَجْعَةً وَيَذْكُرُ ذَلِكَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdullah bin 'Abdul Wahhab] telah menceritakan kepada kami [Khalid bin Al Harits] berkata; 'Ubaidullah ditanya tentang Al Muhashshab\". Maka ['Ubaidullah] menceritakan kepada kami dari [Nafi'] berkata: \"Rasulullah shallallahu 'alaihi wasallam pernah berhenti singgah disana, begitu juga 'Umar dan Ibnu 'Umar\". Dan dari Nafi' bahwa [Ibnu'Umar radliallahu 'anhuma] pernah disana, yaitu di Al Muhashshab, shalat Zhuhur, dan 'Ashar\". Dan aku menduga dia berkata: \"dan shalat Maghrib.\" Khailid berkata: \"Aku tidak meragukan tentang shalat 'Isya', lalu dia tidur sejenak disana\". Lalu dia menyebutkan hal itu dari Nabi shallallahu 'alaihi wasallam. "},"1648":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ الْهَيْثَمِ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ عَمْرُو بْنُ دِينَارٍ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاكَانَ ذُو الْمَجَازِ وَعُكَاظٌ مَتْجَرَ النَّاسِ فِي الْجَاهِلِيَّةِ فَلَمَّا جَاءَ الْإِسْلَامُ كَأَنَّهُمْ كَرِهُوا ذَلِكَ حَتَّى نَزَلَتْ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ","id":"Telah menceritakan kepada kami ['Utsman bin Al Haitsam] telah mengabarkan kepada kami [Ibnu Juraij] telah berkata, ['Amru bin Dinar] berkata, [Ibnu 'Abbas radliallahu 'anhuma]: \"Dzul Majaz dan Ukazh adalah tempat berdagang orang-orang pada masa jahiliyah. Ketika Islam datang seakan-akan mereka membenci tempat itu, hingga turunlah QS AL Baqarah ayat 195 yang artinya: (\"Tidak ada dosa bagi kalian jika kalian mencari karunia(rezeqi hasil perniagaan) dari Rabb kalian\"), yaitu pada musim haji."},"1649":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنِي إِبْرَاهِيمُ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْحَاضَتْ صَفِيَّةُ لَيْلَةَ النَّفْرِ فَقَالَتْ مَا أُرَانِي إِلَّا حَابِسَتَكُمْ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَقْرَى حَلْقَى أَطَافَتْ يَوْمَ النَّحْرِ قِيلَ نَعَمْ قَالَ فَانْفِرِيقَالَ أَبُو عَبْد اللَّهِ وَزَادَنِي مُحَمَّدٌ حَدَّثَنَا مُحَاضِرٌ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَذْكُرُ إِلَّا الْحَجَّ فَلَمَّا قَدِمْنَا أَمَرَنَا أَنْ نَحِلَّ فَلَمَّا كَانَتْ لَيْلَةُ النَّفْرِ حَاضَتْ صَفِيَّةُ بِنْتُ حُيَيٍّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَلْقَى عَقْرَى مَا أُرَاهَا إِلَّا حَابِسَتَكُمْ ثُمَّ قَالَ كُنْتِ طُفْتِ يَوْمَ النَّحْرِ قَالَتْ نَعَمْ قَالَ فَانْفِرِي قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي لَمْ أَكُنْ حَلَلْتُ قَالَ فَاعْتَمِرِي مِنْ التَّنْعِيمِ فَخَرَجَ مَعَهَا أَخُوهَا فَلَقِينَاهُ مُدَّلِجًا فَقَالَ مَوْعِدُكِ مَكَانَ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada saya [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] berkata; \"Shafiyyah mengalami haidh pada hari Nafar, lalu dia berkata: \"Tidaklah aku memandang diriku melainkan aku telah menyusahkan kalian\". Nabi shallallahu 'alaihi wasallam berkata: \"Celaka, apakah kamu sudah melaksanakan thawaf pada hari Nahar\". Dikatakannya: \"Ya, sudah\". Maka Beliau berkata: \"Pulanglah\". Abu 'Abdullah Al Bukhariy berkata: \"Dan [Muhammad] menambahkan kepadaku, telah menceritakan kepada kami [Muhadhir] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] berkata; \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam dan tidaklah kami menyebutnya melainkan untuk melaksanakan haji. Ketika kami tiba (di Makkah), Beliau memerintahkan kami agar kami bertahallul. Ketika masuk malam Nafar, Shafiyyah binti Huyay mengalami haidh, maka Nabi shallallahu 'alaihi wasallam berkata: \"Celaka, tidaklah kami melihat melainkan kamu telah menyusahkan kami\". Kemudian Beliau bertanya: \"Apakah kamu sudah melaksanakan thawaf pada hari Nahar\". Dia menjawab: \"Ya, benar\". Maka Beliau berkata: \"Kalau begitu, pulanglah\". Kemudian 'Aisyah radliallahu 'anha berkata: \"Wahai Rasulullah, aku belum bertahallul\". Beliau berkata: \"Laksanakanlah 'umrah dari At-Tan'im\". Lalu berangkatlah saudaranya bersamanya kemudian setelah itu kami menemui Beliau dalam keadaan siap berangkat di akhir malam dan berkata: \"Bagian tempat kamu begini begini\"."},"1650":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْعُمْرَةُ إِلَى الْعُمْرَةِ كَفَّارَةٌ لِمَا بَيْنَهُمَا وَالْحَجُّ الْمَبْرُورُ لَيْسَ لَهُ جَزَاءٌ إِلَّا الْجَنَّةُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Sumayya, maulana Abu Bakar bin 'Abdurrahman] dari [Abu Shalih As-Samman] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Umrah demi 'umrah berikutnya menjadi penghapus dosa antara keduanya dan haji mabrur tidak ada balasannya kecuali surga\"."},"1651":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَنَّ عِكْرِمَةَ بْنَ خَالِدٍ سَأَلَ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ الْعُمْرَةِ قَبْلَ الْحَجِّ فَقَالَ لَا بَأْسَ قَالَ عِكْرِمَةُ قَالَ ابْنُ عُمَرَ اعْتَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ أَنْ يَحُجَّوَقَالَ إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ إِسْحَاقَ حَدَّثَنِي عِكْرِمَةُ بْنُ خَالِدٍ سَأَلْتُ ابْنَ عُمَرَ مِثْلَهُ حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ عِكْرِمَةُ بْنُ خَالِدٍ سَأَلْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا مِثْلَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ibnu Juraij] bahwa ['Ikrimah bin Khalid] bertanya kepada [Ibnu'Umar radliallahu 'anhuma] tentang melaksanakan 'umrah sebelum haji. Maka dia menjawab: \"Tidaklah mengapa\". 'Ikrimah berkata; berkata Ibnu'Umar radliallahu 'anhuma: \"Nabi shallallahu 'alaihi wasallam melaksanakan 'umrah sebelum haji\". Dan berkata [Ibrahim bin Saad] dari [Ibnu Ishaq] telah menceritakan kepada saya ['Ikrimah bin Khalid], aku bertanya kepada [Ibnu'Umar radliallahu 'anhuma] seperti itu. Telah menceritakan kepada kami ['Amru bin 'Ali] telah menceritakan kepada kami [Abu 'Ashim] telah mengabarkan kepada kami [Ibnu Juraij], telah berkata, ['Ikrimah bin Khalid]: \"Aku bertanya kepada [Ibnu'Umar radliallahu 'anhuma] seperti itu juga\"."},"1652":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ قَالَ دَخَلْتُ أَنَا وَعُرْوَةُ بْنُ الزُّبَيْرِ الْمَسْجِدَ فَإِذَا عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاجَالِسٌ إِلَى حُجْرَةِ عَائِشَةَ وَإِذَا نَاسٌ يُصَلُّونَ فِي الْمَسْجِدِ صَلَاةَ الضُّحَى قَالَ فَسَأَلْنَاهُ عَنْ صَلَاتِهِمْ فَقَالَ بِدْعَةٌ ثُمَّ قَالَ لَهُ كَمْ اعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعًا إِحْدَاهُنَّ فِي رَجَبٍ فَكَرِهْنَا أَنْ نَرُدَّ عَلَيْهِ قَالَ وَسَمِعْنَا اسْتِنَانَ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ فِي الْحُجْرَةِ فَقَالَ عُرْوَةُ يَا أُمَّاهُ يَا أُمَّ الْمُؤْمِنِينَ أَلَا تَسْمَعِينَ مَا يَقُولُ أَبُو عَبْدِ الرَّحْمَنِ قَالَتْ مَا يَقُولُ قَالَ يَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَمَرَ أَرْبَعَ عُمَرَاتٍ إِحْدَاهُنَّ فِي رَجَبٍ قَالَتْ يَرْحَمُ اللَّهُ أَبَا عَبْدِ الرَّحْمَنِ مَا اعْتَمَرَ عُمْرَةً إِلَّا وَهُوَ شَاهِدُهُ وَمَا اعْتَمَرَ فِي رَجَبٍ قَطُّ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Mujahid] berkata; Ketika aku dan 'Urwah bin Az Zubair masuk kedalam masjid disana ada ['Abdullah bin 'Umar radliallahu 'anhu] sedang duduk di bilik rumah 'Aisyah radliallahu 'anha, sedang orang-orang melaksanakan shalat Dhuha dalam masjid\". Dia (Mujahid) berkata: \"Maka kami bertanya kepadanya tentang shalat yang mereka kerjakan, maka dia berkata: \"Itu adalah bid'ah\". Kemudian dia berkata lagi kepadanya: \"Berapa kali Rasulullah shallallahu 'alaihi wasallam pernah melaksanakan 'umrah?\" Dia menjawab: \"Empat kali, satu diantaranya pada bulan Rajab\". Maka kami pun enggan untuk membantahnya. Mujahid melanjutkan: Kemudian kami mendengar suara ['Aisyah radliallahu 'anha] Ummul Mu'minin sedang menggosok gigi dari balik rumahnya, maka 'Urwah bertanya: \"Wahai ibunda, wahai Ummul Mu'minin, apakah engkau tidak mendengar apa yang dikatakan oleh Abu 'Abdurrahman? 'Aisyah radliallahu 'anha berkata: \"Apa yang telah dikatakannya? 'Urwah menjawab; Dia berkata, bahwa Rasulullah shallallahu 'alaihi wasallam melaksanakan 'umrah sebanyak empat kali satu diantaranya pada bulan Rajab\". 'Aisyah radliallahu 'anha berkata: \"Semoga Allah merahmati Abu 'Abdurrahman, tidaklah Beliau melaksanakan 'umrah sekalipun melainkan aku selalu mengikutinya dan Beliau tidak pernah melaksanakan 'umrah pada bulan Rajab sekalipun\". "},"1653":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ قَالَ سَأَلْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْمَا اعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَجَبٍ","id":"Telah menceritakan kepada kami [Abu 'Ashim] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Atho'] dari ['Urwah bin Az Zubair] berkata; Aku bertanya kepada ['Aisyah radliallahu 'anha]: Maka dia menjawab: Rasulullah shallallahu 'alaihi wasallam tidak pernah melaksanakan 'umrah pada bulan Rajab\". "},"1654":{"ar":"حَدَّثَنَا حَسَّانُ بْنُ حَسَّانٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ سَأَلْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُكَمْ اعْتَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعٌ عُمْرَةُ الْحُدَيْبِيَةِ فِي ذِي الْقَعْدَةِ حَيْثُ صَدَّهُ الْمُشْرِكُونَ وَعُمْرَةٌ مِنْ الْعَامِ الْمُقْبِلِ فِي ذِي الْقَعْدَةِ حَيْثُ صَالَحَهُمْ وَعُمْرَةُ الْجِعِرَّانَةِ إِذْ قَسَمَ غَنِيمَةَ أُرَاهُ حُنَيْنٍ قُلْتُ كَمْ حَجَّ قَالَ وَاحِدَةً","id":"Telah menceritakan kepada kami [Hassan bin Hassan] telah menceritakan kepada kami [Hammam] dari [Qatadah]; Aku bertanya kepada [Anas radliallahu 'anhu]: Berapa kali Nabi shallallahu 'alaihi wasallam melaksanakan 'umrah?\". Dia menjawab: \"Empat kali. Diantaranya, 'umrah Al Hudaibiyah pada bulan Dzul Qa'dah saat Kaum Musyrikin menghalangi Beliau, 'umrah pada tahun berikutnya pada bulan Dzul Qa'dah setelah melakukan perjanjian damai dengan mereka dan 'umrah Al Ji'ranah ketika Beliau membagi-bagikan ghanimah (harta rampasan perang). Aku menduga yang dimaksudnya adalah ghanimah perang Hunain. Aku tanyakan lagi: \"Berapa kali Beliau menunaikan haji?\". Dia menjawab: \"Satu kali\"."},"1655":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ هِشَامُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ قَالَ سَأَلْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُ فَقَالَاعْتَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْه�� وَسَلَّمَ حَيْثُ رَدُّوهُ وَمِنْ الْقَابِلِ عُمْرَةَ الْحُدَيْبِيَةِ وَعُمْرَةً فِي ذِي الْقَعْدَةِ وَعُمْرَةً مَعَ حَجَّتِهِحَدَّثَنَا هُدْبَةُ حَدَّثَنَا هَمَّامٌ وَقَالَ اعْتَمَرَ أَرْبَعَ عُمَرٍ فِي ذِي الْقَعْدَةِ إِلَّا الَّتِي اعْتَمَرَ مَعَ حَجَّتِهِ عُمْرَتَهُ مِنْ الْحُدَيْبِيَةِ وَمِنْ الْعَامِ الْمُقْبِلِ وَمِنْ الْجِعْرَانَةِ حَيْثُ قَسَمَ غَنَائِمَ حُنَيْنٍ وَعُمْرَةً مَعَ حَجَّتِهِ","id":"Telah menceritakan kepada kami [Abu Al Walid Hisyam bin 'Abdul Malik] telah menceritakan kepada kami [Hammam] dari [Qatadah] berkata; Aku bertanya kepada [Anas radliallahu 'anhu] tentang sesuatu, lalu dia berkata: \"Nabi shallallahu 'alaihi wasallam melaksanakan 'umrah sebanyak empat kali. Yaitu 'umrah ketika mereka (Kaum Musyrikin) menghalangi Beliau, 'umrah pada tahun berikutnya yaitu 'umrah Al Hudaibiyah, 'umrah pada bulan Dzul Qa'dah dan 'umrah saat Beliau menunaikan haji\". Telah menceritakan kepada kami [Hudbah] telah menceritakan kepada kami [Hammam] dan dia berkata: \"Beliau shallallahu 'alaihi wasallam melaksanakan 'umrah sebanyak empat kali yang kesemuanya pada bulan Dzul Qa'dah kecuali 'umrah yang Beliau laksanakan bersama hajinya. Yaitu 'umrah Beliau dari Al Hudaibiyah, 'umrah pada tahun berikutnya, 'umrah Al Ji'ranah saat Beliau membagi-bagikan ghanimah (harta rampasan perang) Hunain dan 'umrah dalam 'ibadah haji Beliau\". "},"1656":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عُثْمَانَ حَدَّثَنَا شُرَيْحُ بْنُ مَسْلَمَةَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ يُوسُفَ عَنْ أَبِيهِ عَنْ أَبِي إِسْحَاقَ قَالَ سَأَلْتُ مَسْرُوقًا وَعَطَاءً وَمُجَاهِدًا فَقَالُوا اعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذِي الْقَعْدَةِ قَبْلَ أَنْ يَحُجَّ وَقَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُاعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذِي الْقَعْدَةِ قَبْلَ أَنْ يَحُجَّ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami [Ahmad bin 'Utsman] telah menceritakan kepada kami [Syuraih bin Maslamah] telah menceritakan kepada kami [Ibrahim bin Yusuf] dari [bapaknya] dari [Abu Ishaq] berkata: Aku bertanya kepada [Masruq]. ['Atho'] dan [Mujahid]. Mereka menjawab: \"Rasulullah shallallahu 'alaihi wasallam melaksanakan 'umrah pada bulan Dzul Qa'dah sebelum Beliau menunaikan haji\". Dan dia (Abu Ishaq) berkata: Aku mendengar [Al Bara' bin 'Azib radliallahu 'anhuma] berkata: \"Rasulullah shallallahu 'alaihi wasallam melaksanakan 'umrah pada bulan Dzul Qa'dah sebelum Beliau menunaikan haji sebanyak dua kali\". "},"1657":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يُخْبِرُنَا يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِامْرَأَةٍ مِنْ الْأَنْصَارِ سَمَّاهَا ابْنُ عَبَّاسٍ فَنَسِيتُ اسْمَهَا مَا مَنَعَكِ أَنْ تَحُجِّينَ مَعَنَا قَالَتْ كَانَ لَنَا نَاضِحٌ فَرَكِبَهُ أَبُو فُلَانٍ وَابْنُهُ لِزَوْجِهَا وَابْنِهَا وَتَرَكَ نَاضِحًا نَنْضَحُ عَلَيْهِ قَالَ فَإِذَا كَانَ رَمَضَانُ اعْتَمِرِي فِيهِ فَإِنَّ عُمْرَةً فِي رَمَضَانَ حَجَّةٌ أَوْ نَحْوًا مِمَّا قَالَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] dari ['Atho'] berkata; Aku mendengar [Ibnu 'Abbas radliallahu 'anhuma] mengabarkan kepada kami, katanya: Rasulullah Shallallahu 'alaihiwasallam berkata kepada seorang wanita dari Kaum Anshar yang disebut namanya oleh Ibnu 'Abbas radliallahu 'anhuma namun kami lupa siapa namanya: \"Apa yang menghalangimu untuk menunaikan haji bersama kami?\". Wanita itu berkata: \"Dahulu kami memiliki seekor unta yang selalu digunakan oleh ayah fulan dan anaknya, maksudnya adalah suami dan anak dari perempuan itu, kemudian dia membiarkan unta tersebut untuk mengangkut air. Beliau shallallahu 'alaihi wasallamberkata: \"Apabila datang bulan Ramadhan, laksanakanlah 'umrah karena 'umrah pada bulan Ramadhan seperti 'ibadah haji\" atau seperti itu (haji) sebagaimana Beliau sabdakan. "},"1658":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُوَافِينَ لِهِلَالِ ذِي الْحَجَّةِ فَقَالَ لَنَا مَنْ أَحَبَّ مِنْكُمْ أَنْ يُهِلَّ بِالْحَجِّ فَلْيُهِلَّ وَمَنْ أَحَبَّ أَنْ يُهِلَّ بِعُمْرَةٍ فَلْيُهِلَّ بِعُمْرَةٍ فَلَوْلَا أَنِّي أَهْدَيْتُ لَأَهْلَلْتُ بِعُمْرَةٍ قَالَتْ فَمِنَّا مَنْ أَهَلَّ بِعُمْرَةٍ وَمِنَّا مَنْ أَهَلَّ بِحَجٍّ وَكُنْتُ مِمَّنْ أَهَلَّ بِعُمْرَةٍ فَأَظَلَّنِي يَوْمُ عَرَفَةَ وَأَنَا حَائِضٌ فَشَكَوْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ارْفُضِي عُمْرَتَكِ وَانْقُضِي رَأْسَكِ وَامْتَشِطِي وَأَهِلِّي بِالْحَجِّ فَلَمَّا كَانَ لَيْلَةُ الْحَصْبَةِ أَرْسَلَ مَعِي عَبْدَ الرَّحْمَنِ إِلَى التَّنْعِيمِ فَأَهْلَلْتُ بِعُمْرَةٍ مَكَانَ عُمْرَتِي","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah mengabarkan kepada [Abu Mu'awiyah] telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha]: \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam tepat pada hilal (awal) bulan Dzul Hijjah. Beliau berkata kepada kami: \"Barangsiapa dari kalian yang suka berihram untuk haji, lakukanlah ihramnya untuk haji dan siapa dari kalian yang suka berihram untuk 'umrah, lakukanlah ihramnya untuk 'umrah. Seandainya bukan karena aku telah membawa hewan qurban tentu aku akan berihram untuk 'umrah\". 'Aisyah radliallahu 'anha berkata; \"Maka diantara kami ada yang berihram untuk 'umrah dan ada yang berihram untuk haji dan aku termasuk orang yang berihram untuk 'umrah\". Kemudian hari 'Arafah menaungi aku saat aku mengalami haidh. Kemudian hal ini aku adukan kepada Nabi shallallahu 'alaihi wasallam. Maka Beliau berkata: \"Tinggalkanlah 'umrahmu dan uraikanlah rambut kepalamu dan sisirlah lalu berihramlah untuk haji\". Ketika pada malam Al Hashabah (untuk melempar jumrah di Mina), Beliau mengutus 'Abdurrahman bersamaku menuju At-Tan'im. Maka aku berihram untuk 'umrah sebagai pengganti 'umrahku sebelumnya\"."},"1659":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ عَمْرَو بْنَ أَوْسٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يُرْدِفَ عَائِشَةَ وَيُعْمِرَهَا مِنْ التَّنْعِيمِقَالَ سُفْيَانُ مَرَّةً سَمِعْتُ عَمْرًا كَمْ سَمِعْتُهُ مِنْ عَمْرٍو","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari ['Amru], dia mendengar ['Amru bin Aus] bahwa ['Abdurrahman bin Abu Bakar radliallahu 'anhuma] mengabarkan kepadanya bahwa Nabi shallallahu 'alaihi wasallam memerintahkan dia agar membonceng (membawa dengan hewan tunggangan) 'Aisyah radliallahu 'anha dan menemaninya melaksanakan 'umrah dari At-Tan'im\". Sufyan berkata; suatu kali aku pernah mendengar ['Amr] berkata: \"Berapa kali kamu mendengarnya dari 'Amru?\""},"1660":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْمَجِيدِ عَنْ حَبِيبٍ الْمُعَلِّمِ عَنْ عَطَاءٍ حَدَّثَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَهَلَّ وَأَصْحَابُهُ بِالْحَجِّ وَلَيْسَ مَعَ أَحَدٍ مِنْهُمْ هَدْيٌ غَيْرِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَطَلْحَةَ وَكَانَ عَلِيٌّ قَدِمَ مِنْ الْيَمَنِ وَمَعَهُ الْهَدْيُ فَقَالَ أَهْلَلْتُ بِمَا أَهَلَّ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَذِنَ لِأَصْحَابِهِ أَنْ يَجْعَلُوهَا عُمْرَةً يَطُوفُوا بِالْبَيْتِ ثُمَّ يُقَصِّرُوا وَيَحِلُّوا إِلَّا مَنْ مَعَهُ الْهَدْيُ فَقَالُوا نَنْطَلِقُ إِلَى مِنًى وَذَكَرُ أَحَدِنَا يَقْطُرُ فَبَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ اسْتَقْبَلْتُ مِنْ أَمْرِي مَا اسْتَدْبَرْتُ مَا أَهْدَيْتُ وَلَوْلَا أَنَّ مَعِي الْهَدْيَ لَأَحْلَلْتُ وَأَنَّ عَائِشَةَ حَاضَتْ فَنَسَكَتْ الْمَنَاسِكَ كُلَّهَا غَيْرَ أَنَّهَا لَمْ تَطُفْ بِالْبَيْتِ قَالَ فَلَمَّا طَهُرَتْ وَطَافَتْ قَالَتْ يَا رَسُولَ اللَّهِ أَتَنْطَلِقُونَ بِعُمْرَةٍ وَحَجَّةٍ وَأَنْطَلِقُ بِالْحَجِّ فَأَمَرَ عَبْدَ الرَّحْمَنِ بْنَ أَبِي بَكْرٍ أَنْ يَخْرُجَ مَعَهَا إِلَى التَّنْعِيمِ فَاعْتَمَرَتْ بَعْدَ الْحَجِّ فِي ذِي الْحَجَّةِ وَأَنَّ سُرَاقَةَ بْنَ مَالِكِ بْنِ جُعْشُمٍ لَقِيَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِالْعَقَبَةِ وَهُوَ يَرْمِيهَا فَقَالَ أَلَكُمْ هَذِهِ خَاصَّةً يَا رَسُولَ اللَّهِ قَالَ لَا بَلْ لِلْأَبَدِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami ['Abdul Wahhab bin 'Abdul Majid] dari [Habib Al Mu'alim] dari ['Atho'] telah menceritakan kepadaku [Jabir bin 'Abdullah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam dan para sahabatnya berniat untuk haji dan tidak ada satupun dari mereka yang membawa Al Hadyu (hewan qurban) kecuali Nabi shallallahu 'alaihi wasallam dan Tholhah serta 'Ali yang baru datang dari Yaman juga membawa Al Hadyu, dia berkata: \"Aku berihram sebagaimana Rasulullah shallallahu 'alaihi wasallam berihram. Dan Nabi shallallahu 'alaihi wasallam mengijinkan para sahabat Beliau untuk menjadikan ihram mereka sebagai 'umrah, mereka thawaf di Ka'bah Baitullah, kemudian memotong (memendekkan) rambut lalu bertahallul kecuali siapa yang membawa Al Hadyu. Mereka berkata: \"Kemudian kami berangkat menuju Mina lalu diantara kami ada yang menyebut bahwa dia menarik diri. Hal ini kemudian sampai kepada Nabi shallallahu 'alaihi wasallam, maka Beliau berkata: \"Kalaulah aku bisa mengulang kembali urusanku yang telah lewat, niscaya aku tidak membawa binatang korban. Seandainya aku tidak membawa Al Hadyu, sudah pasti aku akan bertahallul\". Kemudian 'Aisyah radliallahu 'anha mengalami haidh sedangkan dia sudah menyelesaikan seluruh manasik kecuali thawaf di Ka'bah Baitullah. Ketika dia sudah suci, dia melaksanakan thawaf di Ka'bah Baitullah. Dia berkata: 'Wahai Rasulullah, apakah kalian akan berangkat pulang dengan membawa haji dan 'umrah sedangkan aku dengan niat haji saja?\" Maka Beliau memerintahkan 'Abdurrahman bin Abu Bakar agar berangkat bersama 'Aisyah radliallahu 'anha ke Tan'im. Maka 'Aisyah radliallahu 'anha melaksanakan 'umrah setelah melaksanakan manasik haji pada bulan Dzul Hijjah\". Dan Suraqah bin Malik bin Ju'syam bertemu Nabi shallallahu 'alaihi wasallam saat Beliau berada di Al 'Aqabah sedang melempar jumrah, dia bertanya: \"Apakah ini khusus buat kalian, wahai Rasulullah? Beliau berkata: \"Tidak, tapi untuk selamanya\"."},"1661":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى حَدَّثَنَا هِشَامٌ قَالَ أَخْبَرَنِي أَبِي قَالَ أَخْبَرَتْنِي عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُوَافِينَ لِهِلَالِ ذِي الْحَجَّةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ أَنْ يُهِلَّ بِعُمْرَةٍ فَلْيُهِلَّ وَمَنْ أَحَبَّ أَنْ يُهِلَّ بِحَجَّةٍ فَلْيُهِلَّ وَلَوْلَا أَنِّي أَهْدَيْتُ لَأَهْلَلْتُ بِعُمْرَةٍ فَمِنْهُمْ مَنْ أَهَلَّ بِعُمْرَةٍ وَمِنْهُمْ مَنْ أَهَلَّ بِحَجَّةٍ وَكُنْتُ مِمَّنْ أَهَلَّ بِعُمْرَةٍ فَحِضْتُ قَبْلَ أَنْ أَدْخُلَ مَكَّةَ فَأَدْرَكَنِي يَوْمُ عَرَفَةَ وَأَنَا حَائِضٌ فَشَكَوْتُ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ دَعِي عُمْرَتَكِ وَانْقُضِي رَأْسَكِ وَامْتَشِطِي وَأَهِلِّي بِالْحَجِّ فَفَعَلْتُ فَلَمَّا كَانَتْ لَيْلَةُ الْحَصْبَةِ أَرْسَلَ مَعِي عَبْدَ الرَّحْمَنِ إِلَى التَّنْعِيمِ فَأَرْدَفَهَا فَأَهَلَّتْ بِعُمْرَةٍ مَكَانَ عُمْرَتِهَا فَقَضَى اللَّهُ حَجَّهَا وَعُمْرَتَهَا وَلَمْ يَكُنْ فِي شَيْءٍ مِنْ ذَلِكَ هَدْيٌ وَلَا صَدَقَةٌ وَلَا صَوْمٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Hisyam] berkata, telah mengabarkan kepada saya [bapaknya] berkata, telah mengabarkan kepada saya ['Aisyah radliallahu 'anha] berkata: \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam tepat pada hilal (awal) bulan Dzul Hijjah. Rasulullah shallallahu 'alaihi wasallam berkata: \"Barangsiapa yang suka berihram untuk 'umrah, lakukanlah dan siapa yang suka berihram untuk haji, lakukanlah. Seandainya bukan karena aku telah membawa hewan qurban tentu aku akan berihram untuk 'umrah\". 'Aisyah radliallahu 'anha berkata: \"Maka diantara mereka ada yang berihram untuk 'umrah dan ada yang berihram untuk haji dan aku termasuk orang yang berihram untuk 'umrah\". Kemudian aku mengalami haidh sebelum aku memasuki Makkah dan aku mendapatkan hari \"Arafah dalam keadaan haidh. Hal ini aku adukan kepada Rasulullah shallallahu 'alaihi wasallam. Beliau berkata: \"Tinggalkanlah 'umrahmu dan uraikanlah rambut kepalamu dan sisirlah lalu berihramlah untuk haji\". Maka perintah Beliau itu aku laksanakan. Ketika pada malam Al Hashabah (untuk melempar jumrah di Mina), Beliau mengutus 'Abdurrahman bersamaku menuju At-Tan'im. Maka dia memboncengiku lalu aku berihram untuk 'umrah sebagai pengganti 'umrahku sebelumnya\". Maka Allah menetapkan terlaksananya haji dan 'umrahnya 'Aisyah radliallahu 'anha dan tidak ada sesuatupun sebagai pengganti dari itu semua baik berupa hewan qurban, shadaqah maupun shaum. "},"1662":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ وَعَنْ ابْنِ عَوْنٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَا قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَايَا رَسُولَ اللَّهِ يَصْدُرُ النَّاسُ بِنُسُكَيْنِ وَأَصْدُرُ بِنُسُكٍ فَقِيلَ لَهَا انْتَظِرِي فَإِذَا طَهُرْتِ فَاخْرُجِي إِلَى التَّنْعِيمِ فَأَهِلِّي ثُمَّ ائْتِينَا بِمَكَانِ كَذَا وَلَكِنَّهَا عَلَى قَدْرِ نَفَقَتِكِ أَوْ نَصَبِكِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Ibnu 'Aun] dari [Al Qasim bin Muhammad]. Dan dari [Ibnu 'Aun] dari [Ibrahim] dari [Al Aswad] keduanya berkata; ['Aisyah radliallahu 'anha] berkata; \"Wahai Rasulullah, orang-orang selesai dengan mengambil dua manasik sedangkan aku hanya satu. Maka dikatakan kepadanya; \"Tunggulah, jika kamu sudah suci maka keluarlah menuju Tan'im lalu berihramlah kemudian temuilah kami di tempat ini namun derajatnya tergantung pengorbanan dan tingkat kesulitanmu\"."},"1663":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا أَفْلَحُ بْنُ حُمَيْدٍ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُهِلِّينَ بِالْحَجِّ فِي أَشْهُرِ الْحَجِّ وَحُرُمِ الْحَجِّ فَنَزَلْنَا سَرِفَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ مَنْ لَمْ يَكُنْ مَعَهُ هَدْيٌ فَأَحَبَّ أَنْ يَجْعَلَهَا عُمْرَةً فَلْيَفْعَلْ وَمَنْ كَانَ مَعَهُ هَدْيٌ فَلَا وَكَانَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرِجَالٍ مِنْ أَصْحَابِهِ ذَوِي قُوَّةٍ الْهَدْيُ فَلَمْ تَكُنْ لَهُمْ عُمْرَةً فَدَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَبْكِي فَقَالَ مَا يُبْكِيكِ قُلْتُ سَمِعْتُكَ تَقُولُ لِأَصْحَابِكَ مَا قُلْتَ فَمُنِعْتُ الْعُمْرَةَ قَالَ وَمَا شَأْنُكِ قُلْتُ لَا أُصَلِّي قَالَ فَلَا يَضِرْكِ أَنْتِ مِنْ بَنَاتِ آدَمَ كُتِبَ عَلَيْكِ مَا كُتِبَ عَلَيْهِنَّ فَكُونِي فِي حَجَّتِكِ عَسَى اللَّهُ أَنْ يَرْزُقَكِهَا قَالَتْ فَكُنْتُ حَتَّى نَفَرْنَا مِنْ مِنًى فَنَزَلْنَا الْمُحَصَّبَ فَدَعَا عَبْدَ الرَّحْمَنِ فَقَالَ اخْرُجْ بِأُخْتِكَ الْحَرَمَ فَلْتُهِلَّ بِعُمْرَةٍ ثُمَّ افْرُغَا مِنْ طَوَافِكُمَا أَنْتَظِرْكُمَا هَا هُنَا فَأَتَيْنَا فِي جَوْفِ اللَّيْلِ فَقَالَ فَرَغْتُمَا قُلْتُ نَعَمْ فَنَادَى بِالرَّحِيلِ فِي أَصْحَابِهِ فَارْتَحَلَ النَّاسُ وَمَنْ طَافَ بِالْبَيْتِ قَبْلَ صَلَاةِ الصُّبْحِ ثُمَّ خَرَجَ مُوَجِّهًا إِلَى الْمَدِينَةِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Aflah bin Humaid] dari [Al Qasim] dari ['Aisyah radliallahu 'anha] berkata: \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam untuk melaksanakan haji pada bulan-bulan haji dan ihram-ihram haji. Ketika kami berhenti di Sarif, Nabi shallallahu 'alaihi wasallam berkata kepada para sahabatnya: \"Barangsiapa tidak membawa Al Hadyu dan suka untuk menjadikan ihramnya untuk 'umrah, lakukanlah dan siapa yang membawa Al Hadyu, tidak boleh (menjadikan ihramnya sebagai 'umrah) \". Nabi shallallahu 'alaihi wasallam beserta beberapa orang dari sahabat Beliau yang berbadan kuat dan membawa Al Hadyu, tidak berihram untuk 'umrah. Kemudian Nabi shallallahu 'alaihi wasallam masuk menemuiku saat itu aku sedang menangis, maka Beliau bertanya: \"Apa yang membuatmu menangis?\" 'Aisyah radliallahu 'anha menjawab: \"Aku mendengar apa yang anda katakan kepada para sahabat anda sehingga aku terhalang menjadikan ihramku sebagai 'umrah\". Beliau berkata: \"Apa hubungannya denganmu? '\" Aku jawab: \"Aku sedang tidak shalat\". Beliau berkata: \"Tidak apa, karena kamu adalah dari anak-anak perempuan keturunan Adam yang telah ditetapkan ketentuan atas mereka, maka laksanakanlah hajimu semoga Allah memberikanmu karunia dengan hajimu ini\". 'Aisyah radliallahu 'anha berkata: \"Maka aku laksanakan hingga kami keluar (nafar) dari Mina lalu singgah di tempat pelemparan jumrah, Beliau memanggil 'Abdurrahman lalu berkata: \"Keluarlah kamu bersama saudaramu dari tanah haram lalu berihramlah untuk 'umrah kemudian jika kalian berdua telah selesai dari thawaf (datanglah kemari), kami menunggu kalian berdua disini\". Maka kami temui Beliau pada tengah malam. Beliau bertanya: \"Apakah kalian telah selesai?\". Aku jawab: \"Ya, sudah\". Maka Beliau menyeru para sahabatnya agar bersiap-siap berangkat. Maka orang-orang dan termasuk yang sedang berthawaf di Ka'bah Baitullah bergegas sebelum shalat Shubuh lalu berangkat pulang menuju Madinah. "},"1664":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا عَطَاءٌ قَالَ حَدَّثَنِي صَفْوَانُ بْنُ يَعْلَى بْنِ أُمَيَّةَ يَعْنِي عَنْ أَبِيهِأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِالْجِعْرَانَةِ وَعَلَيْهِ جُبَّةٌ وَعَلَيْهِ أَثَرُ الْخَلُوقِ أَوْ قَالَ صُفْرَةٌ فَقَالَ كَيْفَ تَأْمُرُنِي أَنْ أَصْنَعَ فِي عُمْرَتِي فَأَنْزَلَ اللَّهُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسُتِرَ بِثَوْبٍ وَوَدِدْتُ أَنِّي قَدْ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أُنْزِلَ عَلَيْهِ الْوَحْيُ فَقَالَ عُمَرُ تَعَالَ أَيَسُرُّكَ أَنْ تَنْظُرَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ أَنْزَلَ اللَّهُ عَلَيْهِ الْوَحْيَ قُلْتُ نَعَمْ فَرَفَعَ طَرَفَ الثَّوْبِ فَنَظَرْتُ إِلَيْهِ لَهُ غَطِيطٌ وَأَحْسِبُهُ قَالَ كَغَطِيطِ الْبَكْرِ فَلَمَّا سُرِّيَ عَنْهُ قَالَ أَيْنَ السَّائِلُ عَنْ الْعُمْرَةِ اخْلَعْ عَنْكَ الْجُبَّةَ وَاغْسِلْ أَثَرَ الْخَلُوقِ عَنْكَ وَأَنْقِ الصُّفْرَةَ وَاصْنَعْ فِي عُمْرَتِكَ كَمَا تَصْنَعُ فِي حَجِّكَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami ['Atho'] berkata, telah menceritakan kepada saya [Shawan bin Ya'la bin Umayyah], yaitu dari [bapaknya] bahwa ada seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam saat Beliau berada di Al Ji'ranah. Orang itu mengenakan jubah (baju besar) yang masih terasa sisa wewangian padanya atau nampat sisa pewarna kuning, berkata: \"Bagaimana aku harus mengerjakan 'umrahku?\". Maka Allah subhanahu wata'ala menurunkan wahyu kepada Nabi shallallahu 'alaihi wasallam dan wajah Beliau ditutup dengan kain. Ya'la bin Umayyah berkata; \"Aku sendiri sangat ingin dapat melihat Nabi shallallahu 'alaihi wasallam ketika sedang menerima wahyu\". Maka 'Umar radliallahu 'anhu berkata: \"Kemarilah, apakah melihat Nabi shallallahu 'alaihi wasallam ketika sedang menerima wahyu dapat menyenangkanmu?\". Aku katakan: \"Ya\". Maka 'Umar membuka ujung kain yang tadi menutupi wajah Nabi shallallahu 'alaihi wasallam, lalu aku dapat melihat Beliau sedang bernapas dalam tidurnya\". (Kata Shafwan) aku menduga bapakku berkata: \"Beliau mendengkur sejenak\". Ketika Beliau selesai menerima wahyu, Beliau bertanya: \"Mana orang tadi yang bertanya tentang 'umrah?. Lepaslah jubahmu, cucilah dari sisa wewangian dan pewarna kuning dan kerjakan 'umrahmu seperti kamu mengerjakan haji\"."},"1665":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّهُ قَالَ قُلْتُ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا يَوْمَئِذٍ حَدِيثُ السِّنِّأَرَأَيْتِ قَوْلَ اللَّهِ تَبَارَكَ وَتَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }فَلَا أُرَى عَلَى أَحَدٍ شَيْئًا أَنْ لَا يَطَّوَّفَ بِهِمَا فَقَالَتْ عَائِشَةُ كَلَّا لَوْ كَانَتْ كَمَا تَقُولُ كَانَتْ فَلَا جُنَاحَ عَلَيْهِ أَنْ لَا يَطَّوَّفَ بِهِمَا إِنَّمَا أُنْزِلَتْ هَذِهِ الْآيَةُ فِي الْأَنْصَارِ كَانُوا يُهِلُّونَ لِمَنَاةَ وَكَانَتْ مَنَاةُ حَذْوَ قُدَيْدٍ وَكَانُوا يَتَحَرَّجُونَ أَنْ يَطُوفُوا بَيْنَ الصَّفَا وَالْمَرْوَةِ فَلَمَّا جَاءَ الْإِسْلَامُ سَأَلُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَأَنْزَلَ اللَّهُ تَعَالَى{ إِنَّ الصَّفَا وَالْمَرْوَةَ مِنْ شَعَائِرِ اللَّهِ فَمَنْ حَجَّ الْبَيْتَ أَوْ اعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَنْ يَطَّوَّفَ بِهِمَا }زَادَ سُفْيَانُ وَأَبُو مُعَاوِيَةَ عَنْ هِشَامٍ مَا أَتَمَّ اللَّهُ حَجَّ امْرِئٍ وَلَا عُمْرَتَهُ لَمْ يَطُفْ بَيْنَ الصَّفَا وَالْمَرْوَةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] bahwa dia berkata; Aku pernah bertanya kepada ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam saat itu aku masih muda: \"Bagaimana pendapatmu tentang firman Allah Ta'ala (QS Al Baqarah 158) yang artinya: (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah. Maka barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\"), kalau aku berpendapat bahwa seseorang tidak mengapa untuk tidak berthawaf (sa'iy) antara kedua bukit itu. 'Aisyah radliallahu 'anha berkata: \"Bukanlah begitu. Seandainya ayat ini maksudnya sebagaimana yang kamu katakan itu, berarti tidak berdosa bila ada orang yang tidak melaksanakan sa'iy antara keduanya. Sesungguhnya ayat ini turun berkenaan dengan Kaum Anshar yang dahulu mereka berniat haji untuk patung Manat (yang mereka sembah) di daerah sekitar Qudaid. Lantas mereka merasa berdosa bila harus sa'iy antara bukit Ash-Shafaa dan Al Marwah. Setelah Islam datang, mereka bertanya kepada Rasulullah shallallahu 'alaihi wasallam masalah itu, maka kemudian Allah Ta'ala menurunkan ayat (\"Sesungguhnya Ash-Shafaa dan Al Marwah adalah sebahagian dari syi'ar-syi'ar Allah. Barangsiapa yang beribadah haji ke Baitullah atau ber'umrah, maka tidak ada dosa baginya mengerjakan sa'iy antara keduanya\"). [Sufyan] dan [Abu Mu'awiyah] menambahkan dari [Hisyam] (yakni dari bapaknya dari 'Aisyah radliallahu 'anha): \"Allah tidak akan menerima haji atau 'umrah seseorang yang tidak melakukan sa'iy antara bukit Ash-Shafaa dan Al Marwah\"."},"1666":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ عَنْ جَرِيرٍ عَنْ إِسْمَاعِيلَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَاعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاعْتَمَرْنَا مَعَهُ فَلَمَّا دَخَلَ مَكَّةَ طَافَ وَطُفْنَا مَعَهُ وَأَتَى الصَّفَا وَالْمَرْوَةَ وَأَتَيْنَاهَا مَعَهُ وَكُنَّا نَسْتُرُهُ مِنْ أَهْلِ مَكَّةَ أَنْ يَرْمِيَهُ أَحَدٌ فَقَالَ لَهُ صَاحِبٌ لِي أَكَانَ دَخَلَ الْكَعْبَةَ قَالَ لَا قَالَ فَحَدِّثْنَا مَا قَالَ لِخَدِيجَةَ قَالَ بَشِّرُوا خَدِيجَةَ بِبَيْتٍ مِنْ الْجَنَّةِ مِنْ قَصَبٍ لَا صَخَبَ فِيهِ وَلَا نَصَبَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] dari [Jarir] dari [Isma'il] dari ['Abdullah bin Abu Awfa] berkata: \"Rasulullah shallallahu 'alaihi wasallam menunaikan 'umrah begitu juga kami bersama Beliau. Ketika Beliau memasuki Makkah Beliau melaksanakan thawaf, begitu juga kami melaksanakannya kemudian Beliau mendatangi bukit Ash-Shafaa dan Al Marwah begitu juga kami (untuk melaksanakan sa'iy). Saat itu kami melindungi Beliau dari penduduk Makkah bila ada seseorang yang akan melempari Beliau. Ada di antara sahabatku yang bertanya kepadanya ('Abdullah bin Abu Awfa): \"Apakah pada saat itu Beliau masuk ke dalam Ka'bah?\". Dia menjawab: \"Tidak\". Sahabatku itu berkata: \"Ceritakanlah kepada kami apa yang dikatakan Beliau tentang Khadijah radliallahu 'anha\". Beliau bersabda: \"Berikanlah kabar genbira kepada Khadijah (bahwa ia akan memperoleh) rumah di surga yang terbuat dari mutiara yang didalamnya tidak ada hiruk pikuk dan kepayahan\". "},"1667":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَأَلْنَا ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ رَجُلٍ طَافَ بِالْبَيْتِ فِي عُمْرَةٍ وَلَمْ يَطُفْ بَيْنَ الصَّفَا وَالْمَرْوَةِ أَيَأْتِي امْرَأَتَهُ فَقَالَ قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَافَ بِالْبَيْتِ سَبْعًا وَصَلَّى خَلْفَ الْمَقَامِ رَكْعَتَيْنِ وَطَافَ بَيْنَ الصَّفَا وَالْمَرْوَةِ سَبْعًا وَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌقَالَ وَسَأَلْنَا جَابِرَ بْنَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ لَا يَقْرَبَنَّهَا حَتَّى يَطُوفَ بَيْنَ الصَّفَا وَالْمَرْوَةِ","id":"Telah menceritakan kepada kami [Al Humaidiy] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] berkata: \"Kami pernah bertanya kepada [Ibnu'Umar radliallahu 'anhuma] tentang seseorang yang melaksanakan thawaf di Ka'bah Baitullah dam 'ibadah 'umrahnya namun belum melaksanakan sa'iy antara bukit Shafaa dan Marwah, apakah dia boleh mendatangi (berhubungan dengan) isterinya?. Dia menjawab: \"Nabi shallallahu 'alaihi wasallam pernah datang ke Baitullah untuk haji yang Beliau thawaf di Ka'bah Baitullah tujuh kali putaran kemudian shalat dua raka'at di belakang Maqam (Ibrahim) lalu melaksakan sa'iy antara bukit Shafaa dan Marwah tujuh kali. (Kemudian dia membaca QS Al Ahzab ayat 21 yang artinya): (\"Sungguh bagi kalian ada suri tauladan yang baik pada diri Rasulullah\"). Dan kami pernah pula bertanya kepada [Jabir bin 'Abdullah radliallahu 'anhu] tentang hal ini. Maka dia berkata: \"Janganlah orang itu mendekati isterinya hingga dia melaksanakan sa'iy antara bukit Shafaa dan Marwah\". "},"1668":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْبَطْحَاءِ وَهُوَ مُنِيخٌ فَقَالَ أَحَجَجْتَ قُلْتُ نَعَمْ قَالَ بِمَا أَهْلَلْتَ قُلْتُ لَبَّيْكَ بِإِهْلَالٍ كَإِهْلَالِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحْسَنْتَ طُفْ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ أَحِلَّ فَطُفْتُ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ أَتَيْتُ امْرَأَةً مِنْ قَيْسٍ فَفَلَتْ رَأْسِي ثُمَّ أَهْلَلْتُ بِالْحَجِّ فَكُنْتُ أُفْتِي بِهِ حَتَّى كَانَ فِي خِلَافَةِ عُمَرَ فَقَالَ إِنْ أَخَذْنَا بِكِتَابِ اللَّهِ فَإِنَّهُ يَأْمُرُنَا بِالتَّمَامِ وَإِنْ أَخَذْنَا بِقَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّهُ لَمْ يَحِلَّ حَتَّى يَبْلُغَ الْهَدْيُ مَحِلَّهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Qais bin Muslim] dari [Thoriq bin Syihab] dari [Abu Musa Al As'ariy radliallahu 'anhu] berkata; \"Aku menemui Rasulullah shallallahu 'alaihi wasallam ketika Beliau berada di Bathha', ketika Beliau singgah untukk istirahat lalu Beliau bertanya kepadaku: \"Bagaimana cara kamu berihram?\". Aku jawab: \"Aku berihram dengan bertalbiyah (berniat memulai haji) sebagaimana Nabi shallallahu 'alaihi wasallam berihram\". Maka Beliau berkata: \"Kamu sudah berbuat dengan baik, maka thawaflah di Ka'bah Baitullah dan sa'iy antara bukit Shafaa dan Marwah lalu bertahallullah\". Maka aku thawaf di Ka'bah Baitullah dan sa'iy antara bukit Shafaa dan Marwah. Kemudian aku menemui seorang wanita dari Banu Qais lalu dia mencari kutu kepalaku. Kemudian aku berihram untuk haji. Setelah itu aku selalu memberi fatwa cara manasik seperti itu hingga masa khilafah 'Umar radliallahu 'anhu yang dia berkata: \"Jika kita mengambil pelajaran dari Kitab Allah maka Dia memerintahkan kita untuk menyempurnakannya dan apabila kita mengambil sabda Nabi shallallahu 'alaihi wasallam, sesungguhnya Beliau tidak bertahallul hingga Al Hadyu sampai pada tempat penyembelihannya\". "},"1669":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنَا عَمْرٌو عَنْ أَبِي الْأَسْوَدِ أَنَّ عَبْدَ اللَّهِ مَوْلَى أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ حَدَّثَهُ أَنَّهُ كَانَ يَسْمَعُ أَسْمَاءَتَقُولُ كُلَّمَا مَرَّتْ بِالحَجُونِ صَلَّى اللَّهُ عَلَى رَسُولِهِ مُحَمَّدٍ لَقَدْ نَزَلْنَا مَعَهُ هَا هُنَا وَنَحْنُ يَوْمَئِذٍ خِفَافٌ قَلِيلٌ ظَهْرُنَا قَلِيلَةٌ أَزْوَادُنَا فَاعْتَمَرْتُ أَنَا وَأُخْتِي عَائِشَةُ وَالزُّبَيْرُ وَفُلَانٌ وَفُلَانٌ فَلَمَّا مَسَحْنَا الْبَيْتَ أَحْلَلْنَا ثُمَّ أَهْلَلْنَا مِنْ الْعَشِيِّ بِالْحَجِّ","id":"Telah menceritakan kepada kami [Ahmad bin 'Isa] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepada kami ['Amru] dari [Abu Al Aswad] bahwa ['Abdullah, maula Asma' binti Abu Bakar] menceritakan kepadanya bahwa dia mendengar [Asma'] berkata: \"Setiap kali ia melewati Al Hajun ia bersalawat untuk Rasulullah Muhammad, dan berkata; \"Sungguh kami pernah singgah bersama Beliau disini, dan ketika itu kami amat kekurangan, bekal kami menipis. Lalu aku ber'umrah dengan saudara perempuanku 'Aisyah, Az Zubair, fulan dan fulan. Ketika kami telah selesai dari thawaf di Ka'bah, kami bertahallul kemudian kami berniat haji dari Al 'Asyiy\"."},"1670":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَفَلَ مِنْ غَزْوٍ أَوْ حَجٍّ أَوْ عُمْرَةٍ يُكَبِّرُ عَلَى كُلِّ شَرَفٍ مِنْ الْأَرْضِ ثَلَاثَ تَكْبِيرَاتٍ ثُمَّ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ آيِبُونَ تَائِبُونَ عَابِدُونَ سَاجِدُونَ لِرَبِّنَا حَامِدُونَ صَدَقَ اللَّهُ وَعْدَهُ وَنَصَرَ عَبْدَهُ وَهَزَمَ الْأَحْزَابَ وَحْدَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam apabila kembali dari suatu peperangan atau haji atau 'umrah, Beliau bertakbir tiga kali pada setiap dataran tinggi dari permukaan bumi lalu berdo'a: \"Laa ilaaha illallahu wahdahu laa syariika lahu, lahul mulku wa lahul hamdu wa huwa 'alaa kulli syai'in qadiir. Aayibuuna taa'buuna 'aabiduuna saajiduuna li rabbinaa haamiduun. Shadaqallah wa'dahu wa nashara 'abdahu wa hazamal ahzaaba wahdah\". (Tidak ada ilah yang berhak disembah selain Allah satu-satunya, tidak ada sekutu bagi-Nya. Milik-Nya segala kerajaan, dan pujian dan Dia Maha Berkuasa atas segala sesuatu. Kita kembali, sebagai hamba yang bertaubat, ber'ibadah, sujud untuk Rabb kita dan yang memuji-Nya. Allah Maha Benar dengan janji-Nya, menolong hamba-Nya dan menghancurkan musuh-musuh-Nya) \"."},"1671":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ اسْتَقْبَلَتْهُ أُغَيْلِمَةُ بَنِي عَبْدِ الْمُطَّلِبِ فَحَمَلَ وَاحِدًا بَيْنَ ��َدَيْهِ وَآخَرَ خَلْفَهُ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: Ketika Nabi shallallahu 'alaihi wasallam sampai di Makkah Beliau ditemui anak-anak kecil Suku Bani 'Abdul Muthalib lalu Beliau menggendong salah satu dari mereka di depan dan yang lainnya dibelakang\""},"1672":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ الحَجَّاجِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا خَرَجَ إِلَى مَكَّةَ يُصَلِّي فِي مَسْجِدِ الشَّجَرَةِ وَإِذَا رَجَعَ صَلَّى بِذِي الْحُلَيْفَةِ بِبَطْنِ الْوَادِي وَبَاتَ حَتَّى يُصْبِحَ","id":"Telah menceritakan kepada kami [Ahmad bin Al Hajjaj] telah menceritakan kepada kami [Anas bin 'Iyadh] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam pergi menuju Makkah, Beliau shalat di masjid Asy-Syajarah dan jika kembali Beliau shalat di Dzul Hulaifah di dasar lembah dan bermalam disana hingga shubuh."},"1673":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا هَمَّامٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَطْرُقُ أَهْلَهُ كَانَ لَا يَدْخُلُ إِلَّا غُدْوَةً أَوْ عَشِيَّةً","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Hammam] dari [Ishaq bin 'Abdullah bin Abu Tholhah] dari [Anas radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam tidak pernah pulang kepada keluarganya secara mendadak di malam hari dan tidak memasuki rumah kecuali pada pagi atau siang hari\"."},"1674":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَارِبٍ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَطْرُقَ أَهْلَهُ لَيْلًا","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Syu'bah] dari [Muharib] dari [Jabir radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam melarang jika seseorang pulang mendadak kepada keluarganya di malam hari\"."},"1675":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي حُمَيْدٌ أَنَّهُ سَمِعَ أَنَسًا رَضِيَ اللَّهُ عَنْهُ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَدِمَ مِنْ سَفَرٍ فَأَبْصَرَ دَرَجَاتِ الْمَدِينَةِ أَوْضَعَ نَاقَتَهُ وَإِنْ كَانَتْ دَابَّةً حَرَّكَهَاقَالَ أَبُو عَبْد اللَّهِ زَادَ الْحَارِثُ بْنُ عُمَيْرٍ عَنْ حُمَيْدٍ حَرَّكَهَا مِنْ حُبِّهَا حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَاعِيلُ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَ جُدُرَاتِ تَابَعَهُ الْحَارِثُ بْنُ عُمَيْرٍ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah mengabarkan kepada kami [Muhammad bin Ja'far] berkata, telah mengabarkan kepada saya [Humaid], bahwa dia mendengar [Anas radliallahu 'anhu] berkata: \" Rasulullah shallallahu 'alaihi wasallam bila pulang dari bepergian dan melihat dataran tinggi kota Madinah, Beliau mempercepat jalan unta Beliau dan bila menunggang hewan lain Beliau memacunya\". Abu 'Abdullah Al Bukhariy berkata: [Al Harits bin 'Umair] dari [Humaid]: \"Beliau memacunya karena kecintaannya (kepada Madinah). Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Isma'il] dari [Humaid] dari [Anas] berkata, \"…. Beliau melihat dinding-dinding kota Madinah ….\". Hadits ini diikuti pula oleh [Al Harits bin 'Umair]."},"1676":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ رَضِيَ اللَّهُ عَنْهُ يَقُولُنَزَلَتْ هَذِهِ الْآيَةُ فِينَا كَانَتْ الْأَنْصَارُ إِذَا حَجُّوا فَجَاءُوا لَمْ يَدْخُلُوا مِنْ قِبَلِ أَبْوَابِ بُيُوتِهِمْ وَلَكِنْ مِنْ ظُهُورِهَا فَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ فَدَخَلَ مِنْ قِبَلِ بَابِهِ فَكَأَنَّهُ عُيِّرَ بِذَلِكَ فَنَزَلَتْ{ وَلَيْسَ الْبِرُّ بِأَنْ تَأْتُوا الْبُيُوتَ مِنْ ظُهُورِهَا وَلَكِنَّ الْبِرَّ مَنْ اتَّقَى وَأْتُوا الْبُيُوتَ مِنْ أَبْوَابِهَا }","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] berkata; Aku mendengar [Al Bara' radliallahu 'anhu] berkata: \"Ayat ini turun kepada kami, yaitu Kaum Anshar jika mereka menunaikan haji lalu kembali pulang, mereka tidak memasuki rumah-rumah mereka dari pintu depannya namun mereka masuk dari belakang. Kemudian datanglah seseorang dari Kaum Anshar yang ia masuk dari pintu depan seakan-akan ia merubah kebiasaan tadi. Maka kemudian turunlah firman Allah QS Al Baqarah ayat 189 yang artinya: (\"Dan bukanlah kebajikan memasuki rumah-rumah dari belakangnya, akan tetapi kebajikan itu ialah kebajikan orang yang bertakwa. Dan masuklah ke rumah-rumah itu dari pintu-pintunya\")."},"1677":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ السَّفَرُ قِطْعَةٌ مِنْ الْعَذَابِ يَمْنَعُ أَحَدَكُمْ طَعَامَهُ وَشَرَابَهُ وَنَوْمَهُ فَإِذَا قَضَى نَهْمَتَهُ فَلْيُعَجِّلْ إِلَى أَهْلِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam berkata: \"Bepergian (safar) itu adalah sebagian dari siksaan, yang menghalangi seseorang dari kalian dari makan, minum dan tidurnya. Maka apabila dia telah selesai dari urusannya hendaklah dia segera kembali kepada keluarganya\"."},"1678":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَخْبَرَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ أَبِيهِ قَالَ كُنْتُ مَعَ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَابِطَرِيقِ مَكَّةَ فَبَلَغَهُ عَنْ صَفِيَّةَ بِنْتِ أَبِي عُبَيْدٍ شِدَّةُ وَجَعٍ فَأَسْرَعَ السَّيْرَ حَتَّى كَانَ بَعْدَ غُرُوبِ الشَّفَقِ نَزَلَ فَصَلَّى الْمَغْرِبَ وَالْعَتَمَةَ جَمَعَ بَيْنَهُمَا ثُمَّ قَالَ إِنِّي رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَدَّ بِهِ السَّيْرُ أَخَّرَ الْمَغْرِبَ وَجَمَعَ بَيْنَهُمَا","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah mengabarkan kepada kami [Muhammad bin Ja'far] berkata, telah mengabarkan kepada saya [Zaid bin Aslam] dari [bapaknya] berkata; Aku pernah bersama ['Abdullah bin 'Umar radliallahu 'anhu] pada suatu jalan di kota Makkah. Lalu sampai berita kepadanya bahwa Shafiyyah binti Abu 'Ubaid sedang menderita sakit. Maka dia mempercepat jalannya hingga apabila warna kuning dilangit telah hilang dia berhenti dan melaksanakan shalat Maghrib dan 'Isya' dengan dijama' (menggabungkan keduanya), kemudian dia berkata: \"Aku melihat Nabi shallallahu 'alaihi wasallam apabila perjalanannya sedang berat dan tergesa-gesa Beliau mengakhirkan shalat Maghrib lalu menggabungkannya dengan keduanya (dengan shalat 'Isya') \"."},"1679":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاحِينَ خَرَجَ إِلَى مَكَّةَ مُعْتَمِرًا فِي الْفِتْنَةِ قَالَ إِنْ صُدِدْتُ عَنْ الْبَيْتِ صَنَعْتُ كَمَا صَنَعْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَهَلَّ بِعُمْرَةٍ مِنْ أَجْلِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ أَهَلَّ بِعُمْرَةٍ عَامَ الْحُدَيْبِيَةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] bahwa ['Abdullah bin 'Umar radliallahu 'anhu] ketika berangkat menuju Makkah untuk menunaikan 'umrah pada zaman timbulnya fitnah (kekacauan) dia berkata: \"Jika aku dihalangi dari (ber'ibadah) di Baitullah, maka aku akan melaksanakan 'ibadah 'umrah ini sebagaimana kami pernah melaksanakannya bersama Rasulullah shallallahu 'alaihi wasallam\". Maka dia berihram untuk 'umrahnya dengan mencontoh Rasulullah shallallahu 'alaihi wasallam yang pernah berihram untuk 'umrah pada tahun perjanjian Hudaibiyah."},"1680":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ وَسَالِمَ بْنَ عَبْدِ اللَّهِ أَخْبَرَاهُ أَنَّهُمَا كَلَّمَا عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَالَيَالِيَ نَزَلَ الْجَيْشُ بِابْنِ الزُّبَيْرِ فَقَالَا لَا يَضُرُّكَ أَنْ لَا تَحُجَّ الْعَامَ وَإِنَّا نَخَافُ أَنْ يُحَالَ بَيْنَكَ وَبَيْنَ الْبَيْتِ فَقَالَ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَالَ كُفَّارُ قُرَيْشٍ دُونَ الْبَيْتِ فَنَحَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَدْيَهُ وَحَلَقَ رَأْسَهُ وَأُشْهِدُكُمْ أَنِّي قَدْ أَوْجَبْتُ الْعُمْرَةَ إِنْ شَاءَ اللَّهُ أَنْطَلِقُ فَإِنْ خُلِّيَ بَيْنِي وَبَيْنَ الْبَيْتِ طُفْتُ وَإِنْ حِيلَ بَيْنِي وَبَيْنَهُ فَعَلْتُ كَمَا فَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا مَعَهُ فَأَهَلَّ بِالْعُمْرَةِ مِنْ ذِي الْحُلَيْفَةِ ثُمَّ سَارَ سَاعَةً ثُمَّ قَالَ إِنَّمَا شَأْنُهُمَا وَاحِدٌ أُشْهِدُكُمْ أَنِّي قَدْ أَوْجَبْتُ حَجَّةً مَعَ عُمْرَتِي فَلَمْ يَحِلَّ مِنْهُمَا حَتَّى حَلَّ يَوْمَ النَّحْرِ وَأَهْدَى وَكَانَ يَقُولُ لَا يَحِلُّ حَتَّى يَطُوفَ طَوَافًا وَاحِدًا يَوْمَ يَدْخُلُ مَكَّةَحَدَّثَنِي مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ أَنَّ بَعْضَ بَنِي عَبْدِ اللَّهِ قَالَ لَهُ لَوْ أَقَمْتَ بِهَذَا","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad bin Asma'] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] bahwa ['Ubaidullah bin 'Abdullah] dan [Salim bin 'Abdullah] keduanya mengabarkan kepadanya bahwa keduanya pernah berbicara dengan ['Abdullah bin 'Umar radliallahu 'anhu] pada suatu malam saat datangnya pasukan Ibnu Az Zubair. Keduanya berkata: \"Tidak memberikan madharat kepadamu seandainya kamu tidak menunaikan haji pada tahun ini karena kami khawatir akan terjadi penghalangan buatmu menuju Baitullah\". Maka 'Abdullah bin 'Umar radliallahu 'anhu berkata: \"Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam lalu Kafir Quraisy menghalangi kami dari Baitullah. Kemudian Nabi shallallahu 'alaihi wasallam menyembelih hewan qurban dan mencukur rambut Beliau. Dan aku bersaksi kepada kalian bahwa aku telah mewajibkan (berniat untuk) 'umrah ini, dan insya Allah aku akan berangkat. Jika aku diberi kebebasan, aku akan laksanakan thawaf di Baitullah, namun bila aku dihalangi, aku akan melaksanakan sebagaimana Nabi shallallahu 'alaihi wasallam pernah melaksanakannya yang saat itu aku bersama Beliau yang berihram untuk 'umrah dari Dzul Hulaifah kemudian berjalan sesaat lalu berkata: \"Sesungguhnya pelaksanaan haji dan 'umrah satu. Dan aku bersaksi kepada kalian bahwa aku telah mewajibkan diriku untuk berihram haji bersama 'umrahku\". Dan Beliau tidak bertahallul dari keduanya hingga Beliau bertahallul pada hari Nahar sesaat setelah menyembelih hewan qurban\". Dan dia 'Abdullah bin 'Umar radliallahu 'anhu berkata: \"Beliau tidak bertahallul ketika menyelesaikan thawaf yang satu pada hari memasuki Makkah\". Telah menceritakan kepada saya [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah] dari [Nafi']; Bahwa ada [sebagian dari anak-anak 'Abdullah] berkata, kepadanya: \"Seandainya kamu menunaikan ini.\""},"1681":{"ar":"حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ صَالِحٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عِكْرِمَةَ قَالَ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاقَدْ أُحْصِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَلَقَ رَأْسَهُ وَجَامَعَ نِسَاءَهُ وَنَحَرَ هَدْيَهُ حَتَّى اعْتَمَرَ عَامًا قَابِلًا","id":"Telah menceritakan kepada kami [Muhammad] berkata, telah menceritakan kepada kami [Yahya bin Shalih] telah menceritakan kepada kami [Mu'awiyah bin Salam] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari ['Ikrimah] berkata, [Ibnu 'Abbas radliallahu 'anhuma] berkata: Rasulullah Shallallahu'alaihi shallallahu 'alaihi wasallam pernah terhalang melaksanakan haji, maka Beliau mencukur rambut Beliau, mendatangi isterinya dan menyembelih hewan korban. Beliau baru ber'umrah pada tahun berikutnya."},"1682":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَالِمٌ قَالَ كَانَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُأَلَيْسَ حَسْبُكُمْ سُنَّةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ حُبِسَ أَحَدُكُمْ عَنْ الْحَجِّ طَافَ بِالْبَيْتِ وَبِالصَّفَا وَالْمَرْوَةِ ثُمَّ حَلَّ مِنْ كُلِّ شَيْءٍ حَتَّى يَحُجَّ عَامًا قَابِلًا فَيُهْدِي أَوْ يَصُومُ إِنْ لَمْ يَجِدْ هَدْيًاوَعَنْ عَبْدِ اللَّهِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَالِمٌ عَنْ ابْنِ عُمَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Ahmad bin Muhammad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yunus] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Salim] berkata; [Ibnu'Umar radliallahu 'anhuma] berkata: \"Tidak cukupkah bagi kalian sunnah Rasulullah shallallahu 'alaihi wasallam apabila seorang dari kalian terhalang melaksanakan haji, maka hendaklah dia thawaf di Ka'bah Baitullah lalu sa'iy antara bukit Shafaa dan Marwah kemudian bertahallul dari segala sesuatu hingga dia melaksanakan hajinya pada tahun berikutnya, dan dia menyembelih hewan qurban atau shaum jika tidak membawa hewan qurban?\". Dan dari ['Abdullah] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] berkata, telah menceritakan kepada saya [Salim] dari [Ibnu'Umar radliallahu 'anhuma] seperti hadits ini\"."},"1683":{"ar":"حَدَّثَنَا مَحْمُودٌ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ الْمِسْوَرِ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحَرَ قَبْلَ أَنْ يَحْلِقَ وَأَمَرَ أَصْحَابَهُ بِذَلِكَ","id":"Telah menceritakan kepada kami [Mahmud] telah menceritakan kepada kami ['Abdur Razzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] dari ['Urwah] dari [Al Miswar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam menyembelih hewan qurban sebelum mencukur rambut lalu memerintahkan para sahabat Beliau melakukan hal yang sama."},"1684":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ أَخْبَرَنَا أَبُو بَدْرٍ شُجَاعُ بْنُ الْوَلِيدِ عَنْ عُمَرَ بْنِ مُحَمَّدٍ الْعُمَرِيِّ قَالَ وَحَدَّثَ نَافِعٌ أَنَّعَبْدَ اللَّهِ وَسَالِمًا كَلَّمَا عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَ خَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُعْتَمِرِينَ فَحَالَ كُفَّارُ قُرَيْشٍ دُونَ الْبَيْتِ فَنَحَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُدْنَهُ وَحَلَقَ رَأْسَهُ","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdurrahim] telah mengabarkan kepada kami [Abu Badar Suja'] dari ['Umar bin Muhammad Al 'Umariy] berkata; dan [Nafi'] telah menceritakan bahwa 'Abdullah dan Salim keduanya berbicara kepada ['Abdullah bin 'Umar radliallahu 'anhuma], maka dia ('Abdullah bin 'Umar radliallahu 'anhu) berkata: \"Kami pernah keluar bersama Nabi shallallahu 'alaihi wasallam untuk melaksanakan 'umrah lalu orang-orang Kafir Quraisy menghalangi kami dari Baitullah. Maka Rasulullah shallallahu 'alaihi wasallam menyembelih hewan sembelihannya lalu mencukur rambut Beliau\". "},"1685":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَحِينَ خَرَجَ إِلَى مَكَّةَ مُعْتَمِرًا فِي الْفِتْنَةِ إِنْ صُدِدْتُ عَنْ الْبَيْتِ صَنَعْنَا كَمَا صَنَعْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَهَلَّ بِعُمْرَةٍ مِنْ أَجْلِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ أَهَلَّ بِعُمْرَةٍ عَامَ الْحُدَيْبِيَةِ ثُمَّ إِنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ نَظَرَ فِي أَمْرِهِ فَقَالَ مَا أَمْرُهُمَا إِلَّا وَاحِدٌ فَالْتَفَتَ إِلَى أَصْحَابِهِ فَقَالَ مَا أَمْرُهُمَا إِلَّا وَاحِدٌ أُشْهِدُكُمْ أَنِّي قَدْ أَوْجَبْتُ الْحَجَّ مَعَ الْعُمْرَةِ ثُمَّ طَافَ لَهُمَا طَوَافًا وَاحِدًا وَرَأَى أَنَّ ذَلِكَ مُجْزِيًا عَنْهُ وَأَهْدَى","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Malik] dari [Nafi'] bahwa ['Abdullah bin 'Umar radliallahu 'anhu] berkata, ketika dia hendak berangkat melaksanakan 'umrah saat terjadinya fitnah: Jika aku dihalang-halangi dari Baitullah, kami akan melakukan seperti yang dilakukan Rasulullah shallallahu 'alaihi wasallam, yaitu aku akan berihram untuk 'umrah karena Nabi shallallahu 'alaihi wasallam pernah berihram untuk 'umrah pada tahun perjanjian Hudaibiyah\" Kemudian 'Abdullah bin 'Umar radliallahu 'anhu memandang bahwa urusan keduanya (haji dan 'umrah) tidak lain kecuali satu. Lalu dia mendatangi para shahabatnya seraya berkata: \"Aku bersaksi kepada kalian bahwa aku telah meniatkan hajiku ini bersama 'umrah\". Maka dia thawaf untuk keduanya (haji dan 'umrah) dengan satu thawaf dan memandang bahwa hal itu sudah memadai lalu dia berqurban."},"1686":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ حُمَيْدِ بْنِ قَيْسٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَعَلَّكَ آذَاكَ هَوَامُّكَ قَالَ نَعَمْ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْلِقْ رَأْسَكَ وَصُمْ ثَلَاثَةَ أَيَّامٍ أَوْ أَطْعِمْ سِتَّةَ مَسَاكِينَ أَوْ انْسُكْ بِشَاةٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Humaid bin Qais] dari [Mujahid] dari ['Abdurrahman bin Abu Laila] dari [Ka'ab bin 'Ujrah radliallahu 'anhu] dari Rasulullah shallallahu 'alaihi wasallam bahwa Beliau berkata: \"Barangkali kamu terkena serangga (kutu di kepala)?\". Dia menjawab: \"Benar, wahai Rasulullah\". Maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Cukurlah rambutmu, lalu shaum tiga hari atau berilah makan enam orang miskin atau berqurban dengan seekor kambing\". "},"1687":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سَيْفٌ قَالَ حَدَّثَنِي مُجَاهِدٌ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى أَنَّ كَعْبَ بْنَ عُجْرَةَ حَدَّثَهُ قَالَوَقَفَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحُدَيْبِيَةِ وَرَأْسِي يَتَهَافَتُ قَمْلًا فَقَالَ يُؤْذِيكَ هَوَامُّكَ قُلْتُ نَعَمْ قَالَ فَاحْلِقْ رَأْسَكَ أَوْ قَالَ احْلِقْ قَالَ فِيَّ نَزَلَتْ هَذِهِ الْآيَةُ{ فَمَنْ كَانَ مِنْكُمْ مَرِيضًا أَوْ بِهِ أَذًى مِنْ رَأْسِهِ }إِلَى آخِرِهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُمْ ثَلَاثَةَ أَيَّامٍ أَوْ تَصَدَّقْ بِفَرَقٍ بَيْنَ سِتَّةٍ أَوْ انْسُكْ بِمَا تَيَسَّرَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sayf] berkata, telah menceritakan kepada saya [Mujahid] berkata, aku mendengar ['Abdurrahman bin Abu Laila] bahwa [Ka'ab bin 'Ujrah radliallahu 'anhu] berkata: \"Rasulullah shallallahu 'alaihi wasallam menghampiriku di Hudaibiyah ketika kepalaku dipenuhi kutu, Beliau berkata: \"Barangkali kamu terkena serangga (kutu di kepala)?\". Aku jawab: \"Benar, wahai Rasulullah\". Maka Beliau berkata: \"Cukurlah rambutnu\". Atau dia berkata: \"Ayat ini turun untukku\" (QS Al Baqarah ayat 196 yang artinya): (\"....Maka barangsiapa dari kalian yang sakit atau tertimpa sesuatu pada kepalanya...) hingga akhir ayat. Maka Nabi shallallahu 'alaihi wasallam berkata: \"Laksanakanlah shaum tiga hari atau bershadaqah sebanyak faraq (tiga sha') terhadap enam orang atau berqurban dengan yang mudah buatmu\". "},"1688":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصْبَهَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلٍ قَالَ جَلَسْتُ إِلَى كَعْبِ بْنِ عُجْرَةَ رَضِيَ اللَّهُ عَنْهُفَسَأَلْتُهُ عَنْ الْفِدْيَةِ فَقَالَ نَزَلَتْ فِيَّ خَاصَّةً وَهِيَ لَكُمْ عَامَّةً حُمِلْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْقَمْلُ يَتَنَاثَرُ عَلَى وَجْهِي فَقَالَ مَا كُنْتُ أُرَى الْوَجَعَ بَلَغَ بِكَ مَا أَرَى أَوْ مَا كُنْتُ أُرَى الْجَهْدَ بَلَغَ بِكَ مَا أَرَى تَجِدُ شَاةً فَقُلْتُ لَا فَقَالَ فَصُمْ ثَلَاثَةَ أَيَّامٍ أَوْ أَطْعِمْ سِتَّةَ مَسَاكِينَ لِكُلِّ مِسْكِينٍ نِصْفَ صَاعٍ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari ['Abdurrahman bin Al Ashbahaniy] dari ['Abdullah bin Aku mendengar 'qil] berkata; 'Aku duduk dekat dengan [Ka'ab bin 'Ujrah radliallahu 'anhu] lalu aku bertanya kepadanya tentang fidyah, maka dia menawab: \"Ayat itu turun untukku secara khusus dan buat kalian secara umum, yaitu aku pernah dibawa kepada Rasulullah shallallahu 'alaihi wasallam sementara wajahku banyak dipenuhi kutu, maka Beliau berkata: \"Mengapa aku melihat kamu dalam keadaan sakit sedemikian parah yang belum pernah aku lihat sebelumnya? dan mengapa aku melihat kamu dalam keadaan kepayahan sedemikian memuncak yang belum pernah aku lihat sebelumnya? apakah kamu memiliki kambing?\". Aku jawab: \"Benar\". Maka Beliau berkata: \"Laksanakanlah shaum tiga hari atau berilah makan enam orang miskin yang untuk setiap satu orang miskin sebanyak setengah sha'\"."},"1689":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا رَوْحٌ حَدَّثَنَا شِبْلٌ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَآهُ وَأَنَّهُ يَسْقُطُ عَلَى وَجْهِهِ فَقَالَ أَيُؤْذِيكَ هَوَامُّكَ قَالَ نَعَمْ فَأَمَرَهُ أَنْ يَحْلِقَ وَهُوَ بِالْحُدَيْبِيَةِ وَلَمْ يَتَبَيَّنْ لَهُمْ أَنَّهُمْ يَحِلُّونَ بِهَا وَهُمْ عَلَى طَمَعٍ أَنْ يَدْخُلُوا مَكَّةَ فَأَنْزَلَ اللَّهُ الْفِدْيَةَ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُطْعِمَ فَرَقًا بَيْنَ سِتَّةٍ أَوْ يُهْدِيَ شَاةً أَوْ يَصُومَ ثَلَاثَةَ أَيَّامٍوَعَنْ مُحَمَّدِ بْنِ يُوسُفَ حَدَّثَنَا وَرْقَاءُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ مُجَاهِدٍ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَآهُ وَقَمْلُهُ يَسْقُطُ عَلَى وَجْهِهِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Rauh] telah menceritakan kepada saya [Syibil] dari [Ibnu Abu Najih] dari [Mujahid] berkata, telah menceritakan kepada saya ['Abdurrahman bin Abu Laila] dari [Ka'ab bin 'Ujrah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam melihatnya sedang pada wajahnya banyak berjatuhan serangga. Beliau bertanya: \"Barangkali kamu terkena serangga (kutu di kepala)?\". Dia menjawab: \"Benar\". Maka Beliau memerintahkannya agar mencukur rambutnya. Saat itu Beliau sedang berada di Hudaibiyah dan belum menjelaskan kepada mereka bahwa mereka harus bertahallul disana sedangkan Beliau sangat ingin agar mereka dapat memasuki Makkah. Maka Allah menurunkan ayat tentang fidyah. Maka Rasulullah shallallahu 'alaihi wasallam memerintahkannya agar bershadaqah sebanyak faraq (tiga sha') atau berqurban dengan seekor kambing atau shaum tiga hari. Dan dari [Muhammad bin Yusuf] telah menceritakan kepada kami [Warqa'] dari [Ibnu Abu Najih] dari [Mujahid] telah mengabarkan kepada kami ['Abdurrahman bin Abu Laila] dari [Ka'ab bin 'Ujrah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam melihatnya (Ka'ab bin 'Ujrah radliallahu 'anhu) dalam keadaan wajahnya dipenuhi kutu yang berjatuhan, dan terus seperti diatas."},"1690":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ سَمِعْتُ أَبَا حَازِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَجَّ هَذَا الْبَيْتَ فَلَمْ يَرْفُثْ وَلَمْ يَفْسُقْ رَجَعَ كَمَا وَلَدَتْهُ أُمُّهُ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Manshur] aku mendengar [Abu Hazim] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menunaikan haji di Baitullah ini kemudian tidak berkata, -kata kotor dan tidak berbuat fasiq maka bila dia kembali keadaannya seperti saat dilahirkan oleh ibunya\". "},"1691":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَجَّ هَذَا الْبَيْتَ فَلَمْ يَرْفُثْ وَلَمْ يَفْسُقْ رَجَعَ كَيَوْمِ وَلَدَتْهُ أُمُّهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Abu Hazim] dari [Abu Hurairah radliallahu 'anhu] berkata, Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menunaikan haji di Baitullah ini kemudian tidak berkata-kata kotor dan tidak berbuat fasiq maka bila dia kembali keadaannya seperti saat dilahirkan oleh ibunya\"."},"1692":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ قَالَانْطَلَقَ أَبِي عَامَ الْحُدَيْبِيَةِ فَأَحْرَمَ أَصْحَابُهُ وَلَمْ يُحْرِمْ وَحُدِّثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ عَدُوًّا يَغْزُوهُ فَانْطَلَقَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَيْنَمَا أَنَا مَعَ أَصْحَابِهِ تَضَحَّكَ بَعْضُهُمْ إِلَى بَعْضٍ فَنَظَرْتُ فَإِذَا أَنَا بِحِمَارِ وَحْشٍ فَحَمَلْتُ عَلَيْهِ فَطَعَنْتُهُ فَأَثْبَتُّهُ وَاسْتَعَنْتُ بِهِمْ فَأَبَوْا أَنْ يُعِينُونِي فَأَكَلْنَا مِنْ لَحْمِهِ وَخَشِينَا أَنْ نُقْتَطَعَ فَطَلَبْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْفَعُ فَرَسِي شَأْوًا وَأَسِيرُ شَأْوًا فَلَقِيتُ رَجُلًا مِنْ بَنِي غِفَارٍ فِي جَوْفِ اللَّيْلِ قُلْتُ أَيْنَ تَرَكْتَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَرَكْتُهُ بِتَعْهَنَ وَهُوَ قَائِلٌ السُّقْيَا فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَهْلَكَ يَقْرَءُونَ عَلَيْكَ السَّلَامَ وَرَحْمَةَ اللَّهِ إِنَّهُمْ قَدْ خَشُوا أَنْ يُقْتَطَعُوا دُونَكَ فَانْتَظِرْهُمْ قُلْتُ يَا رَسُولَ اللَّهِ أَصَبْتُ حِمَارَ وَحْشٍ وَعِنْدِي مِنْهُ فَاضِلَةٌ فَقَالَ لِلْقَوْمِ كُلُوا وَهُمْ مُحْرِمُونَ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari ['Abdullah bin Abu Qatadah] berkata; [Bapakku] berangkat pada tahun Perjanjian Hudaibiyah lalu para sahabat (Nabi shallallahu 'alaihi wasallam) berihram sedangkan dia tidak. Lalu Nabi shallallahu 'alaihi wasallam mendapatkan berita bahwa para musuh akan menyerang Beliau, maka Nabi shallallahu 'alaihi wasallam berangkat. Dan ketika aku bersama para sahabat Beliau yang sedang tertawa saling bercengkerama satu sama lain, aku melihat ada seekor keledai liar. Keledai itu aku ikuti kemudian aku tikam dan aku ikat sehingga tidak bergerak lagi. Aku meminta bantuan mereka namun mereka enggan untuk membantuku. Lalu kami memakan dagingnya namun kami khawatir ada musuh. Maka aku mencari Nabi shallallahu 'alaihi wasallam dengan terkadang memacu lari kudaku dan terkadang aku memperlambatnya. Kemudian aku berjumpa dengan seseorang dari Bani Ghifar pada tengah malam lalu aku bertanya kepadanya: \"Dimana kamu meninggalkan Nabi shallallahu 'alaihi wasallam?\". Dia berkata: \"Aku meninggalkan Beliau di daerah Ta'hin yang Beliau beristirahat siangnya di Suqya\". (Setelah bertemu), aku berkata: \"Wahai Rasulullah, keluarga (para sahabat) baginda menyampaikan salam dan rahmat Allah buat baginda. Mereka sedang khawatir menghadapi musuh tanpa mendampingi baginda, maka tunggulah mereka\". Aku katakan pula kepada Beliau: \"Wahai Rasulullah, aku telah berburu keledai liar dan aku masih menyisakan dagingnya\". Maka Beliau berkata, untuk mereka: \"Makanlah\". Padahal saat itu mereka sedang berihram."},"1693":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ أَنَّ أَبَاهُ حَدَّثَهُ قَالَانْطَلَقْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْحُدَيْبِيَةِ فَأَحْرَمَ أَصْحَابُهُ وَلَمْ أُحْرِمْ فَأُنْبِئْنَا بِعَدُوٍّ بِغَيْقَةَ فَتَوَجَّهْنَا نَحْوَهُمْ فَبَصُرَ أَصْحَابِي بِحِمَارِ وَحْشٍ فَجَعَلَ بَعْضُهُمْ يَضْحَكُ إِلَى بَعْضٍ فَنَظَرْتُ فَرَأَيْتُهُ فَحَمَلْتُ عَلَيْهِ الْفَرَسَ فَطَعَنْتُهُ فَأَثْبَتُّهُ فَاسْتَعَنْتُهُمْ فَأَبَوْا أَنْ يُعِينُونِي فَأَكَلْنَا مِنْهُ ثُمَّ لَحِقْتُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَشِينَا أَنْ نُقْتَطَعَ أَرْفَعُ فَرَسِي شَأْوًا وَأَسِيرُ عَلَيْهِ شَأْوًا فَلَقِيتُ رَجُلًا مِنْ بَنِي غِفَارٍ فِي جَوْفِ اللَّيْلِ فَقُلْتُ أَيْنَ تَرَكْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تَرَكْتُهُ بِتَعْهَنَ وَهُوَ قَائِلٌ السُّقْيَا فَلَحِقْتُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَتَيْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَصْحَابَكَ أَرْسَلُوا يَقْرَءُونَ عَلَيْكَ السَّلَامَ وَرَحْمَةَ اللَّهِ وَبَرَكَاتِهِ وَإِنَّهُمْ قَدْ خَشُوا أَنْ يَقْتَطِعَهُمْ الْعَدُوُّ دُونَكَ فَانْظُرْهُمْ فَفَعَلَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا اصَّدْنَا حِمَارَ وَحْشٍ وَإِنَّ عِنْدَنَا فَاضِلَةً فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ كُلُوا وَهُمْ مُحْرِمُونَ","id":"Telah menceritakan kepada kami [Sa'id bin Ar-Rabi'] telah menceritakan kepada kami ['Ali bin Al Mubarak] dari [Yahya] dari ['Abdullah bin Abu Qatadah] bahwa [bapaknya] menceritakan kepadanya, katanya: Kami berangkat bersama Nabi shallallahu 'alaihi wasallam pada tahun Perjanjian Hudaibiyah lalu para sahabat berihram sedangkan aku tidak. Lalu kami mendapatkan berita bahwa para musuh sudah berada di Ghoiqah. Kami berangkat menghadapi mereka. Dalam perjalanan para sahabatku melihat ada seekor keledai liar yang menjadikan mereka tertawa satu sama lain. Maka aku intai lalu aku ikuti dengan kudaku lalu aku tikam dan ikat sehingga tidak bergerak lagi. Aku meminta bantuan kepada mereka namun mereka enggan untuk membantuku. Lalu kami memakan dagingnya. Kemudian aku berusaha menyusul Rasulullah shallallahu 'alaihi wasallam karena kami khawatir ada musuh. Maka aku terkadang memacu lari kudaku dan terkadang aku memperlambatnya. Kemudian aku berjumpa dengan seseorang dari Bani Ghifar pada tengah malam lalu aku bertanya kepadanya: \"Dimana kamu meninggalkan Nabi Rasulullah shallallahu 'alaihi wasallam?\". Dia berkata: \"Tadi aku meninggalkan Beliau di daerah Ta'han yang Beliau beristirahat siangnya di Suqya\". Akhirnya aku berjumpa dengan Rasulullah shallallahu 'alaihi wasallam hingga aku hampiri, lalu aku berkata: \"Wahai Rasulullah, para sahabat baginda menyampaikan salam dan rahmat serta barakah Allah buat baginda. Mereka sedang khawatir menghadapi musuh tanpa mendampingi baginda, maka tunggulah mereka\". Maka Beliau menunggu mereka. Aku katakan pula kepada Beliau: \"Wahai Rasulullah, kami telah berburu keledai liar dan kami masih menyisakan dagingnya\". Maka Rasulullah shallallahu 'alaihi wasallam berkata, kepada para sahabat Beliau: \"Makanlah\". Sedang saat itu mereka sedang berihram."},"1694":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا صَالِحُ بْنُ كَيْسَانَ عَنْ أَبِي مُحَمَّدٍ نَافِعٍ مَوْلَى أَبِي قَتَادَةَ سَمِعَ أَبَا قَتَادَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْقَاحَةِ مِنْ الْمَدِينَةِ عَلَى ثَلَاثٍ ح و حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا صَالِحُ بْنُ كَيْسَانَ عَنْ أَبِي مُحَمَّدٍ عَنْ أَبِي قَتَادَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْقَاحَةِ وَمِنَّا الْمُحْرِمُ وَمِنَّا غَيْرُ الْمُحْرِمِ فَرَأَيْتُ أَصْحَابِي يَتَرَاءَوْنَ شَيْئًا فَنَظَرْتُ فَإِذَا حِمَارُ وَحْشٍ يَعْنِي وَقَعَ سَوْطُهُ فَقَالُوا لَا نُعِينُكَ عَلَيْهِ بِشَيْءٍ إِنَّا مُحْرِمُونَ فَتَنَاوَلْتُهُ فَأَخَذْتُهُ ثُمَّ أَتَيْتُ الْحِمَارَ مِنْ وَرَاءِ أَكَمَةٍ فَعَقَرْتُهُ فَأَتَيْتُ بِهِ أَصْحَابِي فَقَالَ بَعْضُهُمْ كُلُوا وَقَالَ بَعْضُهُمْ لَا تَأْكُلُوا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ أَمَامَنَا فَسَأَلْتُهُ فَقَالَ كُلُوهُ حَلَالٌقَالَ لَنَا عَمْرٌو اذْهَبُوا إِلَى صَالِحٍ فَسَلُوهُ عَنْ هَذَا وَغَيْرِهِ وَقَدِمَ عَلَيْنَا هَا","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Shalih bin Kaisan] dari [Abu Nuhammad Nafi'] maulanya Abu Qatadah dia mendengar [Abu Qatadah radliallahu 'anhu] berkata: \"Kami berangkat bersama Nabi shallallahu 'alaihi wasallam dan tiba di Qahah yang jaraknya tiga hari perjalanan dari Madinah\". Dan diriwayatkan pula, telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Shalih bin Kaisan] dari [Abu Muhammad] dari [Abu Qatadah radliallahu 'anhu] berkata: \": \"Kami berangkat bersama Nabi shallallahu 'alaihi wasallam dan tiba di Qahah. Diantara kami ada yang berihram dan ada pula yang tidak. Aku melihat para sahabatku sedang memperhatikan sesuatu. Maka aku ikut memperhatikannya yang ternyata seekor keledai liar yang sudah terkena cambuk. Mereka berkata: \"Kami tidak akan membantumu untuk mendapatkannya karena kami sedang berihram. Maka aku berusaha menangkapnya lalu berhasil, kemudian aku bawa keledai tersebut dari balik bukit kecil lalu aku menyembelihnya. Kemudian aku datang menemui para sahabat membawa dagingnya. Diantara mereka ada yang berkata: \"Makanlah\". Dan sebagian yang lain mengatakan: \"Jangan kalian makan\". Maka aku menemui Nabi shallallahu 'alaihi wasallam sedang saat itu Beliau berada di depan kami, lalu aku bertanya tentang masalah itu, maka Beliau berkata: \"Makanlah daging itu karena dia halal\". Maka kemudian 'Amru berkata, kepada kami: \"Pergilah dan temui Shalih lalu tanyakan kepadanya tentang masalah ini dan masalah lainnya. Maka Shalih menemui kami lalu berkata, \" Bawalah kemari\"."},"1695":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا عُثْمَانُ هُوَ ابْنُ مَوْهَبٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَبِي قَتَادَةَ أَنَّ أَبَاهُ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ حَاجًّا فَخَرَجُوا مَعَهُ فَصَرَفَ طَائِفَةً مِنْهُمْ فِيهِمْ أَبُو قَتَادَةَ فَقَالَ خُذُوا سَاحِلَ الْبَحْرِ حَتَّى نَلْتَقِيَ فَأَخَذُوا سَاحِلَ الْبَحْرِ فَلَمَّا انْصَرَفُوا أَحْرَمُوا كُلُّهُمْ إِلَّا أَبُو قَتَادَةَ لَمْ يُحْرِمْ فَبَيْنَمَا هُمْ يَسِيرُونَ إِذْ رَأَوْا حُمُرَ وَحْشٍ فَحَمَلَ أَبُو قَتَادَةَ عَلَى الْحُمُرِ فَعَقَرَ مِنْهَا أَتَانًا فَنَزَلُوا فَأَكَلُوا مِنْ لَحْمِهَا وَقَالُوا أَنَأْكُلُ لَحْمَ صَيْدٍ وَنَحْنُ مُحْرِمُونَ فَحَمَلْنَا مَا بَقِيَ مِنْ لَحْمِ الْأَتَانِ فَلَمَّا أَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا يَا رَسُولَ اللَّهِ إِنَّا كُنَّا أَحْرَمْنَا وَقَدْ كَانَ أَبُو قَتَادَةَ لَمْ يُحْرِمْ فَرَأَيْنَا حُمُرَ وَحْشٍ فَحَمَلَ عَلَيْهَا أَبُو قَتَادَةَ فَعَقَرَ مِنْهَا أَتَانًا فَنَزَلْنَا فَأَكَلْنَا مِنْ لَحْمِهَا ثُمَّ قُلْنَا أَنَأْكُلُ لَحْمَ صَيْدٍ وَنَحْنُ مُحْرِمُونَ فَحَمَلْنَا مَا بَقِيَ مِنْ لَحْمِهَا قَالَ أَمِنْكُمْ أَحَدٌ أَمَرَهُ أَنْ يَحْمِلَ عَلَيْهَا أَوْ أَشَارَ إِلَيْهَا قَالُوا لَا قَالَ فَكُلُوا مَا بَقِيَ مِنْ لَحْمِهَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] telah menceritakan kepada kami ['Utsman, dia adalah putra Mawhab] berkata, telah mengabarkan kepada saya ['Abdullah bin Abu Qatadah] bahwa [Abu Qatadah] mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersama mereka (para sahabat) berangkat untuk menunaikan haji. Lalu sebagian rambongan ada yang berpisah, diantaranya adalah Abu Qatadah radliallahu 'anhu. Beliau berkata, kepada rombongan ini: \"Ambillah jalan menyusuri tepi pantai hingga kita bertemu\". Maka mereka mengambil jalan di tepian pantai. Ketika mereka hendak berangkat, semua anggota rambongan itu berihram kecuali Abu Qatadah. Ketika mereka sedang berjalan, mereka melihat ada seeokor keledai liar. Maka Abu Qatadah menghampiri keledai itu lalu menyembelihnya yang sebagian dagingnya dibawa ke hadapan kami. Maka mereka berhenti lalu memakan daging keledai tersebut. Sebagian dari mereka ada yang berkata: \"Apakah kita boleh memakan daging hewan buruan padahal kita sedang berihram?\". Maka kami bawa sisa daging tersebut. Ketika mereka berjumpa dengan Rasulullah shallallahu 'alaihi wasallam, mereka berkata: \"Wahai Rasulullah, kami sedang berihram sedangkan Abu Qatadah tidak. Lalu kami melihat ada keledai-keledai liar kemudian Abu Qatadah menangkapnya lalu menyembelihnya kemudian sebagian dagingnya dibawa kepada kami, lalu kami berhenti dan memakan dari daging tersebut kemudian diantara kami ada yang berkata: \"Apakah kita boleh memakan daging hewan buruan padahal kita sedang berihram?\". Lalu kami bawa sisa dagingnya itu kemari\". Beliau bertanya: \"Apakah ada seseorang diantara kalian yang sedang berihram menyuruh Abu Qatadah untuk memburunya atau memberi isyarat kepadanya?\". Mereka menjawab: \"Tidak ada\". Maka Beliau bersabda: \"Makanlah sisa daging yang ada itu\". "},"1696":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ الصَّعْبِ بْنِ جَثَّامَةَ اللَّيْثِيِّأَنَّهُ أَهْدَى لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِمَارًا وَحْشِيًّا وَهُوَ بِالْأَبْوَاءِ أَوْ بِوَدَّانَ فَرَدَّهُ عَلَيْهِ فَلَمَّا رَأَى مَا فِي وَجْهِهِ قَالَ إِنَّا لَمْ نَرُدَّهُ عَلَيْكَ إِلَّا أَنَّا حُرُمٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Uqbah bin Mas'ud] dari ['Abdullah bin 'Abbas] dari [Ash-Sha'bi bin Jatstsamah Al Laitsiy] bahwa dia (Ash-Sha'bi) memberi hadiah kepada Rasulullah shallallahu 'alaihi wasallam berupa seekor keledai yang liar saat beliau berada di Abwa' atau di Waddan. Lalu Beliau mengembalikan hadiah itu kepadanya. Ketika Beliau melihat apa yang ada di wajahnya, Beliau berkata: \"Kami tidak bermaksud menolak hadiah darimu, namun ini tidak lain karena aku sedang berihram\"."},"1697":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَمْسٌ مِنْ الدَّوَابِّ لَيْسَ عَلَى الْمُحْرِمِ فِي قَتْلِهِنَّ جُنَاحٌوَعَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ زَيْدِ بْنِ جُبَيْرٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُ حَدَّثَتْنِي إِحْدَى نِسْوَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْتُلُ الْمُحْرِمُ حَدَّثَنَا أَصْبَغُ بْنُ الْفَرَجِ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَتْ حَفْصَةُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسٌ مِنْ الدَّوَابِّ لَا حَرَجَ عَلَى مَنْ قَتَلَهُنَّ الْغُرَابُ وَالْحِدَأَةُ وَالْفَأْرَةُ وَالْعَقْرَبُ وَالْكَلْبُ الْعَقُورُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada lima jenis hewan yang tidak berdosa bagi orang yang sedang berihram untuk membunuhnya\". Dan dari ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam telah bersabda, telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Abu 'Awanah] dari [Zaid bin Jubair] berkata,, aku mendengar [Ibnu'Umar radliallahu 'anhuma] berkata; telah menceritakan kepada saya salah seorang isteri Nabi shallallahu 'alaihi wasallam dari Nabi shallallahu 'alaihi wasallam: \"Orang yang sedang ihram membunuh…\". Telah menceritakan kepada kami [Ashbagh bin Al Faraj] berkata, telah mengabarkan kepadaku ['Abdullah bin Wahb] dari [Yunus] dari [Ibnu Syihab] dari [Salim] berkata; ['Abdullah bin 'Umar radliallahu 'anhuma] berkata,, telah berkata, [Hafshah]; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada lima jenis hewan yang seseorang tidak berdosa jika membunuhnya, yaitu: burung gagak, burung rajawali, tikus, kalajengking dan anjing galak\"."},"1698":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَمْسٌ مِنْ الدَّوَابِّ كُلُّهُنَّ فَاسِقٌ يَقْتُلُهُنَّ فِي الْحَرَمِ الْغُرَابُ وَالْحِدَأَةُ وَالْعَقْرَبُ وَالْفَأْرَةُ وَالْكَلْبُ الْعَقُورُ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] berkata, telah menceritakan kepada saya [Ibnu Wahb] berkata, telah menceritakan kepada saya [Yunus] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah radliallahu 'anha] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada lima jenis hewan yang kesemuanya berbahaya sehingga boleh dibunuh saat ihram, yaitu: burung gagak, burung rajawali, tikus, kalajengking dan anjing galak\"."},"1699":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي إِبْرَاهِيمُ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَمَا نَحْنُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَارٍ بِمِنًى إِذْ نَزَلَ عَلَيْهِ وَالْمُرْسَلَاتِ وَإِنَّهُ لَيَتْلُوهَا وَإِنِّي لَأَتَلَقَّاهَا مِنْ فِيهِ وَإِنَّ فَاهُ لَرَطْبٌ بِهَا إِذْ وَثَبَتْ عَلَيْنَا حَيَّةٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْتُلُوهَا فَابْتَدَرْنَاهَا فَذَهَبَتْ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وُقِيَتْ شَرَّكُمْ كَمَا وُقِيتُمْ شَرَّهَا","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepada saya [Ibrahim] dari [Al Aswad] dari ['Abdullah radliallahu 'anhu] berkata: \"Ketika kami sedang bersama Nabi shallallahu 'alaihi wasallam di dalam goa di Mina, wahyu turun kepada Beliau yaitu surat Wal mursalaat. Saat itu Beliau membacakannya, dan aku mengambil hafalan bacaan surah tersebut langsung dari gerak bibir (mulut) Beliau. Ketika mulut Beliau masih basah membacakan surah tersebut tiba-tiba ada seekor ular melompat kepada kami, maka Nabi shallallahu 'alaihi wasallam berkata: \"Bunuhlah ular itu\". Maka kami mengejar ular itu namun ular itu sudah pergi. Maka Nabi shallallahu 'alaihi wasallam berkata: \"Ular itu telah lolos dari kejahatan kalian sebagaimana kalian sudah lolos dari kejahatannya\"."},"1700":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْوَزَغِ فُوَيْسِقٌ وَلَمْ أَسْمَعْهُ أَمَرَ بِقَتْلِهِ قَالَ أَبُو عَبْد اللَّهِ إِنَّمَا أَرَدْنَا بِهَذَا أَنَّ مِنًى مِنْ الْحَرَمِ وَأَنَّهُمْ لَمْ يَرَوْا بِقَتْلِ الْحَيَّةِ بَأْسًا","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Cecak itu kecil bahayanya\". Dan aku tidak mendengar Beliau memerintahkan untuk membunuhnya\". Berkata, Abu 'Abdullah Al Bukhariy: \"Yang kami inginkan dengan keterangan ini adalah bahwa Mina termasuk tanah haram (suci) dan mereka (para shahabat) tidak memandang membunuh ular itu berdosa\"."},"1701":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي شُرَيْحٍ الْعَدَوِيِّأَنَّهُ قَالَ لِعَمْرِو بْنِ سَعِيدٍ وَهُوَ يَبْعَثُ الْبُعُوثَ إِلَى مَكَّةَ ائْذَنْ لِي أَيُّهَا الْأَمِيرُ أُحَدِّثْكَ قَوْلًا قَامَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْغَدِ مِنْ يَوْمِ الْفَتْحِ فَسَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي وَأَبْصَرَتْهُ عَيْنَايَ حِينَ تَكَلَّمَ بِهِ إِنَّهُ حَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ مَكَّةَ حَرَّمَهَا اللَّهُ وَلَمْ يُحَرِّمْهَا النَّاسُ فَلَا يَحِلُّ لِامْرِئٍ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ يَسْفِكَ بِهَا دَمًا وَلَا يَعْضُدَ بِهَا شَجَرَةً فَإِنْ أَحَدٌ تَرَخَّصَ لِقِتَالِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُولُوا لَهُ إِنَّ اللَّهَ أَذِنَ لِرَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَأْذَنْ لَكُمْ وَإِنَّمَا أَذِنَ لِي سَاعَةً مِنْ نَهَارٍ وَقَدْ عَادَتْ حُرْمَتُهَا الْيَوْمَ كَحُرْمَتِهَا بِالْأَمْسِ وَلْيُبَلِّغْ الشَّاهِدُ الْغَائِبَ فَقِيلَ لِأَبِي شُرَيْحٍ مَا قَالَ لَكَ عَمْرٌو قَالَ أَنَا أَعْلَمُ بِذَلِكَ مِنْكَ يَا أَبَا شُرَيْحٍ إِنَّ الْحَرَمَ لَا يُعِيذُ عَاصِيًا وَلَا فَارًّا بِدَمٍ وَلَا فَارًّا بِخُرْبَةٍخُرْبَةٌ بَلِيَّةٌ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada saya [Al Laits] dari [Sa'id bin Abu Sa'id Al Maqburi] dari [Abu Syuraih Al 'Adawiy] bahwa dia berkata, kepada 'Amru bin Sa'id saat dia mengutus rambongan ke Makkah: \"izinkan aku wahai Pemimpin (amir) untuk menyampaikan satu sabda Nabi shallallahu 'alaihi wasallam saat Beliau memberikan khuthbah sehari setelah hari Pembebasan Makkah, aku mendengar dengan telingaku sendiri dan merasakan dengan hatiku sendiri serta melihat dengan mata kepalaku sendiri ketika Beliau shallallahu 'alaihi wasallam mengucapkannya, Beliau memuji Allah dan mensucikannya kemudian bersabda: 'Sesungguhnya Makkah, Allah telah mensucikannya namun orang-orang (Musyrikin Makkah) tidak mensucikannya. Maka tidak halal bagi setiap orang yang beriman kepada Allah dan Hari Akhir menumpahkan darah didalamnya, dan tidak boleh mencabut pepohonan di dalamnya. Kalau sesorang diberikan kebolehan memerangi Rasulullah shallallahu 'alaihi wasallam di dalamnya katakanlah bahwa Allah Ta'ala telah mengizinkan kepada RasulNya dan tidak mengizinkan kepada kalian. Sesungguhnya Dia (Allah Ta'ala) telah mengizinkanku pada suatu masa di siang hari kemudian dikembalikan kesuciannya hari ini sebagaimana disucikannya sebelumnya. Maka hendaklah yang hadir menyampaikan kepada yang tidak hadir\". Ditanyakan kepada Abu Syuraij: \"Apa yang dikatakan 'Amru?\". Katanya: \"Aku lebih mengetahui tentang peristiwa itu daripadamu wahai Abu Syuraij: \"Sesungguhnya di tanah haram ini, Beliau tidak akan melindungi orang yang bermaksiat, orang yang (dihukum karena) menumpahkan darah dan orang yang mencuri\"."},"1702":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ حَرَّمَ مَكَّةَ فَلَمْ تَحِلَّ لِأَحَدٍ قَبْلِي وَلَا تَحِلُّ لِأَحَدٍ بَعْدِي وَإِنَّمَا أُحِلَّتْ لِي سَاعَةً مِنْ نَهَارٍ لَا يُخْتَلَى خَلَاهَا وَلَا يُعْضَدُ شَجَرُهَا وَلَا يُنَفَّرُ صَيْدُهَا وَلَا تُلْتَقَطُ لُقَطَتُهَا إِلَّا لِمُعَرِّفٍ وَقَالَ الْعَبَّاسُ يَا رَسُولَ اللَّهِ إِلَّا الْإِذْخِرَ لِصَاغَتِنَا وَقُبُورِنَا فَقَالَ إِلَّا الْإِذْخِرَوَعَنْ خَالِدٍ عَنْ عِكْرِمَةَ قَالَ هَلْ تَدْرِي مَا لَا يُنَفَّرُ صَيْدُهَا هُوَ أَنْ يُنَحِّيَهُ مِنْ الظِّلِّ يَنْزِلُ مَكَانَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Allah telah mengikrarkan kesucian kota Makkah, maka tidak dihalalkan buat seorang pun sebelum dan tidak dihalalkan pula buat seorangpun susudahku. Sesungguhnya pernah dihalalkan buatku sesaat dalam suatu hari. (Karenanya di Makkah) tidak boleh dipotong rumputnya dan tidak boleh ditebang pohonnya dan tidak boleh diburu hewan buruannya dan tidak ditemukan satupun barang temuan kecuali harus dikembalikan kepada yng mengenalnya (pemiliknya) \". Berkata, Al 'Abbas radliallahu 'anhu: \"Wahai Rasulullah, kecuali pohon idzkhir (pohon yang harum baunya) yang berguna untuk pengerjaan penambangan emas kami dan qubur-qubur kami. Maka Beliau bersabda: \"Ya kecuali pohon idzkhir\". Dan dari Khalid dari 'Ikrimah: \"Apakah kamu mengerti yang dimaksud dengan dilarang memburu binatang buruan? adalah menyingkirkannya dari tempat berlindung yang dijadikannya tempat bersinggah\"."},"1703":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ افْتَتَحَ مَكَّةَ لَا هِجْرَةَ وَلَكِنْ جِهَادٌ وَنِيَّةٌ وَإِذَا اسْتُنْفِرْتُمْ فَانْفِرُوا فَإِنَّ هَذَا بَلَدٌ حَرَّمَ اللَّهُ يَوْمَ خَلَقَ السَّمَوَاتِ وَالْأَرْضَ وَهُوَ حَرَامٌ بِحُرْمَةِ اللَّهِ إِلَى يَوْمِ الْقِيَامَةِ وَإِنَّهُ لَمْ يَحِلَّ الْقِتَالُ فِيهِ لِأَحَدٍ قَبْلِي وَلَمْ يَحِلَّ لِي إِلَّا سَاعَةً مِنْ نَهَارٍ فَهُوَ حَرَامٌ بِحُرْمَةِ اللَّهِ إِلَى يَوْمِ الْقِيَامَةِ لَا يُعْضَدُ شَوْكُهُ وَلَا يُنَفَّرُ صَيْدُهُ وَلَا يَلْتَقِطُ لُقَطَتَهُ إِلَّا مَنْ عَرَّفَهَا وَلَا يُخْتَلَى خَلَاهَا قَالَ الْعَبَّاسُ يَا رَسُولَ اللَّهِ إِلَّا الْإِذْخِرَ فَإِنَّهُ لِقَيْنِهِمْ وَلِبُيُوتِهِمْ قَالَ قَالَ إِلَّا الْإِذْخِرَ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Mujahid] dari [Thawus] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bersabda pada hari pebebasan kota Makkah: \"Tidak ada lagi hijrah tetapi yang ada adalah jihad dan niat dan jika kalian diperintahkan berangkat perang maka berangkatlah. Sesungguhnya negeri ini telah Allah Ikrarkan kesucikannya sejak hari penciptaan langit dan bumi. Maka dia akan terus suci dengan pensucian dari Allah itu hingga hari qiyamat sehingga tidak dibolehkan perang didalamnya buat seorangpun sebelum aku dan tidak dihalalkan pula buatku kecuali sesaat dalam suatu hari. Maka dia suci dengan pensucian dari Allah itu hingga hari qiyamat, dan tidak boleh ditebang pepohonannya dan tidak boleh diburu hewan buruannya dan tidak ditemukan satupun barang temuan kecuali harus dikembalikan kepada yang mengenalnya (pemiliknya) dan tidak boleh dipotong rumputnya\". Berkata, Al 'Abbas radliallahu 'anhu: \"Wahai Rasulullah, kecuali pohon idzkhir yang berguna untuk wewangian tukang besi mereka dan rumah-rumah mereka\". Dia berkata,, maka Beliau bersabda: \"Ya, kecuali pohon idzkhir\"."},"1704":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ قَالَ لَنَا عَمْرٌو أَوَّلُ شَيْءٍ سَمِعْتُ عَطَاءً يَقُولُ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُاحْتَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْرِمٌثُمَّ سَمِعْتُهُ يَقُولُ حَدَّثَنِي طَاوُسٌ عَنْ ابْنِ عَبَّاسٍ فَقُلْتُ لَعَلَّهُ سَمِعَهُ مِنْهُمَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] berkata; ['Amru] berkata, kepada kami: \"Hal yang pertama kali aku dengar dari ['Atho'] adalah saat dia berkata: Aku mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Rasulullah shallallahu 'alaihi wasallam berbekam saat sedang ihram\". Kemudian aku mendengar dia berkata, telah menceritakan kepada saya [Thowus] dari [Ibnu 'Abbas radliallahu 'anhuma]. Maka aku katakan: \"Barangkali dia mendengarnya dari keduanya\"."},"1705":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ عَلْقَمَةَ بْنِ أَبِي عَلْقَمَةَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ ابْنِ بُحَيْنَةَ رَضِيَ اللَّهُ عَنْهُ قَالَاحْتَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُحْرِمٌ بِلَحْيِ جَمَلٍ فِي وَسَطِ رَأْسِهِ","id":"Telah menceritakan kepada kami [Khalid bin Mukhallad] telah menceritakan kepada kami [Sulaiman biun Bilal] dari ['Alqamah] dari ['Abdurrahman Al A'raj] dari [Ibnu Buhainah] radliallahu 'anhu berkata: \"Nabi shallallahu 'alaihi wasallam berbekam saat sedang ihram ketika berada di Lahyi Jamal pada begian tengah kepala Beliau\". "},"1706":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ عَبْدُ الْقُدُّوسِ بْنُ الْحَجَّاجِ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي عَطَاءُ بْنُ أَبِي رَبَاحٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَ مَيْمُونَةَ وَهُوَ مُحْرِمٌ","id":"Telah menceritakan kepada kami [Abu Al Mughirah 'Abdul Quddus bin Al Hajjaj] telah menceritakan kepada kami [Al Awza'iy] telah menceritakan kepada saya ['Atho' bin Abu Rabah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam menikahi Maimunah saat Beliau sedang ihram."},"1707":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ ي��زِيدَ حَدَّثَنَا اللَّيْثُ حَدَّثَنَا نَافِعٌ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ مَاذَا تَأْمُرُنَا أَنْ نَلْبَسَ مِنْ الثِّيَابِ فِي الْإِحْرَامِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَلْبَسُوا الْقَمِيصَ وَلَا السَّرَاوِيلَاتِ وَلَا الْعَمَائِمَ وَلَا الْبَرَانِسَ إِلَّا أَنْ يَكُونَ أَحَدٌ لَيْسَتْ لَهُ نَعْلَانِ فَلْيَلْبَسْ الْخُفَّيْنِ وَلْيَقْطَعْ أَسْفَلَ مِنْ الْكَعْبَيْنِ وَلَا تَلْبَسُوا شَيْئًا مَسَّهُ زَعْفَرَانٌ وَلَا الْوَرْسُ وَلَا تَنْتَقِبْ الْمَرْأَةُ الْمُحْرِمَةُ وَلَا تَلْبَسْ الْقُفَّازَيْنِتَابَعَهُ مُوسَى بْنُ عُقْبَةَ وَإِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ بْنِ عُقْبَةَ وَجُوَيْرِيَةُ وَابْنُ إِسْحَاقَ فِي النِّقَابِ وَالْقُفَّازَيْنِ وَقَالَ عُبَيْدُ اللَّهِ وَلَا وَرْسٌ وَكَانَ يَقُولُ لَا تَتَنَقَّبْ الْمُحْرِمَةُ وَلَا تَلْبَسْ الْقُفَّازَيْنِ وَقَالَ مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ لَا تَتَنَقَّبْ الْمُحْرِمَةُ وَتَابَعَهُ لَيْثُ بْنُ أَبِي سُلَيْمٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yazid] telah mengabarkan kepada kami [Al Laits] telah menceritakan kepada kami [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] berkata: Seorang laki-laki datang lalu berkata: \"Wahai Rasulullah, pakaian apa yang baginda perintahkan untuk kami ketika ihram)?. Nabi shallallahu 'alaihi wasallam menjawab: \"Janganlah kalian mengenakan baju, celana, sorban, mantel (pakaian yang menutupi kepala) kecuali seseorang yang tidak memiliki sandal, hendaklah dia mengenakan sapatu tapi dipotongnya hingga berada dibawah mata kaki dan jangan pula kalian memakai pakaian yang diberi minyak wangi atau wewangian dari daun tumbuhan. Dan wanita yang sedang ihram tidak boleh memakai cadar (penutup wajah) dan sarung tangan\". Hadits ini dikuatkan pula oleh [Musa bin 'Uqbah] dan [Isma'il bin Ibrahim bin 'Uqbah] dan [Juwairiyah] dan [Ibnu Ishaq] tentang cadar (tutup muka) dan sarung tangan. Dan berkata, ['Ubaidullah]; dan tidak pula wewangian dari daun tumbuhan yang wangi. Dan Beliau bersabda: \"Dan wanita yang sedang ihram janganlah memakai cadar dan juga jangan memakai sarung tangan\". Dan berkata, [Malik] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma]: \"Dan wanita yang sedang ihram janganlah memakai\". Dan hadits ini dikuatkan pula oleh [Laits bin Abu Salim]."},"1708":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الْحَكَمِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَوَقَصَتْ بِرَجُلٍ مُحْرِمٍ نَاقَتُهُ فَقَتَلَتْهُ فَأُتِيَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اغْسِلُوهُ وَكَفِّنُوهُ وَلَا تُغَطُّوا رَأْسَهُ وَلَا تُقَرِّبُوهُ طِيبًا فَإِنَّهُ يُبْعَثُ يُهِلُّ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Al Hakam] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Ada seorang laki-laki yang sedang berihram dijatuhkan oleh untanya hingga meninggal dunia. Lalu jenazahnya dibawa kepada Rasulullah shallallahu 'alaihi wasallam, maka Beliau bersabda: \"Mandikanlah dia dan kafanilah dan janganlah ditutupkepalanya dan jangan diberi wewangian karena dia nanti akan dibangkitkan (pada hari qiyamat) dalam keadaan berihram\"."},"1709":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِأَنَّ عَبْدَ اللَّهِ بْنَ الْعَبَّاسِ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ اخْتَلَفَا بِالْأَبْوَاءِ فَقَالَ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ يَغْسِلُ الْمُحْرِمُ رَأْسَهُ وَقَالَ الْمِسْوَرُ لَا يَغْسِلُ الْمُحْرِمُ رَأْسَهُ فَأَرْسَلَنِي عَبْدُ اللَّهِ بْنُ الْعَبَّاسِ إِلَى أَبِي أَيُّوبَ الْأَنْصَارِيِّ فَوَجَدْتُهُ يَغْتَسِلُ بَيْنَ الْقَرْنَيْنِ وَهُوَ يُسْتَرُ بِثَوْبٍ فَسَلَّمْتُ عَلَيْهِ فَقَالَ مَنْ هَذَا فَقُلْتُ أَنَا عَبْدُ اللَّهِ بْنُ حُنَيْنٍ أَرْسَلَنِي إِلَيْكَ عَبْدُ اللَّهِ بْنُ الْعَبَّاسِ أَسْأَلُكَ كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْسِلُ رَأْسَهُ وَهُوَ مُحْرِمٌ فَوَضَعَ أَبُو أَيُّوبَ يَدَهُ عَلَى الثَّوْبِ فَطَأْطَأَهُ حَتَّى بَدَا لِي رَأْسُهُ ثُمَّ قَالَ لِإِنْسَانٍ يَصُبُّ عَلَيْهِ اصْبُبْ فَصَبَّ عَلَى رَأْسِهِ ثُمَّ حَرَّكَ رَأْسَهُ بِيَدَيْهِ فَأَقْبَلَ بِهِمَا وَأَدْبَرَ وَقَالَ هَكَذَا رَأَيْتُهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Zaid bin Aslam] dari [Ibrahim bin 'Abdullah bin Hunain] dari [bapaknya] bahwa 'Abdullah bin 'Abbas radliallahu 'anhu dan Al Miswar bin Makhramah berselisih pendapat ketika keduanya berada di Abwa'. 'Abdullah bin 'Abbas radliallahu 'anhu berkata; Orang yang sedang ihram membasuh kepalanya. Sedangkan Al Miswar berkata; Orang yang sedang ihram tidak boleh membasuh kepalanya. Maka 'Abdullah bin 'Abbas radliallahu 'anhu mengutusku untuk menemui [Abu Ayyub Al Anshariy]. Aku jumpai dia sedang mandi dibawah dua pohon dan dia berlindung dari balik kain. Maka aku memberi salam kepadanya. Dia bertanya: \"Siapa ini?\". Aku jawab: \"Aku 'Abdullah bin Hunain, 'Abdullah bin 'Abbas radliallahu 'anhu mengutusku kepadamu untuk menanyakan bagaimana dahulu Rasulullah shallallahu 'alaihi wasallam membasuh kepala Beliau ketika Beliau sedang ihram?\". Maka Abu Ayyub menyingkap kain penutup dengan tangannya sehingga kepalanya nampak olehku lalu dia berkata, kepada seseorang yang mengucurkan air kepadanya; \"Kucurkanlah air itu\". Maka orang itu mengucurkan air ke kepalanya lalu dia menggerak-gerakkan kepalanya dengan kedua tangannya lalu menarik tangannya kedepan ke belakang, lalu berkata: \"Begitulah aku pernah melihat Nabi shallallahu 'alaihi wasallam melakukannya\". "},"1710":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ سَمِعْتُ جَابِرَ بْنَ زَيْدٍ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ بِعَرَفَاتٍ مَنْ لَمْ يَجِدْ النَّعْلَيْنِ فَلْيَلْبَسْ الْخُفَّيْنِ وَمَنْ لَمْ يَجِدْ إِزَارًا فَلْيَلْبَسْ سَرَاوِيلَ لِلْمُحْرِمِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepada saya ['Amru bin Dinar]; aku mendengar [Jabir bin Zaid]; Aku mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam berkhuthbah di 'Arafah: \"Barangsiapa yang tidak memiliki sepasang sandal hendaklah dia memakai sepatunya. Dan barangsiapa yang tidak memiliki kain sarung hendaklah dia memakai celana untuk ihram\"."},"1711":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ سَالِمٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَلْبَسُ الْمُحْرِمُ مِنْ الثِّيَابِ فَقَالَ لَا يَلْبَسْ الْقَمِيصَ وَلَا الْعَمَائِمَ وَلَا السَّرَاوِيلَاتِ وَلَا الْبُرْنُسَ وَلَا ثَوْبًا مَسَّهُ زَعْفَرَانٌ وَلَا وَرْسٌ وَإِنْ لَمْ يَجِدْ نَعْلَيْنِ فَلْيَلْبَسْ الْخُفَّيْنِ وَلْيَقْطَعْهُمَا حَتَّى يَكُونَا أَسْفَلَ مِنْ الْكَعْبَيْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Ibrahim bin Sa'ad] telah menceritakan kepada kami [Ibnu Syihab] dari [Salim] dari ['Abdullah radliallahu 'anhu]; Rasulullah shallallahu 'alaihi wasallam ditanya tentang pakaian yang dibolehkan dipakai oleh seorang yang sedang berihram. Maka Beliau bersabda: \"Janganlah dia mengenakan gamis (baju), sorban, celana, mantel (pakaian yang menutupi kepala) dan jangan pula dia memakai pakaian yang diberi minyak wangi atau wewangian yang terbuat dari daun tumbuhan dan apabila dia tidak memiliki sepasang sandal, hendaklah dia mengenakan sapatu tapi dipotongnya hingga berada dibawah mata kaki\"."},"1712":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَخَطَبَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَاتٍ فَقَالَ مَنْ لَمْ يَجِدْ الْإِزَارَ فَلْيَلْبَسْ السَّرَاوِيلَ وَمَنْ لَمْ يَجِدْ النَّعْلَيْنِ فَلْيَلْبَسْ الْخُفَّيْنِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Amru bin Dinar] dari [Jabir bin Zaid] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: Nabi shallallahu 'alaihi wasallam menyampaikam khathbah kepada kami, Beliau bersabda: \"Barangsiapa yang tidak memiliki kain sarung hendaklah dia memakai celana dan barangsiapa yang tidak memiliki sepasang sandal, hendaklah dia mengenakan sepatu\". "},"1713":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُاعْتَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذِي الْقَعْدَةِ فَأَبَى أَهْلُ مَكَّةَ أَنْ يَدَعُوهُ يَدْخُلُ مَكَّةَ حَتَّى قَاضَاهُمْ لَا يُدْخِلُ مَكَّةَ سِلَاحًا إِلَّا فِي الْقِرَابِ","id":"Telah menceritakan kepada kami ['Ubaidullah] dari [Isra'il] dari [Abu Ishaq] dari [Al Bara' radliallahu 'anhu]: \"Rasulullah shallallahu 'alaihi wasallam melaksanakan 'umrah pada bulan Dzul Qa'dah namun penduduk Makkah enggan membolehkan Beliau memasuki kota Makkah hingga akhirnya Beliau sepakat untuk tidak memasuki Makkah dengan membawa senjata terhunus kecuali dalam sarungnya.\""},"1714":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا ابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَّتَ لِأَهْلِ الْمَدِينَةِ ذَا الْحُلَيْفَةِ وَلِأَهْلِ نَجْدٍ قَرْنَ الْمَنَازِلِ وَلِأَهْلِ الْيَمَنِ يَلَمْلَمَ هُنَّ لَهُنَّ وَلِكُلِّ آتٍ أَتَى عَلَيْهِنَّ مِنْ غَيْرِهِمْ مِمَّنْ أَرَادَ الْحَجَّ وَالْعُمْرَةَ فَمَنْ كَانَ دُونَ ذَلِكَ فَمِنْ حَيْثُ أَنْشَأَ حَتَّى أَهْلُ مَكَّةَ مِنْ مَكَّةَ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ibnu Thowus] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam telah menetapkan miqat bagi penduduk Madinah di Dzul Hulaifah, bagi penduduk Najed di Qarnul Manazil dan bagi penduduk Yaman di Yalamlam. Dan begitu pulalah ketentuan bagi setiap orang yang datang melewati tempat-tempat tersebut selain penduduk negeri-negeri tersebut yang berniat untuk haji dan 'umrah. Bagi orang-orang selain itu (yang tinggal lebih dekat ke Makkah dari pada tempat-tempat itu), maka dia memulai dari tempat yang dijadikannya tinggal sehingga bagi penduduk Makkah mereka memulainya dari (rumah mereka) di Makkah\".\"."},"1715":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَامَ الْفَتْحِ وَعَلَى رَأْسِهِ الْمِغْفَرُ فَلَمَّا نَزَعَهُ جَاءَ رَجُلٌ فَقَالَ إِنَّ ابْنَ خَطَلٍ مُتَعَلِّقٌ بِأَسْتَارِ الْكَعْبَةِ فَقَالَ اقْتُلُوهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Anas bin Malik radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam memasuki Makkah pada tahun Penaklukan Makkah dengan mengenakan pelindung kepala terbuat dari besi diatas kepala Beliau. Ketika Beliau melepaskannya, datang seseorang lalu berkata; \"Sesungguhnya Ibnu Khathol sedang berlindung di balik kain penutup Ka'bah. Maka Beliau berkata: \"Bunuhlah dia\". "},"1716":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا عَطَاءٌ قَالَ حَدَّثَنِي صَفْوَانُ بْنُ يَعْلَى بْنِ أُمَيَّةَ عَنْ أَبِيهِ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَاهُ رَجُلٌ عَلَيْهِ جُبَّةٌ فِيهِ أَثَرُ صُفْرَةٍ أَوْ نَحْوُهُ كَانَ عُمَرُ يَقُولُ لِي تُحِبُّ إِذَا نَزَلَ عَلَيْهِ الْوَحْيُ أَنْ تَرَاهُ فَنَزَلَ عَلَيْهِ ثُمَّ سُرِّيَ عَنْهُ فَقَالَ اصْنَعْ فِي عُمْرَتِكَ مَا تَصْنَعُ فِي حَجِّكَ وَعَضَّ رَجُلٌ يَدَ رَجُلٍ يَعْنِي فَانْتَزَعَ ثَنِيَّتَهُ فَأَبْطَلَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami ['Atho'] berkata, telah menceritakan kepada saya [Shafwan bin Ya'la bin Umayyah] dari [bapaknya] berkata; Ketika aku sedang bersama Rasulullah shallallahu 'alaihi wasallam tiba-tiba datang seseorang yang mengenakan jubah yang tampak pada jubahnya pewarna kuning atau sejenisnya. Saat itu 'Umar berkata, kepadaku: \"Kamu suka bila Beliau sedang menerima wahyu kamu dapat melihatnya?\". Maka wahyu turun kepada Beliau kemudian setelah selesai, Beliau bersabda: \"Kerjakanlah manasik dalam 'umrahmu seperti kamu kerjakan dalam hajimu\". "},"1717":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبَيْنَا رَجُلٌ وَاقِفٌ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ إِذْ وَقَعَ عَنْ رَاحِلَتِهِ فَوَقَصَتْهُ أَوْ قَالَ فَأَقْعَصَتْهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْسِلُوهُ بِمَاءٍ وَسِدْرٍ وَكَفِّنُوهُ فِي ثَوْبَيْنِ أَوْ قَالَ ثَوْبَيْهِ وَلَا تُحَنِّطُوهُ وَلَا تُخَمِّرُوا رَأْسَهُ فَإِنَّ اللَّهَ يَبْعَثُهُ يَوْمَ الْقِيَامَةِ يُلَبِّي","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru bin Dinar] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; \"Ada seorang laki-laki ketika sedang wukuf bersama Nabi shallallahu 'alaihi wasallam di 'Arafah terjatuh dari hewan tunggangannya sehingga ia terinjak\" atau dia Ibnu 'Abbas radliallahu 'anhuma berkata: \"Hingga orang itu mati seketika\". Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Mandikanlah dia dengan air dan (air) yang dicampur daun bidara dan kafanilah dengan dua helai kain, Atau kata Beliau: dengan dua helai pakaian (ihram) nya dan janganlah diberi wewangian dan jangan pula diberi tutup kepala (serban) karena dia nanti Allah akan membangkitkannya pada hari qiyamat dalam keadaan bertalbiyyah\"."},"1718":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَبَيْنَا رَجُلٌ وَاقِفٌ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَةَ إِذْ وَقَعَ عَنْ رَاحِلَتِهِ فَوَقَصَتْهُ أَوْ قَالَ فَأَوْقَصَتْهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْسِلُوهُ بِمَاءٍ وَسِدْرٍ وَكَفِّنُوهُ فِي ثَوْبَيْنِ وَلَا تَمَسُّوهُ طِيبًا وَلَا تُخَمِّرُوا رَأْسَهُ وَلَا تُحَنِّطُوهُ فَإِنَّ اللَّهَ يَبْعَثُهُ يَوْمَ الْقِيَامَةِ مُلَبِّيًا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhum] berkata; \"Ketika ada seorang laki-laki yang sedang wukuf bersama Nabi shallallahu 'alaihi wasallam di 'Arafah terjatuh dari hewan tunggangannya sehingga ia terinjak\" atau dia (Ibnu 'Abbas radliallahu 'anhuma) berkata: \"Hingga orang itu mati seketika\". Maka Nabi shallallahu 'alaihi wasallam berkata: \"Mandikanlah dia dengan air dan (air) dicampur daun bidara dan kafanilah dengan dua helai kain dan janganlah (kainnya) diberi wewangian dan jangan pula diberi tutup kepala (serban) dan jangan pula (jasadnya) diberi wewangian karena Allah nanti membangkitkannya pada hari qiyamat dalam keadaan bertalbiyyah\"."},"1719":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَجُلًا كَانَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَقَصَتْهُ نَاقَتُهُ وَهُوَ مُحْرِمٌ فَمَاتَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْسِلُوهُ بِمَاءٍ وَسِدْرٍ وَكَفِّنُوهُ فِي ثَوْبَيْهِ وَلَا تَمَسُّوهُ بِطِيبٍ وَلَا تُخَمِّرُوا رَأْسَهُ فَإِنَّهُ يُبْعَثُ يَوْمَ الْقِيَامَةِ مُلَبِّيًا","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abu Bisyir] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa ada seorang laki-laki ketika sedang bersama Nabi shallallahu 'alaihi wasallam dijatuhkan oleh untanya dalam keadaan sedang berihram hingga meninggal dunia. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mandikanlah dia dengan air dan air yang dicampur daun bidara dan kafanilah dengan dua helai kain dan janganlah diberi wewangian dan jangan pula diberi tutup kepala (serban) karena dia nanti dibangkitkan pada hari qiyamat dalam keadaan bertalbiyyah\"."},"1720":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ امْرَأَةً مِنْ جُهَيْنَةَ جَاءَتْ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ أُمِّي نَذَرَتْ أَنْ تَحُجَّ فَلَمْ تَحُجَّ حَتَّى مَاتَتْ أَفَأَحُجُّ عَنْهَا قَالَ نَعَمْ حُجِّي عَنْهَا أَرَأَيْتِ لَوْ كَانَ عَلَى أُمِّكِ دَيْنٌ أَكُنْتِ قَاضِيَةً اقْضُوا اللَّهَ فَاللَّهُ أَحَقُّ بِالْوَفَاءِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyir] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa ada seorang wanita dari suku Juhainah datang menemui Nabi shallallahu 'alaihi wasallam lalu berkata: \"Sesungguhnya ibuku telah bernadzar untuk menunaikan haji namun dia belum sempat menunaikannya hingga meninggal dunia, apakah boleh aku menghajikannya?\". Beliau menjawab: \"Tunaikanlah haji untuknya. Bagaimana pendapatmnu jika ibumu mempunyai hutang, apakah kamu wajib membayarkannya?. Bayarlah hutang kepada Allah karena (hutang) kepada Allah lebih patut untuk dibayar\"."},"1721":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ شِهَابٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ عَنْ الْفَضْلِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمْ أَنَّ امْرَأَةً ح حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ حَدَّثَنَا ابْنُ شِهَابٍ عَنْ سُلَيْمَانَ بْنَ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَجَاءَتْ امْرَأَةٌ مِنْ خَثْعَمَ عَامَ حَجَّةِ الْوَدَاعِ قَالَتْ يَا رَسُولَ اللَّهِ إِنَّ فَرِيضَةَ اللَّهِ عَلَى عِبَادِهِ فِي الْحَجِّ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَسْتَطِيعُ أَنْ يَسْتَوِيَ عَلَى الرَّاحِلَةِ فَهَلْ يَقْضِي عَنْهُ أَنْ أَحُجَّ عَنْهُ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Syihab] dari [Sulaiman bin Yasar] dari [Ibnu 'Abbas] dari [Al Fadhal bin 'Abbas radliallahu 'anhum] bahwa ada seorang wanita. Dan diriwayatkan pula oleh [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul 'Aziz bin Abu Salamah] telah menceritakan kepada kami [Ibnu Syihab] dari [Sulaiman bin Yasar] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Ada seorang wanita dari suku Khats'am pada pelaksanaan Haji Wada' lalu berkata: \"Wahai Rasulullah, kewajiban yang Allah tetapkan buat para hambaNya tentang haji sampai kepada bapakku ketika dia sudah berusia lanjut sehingga dia tidak mampu untuk menempuh perjalanannya, apakah terpenuhi kewajiban untuknya bila aku menghajikannya?. Beliau menjawab: \"Ya\". "},"1722":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ الْفَضْلُ رَدِيفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَتْ امْرَأَةٌ مِنْ خَثْعَمَ فَجَعَلَ الْفَضْلُ يَنْظُرُ إِلَيْهَا وَتَنْظُرُ إِلَيْهِ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْرِفُ وَجْهَ الْفَضْلِ إِلَى الشِّقِّ الْآخَرِ فَقَالَتْ إِنَّ فَرِيضَةَ اللَّهِ أَدْرَكَتْ أَبِي شَيْخًا كَبِيرًا لَا يَثْبُتُ عَلَى الرَّاحِلَةِ أَفَأَحُجُّ عَنْهُ قَالَ نَعَمْ وَذَلِكَ فِي حَجَّةِ الْوَدَاعِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Sulaiman bin Yasar] dari [Ibnu 'Abbas Radliallahu 'anhu] berkata; Ketika AL Fadhal membonceng Nabi shallallahu 'alaihi wasallam tiba-tiba datang seorang wanita dari suku Khats'am sehingga Al Fadhal memandangnya dan wanita itupun memandang kepadanya, maka Nabi shallallahu 'alaihi wasallam mengalihkan wajah Al Fadhah ke arah yang lain. Wanita itu berkata: \"Sesungguhnya kewajiban yang telah Allah tetapkan sampai kepada bapakku ketika dia sudah berusia lanjut sehingga dia tidak mampu untuk menempuh perjalanannya, apakah boleh aku menghajikannya?\". Beliau menjawab: \"Ya\". Peristiwa ini terjadi pada Haji Wada'."},"1723":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُبَعَثَنِي أَوْ قَدَّمَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الثَّقَلِ مِنْ جَمْعٍ بِلَيْلٍ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ubaidullah bin Abu Yazid] berkata; Aku mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam mengutusku atau memanggilku untuk membawa perbekalan para musafir (jama'ah haji) di Jama' pada malam hari\". "},"1724":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَأَقْبَلْتُ وَقَدْ نَاهَزْتُ الْحُلُمَ أَسِيرُ عَلَى أَتَانٍ لِي وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يُصَلِّي بِمِنًى حَتَّى سِرْتُ بَيْنَ يَدَيْ بَعْضِ الصَّفِّ الْأَوَّلِ ثُمَّ نَزَلْتُ عَنْهَا فَرَتَعَتْ فَصَفَفْتُ مَعَ النَّاسِ وَرَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَقَالَ يُونُسُ عَنْ ابْنِ شِهَابٍ بِمِنًى فِي حَجَّةِ الْوَدَاعِ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [anak saudaraku, Ibnu Syihab] dari [pamannya] telah mengabarkan kepada saya ['Ubaidullah bin 'Abdullah bin 'Utbah bin Mas'ud] bahwa ['Abdullah bin 'Abbas radliallahu 'anhu] berkata; \"Pada suatu hari aku datang, saat itu usiaku mendekati baligh dengan menunggang keledai betina milikku sedangkan Rasulullah shallallahu 'alaihi wasallam saat itu sedang shalat (berjama'ah) di Mina hingga aku sampai di hadapan sebagian shaf pertama kemudian aku turun dari keledaiku lalu ia mencari makan sesukanya. Kemudian aku masuk kedalam shaf jama'ah di belakang Rasulullah shallallahu 'alaihi wasallam \". Dan berkata, [Yunus] dari [Ibnu Syihab]: \"Di Mina pada pelaksanaan Haji Wada'\"."},"1725":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ يُونُسَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَاعِيلَ عَنْ مُحَمَّدِ بْنِ يُوسُفَ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَحُجَّ بِي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا ابْنُ سَبْعِ سِنِينَ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Yunus] telah menceritakan kepada kami [Hatim bin Isma'il] dari [Muhammad bin Yusuf] dari [As-Sa'ib bin Yazid] berkata: \"Aku diajak menunaikan haji bersama Rasulullah shallallahu 'alaihi wasallam padahal saat itu usiaku baru tujuh tahun\"."},"1726":{"ar":"حَدَّثَنَا عَمْرُو بْنُ زُرَارَةَ أَخْبَرَنَا الْقَاسِمُ بْنُ مَالِكٍ عَنْ الْجُعَيْدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَسَمِعْتُ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ يَقُولُ لِلسَّائِبِ بْنِ يَزِيدَ وَكَانَ قَدْ حُجَّ بِهِ فِي ثَقَلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Amru bin Zurarah] telah mengabarkan kepada kami [Al Qasim bin Malik] dari [Al Ju'di bin 'Abdurrahman] berkata; Aku mendengar 'Umar bin 'Abdul 'Aziz berkata tentang [As-Saib bin Yazid] yang pernah menunaikan haji bersama rambongan dan perbekalan haji Nabi shallallahu 'alaihi wasallam."},"1727":{"ar":"و قَالَ لِي أَحْمَدُ بْنُ مُحَمَّدٍ هُوَ الْأَزْرَقِيُّ حَدَّثَنَا إِبْرَاهِيمُ عَنْ أَبِيهِ عَنْ جَدِّهِ أَذِنَ عُمَرُ رَضِيَ اللَّهُ عَنْهُلِأَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي آخِرِ حَجَّةٍ حَجَّهَا فَبَعَثَ مَعَهُنَّ عُثْمَانَ بْنَ عَفَّانَ وَعَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ","id":"Dan telahb berkata, kepadaku [Ahmad bin Muhammad] dia adalah Al Azraqiy telah menceritakan kepada kami [Ibrahim] dari [bapaknya] dari [kakeknya] bahwa ['Umar radliallahu 'anhu] memberi izin (untuk menunaikan haji) kepada para isteri Nabi shallallahu 'alaihi wasallam pada akhir haji yang dia lakukan, lalu ia mengutus 'Utsman bin 'Affan dan 'Abdurrahman bin 'Auf bersama mereka."},"1728":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا حَبِيبُ بْنُ أَبِي عَمْرَةَ قَالَ حَدَّثَتْنَا عَائِشَةُ بِنْتُ طَلْحَةَ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ أَلَا نَغْزُو وَنُجَاهِدُ مَعَكُمْ فَقَالَ لَكِنَّ أَحْسَنَ الْجِهَادِ وَأَجْمَلَهُ الْحَجُّ حَجٌّ مَبْرُورٌ فَقَالَتْ عَائِشَةُ فَلَا أَدَعُ الْحَجَّ بَعْدَ إِذْ سَمِعْتُ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Habib bin Abu 'Amrah] berkata, telah menceritakan kepada kami [Aisyah binti Tholhah] dari ['Aisyah Ummul Mukminin radliallahu 'anhu] berkata: \"Wahai Rasululloh, apakah kami tidak boleh ikut berperang dan berjihad bersama kalian?\". Maka Beliau menjawab: \"Akan tetapi (buat kalian) jihad yang paling baik dan paling sempurna adalah haji, yaitu haji mabrur\". Maka 'Aisyah radliallahu 'anha berkata; \"Maka aku tidak pernah meninggalkan haji sejak aku mendengar keterangan ini dari Rasulullah shallallahu 'alaihi wasallam \" "},"1729":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرٍو عَنْ أَبِي مَعْبَدٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُسَافِرْ الْمَرْأَةُ إِلَّا مَعَ ذِي مَحْرَمٍ وَلَا يَدْخُلُ عَلَيْهَا رَجُلٌ إِلَّا وَمَعَهَا مَحْرَمٌ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ أَنْ أَخْرُجَ فِي جَيْشِ كَذَا وَكَذَا وَامْرَأَتِي تُرِيدُ الْحَجَّ فَقَالَ اخْرُجْ مَعَهَا","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru] dari [Abu Ma'bad], sahayanya Ibnu 'Abbas, dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang wanita bepergian kecuali bersama mahramnya dan janganlah seorang laki-laki menemui seorang wanita kecuali wanita itu bersama mahramnya\". Kemudian ada seorang laki-laki yang berkata: \"Wahai Rasulullah, sebenarnya aku berkehendak untuk berangkat bersama pasukan perang ini dan ini namun isteriku hendak menunaikan haji\". Maka Beliau shallallahu 'alaihi wasallam bersabda: \"Berangkatlah haji bersama isterimu\"."},"1730":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ أَخْبَرَنَا حَبِيبٌ الْمُعَلِّمُ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَمَّا رَجَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ حَجَّتِهِ قَالَ لِأُمِّ سِنَانٍ الْأَنْصَارِيَّةِ مَا مَنَعَكِ مِنْ الْحَجِّ قَالَتْ أَبُو فُلَانٍ تَعْنِي زَوْجَهَا كَانَ لَهُ نَاضِحَانِ حَجَّ عَلَى أَحَدِهِمَا وَالْآخَرُ يَسْقِي أَرْضًا لَنَا قَالَ فَإِنَّ عُمْرَةً فِي رَمَضَانَ تَقْضِي حَجَّةً أَوْ حَجَّةً مَعِيرَوَاهُ ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ سَمِعْتُ ابْنَ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عُبَيْدُ اللَّهِ عَنْ عَبْدِ الْكَرِيمِ عَنْ عَطَاءٍ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Yazid bin Zurai'] telah mengabarkan kepada kami [Habib Al Mu'allim] dari ['Atho'] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Ketika Nabi shallallahu 'alaihi wasallam kembali dari pelaksanaan hajinya, Beliau berkata kepada Ummu Sinan Al Anshariyyah: \"Apa yang menghalangimu untuk menunaikan haji?\". Wanita itu berkata: \"Bapak si fulan, yang ia maksud suaminya, memiliki dua ekor unta yang salah satunya sering digunakan untuk menunaikan haji sedangn unta yang satunya lagi digunakan untuk mencari air minum buat kami\". Beliau bersabda: \"'Umrah pada bulan Ramadhan sebanding dengan haji atau haji bersamaku\". Ini diriwayatkan oleh [Ibnu Juraij] dari ['Atho']; Aku mendengar [Ibnu 'Abbas radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam. Dan ['Ubaidullah] berkata, dari ['Abdul Karim] dari ['Atho'] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam. "},"1731":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ قَزَعَةَ مَوْلَى زِيَادٍ قَالَ سَمِعْتُ أَبَا سَعِيدٍوَقَدْ غَزَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثِنْتَيْ عَشْرَةَ غَزْوَةً قَالَ أَرْبَعٌ سَمِعْتُهُنَّ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ يُحَدِّثُهُنَّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْجَبْنَنِي وَآنَقْنَنِي أَنْ لَا تُسَافِرَ امْرَأَةٌ مَسِيرَةَ يَوْمَيْنِ لَيْسَ مَعَهَا زَوْجُهَا أَوْ ذُو مَحْرَمٍ وَلَا صَوْمَ يَوْمَيْنِ الْفِطْرِ وَالْأَضْحَى وَلَا صَلَاةَ بَعْدَ صَلَاتَيْنِ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَبَعْدَ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ وَلَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ مَسْجِدِ الْحَرَامِ وَمَسْجِدِي وَمَسْجِدِ الْأَقْصَى","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari ['Abdul Malik bin 'Umair] dari [Qaza'ah, maula Ziyad] berkata; Aku mendengar [Abu Sa'id] yang sudah pernah mengikuti peperangan bersama Nabi shallallahu 'alaihi wasallam sebanyak dua belas peperangan, berkata: \"Empat perkara yang aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam, atau dia (Qaza'ah) berkata; telah menceritakan Abu Sa'id tentang beberapa perkara yang dia dapatkan dari Nabi shallallahu 'alaihi wasallam yang perkara-perkara itu menakjubkan aku (yaitu): \"Tidak boleh seorang wanita bepergian sepanjang dua hari perjalanan kecuali bersama suaminya atau mahramnya dan tidak boleh shaum dua hari raya, 'Iedul Fithri dan 'Iedul Adhha, dan tidak boleh melaksanakan dua shalat, yaitu setelah 'Ashar hingga matahari terbenam dan setelah Shubuh hingga matahari terbit dan tidaklah ditekankan untuk berziarah kecuali untuk mengunjungi tiga masjid, Al Masjidil Haram, Masjidku dan Masjidil Aqsha\"."},"1732":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا الْفَزَارِيُّ عَنْ حُمَيْدٍ الطَّوِيلِ قَالَ حَدَّثَنِي ثَابِتٌ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى شَيْخًا يُهَادَى بَيْنَ ابْنَيْهِ قَالَ مَا بَالُ هَذَا قَالُوا نَذَرَ أَنْ يَمْشِيَ قَالَ إِنَّ اللَّهَ عَنْ تَعْذِيبِ هَذَا نَفْسَهُ لَغَنِيٌّ وَأَمَرَهُ أَنْ يَرْكَبَ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah mengabarkan kepada kami [Al Fazariy] dari [Humaid Ath-Thowil] berkata, telah menceritakan kepada saya [Tsabit] dari [Anas radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam melihat seorang tua renta yang dipapah oleh kedua anaknya, maka Beliau bertanya: \"Mengapa orang ini berbuat seperti ini?\". Mereka menjawab: \"Dia telah bernadzar untuk berjalan kaki (menuju Makkah) \". Maka Beliau berkata: \"Allah tidak membutuhkan orang ini untuk menyiksa dirinya\". Maka Beliau memerintahkan orang itu naik tunggangan."},"1733":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ أَنَّ ابْنَ جُرَيْجٍ أَخْبَرَهُمْ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ أَبِي أَيُّوبَ أَنَّ يَزِيدَ بْنَ أَبِي حَبِيبٍ أَخْبَرَهُ أَنَّ أَبَا الْخَيْرِ حَدَّثَهُ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَنَذَرَتْ أُخْتِي أَنْ تَمْشِيَ إِلَى بَيْتِ اللَّهِ وَأَمَرَتْنِي أَنْ أَسْتَفْتِيَ لَهَا النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَفْتَيْتُهُ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِتَمْشِ وَلْتَرْكَبْقَالَ وَكَانَ أَبُو الْخَيْرِ لَا يُفَارِقُ عُقْبَةَ قَالَ أَبُو عَبْد اللَّهِ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ يَزِيدَ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam bin Yusuf] bahwa [Ibnu Juraij] telah mengabarkan kepada mereka berkata, telah mengabarkan kepada saya [Sa'id bin Abu Ayyub] bahwa [Yazid bin Abu Habib] telah mengabarkan kepadanya bahwa [Abu Al Khair] menceritakan kepadanya dari ['Uqbah bin 'Amir] berkata: \"Saudara perempuanku telah bernadzar untuk berjalan kali menuju Baitullah lalu dia menyuruh aku untuk meminta fatwa kepada Nabi shallallahu 'alaihi wasallam. Aku datang meminta fatwa kepada Beliau, maka Beliau shallallahu 'alaihi wasallam bersabda: \"Hendaklah dia berjalan kaki dan berkendaraan\". Yazid bin Abu Habib berkata: Abu Al Khair tidak pernah berpisah dari 'Uqbah. Abu 'Abdullah Al Bukhariy berkata, telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Yahya bin Ayyub] dari [Yazid] dari [Abu Al Khair] dari ['Uqbah], lalu dia menyebutkan hadits tersebut diatas. "},"1734":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا عَاصِمٌ أَبُو عَبْدِ الرَّحْمَنِ الْأَحْوَلُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَدِينَةُ حَرَمٌ مِنْ كَذَا إِلَى كَذَا لَا يُقْطَعُ شَجَرُهَا وَلَا يُحْدَثُ فِيهَا حَدَثٌ مَنْ أَحْدَثَ حَدَثًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Tsabit bin Tazid] telah menceritakan kepada kami ['Ashim Abu 'Abdurrahman Al Ahwal] dari [Anas radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Madinah adalah tanah suci dari ini dan ini. Yaitu tidak boleh ditebang pepohonannya dan tidak boleh berbuat kemungkaran didalamnya. Barangsiapa yang berbuat kemungkaran (bid'ah) yang dilarang agama didalamnya maka orang itu akan mendapat laknat dari Allah, para malaikat dan seluruh manusia\". "},"1735":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَأَمَرَ بِبِنَاءِ الْمَسْجِدِ فَقَالَ يَا بَنِي النَّجَّارِ ثَامِنُونِي فَقَالُوا لَا نَطْلُبُ ثَمَنَهُ إِلَّا إِلَى اللَّهِ فَأَمَرَ بِقُبُورِ الْمُشْرِكِينَ فَنُبِشَتْ ثُمَّ بِالْخِرَبِ فَسُوِّيَتْ وَبِالنَّخْلِ فَقُطِعَ فَصَفُّوا النَّخْلَ قِبْلَةَ الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] dari [Abu At-Tayyah] dari [Anas radliallahu 'anhu]; Nabi shallallahu 'alaihi wasallam datang ke Madinah kemudian Beliau memerintahkan untuk membangun masjid lalu berkata: \"Wahai Banu Najar, juallah kepadaku berapa harga (kebun kalian) \". Mereka menjawab: \"Kami tidak menjualnya kecuali kepada Allah\". Maka Beliau memerintahkan quburan-quburan Kaum Musyrikin agar digali lalu bangunan-bangunannya dihancurkan kemudian diratakan dengan tanah dan memerintahkan pula agar pohon-pohon kurma ditebang lalu batang pepohonan itu dipasang bersusun untuk arah qiblat masjid."},"1736":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حُرِّمَ مَا بَيْنَ لَابَتَيْ الْمَدِينَةِ عَلَى لِسَانِي قَالَ وَأَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَنِي حَارِثَةَ فَقَالَ أَرَاكُمْ يَا بَنِي حَارِثَةَ قَدْ خَرَجْتُمْ مِنْ الْحَرَمِ ثُمَّ الْتَفَتَ فَقَالَ بَلْ أَنْتُمْ فِيهِ","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] berkata, telah menceritakan kepada saya [saudaraku] dari [Sulaiman] dari ['Ubaidullah bin 'Umar] dari [Sa'id Al Maqbariy] dari [Abu Hurairah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Daerah yang disucikan (haram) di Madinah ini adalah antara dua buah batu hitam sebagaimana aku sabdakan\". Kemudian Nabi shallallahu 'alaihi wasallam mendatangi desa Banu Haritsah seraya bersabda: \"Aku memandang sepertinya kalian berada diluar dari tanah haram\". Kemudian Beliau terdiam sejenak lalu bersabda lagi: \"Tidak, bahkan kalian berada pada tanah haram\"."},"1737":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِيهِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَمَا عِنْدَنَا شَيْءٌ إِلَّا كِتَابُ اللَّهِ وَهَذِهِ الصَّحِيفَةُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةُ حَرَمٌ مَا بَيْنَ عَائِرٍ إِلَى كَذَا مَنْ أَحْدَثَ فِيهَا حَدَثًا أَوْ آوَى مُحْدِثًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ صَرْفٌ وَلَا عَدْلٌ وَقَالَ ذِمَّةُ الْمُسْلِمِينَ وَاحِدَةٌ فَمَنْ أَخْفَرَ مُسْلِمًا فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ صَرْفٌ وَلَا عَدْلٌ وَمَنْ تَوَلَّى قَوْمًا بِغَيْرِ إِذْنِ مَوَالِيهِ فَعَلَيْهِ لَعْنَةُ اللَّهِ وَالْمَلَائِكَةِ وَالنَّاسِ أَجْمَعِينَ لَا يُقْبَلُ مِنْهُ صَرْفٌ وَلَا عَدْلٌقَالَ أَبُو عَبْد اللَّهِ عَدْلٌ فِدَاءٌ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami ['Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim at-Taymiy] dari [bapaknya] dari ['Ali radliallahu 'anhu] berkata: \"Tidak ada sesuatu yang kami miliki kecuali Kitabulloh dan ash-shahifah (lembaran-lembaran hadits) ini, dari Nabi shallallahu 'alaihi wasallam bersabda: \"Madinah adalah tanah suci yang wilayahnya antara gurun sahara hingga ini. Maka barangsiapa yang berbuat kemungkaran (bid'ah) yang dilarang agama didalamnya atau membantu orang berbuat bid'ah maka orang itu akan mendapat laknat dari Allah, para malaikat dan seluruh manusia dan tidak akan diterima darinya amalan 'ibadah wajib dan sunnahnya\" (atau taubat dan tebusannya). Dan Beliau bersabda: \"Perlindungan Kaum Muslimin adalah satu, maka barangsiapa melepas ikatan perjanjian dengan seorang muslim maka orang itu akan mendapat laknat dari Allah, para malaikat dan seluruh manusia dan tidak akan diterima darinya amalan 'ibadah wajib dan sunnahnya baginya dan barangsiapa yang mengambil perwalian suatu kaum tanpa seizin walinya maka orang itu akan mendapat laknat dari Allah, para malaikat dan seluruh manusia dan tidak akan diterima darinya amalan 'ibadah wajib dan sunnahnya\". Berkata, Abu 'Abdullah Al Bukhariy: istilah al'adh artinya: \"Tebusan\"."},"1738":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ سَمِعْتُ أَبَا الْحُبَابِ سَعِيدَ بْنَ يَسَارٍ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْتُ بِقَرْيَةٍ تَأْكُلُ الْقُرَى يَقُولُونَ يَثْرِبُ وَهِيَ الْمَدِينَةُ تَنْفِي النَّاسَ كَمَا يَنْفِي الْكِيرُ خَبَثَ الْحَدِيدِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Yahya bin Sa'id] berkata, aku mendengar [Abu Al Hubab Sa'id bin Yasar] berkata; Aku mendengar [Abu Hurairah radliallahu 'anhu] berkata,, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku diperintahkan (untuk berhijrah) ke suatu tempat yang daya tariknya lebih dominan daripada tempat-tempat lain, yaitu kota Madinah, kota ini membersihklan manusia (yang jahat) sebagaimana alat tempa besi yang membersihkan karat besi\". "},"1739":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ قَالَ حَدَّثَنِي عَمْرُو بْنُ يَحْيَى عَنْ عَبَّاسِ بْنِ سَهْلِ بْنِ سَعْدٍ عَنْ أَبِي حُمَيْدٍ رَضِيَ اللَّهُ عَنْهُأَقْبَلْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ تَبُوكَ حَتَّى أَشْرَفْنَا عَلَى الْمَدِينَةِ فَقَالَ هَذِهِ طَابَةٌ","id":"Telah menceritakan kepada kami [Khalid bin Mukhallad] telah menceritakan kepada kami [Sulaiman] berkata, telah menceritakan kepada saya ['Amru bin Yahya] dari ['Abbas bin Sahal bin Sa'ad] dari [Abu Humaid radliallahu 'anhu]: Kami berjumpa dengan Nabi shallallahu 'alaihi wasallam di Tabuk hingga kami kembali ke Madinah dimana kemudian Beliau berkata: 'Ini adalah Thobah\"."},"1740":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ كَانَ يَقُولُلَوْ رَأَيْتُ الظِّبَاءَ بِالْمَدِينَةِ تَرْتَعُ مَا ذَعَرْتُهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَيْنَ لَابَتَيْهَا حَرَامٌ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] bahwa dia berkata: \"Seandainya aku melihat seekor kijang sedang digembalakan di Madinah ini tentu aku tidak akan membuatnya terkejut (menggannggunya). Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Antara dua batu hitam kota Madinah adalah tanah haram\"."},"1741":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَ��ْرُكُونَ الْمَدِينَةَ عَلَى خَيْرِ مَا كَانَتْ لَا يَغْشَاهَا إِلَّا الْعَوَافِ يُرِيدُ عَوَافِيَ السِّبَاعِ وَالطَّيْرِ وَآخِرُ مَنْ يُحْشَرُ رَاعِيَانِ مِنْ مُزَيْنَةَ يُرِيدَانِ الْمَدِينَةَ يَنْعِقَانِ بِغَنَمِهِمَا فَيَجِدَانِهَا وَحْشًا حَتَّى إِذَا بَلَغَا ثَنِيَّةَ الْوَدَاعِ خَرَّا عَلَى وُجُوهِهِمَا","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Sa'id bin Al Musayab] bahwa [Abu Hurairah radliallahu 'anhu] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Suatu saat nanti penduduk akan meninggalkan Madinah dalam keadaan baik sebagaimana keadaannya semula. Tidak ada lagi yang mendatanginya kecuali 'awaf, yaitu binatang-binatang buas dan burung-burung. Orang terakhir yang akan meninggal adalah dua orang pengembala dari suku Muzaynah yang keduanya mendatangi Madinah untuk menghalau kambing, lalu di Madinah keduanya mendapati binatang liar hingga ketika keduanya tiba di bukit Wada' keduanya jatuh tersungkur karena pingsan\". "},"1742":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ سُفْيَانَ بْنِ أَبِي زُهَيْرٍ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تُفْتَحُ الْيَمَنُ فَيَأْتِي قَوْمٌ يُبِسُّونَ فَيَتَحَمَّلُونَ بِأَهْلِهِمْ وَمَنْ أَطَاعَهُمْ وَالْمَدِينَةُ خَيْرٌ لَهُمْ لَوْ كَانُوا يَعْلَمُونَ وَتُفْتَحُ الشَّأْمُ فَيَأْتِي قَوْمٌ يُبِسُّونَ فَيَتَحَمَّلُونَ بِأَهْلِيهِمْ وَمَنْ أَطَاعَهُمْ وَالْمَدِينَةُ خَيْرٌ لَهُمْ لَوْ كَانُوا يَعْلَمُونَ وَتُفْتَحُ الْعِرَاقُ فَيَأْتِي قَوْمٌ يُبِسُّونَ فَيَتَحَمَّلُونَ بِأَهْلِيهِمْ وَمَنْ أَطَاعَهُمْ وَالْمَدِينَةُ خَيْرٌ لَهُمْ لَوْ كَانُوا يَعْلَمُونَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Abdullah bin Az Zubair] dari [Sufyan bin Abu Zuhair radliallahu 'anhu] bahwa dia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Nanti negeri Yaman akan ditaklukkkan lalu akan datang suatu kaum yang menggiring hewan tunggangan mereka secara perlahan-lahan menuju lokasi tersebut dengan membawa keluarga dan orang-orang yang menaati mereka. Dan Madinah lebih baik bagi mereka seandainya merka mengetahui. Kemudian negeri Syam akan ditaklukkan, lalu akan datang suatu kaum yang menggiring hewan tunggangan mereka secara perlahan-lahan menuju negeri tersebut dengan membawa keluarga dan orang-orang yang menaati mereka. Padahal Madinah lebih baik bagi mereka seandainya merka mengetahui. Kemudian negeri 'Iraq akan ditaklukkan lalu akan datang suatu kaum yang menggiring hewan tunggangan mereka secara perlahan-lahan menuju negeri tersebut dengan membawa keluarga dan orang-orang yang mentaati mereka. Padahal Madinah lebih baik bagi mereka seandainya merka mengetahui\"."},"1743":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْإِيمَانَ لَيَأْرِزُ إِلَى الْمَدِينَةِ كَمَا تَأْرِزُ الْحَيَّةُ إِلَى جُحْرِهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Anas bin 'Iyadh] berkata, telah menceritakan kepada saya ['Ubaidullah] dari [Khubaib bin 'Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Iman akan menyebar di Madinah sebagaimana ular yang keluar (mencari makan) lalu masuk kedalam lubangnya (untuk berlindung) \"."},"1744":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ حُرَيْثٍ أَخْبَرَنَا الْفَضْلُ عَنْ جُعَيْدٍ عَنْ عَائِشَةَ هِيَ بِنْتُ سَعْدٍ قَالَتْ سَمِعْتُ سَعْدًا رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَكِيدُ أَهْلَ الْمَدِينَةِ أَحَدٌ إِلَّا انْمَاعَ كَمَا يَنْمَاعُ الْمِلْحُ فِي الْمَاءِ","id":"Telah menceritakan kepada kami [Husain bin Huraits] telah mengabarkan kepada kami [Al Fadhal] dari [Ju'aid] dari ['Aisyah, yang maksudnya anak puteri Sa'ad] berkata; aku mendengar [Sa'ad radliallahu 'anhu] berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: 'Tidak ada seorangpun yang memperdaya (membuat tipu daya) bagi penduduk Madinah kecuali dia akan binasa sebagaimana binasanya garam yang larut dalam air\"."},"1745":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا ابْنُ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ سَمِعْتُ أُسَامَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَشْرَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أُطُمٍ مِنْ آطَامِ الْمَدِينَةِ فَقَالَ هَلْ تَرَوْنَ مَا أَرَى إِنِّي لَأَرَى مَوَاقِعَ الْفِتَنِ خِلَالَ بُيُوتِكُمْ كَمَوَاقِعِ الْقَطْرِتَابَعَهُ مَعْمَرٌ وَسُلَيْمَانُ بْنُ كَثِيرٍ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Ibnu Syihab] berkata, telah mengabarkan kepadaku ['Urwah] aku mendengar [Usamah radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam naik ke atas salah satu dari benteng-benteng Madinah lalu berkata: \"Apakah kalian melihat sebagaimana aku melihat?. Sungguh aku melihat tempat-tempat terjadinya fitnah di sela-sela rumah kalian seperti tempat jatuhnya tetesan (air hujan) \". Hadits ini disampaikan pula oleh [Ma'mar] dan [Sulaiman bin Katsir] dari [Az Zuhriy]. "},"1746":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ أَبِي بَكْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْمَدِينَةَ رُعْبُ الْمَسِيحِ الدَّجَّالِ لَهَا يَوْمَئِذٍ سَبْعَةُ أَبْوَابٍ عَلَى كُلِّ بَابٍ مَلَكَانِ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepada saya [Ibrahim bin Sa'ad] dari [bapaknya] dari [kakeknya] dari [Abu Bakrah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Al Masihud-Dajjal yang ditakuti tidak akan dapat memasuki kota Madinah. Pada hari itu Madinah memiliki tujuh pintu yang setiap pintunya akan ada dua malaikat (yang menjaganya) \"."},"1747":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَنْقَابِ الْمَدِينَةِ مَلَائِكَةٌ لَا يَدْخُلُهَا الطَّاعُونُ وَلَا الدَّجَّالُ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Malik] dari [Nu'aim bin 'Abdullah Al Mujmir] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada pintu gerbang kota Madinah ada para malaikat (yang menjaganya) sehingga wabah penyakit dan Al Masihud-Dajjal tidak akan dapat memasukinya\"."},"1748":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا الْوَلِيدُ حَدَّثَنَا أَبُو عَمْرٍو حَدَّثَنَا إِسْحَاقُ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ مِنْ بَلَدٍ إِلَّا سَيَطَؤُهُ الدَّجَّالُ إِلَّا مَكَّةَ وَالْمَدِينَةَ لَيْسَ لَهُ مِنْ نِقَابِهَا نَقْبٌ إِلَّا عَلَيْهِ الْمَلَائِكَةُ صَافِّينَ يَحْرُسُونَهَا ثُمَّ تَرْجُفُ الْمَدِينَةُ بِأَهْلِهَا ثَلَاثَ رَجَفَاتٍ فَيُخْرِجُ اللَّهُ كُلَّ كَافِرٍ وَمُنَافِقٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Al Walid] telah menceritakan kepada kami [Abu 'Amru] telah menceritakan kepada kami [Ishaq] telah menceritakan kepada saya [Anas bin Malik radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada suatu negeripun yang tidak akan dimasuki Dajjal kecuali Makkah dan Madinah, karena tidak ada satu pintu masukpun dari pintu-pintu gerbangnya kecuali ada para malaikat yang berbaris menjaganya. Kemudian Madinah akan berguncang sebanyak tiga kali sehingga Allah mengeluarkan orang-orang kafir dan munafiq daripadanya\". "},"1749":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ قَالَحَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثًا طَوِيلًا عَنْ الدَّجَّالِ فَكَانَ فِيمَا حَدَّثَنَا بِهِ أَنْ قَالَ يَأْتِي الدَّجَّالُ وَهُوَ مُحَرَّمٌ عَلَيْهِ أَنْ يَدْخُلَ نِقَابَ الْمَدِينَةِ بَعْضَ السِّبَاخِ الَّتِي بِالْمَدِينَةِ فَيَخْرُجُ إِلَيْهِ يَوْمَئِذٍ رَجُلٌ هُوَ خَيْرُ النَّاسِ أَوْ مِنْ خَيْرِ النَّاسِ فَيَقُولُ أَشْهَدُ أَنَّكَ الدَّجَّالُ الَّذِي حَدَّثَنَا عَنْكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيثَهُ فَيَقُولُ الدَّجَّالُ أَرَأَيْتَ إِنْ قَتَلْتُ هَذَا ثُمَّ أَحْيَيْتُهُ هَلْ تَشُكُّونَ فِي الْأَمْرِ فَيَقُولُونَ لَا فَيَقْتُلُهُ ثُمَّ يُحْيِيهِ فَيَقُولُ حِينَ يُحْيِيهِ وَاللَّهِ مَا كُنْتُ قَطُّ أَشَدَّ بَصِيرَةً مِنِّي الْيَوْمَ فَيَقُولُ الدَّجَّالُ أَقْتُلُهُ فَلَا أُسَلَّطُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya ['Ubaidullah bin 'Abdullah bin 'Uqbah] bahwa [Abu Sa'id Al Khudriy radliallahu 'anhu] berkata, telah menceritakan kepada kami Rasulullah shallallahu 'alaihi wasallam dengan pembicaraan yang panjang tentang Dajjal. Diantara yang Beliau ceritakan tentangnya adalah, Beliau berkata: \"Dajjal akan datang pada suatu tanah yang tandus di Madinah (untuk memasuki Madinah) padahal dia diharamkan untuk memasuki pintu-pintu gerbang Madinah. Maka pada hari itu keluarlah seorang laki-laki yang merupakan manusia terbaik atau salah seorang dari manusia terbaik menghadangnya seraya berkata; Aku bersaksi bahwa kamu adalah Dajjal yang pernah diceritakan oleh Rasulullah shallallahu 'alaihi wasallam. Maka Dajjal berkata; Bagaimana sikap kalian jika aku membunuh orang ini lalu aku menghidupkannya kembali, apakah kalian masih meragukan kemampuanku?. Mereka menjawab: \"Tidak\". Maka Dajjal membunuh laki-laki terbaik itu lalu menghidupkannya kembali. Laki-laki itu berkata, ketika Dajjal menghidupkannya kembali; \"Demi Allah, hari aku tidak akan lebih waspada kecuali terhadap diriku sendiri. Maka Dajjal berkata; \"Aku akan membunuhnya lagi\". Maka Dajjal tidak sanggup untuk menguasainya\". "},"1750":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَبَّاسٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُجَاءَ أَعْرَابِيٌّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَايَعَهُ عَلَى الْإِسْلَامِ فَجَاءَ مِنْ الْغَدِ مَحْمُومًا فَقَالَ أَقِلْنِي فَأَبَى ثَلَاثَ مِرَارٍ فَقَالَ الْمَدِينَةُ كَالْكِيرِ تَنْفِي خَبَثَهَا وَيَنْصَعُ طَيِّبُهَا","id":"Telah menceritakan kepada kami ['Amru bin 'Abbas] telah menceritakan kepada kami ['Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Al Munkadir] dari [Jabir radliallahu 'anhu]: Ada seorang 'Arab Badwi menemui Nabi shallallahu 'alaihi wasallam lalu berbai'at untuk masuk Islam. Keesokan harinya dia datang lagi dalam keadaan menderita sakit demam lalu berkata: \"Bebaskan aku (Batalkan baiatku) \". (Dia minta keluar dari Islam). Namun Beliau tidak mengabulkannya. Permintaannya itu dilakukan hingga tiga kali. Maka Beliau shallallahu 'alaihi wasallam bersabda: \"Madinah ini seperti alat penempa besi, yang membersihkan orang-orang jelek darinya dan akan menyeleksi orang-orang yang baik saja (untuk tinggal didalamnya) \". "},"1751":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ سَمِعْتُ زَيْدَ بْنَ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُلَمَّا خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أُحُدٍ رَجَعَ نَاسٌ مِنْ أَصْحَابِهِ فَقَالَتْ فِرْقَةٌ نَقْتُلُهُمْ وَقَالَتْ فِرْقَةٌ لَا نَقْتُلُهُمْ فَنَزَلَتْ{ فَمَا لَكُمْ فِي الْمُنَافِقِينَ فِئَتَيْنِ }وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا تَنْفِي الرِّجَالَ كَمَا تَنْفِي النَّارُ خَبَثَ الْحَدِيدِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari ['Adiy bin Tsabit] dari ['Abdullah bin Yazid] berkata; Aku mendengar [Zaid bin Tsabit radliallahu 'anhu] berkata, Ketika Nabi shallallahu 'alaihi wasallam keluar (untuk perang) menuju Uhud, sebagian dari para sahabat ada yang mundur. Sebagian kelompok dari sahabat ada yang berkata: \"Kita akan bunuh mereka\", dan sebagian kelompok lain berkata; \"Kita tidak akan membunuh mereka\". Maka kemudian turunlah firman Allah Ta'ala QS Qn-Nisa ayat 88 yang artinya: (\"Mengapa kalian (terpecah) menjadi dua golongan (yang berbeda pendapat) dalam menyikapi orang-orang munafiqin..?\"). Dan Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kota Madinah ini akan membersihkan orang-orang sebagaimana api membersihkan karatnya besi\". "},"1752":{"ar":"بَاب حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا أَبِي سَمِعْتُ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ اجْعَلْ بِالْمَدِينَةِ ضِعْفَيْ مَا جَعَلْتَ بِمَكَّةَ مِنْ الْبَرَكَةِتَابَعَهُ عُثْمَانُ بْنُ عُمَرَ عَنْ يُونُسَ","id":"Bab. Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Wahab bin Jarir] telah menceritakan kepada kami [bapakku] ms [Yunus] dari [Ibnu Syihab] dari [Anas radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Ya Allah jadikanlah Madinah seperti Makkah, yang dimana Engkau telah menjadikannya (Makkah) penuh dengan barakah\". Hadits ini diikuti oelh ['Utsman bin 'Umar] dari [Yunus]."},"1753":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَدِمَ مِنْ سَفَرٍ فَنَظَرَ إِلَى جُدُرَاتِ الْمَدِينَةِ أَوْضَعَ رَاحِلَتَهُ وَإِنْ كَانَ عَلَى دَابَّةٍ حَرَّكَهَا مِنْ حُبِّهَا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Humaid] dari [Anas radliallahu 'anhu] berkata; Bahwa Nabi shallallahu 'alaihi wasallam apabila pulang dari bepergian dan melihat dataran tinggi kota Madinah, Beliau mempercepat jalan unta Beliau dan bila menunggang hewan lain Beliau memacunya karena kecintaannya (kepada Madinah). "},"1754":{"ar":"حَدَّثَنَا ابْنُ سَلَامٍ أَخْبَرَنَا الْفَزَارِيُّ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَرَادَ بَنُو سَلِمَةَ أَنْ يَتَحَوَّلُوا إِلَى قُرْبِ الْمَسْجِدِ فَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُعْرَى الْمَدِينَةُ وَقَالَ يَا بَنِي سَلِمَةَ أَلَا تَحْتَسِبُونَ آثَارَكُمْ فَأَقَامُوا","id":"Telah menceritakan kepada kami [Ibnu Salam] telah menceritakan kepada kami [Al Fazariy] dari [Humaid Ath-Thowil] dari [Anas radliallahu 'anhu] berkata; Bani Salamah berkehendak untuk pindah tempat tinggal yang mendekat dengan masjid (Nabawi), namun Rasulullah shallallahu 'alaihi wasallam kurang setuju bila Madinah kosong ditinggal manusia, maka Beliau berkata: \"Wahai Bani Salamah, bukankah jejak langkah kalian akan diperhitungkan?. Maka mereka tetap tinggal di tempat mereka semula. "},"1755":{"ar":"بَاب حَدَّثَنَا مُسَدَّدٌ عَنْ يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ قَالَ حَدَّثَنِي خُبَيْبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا بَيْنَ بَيْتِي وَمِنْبَرِي رَوْضَةٌ مِنْ رِيَاضِ الْجَنَّةِ وَمِنْبَرِي عَلَى حَوْضِي","id":"Bab. Telah menceritakan kepada kami [Musaddad] dari [Yahya] dari ['Ubaidullah bin 'Umar] berkata, telah menceritakan kepada saya [Khubaib bin 'Abdurrahman] dari [Hafsh bin 'Ashim] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Diantara rumahku dan mimbarku adalah raudhah (taman) diantara taman-taman surga dan mimbarku berada pada telagaku (di surga) \". "},"1756":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وُعِكَ أَبُو بَكْرٍ وَبِلَالٌ فَكَانَ أَبُو بَكْرٍ إِذَا أَخَذَتْهُ الْحُمَّى يَقُولُ كُلُّ امْرِئٍ مُصَبَّحٌ فِي أَهْلِهِوَالْمَوْتُ أَدْنَى مِنْ شِرَاكِ نَعْلِهِوَكَانَ بِلَالٌ إِذَا أُقْلِعَ عَنْهُ الْحُمَّى يَرْفَعُ عَقِيرَتَهُ يَقُولُ أَلَا لَيْتَ شِعْرِي هَلْ أَبِيتَنَّ لَيْلَةًبِوَادٍ وَحَوْلِي إِذْخِرٌ وَجَلِيلُوَهَلْ أَرِدَنْ يَوْمًا مِيَاهَ مَجَنَّةٍوَهَلْ يَبْدُوَنْ لِي شَامَةٌ وَطَفِيلُقَالَ اللَّهُمَّ الْعَنْ شَيْبَةَ بْنَ رَبِيعَةَ وَعُتْبَةَ بْنَ رَبِيعَةَ وَأُمَيَّةَ بْنَ خَلَفٍ كَمَا أَخْرَجُونَا مِنْ أَرْضِنَا إِلَى أَرْضِ الْوَبَاءِ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ حَبِّبْ إِلَيْنَا الْمَدِينَةَ كَحُبِّنَا مَكَّةَ أَوْ أَشَدَّ اللَّهُمَّ بَارِكْ لَنَا فِي صَاعِنَا وَفِي مُدِّنَا وَصَحِّحْهَا لَنَا وَانْقُلْ حُمَّاهَا إِلَى الْجُحْفَةِ قَالَتْ وَقَدِمْنَا الْمَدِينَةَ وَهِيَ أَوْبَأُ أَرْضِ اللَّهِ قَالَتْ فَكَانَ بُطْحَانُ يَجْرِي نَجْلًا تَعْنِي مَاءً آجِنًا","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata; Ketika Rasulullah shallallahu 'alaihi wasallam sampai di Madinah, Abu Bakar dan Bilal menderita sakit demam. Dan Abu Bakar bila merasakan demam yang panas bersya'ir; Setiap orang pada pagi hari bersantai dengan keluarganya. Padahal kematian lebih dekat dari pada tali sandalnya. Dan Bilal ketika sembuh dari penakit demamnya dia bersa'ir dengan suara keras: Wahai kiranya kesadaranku, dapatkah kiranya aku bermalam semalam. Di sebuah lembah yang dikelilingi pohon idzkir dan jalil. Apakah ada suatu hari nanti aku dapat mencapai air Majannah. Dan apakah bukit Syamah dan Thufail akan tampak bagiku?. Lalu dia berkata: \"Ya Allah, laknatlah Syaibah bin Rabi'ah, 'Uqbah bin Rabi'ah dan Umayyah bin Khalaf yang telah mengusir kami dari suatu negeri ke negeri yang penuh dengan wabah bencana ini\". Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, jadikanlah Madinah sebagai kota yang kami cintai sebagaimana kami mencintai Makkah atau bahkan lebih dari itu. Ya Allah, berikanlah barakah kepada kami dalam timbangan sha' dan mud kami sehatkanlah (makmurkan) Madinah buat kami dan pindahkanlah wabah demamnya ke Juhfah\". 'Aisyah radliallahu 'anha berkata; Ketika kami tiba di Madinah, saat itu Madinah adalah bumi Allah yang paling banyak wabah bencananya. Sambungnya lagi: \"Lembah Bathhan mengalirkan air keruh yang mengandung kuman-kuman penyakit\"."},"1757":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَاللَّهُمَّ ارْزُقْنِي شَهَادَةً فِي سَبِيلِكَ وَاجْعَلْ مَوْتِي فِي بَلَدِ رَسُولِكَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَوَقَالَ ابْنُ زُرَيْعٍ عَنْ رَوْحِ بْنِ الْقَاسِمِ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِيهِ عَنْ حَفْصَةَ بِنْتِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَتْ سَمِعْتُ عُمَرَ نَحْوَهُ وَقَالَ هِشَامٌ عَنْ زَيْدٍ عَنْ أَبِيهِ عَنْ حَفْصَةَ سَمِعْتُ عُمَرَ رَضِيَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Zaid bin Aslam] dari [bapaknya] dari ['Umar radliallahu 'anhu] berkata: \"Ya Allah berilah aku mati syahid dijalanMu, dan jadikanlah kematianku di negeri RasulMu, shallallahu 'alaihi wasallam). Dan [Ibnu Zurai'] berkata, dari [Rauh bin Al Qasim] dari [Zaid bin Aslam] dari [bapaknya] dari [Hafshah binti 'Umar radliallahu 'anhuma] berkata; \"Aku mendengar ['Umar] seperti hadits ini\". Dan [Hisyam] berkata, dari [Zaid] dari [bapaknya] dari [Hafshah]; Aku mendengar ['Umar radliallahu 'anhu]."},"1758":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ أَبِي سُهَيْلٍ عَنْ أَبِيهِ عَنْ طَلْحَةَ بْنِ عُبَيْدِ اللَّهِأَنَّ أَعْرَابِيًّا جَاءَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَائِرَ الرَّأْسِ فَقَالَ يَا رَسُولَ اللَّهِ أَخْبِرْنِي مَاذَا فَرَضَ اللَّهُ عَلَيَّ مِنْ الصَّلَاةِ فَقَالَ الصَّلَوَاتِ الْخَمْسَ إِلَّا أَنْ تَطَّوَّعَ شَيْئًا فَقَالَ أَخْبِرْنِي مَا فَرَضَ اللَّهُ عَلَيَّ مِنْ الصِّيَامِ فَقَالَ شَهْرَ رَمَضَانَ إِلَّا أَنْ تَطَّوَّعَ شَيْئًا فَقَالَ أَخْبِرْنِي بِمَا فَرَضَ اللَّهُ عَلَيَّ مِنْ الزَّكَاةِ فَقَالَ فَأَخْبَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرَائِعَ الْإِسْلَامِ قَالَ وَالَّذِي أَكْرَمَكَ لَا أَتَطَوَّعُ شَيْئًا وَلَا أَنْقُصُ مِمَّا فَرَضَ اللَّهُ عَلَيَّ شَيْئًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْلَحَ إِنْ صَدَقَ أَوْ دَخَلَ الْجَنَّةَ إِنْ صَدَقَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada saya [Isma'il bin Ja'far] dari [Abu Suhail] dari [Bapaknya] dari [Tholhah bin 'Ubaidullah]; Ada seorang 'Arab Baduy datang kepada Rasululloh shallallahu 'alaihi wasallam dalam keadaan kepalanya penuh debu lalu berkata; \"Wahai Rasulullah, kabarkan kepadaku apa yang telah Allah wajibkan buatku tentang shalat?\". Maka Beliau shallallahu 'alaihi wasallam menjawab: \"Shalat lima kali kecuali bila kamu mau menambah dengan yang tathowwu' (sunnat) \". Orang itu bertanya lagi: \"Lalu kabarkan kepadaku apa yang telah Allah wajibkan buatku tentang shaum (puasa)?\". Maka Beliau shallallahu 'alaihi wasallam menjawab: \"Shaum di bulan Ramadhan kecuali bila kamu mau menambah dengan yang tathowwu' (sunnat) \".\"Dan shiyam (puasa) Ramadhan\". Orang itu bertanya lagi: \"Lalu kabarkan kepadaku apa yang telah Allah wajibkan buatku tentang zakat?\". Berkata, Tholhah bin 'Ubaidullah radliallahu 'anhu: Maka Rasulullah shallallahu 'alaihi wasallam menjelaskan kepada orang itu tentang syari-at-syari'at Islam. Kemudian orang itu berkata: \"Demi Dzat yang telah memuliakan anda, Aku tidak akan mengerjakan yang sunnah sekalipun, namun aku pun tidak akan mengurangi satupun dari apa yang telah Allah wajibkan buatku\". Maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Dia akan beruntung jika jujur menepatinya atau dia akan masuk surga jika jujur menepatinya \"."},"1759":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا إِسْمَاعِيلُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَصَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَاشُورَاءَ وَأَمَرَ بِصِيَامِهِ فَلَمَّا فُرِضَ رَمَضَانُ تُرِكَ وَكَانَ عَبْدُ اللَّهِ لَا يَصُومُهُ إِلَّا أَنْ يُوَافِقَ صَوْمَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam melaksanakan puasa hari 'Asyura' (10 Muharam) lalu memerintahkan (para sahabat) untuk melaksanakannya pula. Setelah Allah mewajibklan puasa Ramadhan, maka puasa hari 'Asyura' ditinggalkan. Dan 'Abdullah bin 'Umar radliallahu 'anhu tidaklah melaksanakan puasa hari 'Asyura' kecuali bila bertepatan dengan hari-hari puasa yang biasa dikerjakannya\"."},"1760":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَنَّ عِرَاكَ بْنَ مَالِكٍ حَدَّثَهُ أَنَّ عُرْوَةَ أَخْبَرَهُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ قُرَيْشًا كَانَتْ تَصُومُ يَوْمَ عَاشُورَاءَ فِي الْجَاهِلِيَّةِ ثُمَّ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِصِيَامِهِ حَتَّى فُرِضَ رَمَضَانُ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَاءَ فَلْيَصُمْهُ وَمَنْ شَاءَ أَفْطَرَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] bahwa ['Irak bin Malik] menceritakan kepadanya bahwa ['Urwah] mengabarkan kepadanya dari ['Aisyah radliallahu 'anha]; Bahwa orang-orang Quraisy pada zaman Jahiliyah biasa melaksanakan puasa hari 'Asyura'. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk melaksanakannya pula hingga datang kewajiban shaum Ramadhan. Dan kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang mau melaksanakannya silakan dan siapa yang tidak mau juga tidak apa\". "},"1761":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الصِّيَامُ جُنَّةٌ فَلَا يَرْفُثْ وَلَا يَجْهَلْ وَإِنْ امْرُؤٌ قَاتَلَهُ أَوْ شَاتَمَهُ فَلْيَقُلْ إِنِّي صَائِمٌ مَرَّتَيْنِ وَالَّذِي نَفْسِي بِيَدِهِ لَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ تَعَالَى مِنْ رِيحِ الْمِسْكِ يَتْرُكُ طَعَامَهُ وَشَرَابَهُ وَشَهْوَتَهُ مِنْ أَجْلِي الصِّيَامُ لِي وَأَنَا أَجْزِي بِهِ وَالْحَسَنَةُ بِعَشْرِ أَمْثَالِهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Abu Az Zanad] dari [Al A'raj] dari [Abu Hurairah radliallahu 'anhu]; Bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shaum itu benteng, maka (orang yang melaksanakannya) janganlah berbuat kotor (rafats) dan jangan pula berbuat bodoh. Apabila ada orang yang mengajaknya berkelahi atau menghinanya maka katakanlah aku sedang shaum (ia mengulang ucapannya dua kali). Dan demi Dzat yang jiwaku berada di tanganNya, sungguh bau mulut orang yang sedang shaum lebih harum di sisi Allah Ta'ala dari pada harumnya minyak misik, karena dia meninggalkan makanannya, minuman dan nafsu syahwatnya karena Aku. Shaum itu untuk Aku dan Aku sendiri yang akan membalasnya dan setiap satu kebaikan dibalas dengan sepuiluh kebaikan yang serupa\". "},"1762":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا جَامِعٌ عَنْ أَبِي وَائِلٍ عَنْ حُذَيْفَةَ قَالَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ مَنْ يَحْفَظُ حَدِيثًا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْفِتْنَةِ قَالَ حُذَيْفَةُ أَنَا سَمِعْتُهُ يَقُولُ فِتْنَةُ الرَّجُلِ فِي أَهْلِهِ وَمَالِهِ وَجَارِهِ تُكَفِّرُهَا الصَّلَاةُ وَالصِّيَامُ وَالصَّدَقَةُ قَالَ لَيْسَ أَسْأَلُ عَنْ ذِهِ إِنَّمَا أَسْأَلُ عَنْ الَّتِي تَمُوجُ كَمَا يَمُوجُ الْبَحْرُ قَالَ وَإِنَّ دُونَ ذَلِكَ بَابًا مُغْلَقًا قَالَ فَيُفْتَحُ أَوْ يُكْسَرُ قَالَ يُكْسَرُ قَالَ ذَاكَ أَجْدَرُ أَنْ لَا يُغْلَقَ إِلَى يَوْمِ الْقِيَامَةِ فَقُلْنَا لِمَسْرُوقٍ سَلْهُ أَكَانَ عُمَرُ يَعْلَمُ مَنْ الْبَابُ فَسَأَلَهُ فَقَالَ نَعَمْ كَمَا يَعْلَمُ أَنَّ دُونَ غَدٍ اللَّيْلَةَ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Jami'] dari [Abu Wa'il] dari [Hudzaifah radliallahu 'anhu] berkata; \"Pada suatu hari 'Umar radliallahu 'anhu berkata: \"Siapa yang masih hafal hadits dari Nabi shallallahu 'alaihi wasallam tentang masalah fitnah? Hudzaifah berkata: \"Aku mendengarnya saat Beliau bersabda: \"Yaitu suatu fitnah seseorang dalam keluarganya, harta, anak dan tetangganya. Namun fitnah itu akan terhapus oleh shalat, shaum. shadaqah\". 'Umar berkata: \"Aku bertanya bukan masalah itu. Tapi aku bertanya tentang fitnah yang meluas seperti melubernya air lautan. Hudzaifah berkata: \"Sesungguhnya selain itu ada satu pintu\". 'Umar bertanya: \"Pintu itu terbuka atau sudah rusak?\". Hudzaifah berkata: \"Pintu yang rusak\". 'Umar berkata: \"Kalau begitu pintu itu tidak akan bisa ditutup hingga hari qiyamat\". Maka kami berkata, kepada Masruq: \"Tanyakanlah kepadanya apakah 'Umar mengerti siapa yang dimaksud dengan pintu itu\". Hudzaifah berkata: \"Ya, dia mengerti. Sebagaimana mengertinya dia bahwa setelah besok pasti malam hari\". "},"1763":{"ar":"حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجَنَّةِ بَابًا يُقَالُ لَهُ الرَّيَّانُ يَدْخُلُ مِنْهُ الصَّائِمُونَ يَوْمَ الْقِيَامَةِ لَا يَدْخُلُ مِنْهُ أَحَدٌ غَيْرُهُمْ يُقَالُ أَيْنَ الصَّائِمُونَ فَيَقُومُونَ لَا يَدْخُلُ مِنْهُ أَحَدٌ غَيْرُهُمْ فَإِذَا دَخَلُوا أُغْلِقَ فَلَمْ يَدْخُلْ مِنْهُ أَحَدٌ","id":"Telah menceritakan kepada kami [Khalid bin Mukhallad] telah menceritakan kepada kami [Sulaiman bin Bilal] berkata, telah menceritakan kepada saya [Abu Hazim] dari [Sahal radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Dalam surga ada satu pintu yang disebut dengan Ar-Rayyan, yang pada hari qiyamat tidak akan ada orang yang masuk ke surga melewati pintu itu kecuali para shaimun (orang-orang yang berpuasa). Tidak akan ada seorangpun yang masuk melewati pintu tersebut selain mereka. Lalu dikatakan kepada mereka; Mana para shaimun, maka para shaimun berdiri menghadap. Tidak akan ada seorangpun yang masuk melewati pintu tersebut selain mereka. Apabila mereka telah masuk semuanya, maka pintu itu ditutup dan tidak akan ada seorangpun yang masuk melewati pintu tersebut\"."},"1764":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ قَالَ حَدَّثَنِي مَعْنٌ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَنْفَقَ زَوْجَيْنِ فِي سَبِيلِ اللَّهِ نُودِيَ مِنْ أَبْوَابِ الْجَنَّةِ يَا عَبْدَ اللَّهِ هَذَا خَيْرٌ فَمَنْ كَانَ مِنْ أَهْلِ الصَّلَاةِ دُعِيَ مِنْ بَابِ الصَّلَاةِ وَمَنْ كَانَ مِنْ أَهْلِ الْجِهَادِ دُعِيَ مِنْ بَابِ الْجِهَادِ وَمَنْ كَانَ مِنْ أَهْلِ الصِّيَامِ دُعِيَ مِنْ بَابِ الرَّيَّانِ وَمَنْ كَانَ مِنْ أَهْلِ الصَّدَقَةِ دُعِيَ مِنْ بَابِ الصَّدَقَةِ فَقَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ مَا عَلَى مَنْ دُعِيَ مِنْ تِلْكَ الْأَبْوَابِ مِنْ ضَرُورَةٍ فَهَلْ يُدْعَى أَحَدٌ مِنْ تِلْكَ الْأَبْوَابِ كُلِّهَا قَالَ نَعَمْ وَأَرْجُو أَنْ تَكُونَ مِنْهُمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] berkata, telah menceritakan kepada saya [Ma'an] berkata, telah menceritakan kepada saya [Malik] dari [Ibnu Syihab] dari [Humaid bin 'Abdur Rahman] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menginfaqkan dua jenis (berpasangan) dari hartanya di jalan Allah, maka dia akan dipanggil dari pintu-pintu surga; (lalu dikatakan kepadanya): \"Wahai 'Abdullah, inilah kebaikan (dari apa yang kamu amalkan). Maka barangsiapa dari kalangan ahlu shalat dia akan dipanggil dari pintu shalat dan barangsiapa dari kalangan ahlu jihad dia akan dipanggil dari pintu jihad dan barangsiapa dari kalangan ahlu shiyam (puasa) dia akan dipanggil dari pintu ar-Rayyan dan barangsiapa dari kalangan ahlu shadaqah dia akan dipanggil dari pintu shadaqah\". Lantas Abu Bakar Ash-Shidiq radliallahu 'anhu: \"Demi bapak dan ibuku (sebagai tebusan) untukmu wahai Rasulullah, demi ayah dan ibuku, jika seseorang dipanggil diantara pintu-pintu yang ada, itu sbeuah kepastian, namun apakah mungkin seseorang akan dipanggil dari semua pintu?\". Beliau shallallahu 'alaihi wasallam menjawab: \"Benar, dan aku berharap kamu termasuk diantara mereka\"."},"1765":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ عَنْ أَبِي سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَاءَ رَمَضَانُ فُتِحَتْ أَبْوَابُ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Abu Suhail] dari [bapaknya] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila bulan Ramadhah datang, maka pintu-pintu surga dibuka\"."},"1766":{"ar":"حَدَّثَنِي يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي أَنَسٍ مَوْلَى التَّيْمِيِّينَ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ شَهْرُ رَمَضَانَ فُتِّحَتْ أَبْوَابُ السَّمَاءِ وَغُلِّقَتْ أَبْوَابُ جَهَنَّمَ وَسُلْسِلَتْ الشَّيَاطِينُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada saya [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya [Ibnu Abu Anas, maulanya at-Taymiyyiin] bahwa [bapaknya] menceritakan kepadanya bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila bulan Ramadhah datang, maka pintu-pintu langit dibuka sedangkan pintu-pintu jahannam ditutup dan syaitan-syaitan dibelenggu\"."},"1767":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَسَمِعْتُ رَسُولَ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا رَأَيْتُمُوهُ فَصُومُوا وَإِذَا رَأَيْتُمُوهُ فَأَفْطِرُوا فَإِنْ غُمَّ عَلَيْكُمْ فَاقْدُرُوا لَهُوَقَالَ غَيْرُهُ عَنْ اللَّيْثِ حَدَّثَنِي عُقَيْلٌ وَيُونُسُ لِهِلَالِ رَمَضَانَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] berkata, telah menceritakan kepada saya [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya [Salim bin 'Abdullah bin 'Umar] bahwa [Ibnu'Umar radliallahu 'anhuma] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kamu melihatnya maka berpuasalah dan jika kamu melihatnya lagi maka berbukalah. Apabila kalian terhalang oleh awan maka perkirakanlah jumlahnya (jumlah hari disempurnakan) \". Dan berkata, [selainnya] dari [Al Laits] telah menceritakan kepada saya ['Uqail] dan [Yunus]: \"Ini maksudnya untuk hilal bulan Ramadhan\". "},"1768":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Yahya] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menegakkan lailatul qadar (mengisi dengan ibadah) karena iman kepada Allah dan mengharapkan pahala (hanya dariNya) maka akan diampuni dosa-dosa yang telah dikerjakannya, dan barangsiapa yang melaksanakan shaum Ramadhan karena iman kepada Allah dan mengharapkan pahala (hanya dariNya) maka akan diampuni dosa-dosa yang telah dikerjakannya\"."},"1769":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ أَخْبَرَنَا ابْنُ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَجْوَدَ النَّاسِ بِالْخَيْرِ وَكَانَ أَجْوَدُ مَا يَكُونُ فِي رَمَضَانَ حِينَ يَلْقَاهُ جِبْرِيلُ وَكَانَ جِبْرِيلُ عَلَيْهِ السَّلَام يَلْقَاهُ كُلَّ لَيْلَةٍ فِي رَمَضَانَ حَتَّى يَنْسَلِخَ يَعْرِضُ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقُرْآنَ فَإِذَا لَقِيَهُ جِبْرِيلُ عَلَيْهِ السَّلَام كَانَ أَجْوَدَ بِالْخَيْرِ مِنْ الرِّيحِ الْمُرْسَلَةِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Ibrahim bin Sa'ad] telah mengabarkan kepada kami [Ibnu Syihab] dari ['Ubaidallah bin 'Uqbah] bahwa [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Nabi shallallahu 'alaihi wasallam adalah orang yang paling lembut (dermawan) dalam segala kebaikan. Dan kelembutan Beliau yang paling baik adalah saat bulan Ramadhan ketika Jibril alaihissalam datang menemui Beliau. Dan Jibril Alaihissalam datang menemui Beliau pada setiap malam di bulan Ramadhan (untuk membacakan Al Qur'an) hingga Al Qur'an selesai dibacakan untuk Nabi shallallahu 'alaihi wasallam. Apabila Jibril Alaihissalam datang menemui Beliau, maka Beliau adalah orang yang paling lembut dalam segala kebaikan melebihi lembutnya angin yang berhembus\". "},"1770":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَمْ يَدَعْ قَوْلَ الزُّورِ وَالْعَمَلَ بِهِ فَلَيْسَ لِلَّهِ حَاجَةٌ فِي أَنْ يَدَعَ طَعَامَهُ وَشَرَابَهُ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] telah menceritakan kepada kami [Ibnu Abu Dza'bi] telah menceritakan kepada kami [Sa'id Al Maqbariy] dari [bapaknya] dari [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang tidak meninggalkan ucapan keji dan berbuat keji, Allah tidak butuh orang itu meninggalkan makan dan minumnya\"."},"1771":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامُ بْنُ يُوسُفَ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ أَبِي صَالِحٍ الزَّيَّاتِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ كُلُّ عَمَلِ ابْنِ آدَمَ لَهُ إِلَّا الصِّيَامَ فَإِنَّهُ لِي وَأَنَا أَجْزِي بِهِ وَالصِّيَامُ جُنَّةٌ وَإِذَا كَانَ يَوْمُ صَوْمِ أَحَدِكُمْ فَلَا يَرْفُثْ وَلَا يَصْخَبْ فَإِنْ سَابَّهُ أَحَدٌ أَوْ قَاتَلَهُ فَلْيَقُلْ إِنِّي امْرُؤٌ صَائِمٌ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَخُلُوفُ فَمِ الصَّائِمِ أَطْيَبُ عِنْدَ اللَّهِ مِنْ رِيحِ الْمِسْكِ لِلصَّائِمِ فَرْحَتَانِ يَفْرَحُهُمَا إِذَا أَفْطَرَ فَرِحَ وَإِذَا لَقِيَ رَبَّهُ فَرِحَ بِصَوْمِهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam bun Yusuf] dari [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Atho'] dari [Abu Shalih Az Zayyat] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala telah berfirman: \"Setiap amal anak Adam adalah untuknya kecuali shaum, sesungguhnya shaum itu untuk Aku dan Aku sendiri yang akan memberi balasannya. Dan shaum itu adalah benteng, maka apabila suatu hari seorang dari kalian sedang melaksanakan shaum, maka janganlah dia berkata rafats dan bertengkar sambil berteriak. Jika ada orang lain yang menghinanya atau mengajaknya berkelahi maka hendaklah dia mengatakan 'Aku orang yang sedang shaum. Dan demi Dzat yang jiwa Muhammad berada di tanganNya, sungguh bau mulut orang yang sedang shaum lebih harum di sisi Allah Ta'ala dari pada harumnya minyak misik. Dan untuk orang yang shaum akan mendapatkan dua kegembiraan yang dia akan bergembira dengan keduanya, yaitu apabila berbuka dia bergembira dan apabila berjumpa dengan Rabnya dia bergembira disebabkan 'ibadah shaumnya itu\". "},"1772":{"ar":"حَدَّثَنَا عَبْدَانُ عَنْ أَبِي حَمْزَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَبَيْنَا أَنَا أَمْشِي مَعَ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ فَقَالَ كُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ اسْتَطَاعَ الْبَاءَةَ فَلْيَتَزَوَّجْ فَإِنَّهُ أَغَضُّ لِلْبَصَرِ وَأَحْصَنُ لِلْفَرْجِ وَمَنْ لَمْ يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ فَإِنَّهُ لَهُ وِجَاءٌ","id":"Telah menceritakan kepada kami ['Abdan] dari [Abu Hamzah] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] berkata; Ketika aku sedang berjalan bersama ['Abdullah radliallahu 'anhu], dia berkata: Kami pernah bersama Nabi shallallahu 'alaihi wasallam yang ketika itu Beliau bersabda: \"Barangsiapa yang sudah mampu (menafkahi keluarga), hendaklah dia kawin (menikah) karena menikah itu lebih bisa menundukkan pandangan dan lebih bisa menjaga kemaluan. Barangsiapa yang tidak sanggup (manikah) maka hendaklah dia berpuasa karena puasa itu akan menjadi benteng baginya\". "},"1773":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ رَمَضَانَ فَقَالَ لَا تَصُومُوا حَتَّى تَرَوْا الْهِلَالَ وَلَا تُفْطِرُوا حَتَّى تَرَوْهُ فَإِنْ غُمَّ عَلَيْكُمْ فَاقْدُرُوا لَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam menceritakan tentang bulan Ramadhan lalu Beliau bersabda: \"Janganlah kalian berpuasa hingga kalian melihat hilal dan jangan pula kalian berbuka hingga kalian melihatnya. Apabila kalian terhalang oleh awan maka perkirakanlah jumlahnya (jumlah hari disempurnakan) \". "},"1774":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ لَيْلَةً فَلَا تَصُومُوا حَتَّى تَرَوْهُ فَإِنْ غُمَّ عَلَيْكُمْ فَأَكْمِلُوا الْعِدَّةَ ثَلَاثِينَ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu bulan itu berjumlah dua puluh sembilan malam (hari) maka janganlah kalian berpuasa hingga kalian melihatnya. Apabila kalian terhalang oleh awan maka sempurnakanlah jumlahnya menjadi tiga puluh\". "},"1775":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ جَبَلَةَ بْنِ سُحَيْمٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الشَّهْرُ هَكَذَا وَهَكَذَا وَخَنَسَ الْإِبْهَامَ فِي الثَّالِثَةِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Jabalah bin Sujaim] berkata, aku mendengar [Ibnu'Umar radliallahu 'anhuma] berkata,, Nabi shallallahu 'alaihi wasallam bersabda: \"Bulan itu begini begini\". Lalu Beliau mengepalkan ibu jari tangannya saat menyebutkan hitungan yang ketiga. "},"1776":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ قَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ فَإِنْ غُبِّيَ عَلَيْكُمْ فَأَكْمِلُوا عِدَّةَ شَعْبَانَ ثَلَاثِينَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Muhammad bin Ziyad] berkata, aku mendengar [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda, atau katanya Abu Al Qasim shallallahu 'alaihi wasallam telah bersabda: \"Berpuasalah kalian dengan melihatnya (hilal) dan berbukalah dengan melihatnya pula. Apabila kalian terhalang oleh awan maka sempurnakanlah jumlah bilangan hari bulan Sya'ban menjadi tiga puluh\". "},"1777":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ صَيْفِيٍّ عَنْ عِكْرِمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمِّ سَلَمَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ آلَى مِنْ نِسَائِهِ شَهْرًا فَلَمَّا مَضَى تِسْعَةٌ وَعِشْرُونَ يَوْمًا غَدَا أَوْ رَاحَ فَقِيلَ لَهُ إِنَّكَ حَلَفْتَ أَنْ لَا تَدْخُلَ شَهْرًا فَقَالَ إِنَّ الشَّهْرَ يَكُونُ تِسْعَةً وَعِشْرِينَ يَوْمًا","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Yahya biun 'Abdullah bin Shayfiy] dari ['Ikrimah bin 'Abdurrahman] dari [Ummu Salamah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam pernah bersumpah untuk tidak mendatangi para isteri Beliau selama satu bulan. Ketika telah melewati dua puluh sembilan hari, Beliau keluar untuk mendatangi mereka pada pagi hari atau siang hari. Lalu dikatakan kepada Beliau; \"Lho, baginda telah bersumpah untuk tidak mendatangi mereka selama sebulan. Maka Beliau shallallahu 'alaihi wasallam bersabda: \"Satu bulan itu bisa jadi berjumlah dua puluh sembilan hari\". "},"1778":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَآلَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نِسَائِهِ وَكَانَتْ انْفَكَّتْ رِجْلُهُ فَأَقَامَ فِي مَشْرُبَةٍ تِسْعًا وَعِشْرِينَ لَيْلَةً ثُمَّ نَزَلَ فَقَالُوا يَا رَسُولَ اللَّهِ آلَيْتَ شَهْرًا فَقَالَ إِنَّ الشَّهْرَ يَكُونُ تِسْعًا وَعِشْرِينَ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Humaid] dari [Anas radliallahu 'anhu] berkata: Rasulullah shallallahu 'alaihi wasallam pernah bersumpah untuk tidak mendatangi para isteri Beliau dan kaki Beliau telah mengalami keletihan maka Beliau tinggal di tempat yang tinggi selama dua puluh sembilan hari lalu turun. Orang-orang berkata: \"Wahai Rasulullah, anda telah bersumpah selama satu bulan. Maka Beliau shallallahu 'alaihi wasallam bersabda: \"Satu bulan itu bisa jadi berjumlah dua puluh sembilan hari\". "},"1779":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ إِسْحَاقَ بْنَ سُوَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَحَدَّثَنِي مُسَدَّدٌ حَدَّثَنَا مُعْتَمِرٌ عَنْ خَالِدٍ الْحَذَّاءِ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبِي بَكْرَةَ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ شَهْرَانِ لَا يَنْقُصَانِ شَهْرَا عِيدٍ رَمَضَانُ وَذُو الْحَجَّةِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Mu'tamir] berkata, aku mendengar [Ishaq bin Suwaid] dari ['Abdurrahman bin Abu Bakrah] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam. Dan telah menceritakan kepada saya [Musaddad] telah menceritakan kepada kami [Mu'tamir] dari [Khalid Al Hadzdza'] berkata, telah mengabarkan kepada saya ['Abdurrahman bin Abu Bakrah] dari [bapaknya radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Ada dua bulan yang tidak akan kurang dalam bulan (sama bilangan harinya) yaitu bulan Ramadhan dan Dzul Hijjah\"."},"1780":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْأَسْوَدُ بْنُ قَيْسٍ حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو أَنَّهُ سَمِعَ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّا أُمَّةٌ أُمِّيَّةٌ لَا نَكْتُبُ وَلَا نَحْسُبُ الشَّهْرُ هَكَذَا وَهَكَذَا يَعْنِي مَرَّةً تِسْعَةً وَعِشْرِينَ وَمَرَّةً ثَلَاثِينَ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Al Aswad bin Qais] telah menceritakan kepada kami [Sa'id bin 'Amru] bahwa dia mendengar [Ibnu'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Kita ini adalah ummat yang ummi, yang tidak biasa menulis dan juga tidak menghitung satu bulan itu jumlah harinya segini dan segini, yaitu sekali berjumlah dua puluh sembilan dan sekali berikutnya tiga puluh hari\". "},"1781":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَقَدَّمَنَّ أَحَدُكُمْ رَمَضَانَ بِصَوْمِ يَوْمٍ أَوْ يَوْمَيْنِ إِلَّا أَنْ يَكُونَ رَجُلٌ كَانَ يَصُومُ صَوْمَهُ فَلْيَصُمْ ذَلِكَ الْيَوْمَ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang dari kalian mendahului bulan Ramadhan dengan berpuasa satu atau dua hari kecuali apabila seseorang sudah biasa melaksanakan puasa (sunnat) maka pada hari itu dia dipersilahkan untuk melaksanakannya\". "},"1782":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِس��رَائِيلَ عَنْ أَبِي إِسْحَاقَ عَنْ الْبَرَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ أَصْحَابُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ الرَّجُلُ صَائِمًا فَحَضَرَ الْإِفْطَارُ فَنَامَ قَبْلَ أَنْ يُفْطِرَ لَمْ يَأْكُلْ لَيْلَتَهُ وَلَا يَوْمَهُ حَتَّى يُمْسِيَ وَإِنَّ قَيْسَ بْنَ صِرْمَةَ الْأَنْصَارِيَّ كَانَ صَائِمًا فَلَمَّا حَضَرَ الْإِفْطَارُ أَتَى امْرَأَتَهُ فَقَالَ لَهَا أَعِنْدَكِ طَعَامٌ قَالَتْ لَا وَلَكِنْ أَنْطَلِقُ فَأَطْلُبُ لَكَ وَكَانَ يَوْمَهُ يَعْمَلُ فَغَلَبَتْهُ عَيْنَاهُ فَجَاءَتْهُ امْرَأَتُهُ فَلَمَّا رَأَتْهُ قَالَتْ خَيْبَةً لَكَ فَلَمَّا انْتَصَفَ النَّهَارُ غُشِيَ عَلَيْهِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ أُحِلَّ لَكُمْ لَيْلَةَ الصِّيَامِ الرَّفَثُ إِلَى نِسَائِكُمْ }فَفَرِحُوا بِهَا فَرَحًا شَدِيدًا وَنَزَلَتْ{ وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Isra'il] dari [Abu Ishaq] dari [Al Bara' radliallahu 'anhu] berkata; \"Diantara para sahabat Muhammad shallallahu 'alaihi wasallam ada seseorang apabila sedang shaum lalu tiba waktu berbuka dia pergi tidur sebelum berbuka sehingga dia tidak memakan sesuatu pada malam dan siang hari hingga petang hari. Dan pada suatu ketika Qais bin Shirmah Al Anshariy ketika sedang melaksanakan shaum lalu tiba waktu berbuka dia mendatangi isterinya seraya berkata, kepada isterinya: \"Apakah kamu punya makanan?\" Isterinya berkata: \"Tidak, namun aku akan keluar mencari makanan buatmu\". Kemudian di siang harinya dia bekerja keras hingga mengantuk lalu tertidur. Kemudian isterinya datang. Ketika isterinya melihat dia (sedang tertidur), isterinya berkata: \"Rugilah kamu\". Kemudian pada tengah harinya Qais jatuh pingsan. Lalu persoalan ini diadukan kepada Nabi shallallahu 'alaihi wasallam, maka turunlah firman Allah Ta'ala QS Al Baqarah ayat 197 yang artinya: (\"Dihalalkan bagi kalian pada malam bulan puasa bercampur dengan isttri-isteri kalian\"). Dengan turunnya ayat ini para sahabat merasa sangat senang, hingga kemudian turun sambungan ayatnya: (\"Dan makan minumlah kalian hingga terang bagi kalian benang putih dari benang hitam yaitu di waktu fajar\")."},"1783":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنِي حُصَيْنُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُ قَالَلَمَّا نَزَلَتْ{ حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }عَمَدْتُ إِلَى عِقَالٍ أَسْوَدَ وَإِلَى عِقَالٍ أَبْيَضَ فَجَعَلْتُهُمَا تَحْتَ ��ِسَادَتِي فَجَعَلْتُ أَنْظُرُ فِي اللَّيْلِ فَلَا يَسْتَبِينُ لِي فَغَدَوْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ لَهُ ذَلِكَ فَقَالَ إِنَّمَا ذَلِكَ سَوَادُ اللَّيْلِ وَبَيَاضُ النَّهَارِ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Husyaim] berkata, telah mengabarkan kepada saya [Hushain bin 'Abdurrahman] dari [Asy-Sya'biy] dari ['Adi bin Hatim radliallahu 'anhu] berkata: Ketika turun QS Al Baqarah ayat 197 (\"… hingga terang bagi kalian benang putih dari benang hitam yaitu di waktu fajar\"), maka aku mengambil benang hitam dan benang putih lalu aku letakkan di bawah bantalku untuk aku lihat pada sebagian malam namun tidak tampak olehku. Maka di pagi harinya aku menemui Rasulullah shallallahu 'alaihi wasallam lalu aku ceritakan hal tadi. Maka Beliau bersabda: \"Sesungguhnya yang dimaksud dengan ayat itu adalah gelapnya malam dan terangya siang\". "},"1784":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلِ بْنِ سَعْدٍ ح حَدَّثَنِي سَعِيدُ بْنُ أَبِي مَرْيَمَ حَدَّثَنَا أَبُو غَسَّانَ مُحَمَّدُ بْنُ مُطَرِّفٍ قَالَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَأُنْزِلَتْ{ وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }وَلَمْ يَنْزِلْ{ مِنْ الْفَجْرِ }فَكَانَ رِجَالٌ إِذَا أَرَادُوا الصَّوْمَ رَبَطَ أَحَدُهُمْ فِي رِجْلِهِ الْخَيْطَ الْأَبْيَضَ وَالْخَيْطَ الْأَسْوَدَ وَلَمْ يَزَلْ يَأْكُلُ حَتَّى يَتَبَيَّنَ لَهُ رُؤْيَتُهُمَا فَأَنْزَلَ اللَّهُ بَعْدُ{ مِنْ الْفَجْرِ }فَعَلِمُوا أَنَّهُ إِنَّمَا يَعْنِي اللَّيْلَ وَالنَّهَارَ","id":"Telah menceritakan kepada kami [Sa'id bin Abu Maryam] telah menceritakan kepada kami [Ibnu Abu Hazim] dari [bapaknya] dari [Sahal bin Sa'ad]. Dan diriwayatkan pula, telah menceritakan kepada saya [Sa'id bin Abu Maryam] telah menceritakan kepada kami [Abu Ghossan Muhammad bin Muthorrib] berkata, telah menceritakan kepada saya [Abu Hazim] dari [Sahal bin Sa'ad] berkata: Ketika turun ayat (\"Dan makan minumlah kalian hingga terang bagi kalian benang putih dari benang hitam\") dan belum diturunkan ayat lanjutannya yaitu (\"dari fajar\"), ada diantara orang-orang apabila hendak shaum seseorang yang mengikat seutas benang putih dan benang hitam pada kakinya yang dia senantiasa meneruskan makannya hingga jelas terlihat perbedaan benang-benang itu. Maka Allah Ta'ala kemudian menurunkan ayat lanjutannya (\"dari fajar\"). Dari situ mereka mengetahui bahwa yang dimaksud (dengan benang hitam dan putih) adalah malam dan siang\". "},"1785":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ عَنْ أَبِي أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ وَالْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ بِلَالًا كَانَ يُؤَذِّنُ بِلَيْلٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا وَاشْرَبُوا حَتَّى يُؤَذِّنَ ابْنُ أُمِّ مَكْتُومٍ فَإِنَّهُ لَا يُؤَذِّنُ حَتَّى يَطْلُعَ الْفَجْرُ قَالَ الْقَاسِمُ وَلَمْ يَكُنْ بَيْنَ أَذَانِهِمَا إِلَّا أَنْ يَرْقَى ذَا وَيَنْزِلَ ذَا","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] dari [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibu 'Umar] dan [Al Qasim bin Muhammad] dari ['Aisyah radliallahu 'anha] bahwa Bilal biasa melakukan adzan (pertama) di malam hari, maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Makan dan minumlah kalian hingga Ibnu Ummu Maktum melakukan adzan, karena dia tidak melakukan adzan kecuali sudah terbit fajar\". Al Qasim berkata: \"Jarak antara adzan keduanya itu tidaklah lama melainkan bila yang satunya naik maka yang satunya lagi turun (maksudnya naik ke dan turun dari menara) \"."},"1786":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ أَتَسَحَّرُ فِي أَهْلِي ثُمَّ تَكُونُ سُرْعَتِي أَنْ أُدْرِكَ السُّجُودَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaidullah] telah menceritakan kepada kami ['Abdul 'Aziz bin Abu Hazim] dari [Abu Hazim] dari [Sahal bin Sa'ad radliallahu 'anhu] berkata: \"Aku makan sahur bersama keluargaku kemudian aku bercepat-cepat agar mendapatkan sujud (shalat) bersama Rasulullah shallallahu 'alaihi wasallam \"."},"1787":{"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ عَنْ زَيْدِ بْنِ ثَابِتٍ رَضِيَ اللَّهُ عَنْهُ قَالَتَسَحَّرْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَامَ إِلَى الصَّلَاةِ قُلْتُ كَمْ كَانَ بَيْنَ الْأَذَانِ وَالسَّحُورِ قَالَ قَدْرُ خَمْسِينَ آيَةً","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Anas] dari [Zaid bin Tsabit radliallahu 'anhu] berkata: \"Kami pernah makan sahur bersama Nabi shallallahu 'alaihi wasallam kemudian Beliau pergi untuk melakanakan shalat. Aku bertanya: \"Berapa antara adzan (Shubuh) dan sahur?\". Dia menjawab: \"Sebanyak ukuran bacaan lima puluh ayat\". "},"1788":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جُوَيْرِيَةُ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاصَلَ فَوَاصَلَ النَّاسُ فَشَقَّ عَلَيْهِمْ فَنَهَاهُمْ قَالُوا إِنَّكَ تُوَاصِلُ قَالَ لَسْتُ كَهَيْئَتِكُمْ إِنِّي أَظَلُّ أُطْعَمُ وَأُسْقَى","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Juwairiyah] dari [Nafi'] dari ['Abdullah radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam melaksanakan puasa wishal (puasa terus tanpa berbuka) lalu orang-orang mengikutinya yang mengakibatkan mereka kepayahan. Maka Beliau melarang mereka melakukannya. Namun mereka berkata: \"Tetapi, bukankah baginda melakukan puasa wishal?\". Beliau bersabda: \"Aku tidak sama dengan keadaan kalian karena aku senantiasa diberi makan dan minum\"."},"1789":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَحَّرُوا فَإِنَّ فِي السَّحُورِ بَرَكَةً","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Abdul 'Aziz bin Shuhaib] berkata, aku mendengar [Anas bin Malik radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Bersahurlah kalian, karena didalam sahur ada barakah\". "},"1790":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ يَزِيدَ بْنِ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ رَجُلًا يُنَادِي فِي النَّاسِ يَوْمَ عَاشُورَاءَ إِنَّ مَنْ أَكَلَ فَلْيُتِمَّ أَوْ فَلْيَصُمْ وَمَنْ لَمْ يَأْكُلْ فَلَا يَأْكُلْ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Yazid bin Abu 'Ubaid] dari [Salamah bin Al Akwa' radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam mengutus seseorang untuk menyeru manusia pada (waktu sahur) hari 'Asyura', bila ada seseorang yang sudah makan maka hendaklah ia meneruskan makannya atau hendaklah shaum dan barangsiapa yang belum makan maka hendaklah ia tidak makan (maksudnya teruskan berpuasa) \". "},"1791":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرِ بنِ عَبْدِ الرَّحْمَنِ بنِ الحَارِثِ بْنِ هِشَامِ بْنِ المُغِيرَةِ أَنَّهُ سَمِعَ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِ قَالَ كُنْتُ أَنَا وَأَبِي حِينَ دَخَلْنَا عَلَى عَائِشَةَ وَأُمِّ سَلَمَةَ ح و حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَنَّ أَبَاهُ عَبْدَ الرَّحْمَنِ أَخْبَرَ مَرْوَانَ أَنَّ عَائِشَةَ وَأُمَّ سَلَمَةَ أَخْبَرَتَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُدْرِكُهُ الْفَجْرُ وَهُوَ جُنُبٌ مِنْ أَهْلِهِ ثُمَّ يَغْتَسِلُ وَيَصُومُوَقَالَ مَرْوَانُ لِعَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ أُقْسِمُ بِاللَّهِ لَتُقَرِّعَنَّ بِهَا أَبَا هُرَيْرَةَ وَمَرْوَانُ يَوْمَئِذٍ عَلَى الْمَدِينَةِ فَقَالَ أَبُو بَكْرٍ فَكَرِهَ ذَلِكَ عَبْدُ الرَّحْمَنِ ثُمَّ قُدِّرَ لَنَا أَنْ نَجْتَمِعَ بِذِي الْحُلَيْفَةِ وَكَانَتْ لِأَبِي هُرَيْرَةَ هُنَالِكَ أَرْضٌ فَقَالَ عَبْدُ الرَّحْمَنِ لِأَبِي هُرَيْرَةَ إِنِّي ذَاكِرٌ لَكَ أَمْرًا وَلَوْلَا مَرْوَانُ أَقْسَمَ عَلَيَّ فِيهِ لَمْ أَذْكُرْهُ لَكَ فَذَكَرَ قَوْلَ عَائِشَةَ وَأُمِّ سَلَمَةَ فَقَالَ كَذَلِكَ حَدَّثَنِي الْفَضْلُ بْنُ عَبَّاسٍ وَهُنَّ أَعْلَمُ وَقَالَ هَمَّامٌ وَابْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِي هُرَيْرَةَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ بِالْفِطْرِ وَالْأَوَّلُ أَسْنَدُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Sumayya] maulanya Abu Bakar bin 'Abdurrahman bin Al Harits bin Hisyam bin Al Mughirah bahwa dia mendengar [Abu Bakar bin 'Abdurrahman] berkata: \"Aku dan bapakku ketika menemui ['Aisyah radliallahu 'anha] dan [Ummu Salamah]...Dan diriwayatkan pula, telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Abu Bakar bin 'Abdurrahman bin Al Harits bin Hisyam] bahwa bapaknya, yaitu ['Abdurrahman] mengabarkan kepada Marwan bahwa ['Aisyah radliallahu 'anha] dan [Ummu Salamah] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam pernah mendapatkan waktu Fajar saat Beliau sedang junub di rumah keluarga Beliau. Maka kemudian Beliau mandi dan shaum. Dan berkata, Marwan kepada 'Abdurrahman bin Al Harits: \"Aku bersumpah dengan nama Allah. aku pasti menyampaikan hal ini kepada Abu Hurairah radliallahu 'anhu. Saat itu Marwan adalah pemimpin di Madinah. Maka Abu Bakar berkata: \"Kejadian itu membawa 'Abdurrahman merasa tidak senang\". Kemudian kami ditakdirkan berkumpul di Dzul Hulaifah yang ketika itu Abu Hurairah radliallahu 'anhu termasuk yang hadir disana, maka 'Abdurrahman berkata, kepada [Abu Hurairah radliallahu 'anhu]: \"Aku akan menyampaikan satu hal kepadamu yang seandainya Marwan tidak bersumpah tentangnya kepadaku maka aku tidak akan menyampaikannya kepadamu\". Maka dia menyebutkan apa yang disampaikan 'Aisyah radliallahu 'anha dan Ummu Salamah diatas. Maka Abu Hurairah radliallahu 'anhu berkata: \"Persoalan tadi pernah pula diceritakan kepadaku oleh [Al Fadhal bin 'Abbas] sedangkan mereka ('Aisyah radliallahu 'anha dan Ummu Salamah) lebih mengetahui perkara ini\". Dan berkata, [Hammam] dan [Ibnu 'Abdullah bin 'Umar] dari [Abu Hurairah radliallahu 'anhu]: \"Adalah Nabi shallallahu 'alaihi wasallam memerintahkan untuk berbuka (dalam kasus junub setelah masuk waktu Fajar). Namun hadits pertama diatas lebih kuat sanadnya\"."},"1792":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُقَبِّلُ وَيُبَاشِرُ وَهُوَ صَائِمٌ وَكَانَ أَمْلَكَكُمْ لِإِرْبِهِوَقَالَ قَالَ ابْنُ عَبَّاسٍ{ مَآرِبُ }حَاجَةٌ قَالَ طَاوُسٌ{ غَيْرِ أُولِي الْإِرْبَةِ }الْأَحْمَقُ لَا حَاجَةَ لَهُ فِي النِّسَاءِ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] berkata, [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam mencium dan mencumbu (isteri-isteri Beliau) padahal Beliau sedang berpuasa. Dan Beliau adalah orang yang paling mampu mengendalikan nafsunya dibandingkan kalian\". Dan Al Aswad berkata; Ibnu 'Abbas radliallahu 'anhuma berkata, istilah ma\"aarib maknanya adalah keperluan (seperti dalam QS Thoha ayat 18) artinya hajat. Dan berkata, Thowus (seperti dalam QS An-Nuur ayat 31) artinya: orang dungu yang tidak punya keinginan lagi terhadap wanita. "},"1793":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُقَبِّلُ بَعْضَ أَزْوَاجِهِ وَهُوَ صَائِمٌ ثُمَّ ضَحِكَتْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] dari [Hisyam] berkata, telah mengabarkan kepada saya [bapakku] dari ['Aisyah radliallahu 'anha]. Dan telah diriwayatkan pula, telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam mencium isteri-isteri Beliau\". 'Aisyah radliallahu 'anha kemudian tertawa."},"1794":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ هِشَامِ بْنِ أَبِي عَبْدِ اللَّهِ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ زَيْنَبَ ابْنَةِ أُمِّ سَلَمَةَ عَنْ أُمِّهَا رَضِيَ اللَّهُ عَنْهُمَا قَالَتْبَيْنَمَا أَنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْخَمِيلَةِ إِذْ حِضْتُ فَانْسَلَلْتُ فَأَخَذْتُ ثِيَابَ حِيضَتِي فَقَالَ مَا لَكِ أَنَفِسْتِ قُلْتُ نَعَمْ فَدَخَلْتُ مَعَهُ فِي الْخَمِيلَةِ وَكَانَتْ هِيَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْتَسِلَانِ مِنْ إِنَاءٍ وَاحِدٍ وَكَانَ يُقَبِّلُهَا وَهُوَ صَائِمٌ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Hisyam bin Abu 'Abdullah] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Zainab putri Ummu Salamah] dari [ibunya radliallahu 'anhuma] berkata: Ketika aku bersama Rasulullah shallallahu 'alaihi wasallam dalam satu selimut tiba-tiba aku mengalami haidh maka aku diam-diam pergi lalu aku mengambil pakaian khusus haidhku, Beliau berkata: \"Ada apa denganmu, apakah kamu mengalami hadil?\". Aku jawab: \"Ya\". Lalu aku masuk kedalam selimut bersama Beliau\". Ummu Salamah dan Rasulullah shallallahu 'alaihi wasallam pernah pula mandi bersama dari satu ember air. Dan Beliau juga menciumnya padahal Beliau sedang berpuasa\". "},"1795":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ صَالِحٍ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ وَأَبِي بَكْرٍ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَاكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُدْرِكُهُ الْفَجْرُ فِي رَمَضَانَ مِنْ غَيْرِ حُلْمٍ فَيَغْتَسِلُ وَيَصُومُ","id":"Telah menceritakan kepada kami [Ahmad bin Shalih] telah menceritakan kepada kami [Ibnu Wahab] telah menceritakan kepada kami [Yunus] dari [Ibnu Sihab] dari ['Urwah] dan [Abu Bakar], ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam pernah mendapati masuknya waktu fajar di bulan Ramadhan dalam keadaan Beliau junub, lalu Beliau mandi dan shaum\"."},"1796":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرِ بنِ عَبْدِ الرَّحْمَنِ بنِ الحَارِثِ بْنِ هِشَامِ بْنِ المُغِيرَةِ أَنَّهُ سَمِعَ أَبَا بَكْرِ بْنَ عَبْدِ الرَّحْمَنِكُنْتُ أَنَا وَأَبِي فَذَهَبْتُ مَعَهُ حَتَّى دَخَلْنَا عَلَى عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ أَشْهَدُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَ لَيُصْبِحُ جُنُبًا مِنْ جِمَاعٍ غَيْرِ احْتِلَامٍ ثُمَّ يَصُومُهُ ثُمَّ دَخَلْنَا عَلَى أُمِّ سَلَمَةَ فَقَالَتْ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada saya [Malik] dari [Sumayya] maulanya Abu Bakar bin'Abdurrahman bin Al Harits bin Hisyam bin Al Mughirah bahwa dia mendengar [Abu Bakar bin'Abdurrahman] (berkata,): \"Aku dan bapakku pergi bersama-sama hingga kami datang menemui ['Aisyah radliallahu 'anha] yang dia berkata: \"Aku bersaksi tentang Rasulullah shallallahu 'alaihi wasallam bahwa apabila Beliau pada pagi hari masih dalam keadaan junub setelah berhubungan tanpa mengeluarkan sperma, maka Beliau meneruskan puasanya\". Kemudian kami datang menemui Ummu Salamah yang dia juga berkata, seperti itu\". "},"1797":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا هِشَامٌ حَدَّثَنَا ابْنُ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَسِيَ فَأَكَلَ وَشَرِبَ فَلْيُتِمَّ صَوْمَهُ فَإِنَّمَا أَطْعَمَهُ اللَّهُ وَسَقَاهُ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Ibnu Sirin] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seseorang lupa lalu dia makan dan minum (ketika sedang berpuasa) maka hendaklah dia meneruskan puasanya karena hal itu berarti Allah telah memberinya makan dan minum\". "},"1798":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا مَعْمَرٌ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ عَطَاءِ بْنِ يَزِيدَ عَنْ حُمْرَانَ رَأَيْتُ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُتَوَضَّأَ فَأَفْرَغَ عَلَى يَدَيْهِ ثَلَاثًا ثُمَّ تَمَضْمَضَ وَاسْتَنْثَرَ ثُمَّ غَسَلَ وَجْهَهُ ثَلَاثًا ثُمَّ غَسَلَ يَدَهُ الْيُمْنَى إِلَى الْمَرْفِقِ ثَلَاثًا ثُمَّ غَسَلَ يَدَهُ الْيُسْرَى إِلَى الْمَرْفِقِ ثَلَاثًا ثُمَّ مَسَحَ بِرَأْسِهِ ثُمَّ غَسَلَ رِجْلَهُ الْيُمْنَى ثَلَاثًا ثُمَّ الْيُسْرَى ثَلَاثًا ثُمَّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ نَحْوَ وَضُوئِي هَذَا ثُمَّ قَالَ مَنْ تَوَضَّأَ وُضُوئِي هَذَا ثُمَّ يُصَلِّي رَكْعَتَيْنِ لَا يُحَدِّثُ نَفْسَهُ فِيهِمَا بِشَيْءٍ إِلَّا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Ma'mar] berkata, telah menceritakan kepada saya [Az Zuhriy] dari ['Atho' bin Yazid] dari [Humran] (berkata,): \"Aku melihat ['Utsman bin 'Affan] berwudhu', dia menuangkan air ke telapak tangannya (untuk membasuh kedua telapak tangannya) tiga kali. Kemudian berkumur-kumur dan membasuh hidung lalu mengeluarkan (air) darinya. Kemudian membasuh mukanya tiga kali lalu membasuh lengannya yang kanan hingga ke siku dan lengannya yang kiri hingga ke siku tiga kali kemudian berkata: \"Aku melihat Rasulullah shallallahu 'alaihi wasallam berwudhu' seperti wudhu'ku ini lalu Beliau bersabda: \"Barangsiapa berwudhu' seperti wudhu'ku ini kemudian dia shalat dua raka'at dan tidak berbicara apapun antara keduanya, maka Allah mengampuni dosanya yang lalu\"."},"1799":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ يَزِيدَ بْنَ هَارُونَ حَدَّثَنَا يَحْيَى هُوَ ابْنُ سَعِيدٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ أَخْبَرَهُ عَنْ مُحَمَّدِ بْنِ جَعْفَرِ بْنِ الزُّبَيْرِ بْنِ الْعَوَّامِ بْنِ خُوَيْلِدٍ عَنْ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ أَخْبَرَهُ أَنَّهُ سَمِعَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُإِنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّهُ احْتَرَقَ قَالَ مَا لَكَ قَالَ أَصَبْتُ أَهْلِي فِي رَمَضَانَ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِكْتَلٍ يُدْعَى الْعَرَقَ فَقَالَ أَيْنَ الْمُحْتَرِقُ قَالَ أَنَا قَالَ تَصَدَّقْ بِهَذَا","id":"Telah menceritakan kepada kami ['Abdullah bin Munir] dia mendengar [Yazid bin Harun] (berkata,), telah menceritakan kepada kami [Yahya], dia adalah anaknya Sa'id bahwa ['Abdurrahman bin Al Qasim] mengabarkannya dari [Muhammad bin Ja'far bin Az Zubair bin Al 'Awam bin Khuwaylid] dari ['Abbad bin 'Abdullah bin Az Zubair] mengabarkan kepadanya bahwa dia mendengar ['Aisyah radliallahu 'anha] berkata: \"Ada seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam lalu berkata, \"Wah aku terbakar!\". Beliau bertanya: \"Maksudmu, Ada apa denganmu?\". Orang itu menjawab: \"Aku telah berhubungan dengan isteriku pada siang hari di bulan Ramadhan\". Kemudian Nabi shallallahu 'alaihi wasallam dibawakan sekeranjang kurma, maka Beliau berkata: \"Mana orang yang celaka itu?\". Orang itu menjawab: \"Aku\". Maka Beliau berkata: \"Bershadaqahlah dengan kurma ini\"."},"1800":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي حُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَمَا نَحْنُ جُلُوسٌ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكْتُ قَالَ مَا لَكَ قَالَ وَقَعْتُ عَلَى امْرَأَتِي وَأَنَا صَائِمٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ تَجِدُ رَقَبَةً تُعْتِقُهَا قَالَ لَا قَالَ فَهَلْ تَسْتَطِيعُ أَنْ تَصُومَ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا فَقَالَ فَهَلْ تَجِدُ إِطْعَامَ سِتِّينَ مِسْكِينًا قَالَ لَا قَالَ فَمَكَثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَيْنَا نَحْنُ عَلَى ذَلِكَ أُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَقٍ فِيهَا تَمْرٌ وَالْعَرَقُ الْمِكْتَلُ قَالَ أَيْنَ السَّائِلُ فَقَالَ أَنَا قَالَ خُذْهَا فَتَصَدَّقْ بِهِ فَقَالَ الرَّجُلُ أَعَلَى أَفْقَرَ مِنِّي يَا رَسُولَ اللَّهِ فَوَاللَّهِ مَا بَيْنَ لَابَتَيْهَا يُرِيدُ الْحَرَّتَيْنِ أَهْلُ بَيْتٍ أَفْقَرُ مِنْ أَهْلِ بَيْتِي فَضَحِكَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ أَنْيَابُهُ ثُمَّ قَالَ أَطْعِمْهُ أَهْلَكَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Humaid bin 'Abdurrahman] bahwa [Abu Hurairah radliallahu 'anhu] berkata: \"Ketika kami sedang duduk bermajelis bersama Nabi shallallahu 'alaihi wasallam tiba-tiba datang seorang laki-laki lalu berkata: \"Wahai Rasulullah, binasalah aku\". Beliau bertanya: \"Ada apa denganmu?\". Orang itu menjawab: \"Aku telah berhubungan dengan isteriku sedangkan aku sedang berpuasa\". Maka Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apakah kamu memiliki budak, sehingga kamu harus membebaskannya?\". Orang itu menjawab: \"Tidak\". Lalu Beliau bertanya lagi: \"Apakah kamu sanggup bila harus berpuasa selama dua bulan berturut-turut?\". Orang itu menjawab: \"Tidak\". Lalu Beliau bertanya lagi: \"Apakah kamu memiliki makanan untuk diberikan kepada enam puluh orang miskin?\". Orang itu menjawab: \"Tidak\". Sejenak Nabi shallallahu 'alaihi wasallam terdiam. Ketika kami masih dalam keadaan tadi, Nabi shallallahu 'alaihi wasallam diberikan satu keranjang berisi kurma, lalu Beliau bertanya: \"Mana orang yang bertanya tadi?\". Orang itu menjawab: \"Aku\". Maka Beliau berkata: \"Ambillah kurma ini lalu bershadaqahlah dengannya\". Orang itu berkata: \"Apakah ada orang yang lebih faqir dariku, wahai Rasulullah. Demi Allah, tidak ada keluarga yang tinggal diantara dua perbatasan, yang dia maksud adalah dua gurun pasir, yang lebih faqir daripada keluargaku\". Mendengar itu Nabi shallallahu 'alaihi wasallam menjadi tertawa hingga tampak gigi seri Beliau. Kemudian Beliau berkata: \"Kalau begitu berilah makan keluargamu dengan kurma ini\"."},"1801":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الزُّهْرِيِّ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ الْأَخِرَ وَقَعَ عَلَى امْرَأَتِهِ فِي رَمَضَانَ فَقَالَ أَتَجِدُ مَا تُحَرِّرُ رَقَبَةً قَالَ لَا قَالَ فَتَسْتَطِيعُ أَنْ تَصُومَ شَهْرَيْنِ مُتَتَابِعَيْنِ قَالَ لَا قَالَ أَفَتَجِدُ مَا تُطْعِمُ بِهِ سِتِّينَ مِسْكِينًا قَالَ لَا قَالَ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَقٍ فِيهِ تَمْرٌ وَهُوَ الزَّبِيلُ قَالَ أَطْعِمْ هَذَا عَنْكَ قَالَ عَلَى أَحْوَجَ مِنَّا مَا بَيْنَ لَابَتَيْهَا أَهْلُ بَيْتٍ أَحْوَجُ مِنَّا قَالَ فَأَطْعِمْهُ أَهْلَكَ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Az Zuhriy] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah radliallahu 'anhu] (berkata): \"Datang seorang laki-laki kepada Nabi shallallahu 'alaihi wasallam lalu berkata: \"Ada seseorang yang berhubungan dengan isterinya pada siang hari Ramadhan\". Beliau bertanya: \"Apakah kamu memiliki budak untuk kamu bebaskan?\" Orang itu menjawab: \"Tidak\". Lalu Beliau bertanya lagi: \"Apakah kamu sanggup bila harus berpuasa selama dua bulan berturut-turut?\" Orang itu menjawab: \"Tidak\". Lalu Beliau bertanya lagi: \"Apakah kamu memiliki makanan untuk diberikan kepada enam puluh orang miskin?\" Orang itu menjawab: \"Tidak\". Kemudian Nabi shallallahu 'alaihi wasallam diberikan satu keranjang berisi kurma, keranjang besar yang biasa untuk menampung sampah, lalu Beliau berkata: \"Berilah makan orang lain dengan kurma ini\". Orang itu berkata: \"Apakah ada orang yang lebih membutuhkan dari kami? Tidak ada keluarga yang tinggal diantara dua perbatasan yang lebih membutuhkan bantuan daripada kami\". Maka Beliau berkata: \"Kalau begitu berilah makan keluargamu dengan kurma ini\". "},"1802":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجَمَ وَهُوَ مُحْرِمٌ وَاحْتَجَمَ وَهُوَ صَائِمٌ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam berbekam ketika sedang berihram dan juga berbekam ketika sedang berpuasa."},"1803":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَاحْتَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ صَائِمٌ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam berbekam ketika sedang berpuasa."},"1804":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ ثَابِتًا الْبُنَانِيَّ قَالَسُئِلَ أَنَسُ بْنُ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ أَكُنْتُمْ تَكْرَهُونَ الْحِجَامَةَ لِلصَّائِمِ قَالَ لَا إِلَّا مِنْ أَجْلِ الضَّعْفِوَزَادَ شَبَابَةُ حَدَّثَنَا شُعْبَةُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] telah menceritakan kepada kami [Syu'bah] berkata, aku mendengar [Tsabit Al Bunaniy] berkata; [Anas bin Malik radliallahu 'anhu] pernah ditanya; apakah engkau membenci berbekam ketika berpuasa? Dia menjawab: \"Tidak, kecuali jika fisik lemah\". [Syababah] menambahkan, telah menceritakan kepada kami [Syu'bah]: \"Yaitu pada masa Nabi shallallahu 'alaihi wasallam \"."},"1805":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ الشَّيْبَانِيِّ سَمِعَ ابْنَ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَالَ لِرَجُلٍ انْزِلْ فَاجْدَحْ لِي قَالَ يَا رَسُولَ اللَّهِ الشَّمْسُ قَالَ انْزِلْ فَاجْدَحْ لِي قَالَ يَا رَسُولَ اللَّهِ الشَّمْسُ قَالَ انْزِلْ فَاجْدَحْ لِي فَنَزَلَ فَجَدَحَ لَهُ فَشَرِبَ ثُمَّ رَمَى بِيَدِهِ هَا هُنَا ثُمَّ قَالَ إِذَا رَأَيْتُمْ اللَّيْلَ أَقْبَلَ مِنْ هَا هُنَا فَقَدْ أَفْطَرَ الصَّائِمُتَابَعَهُ جَرِيرٌ وَأَبُو بَكْرِ بْنُ عَيَّاشٍ عَنْ الشَّيْبَانِيِّ عَنْ ابْنِ أَبِي أَوْفَى قَالَ كُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq Asy-Syaibaniy] dia mendengar [Ibnu Abu Awfa radliallahu 'anhudhiyallahu'anhu] berkata; Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan yang ketika itu beliau berkata kepada seseorang: \"Turunlah disini dan siapkan minuman buatku\". Orang itu berkata: \"Wahai Rasulullah, bukankah masih ada matahari?\" Beliau berkata, lagi: \"Turunlah (berhenti disini) dan siapkan minuman buatku\". Orang itu berkata, lagi: \"Wahai Rasulullah, bukankah masih ada matahari?\" Beliau berkata, lagi: \"Turunlah dan siapkan minuman buatku\". Maka orang itu berhenti lalu memberikan minuman kepada Beliau, lalu Beliau minum kemudian melempar sesuatu dengan tangan Beliau ke suatu arah lalu bersabda: \"Apabila kalian telah melihat malam sudah datang dari arah sana maka orang yang puasa sudah boleh berbuka \". Hadits inidikuatkan pula oleh [Jarir] dan [Abu Bakar bin 'Ayyasy] dari [Asy-Syaibaniy] dari [Ibnu Abu Awfa radliallahu 'anhu] berkata: \"Aku pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan\". "},"1806":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ عَائِشَةَأَنَّ حَمْزَةَ بْنَ عَمْرٍو الْأَسْلَمِيَّ قَالَ يَا رَسُولَ اللَّهِ إِنِّي أَسْرُدُ الصَّوْمَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Hisyam] berkata, [bapakku] telah menceritakan kepadaku dari ['Aisyah radliallahu 'anha] bahwa Hamzah bin 'Amru Al Aslamiy berkata: \"Wahai Rasulullah, aku sering berpuasa\"."},"1807":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ حَمْزَةَ بْنَ عَمْرٍو الْأَسْلَمِيَّ قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَأَصُومُ فِي السَّفَرِ وَكَانَ كَثِيرَ الصِّيَامِ فَقَالَ إِنْ شِئْتَ فَصُمْ وَإِنْ شِئْتَ فَأَفْطِرْ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha], isteri Nabi shallallahu 'alaihi wasallam, bahwa Hamzah bin 'Amru Al Aslamiy berkata, kepada Nabi shallallahu 'alaihi wasallam: \"Apakah aku boleh berpuasa saat bepergian? Dia adalah orang yang banyak berpuasa. Maka Beliau menawab: \"Jika kamu mau berpuasalah dan jika kamu mau berbukalah\". "},"1808":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى مَكَّةَ فِي رَمَضَانَ فَصَامَ حَتَّى بَلَغَ الْكَدِيدَ أَفْطَرَ فَأَفْطَرَ النَّاسُقَالَ أَبُو عَبْد اللَّهِ وَالْكَدِيدُ مَاءٌ بَيْنَ عُسْفَانَ وَقُدَيْدٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam pergi menuju Makkah dalam bulan Ramadhan dan Beliau berpuasa. Ketika sampai di daerah Kadid, Beliau berbuka yang kemudian orang-orang turut pula berbuka. Abu 'Abdullah Al Bukhariy berkata: \"Kadid adalah tempat mata air yang terletak antara 'Usfan dan Qudaid\"."},"1809":{"ar":"بَاب حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ أَنَّ إِسْمَاعِيلَ بْنَ عُبَيْدِ اللَّهِ حَدَّثَهُ عَنْ أُمِّ الدَّرْدَاءِ عَنْ أَبِي الدَّرْدَاءِ رَضِيَ اللَّهُ عَنْهُ قَالَخَرَجْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ أَسْفَارِهِ فِي يَوْمٍ حَارٍّ حَتَّى يَضَعَ الرَّجُلُ يَدَهُ عَلَى رَأْسِهِ مِنْ شِدَّةِ الْحَرِّ وَمَا فِينَا صَائِمٌ إِلَّا مَا كَانَ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَابْنِ رَوَاحَةَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada kami [Yahya bin Hamzah] dari ['Abdurrahman bin YAzid bin Jabir] bahwa [Isma'il bin 'Ubaidullah] menceritakan kepada kami dari [Ummu Ad-Darda'] dari [Abu Ad-Darda' radliallahu 'anhu] berkata; Kami pernah bepergian bersama Nabi shallallahu 'alaihi wasallam pada sebagian perjalanan Beliau pada hari yang sangat panas sehingga ada seseorang yang meletakkan tangannya diatas kepalanya karena amat panasnya dan tidak ada diantara kami yang berpuasa kecuali Nabi shallallahu 'alaihi wasallam dan Ibnu Ruwahah. "},"1810":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الْأَنْصَارِيُّ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ عَمْرِو بْنِ الْحَسَنِ بْنِ عَلِيٍّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمْ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَرَأَى زِحَامًا وَرَجُلًا قَدْ ظُلِّلَ عَلَيْهِ فَقَالَ مَا هَذَا فَقَالُوا صَائِمٌ فَقَالَ لَيْسَ مِنْ الْبِرِّ الصَّوْمُ فِي السَّفَرِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Muhammad bin 'Abdurrahman Al Anshariy] berkata; Aku mendengar [Muhammad bin 'Amru bin Al Hasan bin 'Ali] dari [Jabir bin 'Abdullah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam pernah dalam suatu perjalanan melihat kerumunan orang, yang diantaranya ada seseorang yang sedang dipayungi. Beliau bertanya: \"Ada apa ini?\" Mereka menjawab: \"Orang ini sedang berpuasa\". Maka Beliau bersabda: \"Tidak termasuk kebajikan berpuasa dalam perjalanan\"."},"1811":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنَّا نُسَافِرُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَعِبْ الصَّائِمُ عَلَى الْمُفْطِرِ وَلَا الْمُفْطِرُ عَلَى الصَّائِمِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Humaid Ath-Thowil] dari [Anas bin Malik] berkata; \"Kami pernah bepergian bersama Nabi shallallahu 'alaihi wasallam, yang berpuasa tidak mencela yang berbuka dan yang berbuka juga tidak mencela yang berpuasa\"."},"1812":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ إِلَى مَكَّةَ فَصَامَ حَتَّى بَلَغَ عُسْفَانَ ثُمَّ دَعَا بِمَاءٍ فَرَفَعَهُ إِلَى يَدَيْهِ لِيُرِيَهُ النَّاسَ فَأَفْطَرَ حَتَّى قَدِمَ مَكَّةَ وَذَلِكَ فِي رَمَضَانَ فَكَانَ ابْنُ عَبَّاسٍ يَقُولُ قَدْ صَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَفْطَرَ فَمَنْ شَاءَ صَامَ وَمَنْ شَاءَ أَفْطَرَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Manshur] dari [Mujahid] dari [Thowus] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; \"Rasulullah shallallahu 'alaihi wasallam berangkat dari Madinah menuju Makkah dalam keadaan berpuasa sehingga ketika sampai di daerah 'Usfan, Beliau meminta air lalu Beliau mengangkat air itu dengan tangan Beliau agar dilihat oleh orang banyak, lalu Beliau berbuka hingga tiba di Makkah. Kejadian ini di bulan Ramadhan\". Dan Ibnu 'Abbas radliallahu 'anhuma juga berkata: \"Dan Rasulullah shallallahu 'alaihi wasallam juga pernah berpuasa dalam suatu perjalanan Beliau dan juga pernah berbuka. Maka siapa yang mau silakan berpuasa dan siapa yang mau silakan berbuka\". "},"1813":{"ar":"حَدَّثَنَا عَيَّاشٌ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاقَرَأَ{ فِدْيَةٌ طَعَامُ مَسَاكِينَ }قَالَ هِيَ مَنْسُوخَةٌ","id":"Telah menceritakan kepada kami ['Ayyasy] telah menceritakan kepada kami ['Abdul 'Abdullah'laa] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa dia membaca ayat fidyatun to'aamu masaakiin (dendanya adalah memberi makan orang miskin), lalu ia berkata, bahwa ayat ini sudah dihapus."},"1814":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ سَمِعْتُ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا تَقُولُكَانَ يَكُونُ عَلَيَّ الصَّوْمُ مِنْ رَمَضَانَ فَمَا أَسْتَطِيعُ أَنْ أَقْضِيَ إِلَّا فِي شَعْبَانَ قَالَ يَحْيَى الشُّغْلُ مِنْ النَّبِيِّ أَوْ بِالنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Yahya] dari [Abu Salamah] berkata; Aku mendengar ['Aisyah radliallahu 'anha] berkata: \"Aku berhutang puasa Ramadhan dan aku tidak bisa mengqadha'nya kecuali pada bulan Sya'ban\". Yahya berkata: \"Karena dia sibuk karena atau bersama Nabi shallallahu 'alaihi wasallam \"."},"1815":{"ar":"حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي زَيْدٌ عَنْ عِيَاضٍ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَيْسَ إِذَا حَاضَتْ لَمْ تُصَلِّ وَلَمْ تَصُمْ فَذَلِكَ نُقْصَانُ دِينِهَا","id":"Telah menceritakan kepada kami [Ibnu Abu Maryam] telah menceritakan kepada kami [Muhammad bin Ja'far] berkata, telah menceritakan kepada saya [Zaid] dari ['Iyadh] dari [Abu Sa'id radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila (seorang wanita) sedang mengalami haidh, maka dia tidak shalat dan tidak puasa. Yang demikian itu menunjukkan kurangnya agamanya\"."},"1816":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى بْنِ أَعْيَنَ حَدَّثَنَا أَبِي عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ أَنَّ مُحَمَّدَ بْنَ جَعْفَرٍ حَدَّثَهُ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَاتَ وَعَلَيْهِ صِيَامٌ صَامَ عَنْهُ وَلِيُّهُتَابَعَهُ ابْنُ وَهْبٍ عَنْ عَمْرٍو وَرَوَاهُ يَحْيَى بْنُ أَيُّوبَ عَنْ ابْنِ أَبِي جَعْفَرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Khalid] telah menceritakan kepada kami [Muhammad bin Musa bin A'yan] telah menceritakan kepada kami [bapakku] dari ['Amru bin Al Harits] dari ['Ubaidullah bin Abu Ja'far] bahwa [Muhammad bin Ja'far] menceritakan kepadanya dari ['Urwah] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa meninggal dunia dan memiliki hutang puasa maka walinya (boleh) berpuasa untuknya\". Hadits ini dikuatkan pula oleh [Ibnu Wahab] dari ['Amru]. Dan [Yahya bin Ayyub] meriwayatkannya dari [Ibnu Abu Ja'far]."},"1817":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحِيمِ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا زَائِدَةُ عَنْ الْأَعْمَشِ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أُمِّي مَاتَتْ وَعَلَيْهَا صَوْمُ شَهْرٍ أَفَأَقْضِيهِ عَنْهَا قَالَ نَعَمْ قَالَ فَدَيْنُ اللَّهِ أَحَقُّ أَنْ يُقْضَىقَالَ سُلَيْمَانُ فَقَالَ الْحَكَمُ وَسَلَمَةُ وَنَحْنُ جَمِيعًا جُلُوسٌ حِينَ حَدَّثَ مُسْلِمٌ بِهَذَا الْحَدِيثِ قَالَا سَمِعْنَا مُجَاهِدًا يَذْكُرُ هَذَا عَنْ ابْنِ عَبَّاسٍ وَيُذْكَرُ عَنْ أَبِي خَالِدٍ حَدَّثَنَا الْأَعْمَشُ عَنْ الْحَكَمِ وَمُسْلِمٍ الْبَطِينِ وَسَلَمَةَ بْنِ كُهَيْلٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ وَعَطَاءٍ وَمُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَتْ امْرَأَةٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أُخْتِي مَاتَتْ وَقَالَ يَحْيَى وَأَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَتْ امْرَأَةٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أُمِّي مَاتَتْ وَقَالَ عُبَيْدُ اللَّهِ عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ الْحَكَمِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَتْ امْرَأَةٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أُمِّي مَاتَتْ وَعَلَيْهَا صَوْمُ نَذْرٍ وَقَالَ أَبُو حَرِيزٍ حَدَّثَنَا عِكْرِمَةُ عَنْ ابْنِ عَبَّاسٍ قَالَتْ امْرَأَةٌ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاتَتْ أُمِّي وَعَلَيْهَا صَوْمُ خَمْسَةَ عَشَرَ يَوْمًا","id":"Telah menceritakan kepada kami [Muhammad bin 'Abdur Rahim] telah menceritakan kepada kami [Mu'awiyah bin 'Amru] telah menceritakan kepada kami [Za'idah] dari [Al A'masy] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; \"Datang seorang laki-laki kepada Nabi shallallahu 'alaihi wasallam lalu berkata: \"Wahai Rasulullah, sesungguhnya ibuku telah meningal dunia dan dia mempunyai kewajiban (hutang) puasa selama sebulan, apakah aku boleh menunaikannya?\". Beliau Shallallahu'alaihiwasallam berkata: \"Ya\", Beliau melanjutkan: \"Hutang kepada Allah lebih berhaq untuk dibayar\". [Sulaiman] berkata, [Al Hakam] dan [Salamah] berkata; Ketika kami sedang duduk bersama, Muslim menceritakan tentang hadits ini, keduanya berkata; Kami mendengar [Mujahid] menyebutkan masalah ini dari [Ibnu 'Abbas radliallahu 'anhuma]. Dan disebutkan pula dari [Abu Khalid], telah menceritakan kepada kami [Al A'masy] dari [Al Hakam] dan [Muslim Al Bathin] dan [Salamah bin Kuhail] dari [Sa'id bin Jubair] dan ['Atho'] dan [Mujahid] dari [Ibnu 'Abbas radliallahu 'anhuma]; seorang wanita berkata kepada Nabi shallallahu 'alaihi wasallam: \"Sesungguhnya saudara perempuanku telah meninggal dunia\". Dan [Yahya] dan [Abu Mu'awiyah] berkata, telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] radliallahu 'anhuma; seorang wanita berkata kepada Nabi shallallahu 'alaihi wasallam: \"Sesungguhnya ibuku telah meningal dunia\". Dan ['Ubaidullah] berkata; dari [Zaid bin Abi Unaisah] dari [Al Hakam] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas]; seorang wanita berkata kepada Rasulullah shallallahu 'alaihi wasallam; \"sesungguhnya ibuku telah meninggal dunia, dan dia mempunyai tanggungan puasa nadzar.\" Dan [Abu Hariz] berkata, telah menceritakan kepada kami ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma]: seorang wanita berkata kepada Nabi shallallahu 'alaihi wasallam; \"sesungguhnya ibuku telah meninggal dunia, dan dia memiliki hutang puasa selama lima belas hari\"."},"1818":{"ar":"حَدَّثَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ قَالَ سَمِعْتُ أَبِي يَقُولُ سَمِعْتُ عَاصِمَ بْنَ عُمَرَ بْنِ الْخَطَّابِ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَقْبَلَ اللَّيْلُ مِنْ هَا هُنَا وَأَدْبَرَ النَّهَارُ مِنْ هَا هُنَا وَغَرَبَتْ الشَّمْسُ فَقَدْ أَفْطَرَ الصَّائِمُ","id":"Telah menceritakan kepada kami [Al Humaidiy] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Hisyam bin 'Urwah] berkata, aku mendengar [bapakku] berkata, aku mendengar ['Ashim bin 'Umar bin Al Khaththob] dari [bapaknya radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika malam telah datang dari sana dan siang telah berlalu dari sana serta matahari telah tenggelam, maka orang yang berpuasa sudah boleh berbuka \"."},"1819":{"ar":"حَدَّثَنَا إِسْحَاقُ الْوَاسِطِيُّ حَدَّثَنَا خَالِدٌ عَنْ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ وَهُوَ صَائِمٌ فَلَمَّا غَرَبَتْ الشَّمْسُ قَالَ لِبَعْضِ الْقَوْمِ يَا فُلَانُ قُمْ فَاجْدَحْ لَنَا فَقَالَ يَا رَسُولَ اللَّهِ لَوْ أَمْسَيْتَ قَالَ انْزِلْ فَاجْدَحْ لَنَا قَالَ يَا رَسُولَ اللَّهِ فَلَوْ أَمْسَيْتَ قَالَ انْزِلْ فَاجْدَحْ لَنَا قَالَ إِنَّ عَلَيْكَ نَهَارًا قَالَ انْزِلْ فَاجْدَحْ لَنَا فَنَزَلَ فَجَدَحَ لَهُمْ فَشَرِبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ إِذَا رَأَيْتُمْ اللَّيْلَ قَدْ أَقْبَلَ مِنْ هَا هُنَا فَقَدْ أَفْطَرَ الصَّائِمُ","id":"Telah menceritakan kepada kami [Ishaq Al Washithiy] telah menceritakan kepada kami [Khalid] dari [Asy-Syaibaniy] dari ['Abdullah bin Abu Awfa radliallahu 'anhudhiyallahu'anhu] berkata; Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan dan Beliau berpuasa. Ketika matahari terbenam, Beliau berkata kepada sebagian rombongan; \"Wahai fulan, bangun dan siapkanlah minuman buat kami\". Orang yang disuruh itu berkata: \"Wahai Rasulullah, bagaimana jika kita menunggu hingga sore\". Beliau berkata: \"Turunlah dan siapkan minuman buat kami\". Orang itu berkata, lagi: \"Wahai Rasulullah, bagaimana jika kita menunggu hingga sore\". Beliau berkata, lagi: \"Turunlah dan siapkan minuman buat kami\". Orang itu berkata, lagi: \"Sekarang masih siang\". Beliau kembali berkata: \"Turunlah dan siapkan minuman buat kami\". Maka orang itu turun lalu menyiapkan minuman buat mereka. Setelah minum lalu Nabi shallallahu 'alaihi wasallam berkata: \"Apabila kalian telah melihat malam sudah datang dari arah sana maka orang yang puasa sudah boleh berbuka \". "},"1820":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الشَّيْبَانِيُّ سُلَيْمَانُ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُ قَالَسِرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ صَائِمٌ فَلَمَّا غَرَبَتْ الشَّمْسُ قَالَ انْزِلْ فَاجْدَحْ لَنَا قَالَ يَا رَسُولَ اللَّهِ لَوْ أَمْسَيْتَ قَالَ انْزِلْ فَاجْدَحْ لَنَا قَالَ يَا رَسُولَ اللَّهِ إِنَّ عَلَيْكَ نَهَارًا قَالَ انْزِلْ فَاجْدَحْ لَنَا فَنَزَلَ فَجَدَحَ ثُمَّ قَالَ إِذَا رَأَيْتُمْ اللَّيْلَ أَقْبَلَ مِنْ هَا هُنَا فَقَدْ أَفْطَرَ الصَّائِمُ وَأَشَارَ بِإِصْبَعِهِ قِبَلَ الْمَشْرِقِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Asy-Syaibaniy Sulaiman] berkata, aku mendengar ['Abdullah bin Abu Awfa radliallahu 'anhu] berkata; Kami pernah bepergian Rasulullah shallallahu 'alaihi wasallam, ketika itu Beliau berpuasa. Ketika matahari terbenam, Beliau berkata: \"Turunlah, dan siapkanlah minuman buat kami\". Orang yang disuruh itu berkata: \"Wahai Rasulullah, bagaimana jika kita menunggu hingga sore\". Beliau berkata: \"Turunlah dan siapkan minuman buat kami\". Orang itu berkata, lagi: \"Sekarang masih siang\". Beliau berkata, lagi: \"Turunlah dan siapkan minuman buat kami\".\" Maka orang itu turun lalu menyiapkan minuman buat mereka. Setelah minum lalu Nabi shallallahu 'alaihi wasallam berkata: \"Apabila kalian telah melihat malam sudah datang dari arah sana maka orang yang puasa sudah boleh berbuka \". Beliau memberi isyarat dengan jari Beliau ke arah timur."},"1821":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ النَّاسُ بِخَيْرٍ مَا عَجَّلُوا الْفِطْرَ","id":"Telah menceritakan kepada kami ['Abdullah bion Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu HAzim] dari [Sahal bin Sa'ad] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Senantiasa manusia berada dalam kebaikan selama mereka menyegerakan berbuka\"."},"1822":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ سُلَيْمَانَ عَنْ ابْنِ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُ قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَصَامَ حَتَّى أَمْسَى قَالَ لِرَجُلٍ انْزِلْ فَاجْدَحْ لِي قَالَ لَوْ انْتَظَرْتَ حَتَّى تُمْسِيَ قَالَ انْزِلْ فَاجْدَحْ لِي إِذَا رَأَيْتَ اللَّيْلَ قَدْ أَقْبَلَ مِنْ هَا هُنَا فَقَدْ أَفْطَرَ الصَّائِمُ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Abu Bakar] dari [Sulaiman] dari [Ibnu Abu Awfa radliallahu 'anhu] berkata; Aku pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, ketika itu Beliau berpuasa. Hingga ketika sampai pada waktu petang, Beliau berkata kepada seseorang: \"Turunlah, dan siapkanlah minuman aku\". Orang yang disuruh itu berkata: \"Bagaimana jika anda menunggu hingga sore\". Beliau berkata: \"Turunlah dan siapkan minuman buat aku. Apabila kamu telah melihat malam sudah datang dari arah sana maka orang yang puasa sudah boleh berbuka \". "},"1823":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ الصِّدِّيقِ رَضِيَ اللَّهُ عَنْهُمَا قَالَتْأَفْطَرْنَا عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ غَيْمٍ ثُمَّ طَلَعَتْ الشَّمْسُ قِيلَ لِهِشَامٍ فَأُمِرُوا بِالْقَضَاءِ قَالَ لَا بُدَّ مِنْ قَضَاءٍوَقَالَ مَعْمَرٌ سَمِعْتُ هِشَامًا لَا أَدْرِي أَقَضَوْا أَمْ لَا","id":"Telah menceritakan kepada kami ['Abdullah bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah] dari [Fathimah] dari [Asma' binti Abu Bakar Ash-Shiddiq radliallahu 'anhuma] berkata; Kami pernah berbuka puasa pada zaman Nabi shallallahu 'alaihi wasallam ketika hari mendung, ternyata kemudian matahari tampak kembali, maka orang-orang diperintahkan untuk mengqadha'nya, dan Beliau bersabda: \"Harus dilaksanakan qadha'\". Dan [Ma'mar] berkata, aku mendengar [Hisyam]: Aku tidak tahu apakah mereka kemudian mengqadha'nya atau tidak\"."},"1824":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا خَالِدُ بْنُ ذَكْوَانَ عَنْ الرُّبَيِّعِ بِنْتِ مُعَوِّذٍ قَالَتْأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَدَاةَ عَاشُورَاءَ إِلَى قُرَى الْأَنْصَارِ مَنْ أَصْبَحَ مُفْطِرًا فَلْيُتِمَّ بَقِيَّةَ يَوْمِهِ وَمَنْ أَصْبَحَ صَائِمًا فَليَصُمْ قَالَتْ فَكُنَّا نَصُومُهُ بَعْدُ وَنُصَوِّمُ صِبْيَانَنَا وَنَجْعَلُ لَهُمْ اللُّعْبَةَ مِنْ الْعِهْنِ فَإِذَا بَكَى أَحَدُهُمْ عَلَى الطَّعَامِ أَعْطَيْنَاهُ ذَاكَ حَتَّى يَكُونَ عِنْدَ الْإِفْطَارِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Bisyir bin Al Mufadhdhal] telah menceritakan kepada kami [Khalid bin Dzakwan] dari [Ar-Rubai' binti Mu'awwidz] berkata; Nabi shallallahu 'alaihi wasallam mengirim utusan ke kampung Kaum Anshar pada siang hari 'Asyura (untuk menyampaikan): \"Bahwa siapa yang tidak berpuasa sejak pagi hari maka dia harus menggantinya pada hari yang lain, dan siapa yang sudah berpuasa sejak pagi hari maka hendaklah dia melanjutkan puasanya\". Dia (Ar-Rubai' binti Mu'awwidz) berkata; \"Setelah itu kami selalu berpuasa dan kami juga mendidik anak-anak kecil kami untuk berpuasa dan kami sediakan untuk mereka semacam alat permainan terbuat dari bulu domba, apabila seorang dari mereka ada yang menangis meminta makan maka kami beri dia permainan itu. Demikianlah terus kami lakukan hingga tiba waktu berbuka\"."},"1825":{"ar":"حَدَّثَنَا مُسَدَّدٌ قَالَ حَدَّثَنِي يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنِي قَتَادَةُ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُوَاصِلُوا قَالُوا إِنَّكَ تُوَاصِلُ قَالَ لَسْتُ كَأَحَدٍ مِنْكُمْ إِنِّي أُطْعَمُ وَأُسْقَى أَوْ إِنِّي أَبِيتُ أُطْعَمُ وَأُسْقَى","id":"Telah menceritakan kepada kami [Musaddad] berkata, telah menceritakan kepada saya [Yahya] dari [Syu'bah] berkata, telah menceritakan kepada saya [Qatadah] dari [Anas radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian melaksanakan puasa wishal (puasa terus tanpa berbuka) \". Orang-orang berkata: \"Namun, bukankah anda melakukan puasa wishal?\" Beliau bersabda: \"Aku tidak sama dengan keadaan seorang dari kalian karena aku diberi makan dan minum atau dengan redaksi selalu saja aku diberi makan dan minum \"."},"1826":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوِصَالِ قَالُوا إِنَّكَ تُوَاصِلُ قَالَ إِنِّي لَسْتُ مِثْلَكُمْ إِنِّي أُطْعَمُ وَأُسْقَى","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhua] berkata; Rasulullah shallallahu 'alaihi wasallam melarang puasa wishal. Orang-orang berkata: \"Namun, bukankah anda sendiri melakukan puasa wishal?\" Beliau bersabda: \"Aku tidak sama dengan keadaan seorang dari kalian karena aku diberi makan dan minum\"."},"1827":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي ابْنُ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُوَاصِلُوا فَأَيُّكُمْ إِذَا أَرَادَ أَنْ يُوَاصِلَ فَلْيُوَاصِلْ حَتَّى السَّحَرِ قَالُوا فَإِنَّكَ تُوَاصِلُ يَا رَسُولَ اللَّهِ قَالَ إِنِّي لَسْتُ كَهَيْئَتِكُمْ إِنِّي أَبِيتُ لِي مُطْعِمٌ يُطْعِمُنِي وَسَاقٍ يَسْقِينِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah menceritakan kepada saya [Al Laits] telah menceritakan kepada saya [Ibnu Al Hadi] dari ['Abdullah bin Khabbab] dari [Abu Sa'id radliallahu 'anhu] bahwa dia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian melaksanakan puasa wishal, maka siapa dari kalian yang mau melakukan puasa wishal hendaklah dia melakukannya hingga (makan) sahur\". Orang-orang berkata: \"Bukankah anda sendiri melakukan puasa wishal, wahai Rasulullah?\" Beliau bersabda: \"Aku tidak sama dengan keadaan seorang kalian karena saat aku tidur akan ada pemberi makan yang datang kepadaku lalu memberi aku makan dan datang pemberi minum lalu memberi aku minum\"."},"1828":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدٌ قَالَا أَخْبَرَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوِصَالِ رَحْمَةً لَهُمْ فَقَالُوا إِنَّكَ تُوَاصِلُ قَالَ إِنِّي لَسْتُ كَهَيْئَتِكُمْ إِنِّي يُطْعِمُنِي رَبِّي وَيَسْقِينِ قَالَ أَبُو عَبْد اللَّهِلَمْ يَذْكُرْ عُثْمَانُ رَحْمَةً لَهُمْ","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] dan [Muhammad] keduanya berkata, telah mengabarkan kepada kami ['Abdah] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha]; Rasulullah shallallahu 'alaihi wasallam melarang puasa wishal sebagai bentuk kasih sayang kepada mereka (para sahabat). Mereka berkata: \"Bukankah anda sendiri melakukan puasa wishal?\" Beliau bersabda: \"Aku tidak sama dengan keadaan seorang kalian karena aku diberi makan dan minum oleh Rabbku\". Abu 'Abdullah Al Bukhariy berkata: 'Utsman tidak menyebut kalimat; \"Sebagai bentuk kasih sayang kepada mereka\"."},"1829":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْوِصَالِ فِي الصَّوْمِ فَقَالَ لَهُ رَجُلٌ مِنْ الْمُسْلِمِينَ إِنَّكَ تُوَاصِلُ يَا رَسُولَ اللَّهِ قَالَ وَأَيُّكُمْ مِثْلِي إِنِّي أَبِيتُ يُطْعِمُنِي رَبِّي وَيَسْقِينِ فَلَمَّا أَبَوْا أَنْ يَنْتَهُوا عَنْ الْوِصَالِ وَاصَلَ بِهِمْ يَوْمًا ثُمَّ يَوْمًا ثُمَّ رَأَوْا الْهِلَالَ فَقَالَ لَوْ تَأَخَّرَ لَزِدْتُكُمْ كَالتَّنْكِيلِ لَهُمْ حِينَ أَبَوْا أَنْ يَنْتَهُوا","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah menceritakan kepada saya [Abu Salamah bin 'Abdurrahman] bahwa [Abu Hurairah radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam melarang wishal dalam berpuasa. Kemudian ada seseorang dari kalangan Kaum Muslimin yang berkata kepada Beliau: \"Bukankah anda melakukan puasa wishal, wahai Rasulullah?\" Maka Beliau berkata: \"Siapa dari kalian yang keadaannya sama denganku? Aku tidak sama dengan keadaan seorang kalian karena Rabbku selalu memberiku makan dan minum\". Tatkala mereka enggan menghentikan kebiasaan puasa wishal, maka Beliau melakukan puasa wishal bersama mereka hari demi hari, kemudian mereka melihat hilal. Maka ketika itu Beliau bersabda: \"Kalau hilal itu tidak datang (terlambat) pasti aku akan menambah lagi puasa wishal bersama kalian\". Ucapan ini Beliau sampaikan sebagai bentuk sindiran kepada mereka ketika mereka enggan menghentikan puasa wishal. "},"1830":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِيَّاكُمْ وَالْوِصَالَ مَرَّتَيْنِ قِيلَ إِنَّكَ تُوَاصِلُ قَالَ إِنِّي أَبِيتُ يُطْعِمُنِي رَبِّي وَيَسْقِينِ فَاكْلَفُوا مِنْ الْعَمَلِ مَا تُطِيقُونَ","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami ['Abdur RAzzaq] dari [Ma'mar] dari [Hammam] bahwasanya dia mendengar [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam berkata: \"Janganlah kalian melakukan puasa wishal\". Ada seseorang berkata, kepada Beliau: \"Bukankah anda melakukan puasa wishal?\" Beliau menjawab: \" Rabbku selalu memberiku makan dan memberi minum. Maka laksanakanlah amal amal yang kalian mampu saja\". "},"1831":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ حَدَّثَنِي ابْنُ أَبِي حَازِمٍ عَنْ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُوَاصِلُوا فَأَيُّكُمْ أَرَادَ أَنْ يُوَاصِلَ فَلْيُوَاصِلْ حَتَّى السَّحَرِ قَالُوا فَإِنَّكَ تُوَاصِلُ يَا رَسُولَ اللَّهِ قَالَ لَسْتُ كَهَيْئَتِكُمْ إِنِّي أَبِيتُ لِي مُطْعِمٌ يُطْعِمُنِي وَسَاقٍ يَسْقِينِ","id":"Telah menceritakan kepada kami [Ibrahim bin Hamzah] telah menceritakan kepada saya [Ibnu Abu HAzim] dari [YAzid] dari ['Abdullah bin Khabbab] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] bahwa dia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian melaksanakan puasa wishal, maka siapa dari kalian yang mau melakukan puasa wishal hendaklah dia melakukannya hingga (makan) sahur\". Mereka berkata: \"Bukankah anda melakukan puasa wishal, wahai Rasulullah?\" Beliau bersabda: \"Aku tidak sama dengan keadaan seorang kalian karena bagiku ada pemberi makan yang memberi aku makan dan pemberi minum yang memberi aku minum\"."},"1832":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا أَبُو الْعُمَيْسِ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَآخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ سَلْمَانَ وَأَبِي الدَّرْدَاءِ فَزَارَ سَلْمَانُ أَبَا الدَّرْدَاءِ فَرَأَى أُمَّ الدَّرْدَاءِ مُتَبَذِّلَةً فَقَالَ لَهَا مَا شَأْنُكِ قَالَتْ أَخُوكَ أَبُو الدَّرْدَاءِ لَيْسَ لَهُ حَاجَةٌ فِي الدُّنْيَا فَجَاءَ أَبُو الدَّرْدَاءِ فَصَنَعَ لَهُ طَعَامًا فَقَالَ كُلْ قَالَ فَإِنِّي صَائِمٌ قَالَ مَا أَنَا بِآكِلٍ حَتَّى تَأْكُلَ قَالَ فَأَكَلَ فَلَمَّا كَانَ اللَّيْلُ ذَهَبَ أَبُو الدَّرْدَاءِ يَقُومُ قَالَ نَمْ فَنَامَ ثُمَّ ذَهَبَ يَقُومُ فَقَالَ نَمْ فَلَمَّا كَانَ مِنْ آخِرِ اللَّيْلِ قَالَ سَلْمَانُ قُمْ الْآنَ فَصَلَّيَا فَقَالَ لَهُ سَلْمَانُ إِنَّ لِرَبِّكَ عَلَيْكَ حَقًّا وَلِنَفْسِكَ عَلَيْكَ حَقًّا وَلِأَهْلِكَ عَلَيْكَ حَقًّا فَأَعْطِ كُلَّ ذِي حَقٍّ حَقَّهُ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقَ سَلْمَانُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Abu Al 'Umais] dari ['Aun bin Abu Juhaifah] dari [bapaknya] berkata; Nabi shallallahu 'alaihi wasallam mempersaudarakan Salman dan Abu Darda'. Suatu hari Salman mengunjungi Abu Darda', lalu ia melihat Ummu Darda' dengan baju yang kumuh, lalu ia berkata, kepadanya; \"Ada apa denganmu?\" Dia menjawab: \"Saudaramu Abu Darda', dia tidak memperhatikan kebutuhan dunia\". Kemudian Abu Darda' datang, lalu ia membuat makanan untuk Salman. Salman berkata kepada Abu Darda': \"Makanlah!\". Abu Darda' menjawab: \"Aku sedang berpuasa\". Salman berkata: \"Aku tidak akan makan hingga engkau makan\". Dia berkata: \"Lalu Abu Darda' ikut makan\". Pada malam hari Abu Darda' bangun, lalu Salman berkata: \"Teruskanlah tidur\". Maka iapun tidur lalu bangun lagi, lalu Salman berkata: \"Teruskanlah tidur\". Maka iapun tidur lagi. Pada akhir malam Salman berkata: \"Sekarang bangunlah\". Kemudian mereka berdua shalat malam\". Lalu Salman berkata kepada Abu Darda': \"Sesungguhnya Rabbmu mempunyai hak atasmu, dan jiwamu mempunyai hak atasmu, dan isterimu mempunyai hak atasmu, maka berilah setiap hak kepada orang yang berhak\". Kemudian Abu Darda' menemui Nabi shallallahu 'alaihi wasallam lalu ia menceritakan hal itu. Maka Beliau bersabda: \"Salman benar\"."},"1833":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ حَتَّى نَقُولَ لَا يُفْطِرُ وَيُفْطِرُ حَتَّى نَقُولَ لَا يَصُومُ فَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ��سْتَكْمَلَ صِيَامَ شَهْرٍ إِلَّا رَمَضَانَ وَمَا رَأَيْتُهُ أَكْثَرَ صِيَامًا مِنْهُ فِي شَعْبَانَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu An-Nadhar] dari [Abu Salamah] dari ['Aisyah radliallahu 'anha] berkata: \"Rasulullah shallallahu 'alaihi wasallam sedemikian sering melaksanakan shaum hingga kami mengatakan seolah-olah beliau tidak pernah berbuka (tidak shaum), namun beliau juga sering tidak shaum sehingga kami mengatakan seolah-olah Beliau tidak pernah shaum. Dan aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam menyempurnakan puasa selama sebulan penuh kecuali puasa Ramadhan dan aku tidak pernah melihat Beliau paling banyak melaksanakan puasa (sunnat) kecuali di bulan Sya'ban\". "},"1834":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا حَدَّثَتْهُ قَالَتْلَمْ يَكُنْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُ شَهْرًا أَكْثَرَ مِنْ شَعْبَانَ فَإِنَّهُ كَانَ يَصُومُ شَعْبَانَ كُلَّهُ وَكَانَ يَقُولُ خُذُوا مِنْ الْعَمَلِ مَا تُطِيقُونَ فَإِنَّ اللَّهَ لَا يَمَلُّ حَتَّى تَمَلُّوا وَأَحَبُّ الصَّلَاةِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا دُووِمَ عَلَيْهِ وَإِنْ قَلَّتْ وَكَانَ إِذَا صَلَّى صَلَاةً دَاوَمَ عَلَيْهَا","id":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] bahwa ['Aisyah radliallahu 'anha] menceritakan kepadanya, katanya: \"Rasulullah shallallahu 'alaihi wasallam tidak pernah melaksanakan shaum lebih banyak dalam sebulan selain bulan Sya'ban, yang Beliau melaksanakan shaum bulan Sya'ban seluruhnya. Beliau bersabda: \"Lakukanlah amal-amal yang kalian sanggup melaksanakannya, karena Allah tidak akan berpaling (dalam memberikan pahala) sampai kalian yang lebih dahulu berpaling (dari mengerjakan amal) \". Dan shalat yang paling Nabi shallallahu 'alaihi wasallam cintai adalah shalat yang dijaga kesinambungannya sekalipun sedikit. Dan Beliau bila sudah biasa melaksanakan shalat (sunnat) beliau menjaga kesinambungannya\". "},"1835":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَمَا صَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا كَامِلًا قَطُّ غَيْرَ رَمَضَانَ وَيَصُومُ حَتَّى يَقُولَ الْقَائِلُ لَا وَاللَّهِ لَا يُفْطِرُ وَيُفْطِرُ حَتَّى يَقُولَ الْقَائِلُ لَا وَاللَّهِ لَا يَصُومُ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyir] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \" Nabi shallallahu 'alaihi wasallam tidak pernah sekalipun melaksanakan shaum sebulan penuh kecuali puasa Ramadhan. Dan beliau seseorang yang rajin puasa sehingga sehingga ada yang berkomentar; \"Tidak, demi Allah, beliau belum pernah tidak shaum\". Namun sering-sering beliau juga tidak puasa sehingga ada seorang yang berkata; \"Tidak, demi Allah, Beliau belum pernah shaum\". "},"1836":{"ar":"حَدَّثَنِي عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ حُمَيْدٍ أَنَّهُ سَمِعَ أَنَسًا رَضِيَ اللَّهُ عَنْهُ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُفْطِرُ مِنْ الشَّهْرِ حَتَّى نَظُنَّ أَنْ لَا يَصُومَ مِنْهُ وَيَصُومُ حَتَّى نَظُنَّ أَنْ لَا يُفْطِرَ مِنْهُ شَيْئًا وَكَانَ لَا تَشَاءُ تَرَاهُ مِنْ اللَّيْلِ مُصَلِّيًا إِلَّا رَأَيْتَهُ وَلَا نَائِمًا إِلَّا رَأَيْتَهُوَقَالَ سُلَيْمَانُ عَنْ حُمَيْدٍ أَنَّهُ سَأَلَ أَنَسًا فِي الصَّوْمِ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] berkata, telah menceritakan kepada saya [Muhammad bin Ja'far] dari [Humaid] bahwasanya dia mendengar [Anas radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam pernah tidak berpuasa selama sebulan hingga kami menduga beliau tidak pernah puasa seharipun dari bulan itu. Dan pernah juga Beliau puasa hingga seolah-olah kami menduga beliau belum pernah tidak puasa seharipun. Dan seandainya kamu ingin melihat di malam hari Beliau shalat pasti kalian akan melihat Beliau sedang shalat, namun begitu juga saat kamu ingin melihat Beliau tidur, pasti kamu akan melihat Beliau sedang tidur\". Dan berkata, [Sulaiman] dari [Humaid] bahwa dia pernah bertanya kepada [Anas] tentang shaum Rasulullah shallallahu 'alaihi wasallam."},"1837":{"ar":"حَدَّثَنِي مُحَمَّدٌ هُوَ ابْنُ سَلَامٍ أَخْبَرَنَا أَبُو خَالِدٍ الْأَحْمَرُ أَخْبَرَنَا حُمَيْدٌ قَالَ سَأَلْتُ أَنَسًا رَضِيَ اللَّهُ عَنْهُعَنْ صِيَامِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا كُنْتُ أُحِبُّ أَنْ أَرَاهُ مِنْ الشَّهْرِ صَائِمًا إِلَّا رَأَيْتُهُ وَلَا مُفْطِرًا إِلَّا رَأَيْتُهُ وَلَا مِنْ اللَّيْلِ قَائِمًا إِلَّا رَأَيْتُهُ وَلَا نَائِمًا إِلَّا رَأَيْتُهُ وَلَا مَسِسْتُ خَزَّةً وَلَا حَرِيرَةً أَلْيَنَ مِنْ كَفِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا شَمِمْتُ مِسْكَةً وَلَا عَبِيرَةً أَطْيَبَ رَائِحَةً مِنْ رَائِحَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada saya [Muhammad]. Dia adalah Ibnu Salam telah mengabarkan kepada kami [Abu Khalid Al Ahmar] telah mengabarkan kepada kami dari [Humaid] berkata; Aku bertanya kepada [Anas radliallahu 'anhu] tentang shaum Nabi shallallahu 'alaihi wasallam. Dia berkata: \"Tidaklah aku ingin melihat Beliau berpuasa dalam suatu bulan kecuali aku pasti melihatnya, begitu juga tidaklah aku ingin melihat beliau tidak berpuasa, pasti aku juga bisa melihatnya. Dan saat Beliau berdiri shalat malam melainkan aku melihatnya begitu juga bila Beliau tidur melainkan aku juga pernah melihatnya. Dan belum pernah aku menyentuh sutera campuran ataupun sutera halus yang melebihi halusnya telapak tangan Rasulullah shallallahu 'alaihi wasallam dan belum pernah pula aku mencium bau wewangian minyak kasturi dan wewangian lain yang lebih harum dari keharuman (badan) Rasulullah shallallahu 'alaihi wasallam. "},"1838":{"ar":"حَدَّثَنَا إِسْحَاقُ أَخْبَرَنَا هَارُونُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَلِيٌّ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنِي أَبُو سَلَمَةَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ الْعَاصِ رَضِيَ اللَّهُ عَنْهُمَا قَالَدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ يَعْنِي إِنَّ لِزَوْرِكَ عَلَيْكَ حَقًّا وَإِنَّ لِزَوْجِكَ عَلَيْكَ حَقًّا فَقُلْتُ وَمَا صَوْمُ دَاوُدَ قَالَ نِصْفُ الدَّهْرِ","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Harun bin 'Isma'il] telah menceritakan kepada kami ['Ali] telah menceritakan kepada kami [Yahya] berkata, telah menceritakan kepada saya [Abu Salamah] berkata, telah menceritakan kepada saya ['Abdullah bin 'Amru bin Al 'Ash radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam datang menemuiku. Lalu dia menceritakan hadits yang Beliau sabdakan, yaitu: \"Sesungguhnya isterimu mempunyai hak atasmu dan sesungguhnya isterimu mempunyai hak atasmu\". Dan aku bertanya tentang shaum Daud. Maka Beliau menjawab: \"Itu sama halnya separoh dari puasa Dahar (puasa sepanjang tahun) \". "},"1839":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ الْعَاصِ رَضِيَ اللَّهُ عَنْهُمَاقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ اللَّهِ أَلَمْ أُخْبَرْ أَنَّكَ تَصُومُ النَّهَارَ وَتَقُومُ اللَّيْلَ فَقُلْتُ بَلَى يَا رَسُولَ اللَّهِ قَالَ فَلَا تَفْعَلْ صُمْ وَأَفْطِرْ وَقُمْ وَنَمْ فَإِنَّ لِجَسَدِكَ عَلَيْكَ حَقًّا وَإِنَّ لِعَيْنِكَ عَلَيْكَ حَقًّا وَإِنَّ لِزَوْجِكَ عَلَيْكَ حَقًّا وَإِنَّ لِزَوْرِكَ عَلَيْكَ حَقًّا وَإِنَّ بِحَسْبِكَ أَنْ تَصُومَ كُلَّ شَهْرٍ ثَلَاثَةَ أَيَّامٍ فَإِنَّ لَكَ بِكُلِّ حَسَنَةٍ عَشْرَ أَمْثَالِهَا فَإِنَّ ذَلِكَ صِيَامُ الدَّهْرِ كُلِّهِ فَشَدَّدْتُ فَشُدِّدَ عَلَيَّ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أَجِدُ قُوَّةً قَالَ فَصُمْ صِيَامَ نَبِيِّ اللَّهِ دَاوُدَ عَلَيْهِ السَّلَام وَلَا تَزِدْ عَلَيْهِ قُلْتُ وَمَا كَانَ صِيَامُ نَبِيِّ اللَّهِ دَاوُدَ عَلَيْهِ السَّلَام قَالَ نِصْفَ الدَّهْرِ فَكَانَ عَبْدُ اللَّهِ يَقُولُ بَعْدَ مَا كَبِرَ يَا لَيْتَنِي قَبِلْتُ رُخْصَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Al Awza'iy] berkata, telah menceritakan kepada saya [Yahya bin Abu Katsir] berkata, telah menceritakan kepada saya [Abu Salamah bin 'Abdurrahman] berkata, telah menceritakan kepada saya ['Abdullah bin 'Amru bin Al 'Ash radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam berkata kepadaku: \"Wahai 'Abdullah, apakah benar berita bahwa kamu puasa seharian penuh lalu kamu shalat malam sepanjang malam?\" Aku jawab: \"Benar, wahai Rasulullah\". Beliau berkata: \"Janganlah kamu lakukan itu, tetapi shaumlah dan berbukalah, shalat malamlah dan tidurlah, karena untuk jasadmu ada hak atasmu, matamu punya hak atasmu, isterimu punya hak atasmu dan isterimu punya hak atasmu. Dan cukuplah bagimu bila kamu berpuasa selama tiga hari dalam setiap bulan karena bagimu setiap kebaikan akan dibalas dengan sepuluh kebaikan yang serupa dan itu berarti kamu sudah melaksanakan puasa sepanjang tahun seluruhnya\". Maka kemudian aku meminta tambahan, lalu Beliau menambahkannya. Aku katakan: \"Wahai Rasulullah, aku mendapati diriku memiliki kemampuan\". Maka Beliau berkata: \"Berpuasalah dengan puasanya Nabi Allah Daud Alaihissalam dan jangan kamu tambah lebih dari itu\". Aku bertanya: \"Bagaimanakah itu cara puasanya Nabi Allah Daud Alaihissalam?\" Beliau menjawab: \"Dia Alaihissalam berpuasa setengah dari puasa Dahar (puasa sepanjang tahun), caranya yaitu sehari puasa dan sehari tidak\". Di kemudian hari 'Abdullah bin 'Amru bin Al 'Ash radliallahu 'anhuma berkata: \"Duh, seandainya dahulu aku menerima keringanan yang telah diberikan oleh Nabi shallallahu 'alaihi wasallam \"."},"1840":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَبْدَ اللَّهِ بْنَ عَمْرٍو قَالَأُخْبِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي أَقُولُ وَاللَّهِ لَأَصُومَنَّ النَّهَارَ وَلَأَقُومَنَّ اللَّيْلَ مَا عِشْتُ فَقُلْتُ لَهُ قَدْ قُلْتُهُ بِأَبِي أَنْتَ وَأُمِّي قَالَ فَإِنَّكَ لَا تَسْتَطِيعُ ذَلِكَ فَصُمْ وَأَفْطِرْ وَقُمْ وَنَمْ وَصُمْ مِنْ الشَّهْرِ ثَلَاثَةَ أَيَّامٍ فَإِنَّ الْحَسَنَةَ بِعَشْرِ أَمْثَالِهَا وَذَلِكَ مِثْلُ صِيَامِ الدَّهْرِ قُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ فَصُمْ يَوْمًا وَأَفْطِرْ يَوْمَيْنِ قُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ قَالَ فَصُمْ يَوْمًا وَأَفْطِرْ يَوْمًا فَذَلِكَ صِيَامُ دَاوُدَ عَلَيْهِ السَّلَام وَهُوَ أَفْضَلُ الصِّيَامِ فَقُلْتُ إِنِّي أُطِيقُ أَفْضَلَ مِنْ ذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أَفْضَلَ مِنْ ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] bahwa ['Abdullah bin 'Amru] berkata; Diberitakan kepada Rasulullah shallallahu 'alaihi wasallam bahwa aku berkata: \"Demi Allah, sungguh aku pasti akan berpuasa sepanjang hari dan sungguh aku pasti akan shalat malam sepanjang hidupku\". Aku katakan secara terus terang; \"Demi bapak dan ibuku sebagai tebusannya, sungguh aku memang telah mengatakannya\". Maka Beliau berkata: \"Sungguh kamu pasti tidak akan sanggup melaksanakannya. Akan tetapi berpuasalah dan berbukalah, shalat malam dan tidurlah dan berpuasalah selama tiga hari dalam setiap bulan karena setiap kebaikan akan dibalas dengan sepuluh kebaikan yang serupa, dan itu seperti puasa sepanjang tahun \". Aku katakan; \"Sungguh aku mampu lebih dari itu\". Belau berkata: \"Kalau begitu puasalah sehari dan berbukalah selama dua hari\". Aku katakan lagi: \"Sungguh aku mampu yang lebih dari itu\". Beliau berkata: \"Kalau begitu puasalah sehari dan berbukalah sehari, yang demikian itu adalah puasanya Nabi Allah Daud 'alaihi salam yang merupakan puasa yang paling utama.\". Aku katakan lagi: \"Sungguh aku mampu yang lebih dari itu\". Maka beliau bersabda: \"Tidak ada puasa yang lebih utama dari itu\"."},"1841":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ سَمِعْتُ عَطَاءً أَنَّ أَبَا الْعَبَّاسِ الشَّاعِرَ أَخْبَرَهُ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَابَلَغَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي أَسْرُدُ الصَّوْمَ وَأُصَلِّي اللَّيْلَ فَإِمَّا أَرْسَلَ إِلَيَّ وَإِمَّا لَقِيتُهُ فَقَالَ أَلَمْ أُخْبَرْ أَنَّكَ تَصُومُ وَلَا تُفْطِرُ وَتُصَلِّي فَصُمْ وَأَفْطِرْ وَقُمْ وَنَمْ فَإِنَّ لِعَيْنِكَ عَلَيْكَ حَظًّا وَإِنَّ لِنَفْسِكَ وَأَهْلِكَ عَلَيْكَ حَظًّا قَالَ إِنِّي لَأَقْوَى لِذَلِكَ قَالَ فَصُمْ صِيَامَ دَاوُدَ عَلَيْهِ السَّلَام قَالَ وَكَيْفَ قَالَ كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا وَلَا يَفِرُّ إِذَا لَاقَى قَالَ مَنْ لِي بِهَذِهِ يَا نَبِيَّ اللَّهِقَالَ عَطَاءٌ لَا أَدْرِي كَيْفَ ذَكَرَ صِيَامَ الْأَبَدِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَامَ مَنْ صَامَ الْأَبَدَ مَرَّتَيْنِ","id":"Telah menceritakan kepada kami ['Amru bin 'Ali] telah mengabarkan kepada kami [Abu 'Ashim] dari [Abu Juraij] aku mendengar ['Atho'] bahwa [Abu Al 'Abbas Asy-Sya'ir] mengabarkan kepadanya bahwa dia mendengar ['Abdullah bin 'Amru radliallahu 'anhuma] (berkata,); Telah sampai kepada Nabi shallallahu 'alaihi wasallam berita tentang aku bahwa aku akan terus berpuasa dan shalat malam. Aku tak ingat lagi, apakah kemudian beliau mengutus utusan atau aku menemui beliau, dan Beliau berkata: \"Apakah benar kabar bahwa kamu akan berpuasa tidak akan berbuka dan shalat malam (tanpa tidur)? Puasa dan berbukalah, shalat dan juga tidurlah. Karena bagi matamu ada bagian hak atasmu dan bagi dirimu dan keluargamu ada bagian hak atasmu\". 'Abdullah bin 'Amru radliallahu 'anhuma berkata: \"Sungguh aku lebih kuat dari (amal amal) itu\". Beliau berkata: \"Kalau begitu puasalah dengan puasanya Nabi Daud Alaihissalam\". Dia bertanya: \"Bagaimana caranya\". Beliau shallallahu 'alaihi wasallam menawab: \"Nabi Daud 'Alaihissalam berpuasa sehari dan berbuka sehari sehingga dia tidak akan kabur ketika berjumpa dengan musuh\". Dia berkata: \"Lalu Siapa teladan bagi diriku dalam masalah puasa sepanjang jaman ini wahai Nabi shallallahu 'alaihi wasallam Allah? 'Atho' berkata: \"Aku tidak tahu bagaimana dia menyebutkan puasa abadi (sepanjang hidup), karena Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak dianggap puasa bagi siapa yang puasa abadi\". Beliau mengucapkannya dua kali. "},"1842":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مُغِيرَةَ قَالَ سَمِعْتُ مُجَاهِدًا عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صُمْ مِنْ الشَّهْرِ ثَلَاثَةَ أَيَّامٍ قَالَ أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ فَمَا زَالَ حَتَّى قَالَ صُمْ يَوْمًا وَأَفْطِرْ يَوْمًا فَقَالَ اقْرَإِ الْقُرْآنَ فِي كُلِّ شَهْرٍ قَالَ إِنِّي أُطِيقُ أَكْثَرَ فَمَا زَالَ حَتَّى قَالَ فِي ثَلَاثٍ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Mughirah] berkata, aku mendengar [Mujahid] dari ['Abdullah bin 'Umar radliallahu 'anhua] dari Nabi shallallahu 'alaihi wasallam berkata: \"Puasalah dalam sebulan sebanyak tiga hari\". Dia berkata: \"Aku sanggup yang lebih banyak dari itu\". Dia terus saja mengatakan kemampuanya itu hingga akhirnya Beliau berkata: \"Kalau begitu berpuasalah sehari dan berbuka sehari\". Beliau juga berkata, kepadanya: \"Bacalah (khatam) Al Qur'an dalam sebulan\". Dia berkata: \"Aku sanggup yang lebih banyak dari itu\". Dia terus saja mengatakan kemampuannya itu hingga akhirnya Beliau berkata: \"Kalau begitu kamu khatamkan dalam tiga hari\". "},"1843":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا حَبِيبُ بْنُ أَبِي ثَابِتٍ قَالَ سَمِعْتُ أَبَا الْعَبَّاسِ الْمَكِّيَّ وَكَانَ شَاعِرًا وَكَانَ لَا يُتَّهَمُ فِي حَدِيثِهِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ لَتَصُومُ الدَّهْرَ وَتَقُومُ اللَّيْلَ فَقُلْتُ نَعَمْ قَالَ إِنَّكَ إِذَا فَعَلْتَ ذَلِكَ هَجَمَتْ لَهُ الْعَيْنُ وَنَفِهَتْ لَهُ النَّفْسُ لَا صَامَ مَنْ صَامَ الدَّهْرَ صَوْمُ ثَلَاثَةِ أَيَّامٍ صَوْمُ الدَّهْرِ كُلِّهِ قُلْتُ فَإِنِّي أُطِيقُ أَكْثَرَ مِنْ ذَلِكَ قَالَ فَصُمْ صَوْمَ دَاوُدَ عَلَيْهِ السَّلَام كَانَ يَصُومُ يَوْمًا وَيُفْطِرُ يَوْمًا وَلَا يَفِرُّ إِذَا لَاقَى","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Habib bin Abu Tsabit] berkata, aku mendengar [Abu Al 'Abbas Al Makkiy], seorang ahli sya'ir yang tidak dianggap buruk dalam menyampaikan hadits, berkata, aku mendengar ['Abdullah bin 'Amru bin Al 'Ash radliallahu 'anhuma] berkata,, Nabi shallallahu 'alaihi wasallam berkata: \"Apakah benar kamu berpuasa dahr (sepanjang masa) dan shalat sepanjang malam?\" Aku jawab; \"Benar\". Beliau berkata: \"Jika kamu kerjakan itu nanti matamu akan mengantuk dan fisikmu menjadi lemah. Tidak ada nilai puasa bagi siapa yang mengerjakan puasa sepanjang masa. Puasa tiga hari (dalam sebulan) sama nilainya dengan puasa sepanjang jaman\". 'Abdullah bin 'Amru berkata: \"Sungguh aku mampu lebih dari itu\". Beliau berkata: \"Kalau begitu puasalah dengan puasanya Nabi Daud 'alaihi salam, yang dia berpuasa sehari dan berbuka sehari sehingga dia tidak akan kabur ketika berjumpa dengan musuh\". "},"1844":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ شَاهِينَ الْوَاسِطِيُّ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ قَالَ أَخْبَرَنِي أَبُو الْمَلِيحِ قَالَدَخَلْتُ مَعَ أَبِيكَ عَلَى عَبْدِ اللَّهِ بْنِ عَمْرٍو فَحَدَّثَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذُكِرَ لَهُ صَوْمِي فَدَخَلَ عَلَيَّ فَأَلْقَيْتُ لَهُ وِسَادَةً مِنْ أَدَمٍ حَشْوُهَا لِيفٌ فَجَلَسَ عَلَى الْأَرْضِ وَصَارَتْ الْوِسَادَةُ بَيْنِي وَبَيْنَهُ فَقَالَ أَمَا يَكْفِيكَ مِنْ كُلِّ شَهْرٍ ثَلَاثَةُ أَيَّامٍ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ قَالَ خَمْسًا قُلْتُ يَا رَسُولَ اللَّهِ قَالَ سَبْعًا قُلْتُ يَا رَسُولَ اللَّهِ قَالَ تِسْعًا قُلْتُ يَا رَسُولَ اللَّهِ قَالَ إِحْدَى عَشْرَةَ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَوْمَ فَوْقَ صَوْمِ دَاوُدَ عَلَيْهِ السَّلَام شَطْرَ الدَّهَرِ صُمْ يَوْمًا وَأَفْطِرْ يَوْمًا","id":"Telah menceritakan kepada kami [Ishaq bin Syahin Al Washithiy] telah menceritakan kepada kami [Khalid bin 'Abdullah] dari [Khalid Al Hadzdza'] dari [Abu Qalabah] berkata, telah mengabarkan kepada saya [Abu Al Malih] berkata; Aku dan bapakku datang menemui ['Abdullah bin 'Amru] lalu dia menceritakan kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam dikabarkan tentang shaumku lalu Beliau menemuiku. Maka aku berikan kepada Beliau bantal terbuat dari kulit yang disamak yang isinya dari rerumputan, lalu Beliau duduk diatas tanah sehingga bantal tersebut berada di tengah antara aku dan Beliau, lalu Beliau berkata: \"Bukankah cukup bagimu bila kamu berpuasa selama tiga hari dalam setiap bulannya?\" 'Abdullah bin 'Amru berkata; Aku katakan: \"Wahai Rasulullah? (bermaksud minta tambahan) \". Beliau berkata: \"Silahkan kau lakukan Lima hari\". Aku katakan lagi: \"Wahai Rasulullah?\" Beliau berkata: \" Silahkan kau lakukan Tujuh hari\". Aku katakan lagi: \"Wahai Rasulullah?\" Beliau berkata: \" Silahkan kau lakukan Sembilan hari\". Aku katakan lagi: \"Wahai Rasulullah?\" Beliau berkata: \" Silahkan kau lakukan Sebelas hari\". Kemudian Nabi shallallahu 'alaihi wasallam berkata: \"Tidak ada shaum melebihi shaumnya Nabi Daud Aalaihissalam yang merupakan separuh shaum dahar, dia berpuasa sehari dan berbuka sehari\". "},"1845":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَبُو التَّيَّاحِ قَالَ حَدَّثَنِي أَبُو عُثْمَانَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَأَوْصَانِي خَلِيلِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَلَاثٍ صِيَامِ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ وَرَكْعَتَيْ الضُّحَى وَأَنْ أُوتِرَ قَبْلَ أَنْ أَنَامَ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Abu At-Tayyah] berkata, telah menceritakan kepada saya [Abu 'Utsman] dari [Abu Hurairah radliallahu 'anhu] berkata: \"Kekasihku Rasulullah shallallahu 'alaihi wasallam memberi wasiat kepadaku agar aku berpuasa tiga hari dalam setiap bulan, mendirikan shalat Dhuha dua raka'at dan shalat witir sebelum aku tidur\". "},"1846":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي خَالِدٌ هُوَ ابْنُ الْحَارِثِ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أُمِّ سُلَيْمٍ فَأَتَتْهُ بِتَمْرٍ وَسَمْنٍ قَالَ أَعِيدُوا سَمْنَكُمْ فِي سِقَائِهِ وَتَمْرَكُمْ فِي وِعَائِهِ فَإِنِّي صَائِمٌ ثُمَّ قَامَ إِلَى نَاحِيَةٍ مِنْ الْبَيْتِ فَصَلَّى غَيْرَ الْمَكْتُوبَةِ فَدَعَا لِأُمِّ سُلَيْمٍ وَأَهْلِ بَيْتِهَا فَقَالَتْ أُمُّ سُلَيْمٍ يَا رَسُولَ اللَّهِ إِنَّ لِي خُوَيْصَّةً قَالَ مَا هِيَ قَالَتْ خَادِمُكَ أَنَسٌ فَمَا تَرَكَ خَيْرَ آخِرَةٍ وَلَا دُنْيَا إِلَّا دَعَا لِي بِهِ قَالَ اللَّهُمَّ ارْزُقْهُ مَالًا وَوَلَدًا وَبَارِكْ لَهُ فِيهِ فَإِنِّي لَمِنْ أَكْثَرِ الْأَنْصَارِ مَالًا وَحَدَّثَتْنِي ابْنَتِي أُمَيْنَةُ أَنَّهُ دُفِنَ لِصُلْبِي مَقْدَمَ حَجَّاجٍ الْبَصْرَةَ بِضْعٌ وَعِشْرُونَ وَمِائَةٌحَدَّثَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ قَالَ حَدَّثَنِي حُمَيْدٌ سَمِعَ أَنَسًا رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] berkata, telah menceritakan kepada saya [Khalid] dia adalah anak Al Harits telah menceritakan kepada kami [Humaid] dari [Anas radliallahu 'anhu]; Nabi shallallahu 'alaihi wasallam datang menemui Ummu Sulaim, kemudian Ummu Sulaim menyuguhkan kurma dan mentega untuk Beliau. Beliau berkata: \"Simpanlah mentega-mentega kalian untuk suguhan minuman dan kurma-kurma kalian untuk makanannya karena aku sedang berpuasa\". Kemudian Beliau berdiri di pojok rumah mengerjakan shalat sunnat. Setelah itu Beliau memanggil Ummu Sulaim dan anggota keluarga lainnya. Ummu Sulaim berkata: \"Wahai Rasulullah, aku mempunyai permintaan sederhana\". Beliau bertanya: \"Apa itu?\" Ummu Sulaim berkata: \"Pelayan anda itu, Anas, dia tidak pernah meninggalkan kebaikan akhirat sekalipun dan urusan dunianya kecuali dia minta kepadaku\". Maka Beliau berdo'a: \"Ya Allah, karuniakanlah dia harta dan anak-anak dan berilah dia keberkahan didalamnya\". Setelah itu aku menjadi orang yang paling banyak hartanya di kalangan Kaum Anshar. Dan telah menceritakan kepada saya putriku Umainah: \"Setelah itu dia memiliki anak dari sulbiku, yang ketika kedatangan Hajjaj di Bashrah, telah dikuburkan sekitar sebanyak seratus dua sembilan puluh orang\". Dan telah menceritakan kepada kami [Ibnu Abu Maryam] telah mengabarkan kepada kami [Yahya bin Ayyub] berkata, telah menceritakan kepada saya [Humaid] dia mendengar [Anas radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam."},"1847":{"ar":"حَدَّثَنَا الصَّلْتُ بْنُ مُحَمَّدٍ حَدَّثَنَا مَهْدِيٌّ عَنْ غَيْلَانَ ح و حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ حَدَّثَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ مُطَرِّفٍ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سَأَلَهُ أَوْ سَأَلَ رَجُلًا وَعِمْرَانُ يَسْمَعُ فَقَالَ يَا أَبَا فُلَانٍ أَمَا صُمْتَ سَرَرَ هَذَا الشَّهْرِ قَالَ أَظُنُّهُ قَالَ يَعْنِي رَمَضَانَ قَالَ الرَّجُلُ لَا يَا رَسُولَ اللَّهِ قَالَ فَإِذَا أَفْطَرْتَ فَصُمْ يَوْمَيْنِلَمْ يَقُلْ الصَّلْتُ أَظُنُّهُ يَعْنِي رَمَضَانَ قَالَ أَبُو عَبْد اللَّهِ وَقَالَ ثَابِتٌ عَنْ مُطَرِّفٍ عَنْ عِمْرَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ سَرَرِ شَعْبَانَ","id":"Telah menceritakan kepada kami [Ash-Shalt bin Muhammad] telah menceritakan kepada kami [Mahdi] dari [Ghaylan]. Dan diriwayatkan pula, telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Mahdiy bin Maymun] telah menceritakan kepada kami [Ghaylan bin Jarir] dari [Muthrib] dari ['Imran bin Hushain radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bahwa Beliau bertanya atau Beliau bertanya kepada seseorang yang 'Imran mendengarnya, Beliau shallallahu 'alaihi wasallam berkata: \"Wahai bapaknya anu, apakah kamu berpuasa pada hari-hari terakhir bulan ini?\" 'Imran berkata; Aku menduga yang Beliau maksud adalah bulan Ramadhan\". Orang yang ditanya menjawab: \"Tidak, wahai Rasulullah\". Beliau berkata: \"Jika kamu berbuka (tidak puasa) maka kamu harus puasa dua hari (pada hari lain). [Ash-Shalt] tidak berkata; \"Aku menduga, bulan Ramadhan\". Abu 'Abdullah Al Bukhariy berkata,, dan berkata, [Tsabit] dari [Muthrrib] dari ['Imran] dari Nabi shallallahu 'alaihi wasallam: \"Pada hari-hari akhir bulan Sya'ban\". "},"1848":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جُبَيْرِ بْنِ شَيْبَةَ عَنْ مُحَمَّدِ بْنِ عَبَّادٍ قَالَ سَأَلْتُ جَابِرًا رَضِيَ اللَّهُ عَنْهُنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَوْمِ يَوْمِ الْجُمُعَةِ قَالَ نَعَمْزَادَ غَيْرُ أَبِي عَاصِمٍ يَعْنِي أَنْ يَنْفَرِدَ بِصَوْمٍ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari ['Abdul Hamid bin Jubair bin Syaibah] dari [Muhammad bin 'Abbad] berkata; \"Aku bertanya kepada [Jabir radliallahu 'anhu] apakah benar Nabi shallallahu 'alaihi wasallam telah melarang puasa pada hari Jum'at? Dia menjawab: \"Benar\". Selain 'Abu 'Ashim, para perawi menambahkan: \"Yakni apabila mengkhususkan hari Jum'at untuk berpuasa\". "},"1849":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ حَدَّثَنَا أَبُو صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَصُومَنَّ أَحَدُكُمْ يَوْمَ الْجُمُعَةِ إِلَّا يَوْمًا قَبْلَهُ أَوْ بَعْدَهُ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh bin Ghiyats] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] telah menceritakan kepada kami [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] berkata; \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah seorang dari kalian berpuasa pada hari Jum'at kecuali dibarengi dengan satu hari sebelum atau sesudahnya\". "},"1850":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ ح و حَدَّثَنِي مُحَمَّدٌ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي أَيُّوبَ عَنْ جُوَيْرِيَةَ بِنْتِ الْحَارِثِ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا يَوْمَ الْجُمُعَةِ وَهِيَ صَائِمَةٌ فَقَالَ أَصُمْتِ أَمْسِ قَالَتْ لَا قَالَ تُرِيدِينَ أَنْ تَصُومِي غَدًا قَالَتْ لَا قَالَ فَأَفْطِرِيوَقَالَ حَمَّادُ بْنُ الْجَعْدِ سَمِعَ قَتَادَةَ حَدَّثَنِي أَبُو أَيُّوبَ أَنَّ جُوَيْرِيَةَ حَدَّثَتْهُ فَأَمَرَهَا فَأَفْطَرَتْ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Syu'bah]. Dan diriwayatkan pula, telah menceritakan kepada saya [Muhammad] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abu Ayyub] dari [Juwairiyah binti Al harits radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam menemuinya pada hari Jum'at ketika dia sedang berpuasa. Beliau bertanya: \"Apakah kemarin kamu juga berpuasa?\" Dia menjawab: \"Tidak\". Beliau bertanya lagi: \"Apakah besok kamu berniat berpuasa?\" Dia menjawab: \"Tidak\". Maka Beliau berkata: \"Berbukalah (batalkanlah) \". Dan berkata, [Hammad bin Al Ja'di] dia mendengar [Qatadah] telah menceritakan kepada saya [Abu Ayyub] bahwa [Juwairiyah] menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam memerintahkannya agar dia membatalkan puasanya."},"1851":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قُلْتُ لِعَائِشَةَ رَضِيَ اللَّهُ عَنْهَاهَلْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْتَصُّ مِنْ الْأَيَّامِ شَيْئًا قَالَتْ لَا كَانَ عَمَلُهُ دِيمَةً وَأَيُّكُمْ يُطِيقُ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُطِيقُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Alqamah]; Aku bertanya kepada ['Aisyah radliallahu 'anha] apakah Rasulullah shallallahu 'alaihi wasallam mengkhususkan hari-hari tertentu dalam ber'amal?\" Dia menjawab: \"Tidak. Beliau selalu beramal terus menerus tanpa putus. Siapakah dari kalian yang akan mampu sebagaimana yang mampu dikerjakan oleh Rasulullah shallallahu 'alaihi wasallam? "},"1852":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ مَالِكٍ قَالَ حَدَّثَنِي سَالِمٌ قَالَ حَدَّثَنِي عُمَيْرٌ مَوْلَى أُمِّ الْفَضْلِ أَنَّ أُمَّ الْفَضْلِ حَدَّثَتْهُ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ أَبِي النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ عُمَيْرٍ مَوْلَى عَبْدِ اللَّهِ بْنِ الْعَبَّاسِ عَنْ أُمِّ الْفَضْلِ بِنْتِ الْحَارِثِأَنَّ نَاسًا تَمَارَوْا عِنْدَهَا يَوْمَ عَرَفَةَ فِي صَوْمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ بَعْضُهُمْ هُوَ صَائِمٌ وَقَالَ بَعْضُهُمْ لَيْسَ بِصَائِمٍ فَأَرْسَلَتْ إِلَيْهِ بِقَدَحِ لَبَنٍ وَهُوَ وَاقِفٌ عَلَى بَعِيرِهِ فَشَرِبَهُ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Malik] berkata, telah menceritakan kepada saya [Salim] berkata, telah menceritakan kepada saya ['Umair, maula Ummu Al Fadhal] bahwa [Ummu Al Fadhal] menceritakan kepadanya. Dan telah diriwayatkan pula, telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Abu An-Nadhir, maula 'Umar bin 'Ubaidullah] dari ['Umair maula 'Abdullah bin 'Abbas radliallahu 'anhu] dari [Ummu Al Fadhal binti Al Harits] bahwa orang-orang ragu pada hari 'Arafah tentang puasa Nabi shallallahu 'alaihi wasallam. Sebagian dari mereka ada yang mengatakan Beliau berpuasa sebagian yang lain mengatakan tidak, Lalu dia mengutus seseorang membawakan segelas susu ketika Beliau sedang wuquf diatas hewan unggangan Beliau, maka Beliau meminumnya\"."},"1853":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سُلَيْمَانَ حَدَّثَنَا ابْنُ وَهْبٍ أَوْ قُرِئَ عَلَيْهِ قَالَ أَخْبَرَنِي عَمْرٌو عَنْ بُكَيْرٍ عَنْ كُرَيْبٍ عَنْ مَيْمُونَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّاسَ شَكُّوا فِي صِيَامِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَرَفَةَ فَأَرْسَلَتْ إِلَيْهِ بِحِلَابٍ وَهُوَ وَاقِفٌ فِي الْمَوْقِفِ فَشَرِبَ مِنْهُ وَالنَّاسُ يَنْظُرُونَ","id":"Telah menceritakan kepada kami [Yahya bin Sulaiman] telah menceritakan kepada kami [Ibnu Wahab] atau dibacakan kepadanya, dia berkata, telah mengabarkan kepada saya ['Amru] dari [Bukair] dari [Kuraib] dari [Maymunah radliallahu 'anha] bahwa orang-orang ragu tentang puasa Nabi shallallahu 'alaihi wasallam pada hari 'Arafah, lalu ia mengirim susu kepada Beliau yang sedang wukuf di Arafah, maka Beliau meminumnya sementara orang-orang melihatnya."},"1854":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي عُبَيْدٍ مَوْلَى ابْنِ أَزْهَرَ قَالَشَهِدْتُ الْعِيدَ مَعَ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ فَقَالَ هَذَانِ يَوْمَانِ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صِيَامِهِمَا يَوْمُ فِطْرِكُمْ مِنْ صِيَامِكُمْ وَالْيَوْمُ الْآخَرُ تَأْكُلُونَ فِيهِ مِنْ نُسُكِكُمْقَالَ أَبُو عَبْد اللَّهِ قَالَ ابْنُ عُيَيْنَةَ مَنْ قَالَ مَوْلَى ابْنِ أَزْهَرَ فَقَدْ أَصَابَ وَمَنْ قَالَ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ فَقَدْ أَصَابَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu 'Ubaid, maula Ibnu Azhar] berkata; Aku mengikuti shalat 'Ied bersama ['Umar bin Al Khaththob radliallahu 'anhu] lalu dia berkata: \"Inilah dua hari yang Rasulullah shallallahu 'alaihi wasallam melarang puasa padanya, yaitu pada hari saat kalian berbuka dari puasa kalian ('Iedul Fithri) dan hari lainnya adalah hari ketika kalian memakan hewan qurban kalian ('Iedul Adhha) \". Dan Abu 'Abdullah Al Bukhariy berkata; Ibnu 'Uyainah berkata; Siapa yang berkata bahwa Abu 'Ubaid adalah maula Ibnu Azhar berarti dia telah berkata benar dan juga siapa yang berkata bahwa dia adalah maula 'Abdurrahman bin 'Auf, dia juga telah berkata benar."},"1855":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ أَبِيهِ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَوْمِ يَوْمِ الْفِطْرِ وَالنَّحْرِ وَعَنْ الصَّمَّاءِ وَأَنْ يَحْتَبِيَ الرَّجُلُ فِي ثَوْبٍ وَاحِدٍ وَعَنْ صَلَاةٍ بَعْدَ الصُّبْحِ وَالْعَصْرِ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami ['Amru bin Yahya] dari [bapaknya] dari [Abu Sa'id radliallahu 'anhu] berkata: Nabi shallallahu 'alaihi wasallam melarang berpuasa pada hari Raya 'Iedul Fithri dan 'Iedul 'Adhha dan juga melarang berkerudung dengan satu helai kain (berselimut sehingga seluruh bagian badannya tertutup) dan juga melarang seseorang duduk dengan memeluk lututnya hingga mengenai pundaknya dan menutupnya dengan selembar kain dan melarang pula shalat setelah Shubuh dan 'Ashar\"."},"1856":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا هِشَامٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ عَنْ عَطَاءِ بْنِ مِينَا قَالَ سَمِعْتُهُ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَيُنْهَى عَنْ صِيَامَيْنِ وَبَيْعَتَيْنِ الْفِطْرِ وَالنَّحْرِ وَالْمُلَامَسَةِ وَالْمُنَابَذَةِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami [Hisyam] dari [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Amru bin Dinar] dari ['Atho' bin Mina] berkata; Aku mendengar dia menceritakan dari [Abu Hurairah radliallahu 'anhu] yang berkata: \"Telah dilarang berpuasa dan berjual beli pada hari Raya 'Iedul Fithri dan 'Iedul 'Adha, dan juga dilarang jual beli tanpa mengetahui barang yang dijual dan juga jual beli tanpa memeriksa barang yang dijual\"."},"1857":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذٌ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ زِيَادِ بْنِ جُبَيْرٍ قَالَ جَاءَ رَجُلٌ إِلَى ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا فَقَالَرَجُلٌ نَذَرَ أَنْ يَصُومَ يَوْمًا قَالَ أَظُنُّهُ قَالَ الِاثْنَيْنِ فَوَافَقَ ذَ��ِكَ يَوْمَ عِيدٍ فَقَالَ ابْنُ عُمَرَ أَمَرَ اللَّهُ بِوَفَاءِ النَّذْرِ وَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَوْمِ هَذَا الْيَوْمِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Mu'adz] telah mengabarkan kepada kami [Ibnu 'Aun] dari [Ziyad bin Jubair] berkata: Datang seorang laki-laki kepada [Ibnu'Umar radliallahu 'anhuma] lalu berkata: Ada seorang yang bernadzar akan melaksanakan puasa pada suatu hari. Aku menduga dia berkata, hari Senin, lalu hari yang dinadzarkkan itu bertepatan dengan hari Raya 'Ied\". Maka Ibnu'Umar radliallahu 'anhuma berkata: \"Allah telah memerintahkan untuk menunaikan nadzar dan melarang berpuasa pada hari raya ini\"."},"1858":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ قَالَ سَمِعْتُ قَزَعَةَ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُوَكَانَ غَزَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثِنْتَيْ عَشْرَةَ غَزْوَةً قَالَ سَمِعْتُ أَرْبَعًا مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْجَبْنَنِي قَالَ لَا تُسَافِرْ الْمَرْأَةُ مَسِيرَةَ يَوْمَيْنِ إِلَّا وَمَعَهَا زَوْجُهَا أَوْ ذُو مَحْرَمٍ وَلَا صَوْمَ فِي يَوْمَيْنِ الْفِطْرِ وَالْأَضْحَى وَلَا صَلَاةَ بَعْدَ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ وَلَا بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ وَلَا تُشَدُّ الرِّحَالُ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ مَسْجِدِ الْحَرَامِ وَمَسْجِدِ الْأَقْصَى وَمَسْجِدِي هَذَا","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Syu'bah] dari ['Abdul Malik bin 'Umair] berkata, aku mendengar [QAza'ah] berkata; Aku mendengar [Abu Sa'id Al Khudriy radliallahu 'anhu] yang pernah mengikuti peperangan bersama Nabi shallallahu 'alaihi wasallam sebanyak dua belas peperangan, berkata: \"Empat perkara yang aku dapatkan dari Nabi shallallahu 'alaihi wasallam, yang perkara-perkara itu menakjubkan aku (yaitu): \"Tidak boleh seorang wanita bepergian sepanjang dua hari perjalanan kecuali bersama suaminya atau mahramnya, dan tidak boleh shaum dua hari raya, 'Iedul Fithri dan 'Iedul Adhha, dan tidak boleh melaksanakan dua shalat, yaitu setelah 'Ashar hingga matahari terbenam, dan setelah Shubuh hingga matahari terbit, dan tidaklah ditekankan untuk berziarah kecuali untuk mengunjungi tiga masjid, Al Masjidil Haram, Masjidil Aqsha dan Masjidku ini \"."},"1859":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عِيسى بْنِ أَبِي لَيْلَى عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ وَعَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمْ قَالَالَمْ يُرَخَّصْ فِي أَيَّامِ التَّشْرِيقِ أَنْ يُصَمْنَ إِلَّا لِمَنْ لَمْ يَجِدْ الْهَدْيَ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] aku mendengar ['Abdullah bin 'Isa bin Abu Laila] dari [Az Zuhriy] dari ['Urwah] dari ['Aisyah] dan dari [Salim] dari [Ibnu 'Umar radliallahu 'anhuma] keduanya berkata: \"Tidak diperkenankan untuk berpuasa pada hari tasyriq kecuali bagi siapa yang tidak mendapatkan hewan korban (Al Hadyu) ketika menunaikan haji\"."},"1860":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَالصِّيَامُ لِمَنْ تَمَتَّعَ بِالْعُمْرَةِ إِلَى الْحَجِّ إِلَى يَوْمِ عَرَفَةَ فَإِنْ لَمْ يَجِدْ هَدْيًا وَلَمْ يَصُمْ صَامَ أَيَّامَ مِنًىوَعَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ مِثْلَهُ تَابَعَهُ إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Salim bin 'Abdullah bin 'Umar] dari [Ibnu 'Umar radliallahu 'anhuma] berkata: \"Diperbolehkan berpuasa bagi orang yang melaksanakan haji tamattu' (bersenang-senang setelah mengerjakan 'umrah sebelum melaksanakan manasik haji) hingga hari 'Arafah bila tidak membawa hewan qurban (Al Hadyu) dan tidak boleh berpuasa pada hari-hari Mina (Tasyriq) \". Dan dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] seperti hadits ini juga dan dikuatkan oleh [Ibrahim bin Sa'ad] dari [Ibnu Syihab]. "},"1861":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ عُمَرَ بْنِ مُحَمَّدٍ عَنْ سَالِمٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ عَاشُورَاءَ إِنْ شَاءَ صَامَ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari ['Umar bin Muhammad] dari [Salim] dari [bapaknya radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam berkata tentang hari 'Asyura', bila Beliau menghendaki Beliau akan berpuasa\". "},"1862":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِصِيَامِ يَوْمِ عَاشُورَاءَ فَلَمَّا فُرِضَ رَمَضَانُ كَانَ مَنْ شَاءَ صَامَ وَمَنْ شَاءَ أَفْطَرَ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya ['Urwah bin Az Zubair] bahwa ['Aisyah radliallahu 'anha] berkata: \"Rasulullah shallallahu 'alaihi wasallam memerintahkan puasa pada hari 'Asyura' (10 Muharam). Setelah diwajibklan puasa Ramadhan, maka siapa yang mau silakan berpuasa dan siapa yang tidak mau silakan berbuka (tidak berpuasa) \"."},"1863":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ يَوْمُ عَاشُورَاءَ تَصُومُهُ قُرَيْشٌ فِي الْجَاهِلِيَّةِ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُومُهُ فَلَمَّا قَدِمَ الْمَدِينَةَ صَامَهُ وَأَمَرَ بِصِيَامِهِ فَلَمَّا فُرِضَ رَمَضَانُ تَرَكَ يَوْمَ عَاشُورَاءَ فَمَنْ شَاءَ صَامَهُ وَمَنْ شَاءَ تَرَكَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] bahwa ['Aisyah radliallahu 'anha] berkata: \"Orang-orang Quraisy pada masa Jahiliyah melaksanakan puasa hari 'Asyura' dan Rasulullah shallallahu 'alaihi wasallam melaksanakannya. Ketika Beliau sudah tinggal di Madinah Beliau tetap melaksanakannya dan memerintahkan orang-orang untuk melaksanakannya pula. Setelah diwajibklan puasa Ramadhan Beliau meninggalkannya. Maka siapa yang mau silakan berpuasa dan siapa yang tidak mau silakan meninggalkannya\". "},"1864":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ رَضِيَ اللَّهُ عَنْهُمَايَوْمَ عَاشُورَاءَ عَامَ حَجَّ عَلَى الْمِنْبَرِ يَقُولُ يَا أَهْلَ الْمَدِينَةِ أَيْنَ عُلَمَاؤُكُمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ هَذَا يَوْمُ عَاشُورَاءَ وَلَمْ يَكْتُبْ اللَّهُ عَلَيْكُمْ صِيَامَهُ وَأَنَا صَائِمٌ فَمَنْ شَاءَ فَلْيَصُمْ وَمَنْ شَاءَ فَلْيُفْطِرْ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] bahwa dia mendengar [Mu'awiyah bin Abu Sufyan radliallahu 'anhuma] pada hari 'Asyura' ketika tahun penyelenggaraan haji dari atas mimbar berkata: Wahai penduduk Madinah, mana para 'ulama kalian? Aku pernah mendengar bersabda: \"Ini adalah hari 'Asyura' dan Allah belum mewajibkan puasa atas kalian dan sekarang aku sedang berpuasa, maka siapa yang mau silakan berpuasa dan siapa yang tidak mau silakan berbuka (tidak berpuasa) \"."},"1865":{"ar":"حَدَّثَنَا أَبُو مَعْمَرٍ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدِ بْنِ جُبَيْرٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ فَرَأَى الْيَهُودَ تَصُومُ يَوْمَ عَاشُورَاءَ فَقَالَ مَا هَذَا قَالُوا هَذَا يَوْمٌ صَالِحٌ هَذَا يَوْمٌ نَجَّى اللَّهُ بَنِي إِسْرَائِيلَ مِنْ عَدُوِّهِمْ فَصَامَهُ مُوسَى قَالَ فَأَنَا أَحَقُّ بِمُوسَى مِنْكُمْ فَصَامَهُ وَأَمَرَ بِصِيَامِهِ","id":"Telah menceritakan kepada kami [Abu Ma'mar] telah menceritakan kepada kami ['Abdul Warits] telah menceritakan kepada kami [Ayyub] telah menceritakan kepada kami ['Abdullah bin Sa'id bin Jubair] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Ketika Nabi shallallahu 'alaihi wasallam telah sampai dan tinggal di Madinah, Beliau melihat orang-orang Yahudi melaksanakan puasa hari 'Asyura' lalu Beliau bertanya: \"Kenapa kalian mengerjakan ini?\" Mereka menjawab: \"Ini adalah hari kemenangan, hari ketika Allah menyelamatkan Bani Isra'il dari musuh mereka lalu Nabi Musa Alaihissalam menjadikannya sebagai hari berpuasa\". Maka Beliau bersabda: \"Aku lebih berhak dari kalian terhadap Musa\". Lalu Beliau memerintahkan untuk berpuasa. "},"1866":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ أَبِي عُمَيْسٍ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ عَنْ أَبِي مُوسَى رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ يَوْمُ عَاشُورَاءَ تَعُدُّهُ الْيَهُودُ عِيدًا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصُومُوهُ أَنْتُمْ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Abu Usamah] dari [Abu 'Umais] dari [Qais bin Muslim] dari [Thoriq bin Sihab] dari [Abu Musa radliallahu 'anhu] berkata: \"Hari 'Asyura' telah dijadikan oleh orang-orang Yahudi sebagai hari raya mereka, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Berpuasalah kalian pada hari itu\"."},"1867":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ ابْنِ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَمَا رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَحَرَّى صِيَامَ يَوْمٍ فَضَّلَهُ عَلَى غَيْرِهِ إِلَّا هَذَا الْيَوْمَ يَوْمَ عَاشُورَاءَ وَهَذَا الشَّهْرَ يَعْنِي شَهْرَ رَمَضَانَ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Ibnu 'Uyainah] dari ['Ubaidullah bin Abu YAzid] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Tidak pernah aku melihat Nabi shallallahu 'alaihi wasallam sengaja berpuasa pada suatu hari yang Beliau istimewakan dibanding hari-hari lainnya kecuali hari 'Asyura' dan bulan ini, yaitu bulan Ramadhan\". "},"1868":{"ar":"حَدَّثَنَا الْمَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا يَزِيدُ بْنُ أَبِي عُبَيْدٍ عَنْ سَلَمَةَ بْنِ الْأَكْوَعِ رَضِيَ اللَّهُ عَنْهُ قَالَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مِنْ أَسْلَمَ أَنْ أَذِّنْ فِي النَّاسِ أَنَّ مَنْ كَانَ أَكَلَ فَلْيَصُمْ بَقِيَّةَ يَوْمِهِ وَمَنْ لَمْ يَكُنْ أَكَلَ فَلْيَصُمْ فَإِنَّ الْيَوْمَ يَوْمُ عَاشُورَاءَ","id":"Telah menceritakan kepada kami [Al Makkiy bin Ibrahim] telah menceritakan kepada kami [YAzid bin Abu 'Ubaid] dari [Salamah bin Al Akwa' radliallahu 'anhu] berkata: Nabi shallallahu 'alaihi wasallam memerintahkan seseorang dari suku Aslam untuk menyerukan kepada manusia, bila ada seseorang yang sudah makan maka hendaklah ia mengganti puasanya pada hari yang lain dan siapa yang belum makan hendaklah dia meneruskan puasanya karena hari ini adalah hari 'Asyura'\". "},"1869":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لِرَمَضَانَ مَنْ قَامَهُ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya [Abu Salamah] bahwa [Abu Hurairah radliallahu 'anhu] berkata, Rasulullah shallallahu 'alaihi wasallam berkata tentang bulan Ramadhan: \"Barangsiapa yang menegakkannya karena iman kepada Allah dan mengharapkan pahala (hanya dariNya) maka akan diampuni dosa-dosa yang telah dikerjakannya\". "},"1870":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِقَالَ ابْنُ شِهَابٍ فَتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْأَمْرُ عَلَى ذَلِكَ ثُمَّ كَانَ الْأَمْرُ عَلَى ذَلِكَ فِي خِلَافَةِ أَبِي بَكْرٍ وَصَدْرًا مِنْ خِلَافَةِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari [Humaid bin 'Abdurrahman] dari [Abu Hurairah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menegakkan Ramadhan karena iman kepada Allah dan mengharapkan pahala (hanya dariNya) maka akan diampuni dosa-dosa yang telah dikerjakannya\". Ibnu Syihab berkata; Kemudian Rasulullah shallallahu 'alaihi wasallam wafat, namun orang-orang terus melestarikan tradisi menegakkan malam Ramadhan (secara bersama, jamaah), keadaan tersebut terus berlanjut hingga zaman kekhalifahan Abu Bakar dan awal-awal kekhilafahan 'Umar bin Al Khaththob radliallahu 'anhu."},"1871":{"ar":"وَعَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ أَنَّهُ قَالَخَرَجْتُ مَعَ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ لَيْلَةً فِي رَمَضَانَ إِلَى الْمَسْجِدِ فَإِذَا النَّاسُ أَوْزَاعٌ مُتَفَرِّقُونَ يُصَلِّي الرَّجُلُ لِنَفْسِهِ وَيُصَلِّي الرَّجُلُ فَيُصَلِّي بِصَلَاتِهِ الرَّهْطُ فَقَالَ عُمَرُ إِنِّي أَرَى لَوْ جَمَعْتُ هَؤُلَاءِ عَلَى قَارِئٍ وَاحِدٍ لَكَانَ أَمْثَلَ ثُمَّ عَزَمَ فَجَمَعَهُمْ عَلَى أُبَيِّ بْنِ كَعْبٍ ثُمَّ خَرَجْتُ مَعَهُ لَيْلَةً أُخْرَى وَالنَّاسُ يُصَلُّونَ بِصَلَاةِ قَارِئِهِمْ قَالَ عُمَرُ نِعْمَ الْبِدْعَةُ هَذِهِ وَالَّتِي يَنَامُونَ عَنْهَا أَفْضَلُ مِنْ الَّتِي يَقُومُونَ يُرِيدُ آخِرَ اللَّيْلِ وَكَانَ النَّاسُ يَقُومُونَ أَوَّلَهُ","id":"Dan dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Abdurrahman bin 'Abdul Qariy] bahwa dia berkata; \"Aku keluar bersama ['Umar bin Al Khaththob radliallahu 'anhu] pada malam Ramadhan menuju masjid, ternyata orang-orang shalat berkelompok-kelompok secara terpisah-pisah, ada yang shalat sendiri dan ada seorang yang shalat diikuti oleh ma'mum yang jumlahnya kurang dari sepuluh orang. Maka 'Umar berkata: \"Aku pikir seandainya mereka semuanya shalat berjama'ah dengan dipimpin satu orang imam, itu lebih baik\". Kemudian Umar memantapkan keinginannya itu lalu mengumpulkan mereka dalam satu jama'ah yang dipimpin oleh Ubbay bin Ka'ab. Kemudian aku keluar lagi bersamanya pada malam yang lain dan ternyata orang-orang shalat dalam satu jama'ah dengan dipimpin seorang imam, lalu 'Umar berkata: \"Sebaik-baiknya bid'ah adalah ini. Dan mereka yang tidur terlebih dahulu adalah lebih baik daripada yang shalat awal malam, yang ia maksudkan untuk mendirikan shalat di akhir malam, sedangkan orang-orang secara umum melakukan shalat pada awal malam."},"1872":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى وَذَلِكَ فِي رَمَضَانَ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Malik] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam; Rasulullah shallallahu 'alaihi wasallam mendirikan shalat. Dan itu pada bulan Ramadhan."},"1873":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ لَيْلَةً مِنْ جَوْفِ اللَّيْلِ فَصَلَّى فِي الْمَسْجِدِ وَصَلَّى رِجَالٌ بِصَلَاتِهِ فَأَصْبَحَ النَّاسُ فَتَحَدَّثُوا فَاجْتَمَعَ أَكْثَرُ مِنْهُمْ فَصَلَّى فَصَلَّوْا مَعَهُ فَأَصْبَحَ النَّاسُ فَتَحَدَّثُوا فَكَثُرَ أَهْلُ الْمَسْجِدِ مِنْ اللَّيْلَةِ الثَّالِثَةِ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى فَصَلَّوْا بِصَلَاتِهِ فَلَمَّا كَانَتْ اللَّيْلَةُ الرَّابِعَةُ عَجَزَ الْمَسْجِدُ عَنْ أَهْلِهِ حَتَّى خَرَجَ لِصَلَاةِ الصُّبْحِ فَلَمَّا قَضَى الْفَجْرَ أَقْبَلَ عَلَى النَّاسِ فَتَشَهَّدَ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّهُ لَمْ يَخْفَ عَلَيَّ مَكَانُكُمْ وَلَكِنِّي خَشِيتُ أَنْ تُفْتَرَضَ عَلَيْكُمْ فَتَعْجِزُوا عَنْهَا فَتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْأَمْرُ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] telah mengabarkan kepada saya ['Urwah] bahwa ['Aisyah radliallahu 'anha] mengabarkannya bahwa Rasulullah shallallahu 'alaihi wasallam pada suatu malam keluar kamar di tengah malam untuk melaksanakan shalat di masjid. Maka orang-orang kemudian ikut shalat mengikuti shalat Beliau. Pada waktu paginya orang-orang membicarakan kejadian tersebut sehingga pada malam berikutnya orang-orang yang berkumpul bertambah banyak lalu ikut shalat dengan Beliau. Pada waktu paginya orang-orang kembali membicarakan kejadian tersebut. Kemudian pada malam yang ketiga orang-orang yang hadir di masjid semakin bertambah banyak lagi lalu Rasulullah shallallahu 'alaihi wasallam keluar untuk shalat dan mereka ikut shalat bersama Beliau. Kemudian pada malam yang keempat, masjid sudah penuh dengan jama'ah hingga akhirnya Beliau keluar hanya untuk shalat Shubuh. Setelah Beliau selesai shalat Fajar, Beliau menghadap kepada orang banyak kemudian Beliau membaca syahadat lalu bersabda: \"Amma ba'du, sesungguhnya aku bukannya tidak tahu keberadaan kalian (semalam). Akan tetapi aku takut nanti menjadi diwajibkan atas kalian sehingga kalian menjadi keberatan karenanya\". Kemudian setelah Rasulullah shallallahu 'alaihi wasallam meninggal dunia, tradisi shalat (tarawih) secara berjamaah terus berlangsung seperti itu. "},"1874":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ سَأَلَ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَيْفَ كَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ فَقَالَتْ مَا كَانَ يَزِيدُ فِي رَمَضَانَ وَلَا فِي غَيْرِهِ عَلَى إِحْدَى عَشْرَةَ رَكْعَةً يُصَلِّي أَرْبَعًا فَلَا تَسَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي أَرْبَعًا فَلَا تَسَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي ثَلَاثًا فَقُلْتُ يَا رَسُولَ اللَّهِ أَتَنَامُ قَبْلَ أَنْ تُوتِرَ قَالَ يَا عَائِشَةُ إِنَّ عَيْنَيَّ تَنَامَانِ وَلَا يَنَامُ قَلْبِي","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Malik] dari [Sa'id Al Maqbariy] dari [Abu Salamah bin 'Abdurrahman] bahwasanya dia bertanya kepada ['Aisyah radliallahu 'anha] tentang cara shalat Rasulullah shallallahu 'alaihi wasallam di bulan Ramadhan. Maka 'Aisyah radliallahu 'anha menjawab: \"Tidaklah Rasulullah shallallahu 'alaihi wasallam (melaksanakan shalat malam) di bulan Ramadhan dan di bulan-bulan lainnya lebih dari sebelas raka'at, Beliau shalat empat raka'at, maka jangan kamu tanya tentang bagus dan panjangnya kemudian Beliau shalat empat raka'at lagi dan jangan kamu tanya tentang bagus dan panjangnya, kemudian Beliau shalat tiga raka'at. Lalu aku bertanya: \"Wahai Rasulullah, apakah anda tidur sebelum melaksanakan witir?\" Beliau menjawab: \"Wahai 'Aisyah, sesungguhnya kedua mataku tidur, namun hatiku tidaklah tidur\"."},"1875":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ حَفِظْنَاهُ وَإِنَّمَا حَفِظَ مِنَ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَنْ قَامَ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِتَابَعَهُ سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ الزُّهْرِيِّ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] berkata, kami telah menghafal darinya, dia menghafalnya dari [Az Zuhriy] dari [Abu Salamah] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang melaksanakan shaum Ramadhan karena iman kepada Allah dan mengharapkan pahala (hanya dariNya) maka akan diampuni dosa-dosa yang telah dikerjakannya, dan barangsiapa yang menegakkan lailatul qadar karena iman kepada Allah dan mengharapkan pahala (hanya dariNya) maka akan diampuni dosa-dosa yang telah dikerjakannya\". Hadits ini dikuatkan pula oleh [Sulaiman bin Katsir] dari [Az Zuhriy]."},"1876":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رِجَالًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرُوا لَيْلَةَ الْقَدْرِ فِي الْمَنَامِ فِي السَّبْعِ الْأَوَاخِرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَى رُؤْيَاكُمْ قَدْ تَوَاطَأَتْ فِي السَّبْعِ الْأَوَاخِرِ فَمَنْ كَانَ مُتَحَرِّيهَا فَلْيَتَحَرَّهَا فِي السَّبْعِ الْأَوَاخِرِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa ada seorang dari sahabat Nabi shallallahu 'alaihi wasallam yang menyaksilan Lailatul Qadar dalam mimpi terjadi pada tujuh hari terakhir. Maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Aku memandang bahwa mimpi kalian tentang Lailatul Qadar tepat terjadi pada tujuh malam terakhir, maka siapa yang mau mendekatkan diri kepada Allah dengan mencarinya, lakukanlah pada tujuh malam terakhir\"."},"1877":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ فَضَالَةَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ سَأَلْتُ أَبَا سَعِيدٍ وَكَانَ لِي صَدِيقًا فَقَالَاعْتَكَفْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَشْرَ الْأَوْسَطَ مِنْ رَمَضَانَ فَخَرَجَ صَبِيحَةَ عِشْرِينَ فَخَطَبَنَا وَقَالَ إِنِّي أُرِيتُ لَيْلَةَ الْقَدْرِ ثُمَّ أُنْسِيتُهَا أَوْ نُسِّيتُهَا فَالْتَمِسُوهَا فِي الْعَشْرِ الْأَوَاخِرِ فِي الْوَتْرِ وَإِنِّي رَأَيْتُ أَنِّي أَسْجُدُ فِي مَاءٍ وَطِينٍ فَمَنْ كَانَ اعْتَكَفَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْيَرْجِعْ فَرَجَعْنَا وَمَا نَرَى فِي السَّمَاءِ قَزَعَةً فَجَاءَتْ سَحَابَةٌ فَمَطَرَتْ حَتَّى سَالَ سَقْفُ الْمَسْجِدِ وَكَانَ مِنْ جَرِيدِ النَّخْلِ وَأُقِيمَتْ الصَّلَاةُ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْجُدُ فِي الْمَاءِ وَالطِّينِ حَتَّى رَأَيْتُ أَثَرَ الطِّينِ فِي جَبْهَتِهِ","id":"Telah menceritakan kepada kami [Mu'adz bin Fadhalah] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] berkata; Aku bertanya kepada [Abu Sa'id Al Khudriy] yang merupakan salah seorang sahabat karibku. Maka dia berkata: \" Kami pernah ber'i'tikaf bersama Nabi shallallahu 'alaihi wasallam pada sepuluh malam pertengahan dari bulan Ramadhan. Kemudian Beliau keluar pada sepuluh malam yang akhir lalu memberikan khuthbah kepada kami dan berkata: \"Sungguh aku diperlihatkan (dalam mimpi) tentang Lailatul Qadar namun aku lupa atau dilupakan waktunya yang pasti. Namun carilah pada sepuluh malam-malam akhir dan pada malam yang ganjil. Sungguh aku melihat dalam mimpi, bahwa aku sujud diatas tanah dan air (yang becek). Oleh karena itu siapa yang sudah beri'tikaf bersama Rasulullah shallallahu 'alaihi wasallam maka pulanglah\". Maka kami pun pulang. Dan tidaklah kami melihat awan yang tipis sekalipun di langit hingga kemudian tiba-tiba datang awan yang banyak, lalu hujan turun hingga air menetes (karena bocor) lewat atap masjid yang terbuat dari dedaunan kurma. Kemudian setelah shalat (Shubuh) selesai aku melihat Rasulullah shallallahu 'alaihi wasallam sujud diatas air dan tanah yang becek hingga aku melihat sisa-sisanya pada dahi Beliau."},"1878":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْ��ُ سَعِيدٍ حَدَّثَنَا إِسْمَاعِيلُ بْنُ جَعْفَرٍ حَدَّثَنَا أَبُو سُهَيْلٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَحَرَّوْا لَيْلَةَ الْقَدْرِ فِي الْوِتْرِ مِنْ الْعَشْرِ الْأَوَاخِرِ مِنْ رَمَضَانَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Isma'il bin Ja'far] telah menceritakan kepada kami [Abu Suhail] dari [bapaknya] dari ['Aisyah radliallahu 'anha] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Carilah Lailatul Qadar pada malam yang ganjil dalam sepuluh malam yang akhir dari Ramadhan\"."},"1879":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ حَمْزَةَ قَالَ حَدَّثَنِي ابْنُ أَبِي حَازِمٍ وَالدَّرَاوَرْدِيُّ عَنْ يَزِيدَ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجَاوِرُ فِي رَمَضَانَ الْعَشْرَ الَّتِي فِي وَسَطِ الشَّهْرِ فَإِذَا كَانَ حِينَ يُمْسِي مِنْ عِشْرِينَ لَيْلَةً تَمْضِي وَيَسْتَقْبِلُ إِحْدَى وَعِشْرِينَ رَجَعَ إِلَى مَسْكَنِهِ وَرَجَعَ مَنْ كَانَ يُجَاوِرُ مَعَهُ وَأَنَّهُ أَقَامَ فِي شَهْرٍ جَاوَرَ فِيهِ اللَّيْلَةَ الَّتِي كَانَ يَرْجِعُ فِيهَا فَخَطَبَ النَّاسَ فَأَمَرَهُمْ مَا شَاءَ اللَّهُ ثُمَّ قَالَ كُنْتُ أُجَاوِرُ هَذِهِ الْعَشْرَ ثُمَّ قَدْ بَدَا لِي أَنْ أُجَاوِرَ هَذِهِ الْعَشْرَ الْأَوَاخِرَ فَمَنْ كَانَ اعْتَكَفَ مَعِي فَلْيَثْبُتْ فِي مُعْتَكَفِهِ وَقَدْ أُرِيتُ هَذِهِ اللَّيْلَةَ ثُمَّ أُنْسِيتُهَا فَابْتَغُوهَا فِي الْعَشْرِ الْأَوَاخِرِ وَابْتَغُوهَا فِي كُلِّ وِتْرٍ وَقَدْ رَأَيْتُنِي أَسْجُدُ فِي مَاءٍ وَطِينٍ فَاسْتَهَلَّتْ السَّمَاءُ فِي تِلْكَ اللَّيْلَةِ فَأَمْطَرَتْ فَوَكَفَ الْمَسْجِدُ فِي مُصَلَّى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ إِحْدَى وَعِشْرِينَ فَبَصُرَتْ عَيْنِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَظَرْتُ إِلَيْهِ انْصَرَفَ مِنْ الصُّبْحِ وَوَجْهُهُ مُمْتَلِئٌ طِينًا وَمَاءً","id":"Telah menceritakan kepada kami [Ibrahim bin Hamzah] berkata, telah menceritakan kepada saya [Ibnu Abu HAzim] dan [Ad-Darawardiy] dari [YAzid bin Al Had] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Sa'id Al Khudriy radliallahu 'anhu]; Rasulullah shallallahu 'alaihi wasallam 'i'tikaf di bulan Ramadhan pada sepuluh malam pertengahan bulan. Kemudian ketika telah melewati malam ke dua puluh menjelang malam kedua puluh satu Beliau datang kembali ke tempat khusus i'tikaf Beliau begitu pula mereka yang sebelumnya beri'tikaf bersama Beliau. Pada malam ketika Beliau kembali beri'tikaf di bulan tersebut, Beliau menyampaikan khuthbah di hadapan orang banyak dan memerintahkan mereka menurut apa yang Allah kehendaki, lalu Beliau bersabda: \"Aku sudah melaksanakan i'tikaf pada sepuluh malam sebelumnya dari bulan ini kemudian dinampakkan kepadaku agar beri'tikaf pada sepuluh hari terakhir, maka siapa yang telah beri'tikaf bersamaku tetaplah pada tempatnya beri'tikaf. Sungguh telah diperlihatkan kepadaku tentang malam Lailatul Qadar namun aku dilupakan waktunya yang pasti, maka carilah pada sepuluh malam-malam akhir dan carilah pada malam yang ganjil. Sungguh aku melihat diriku (dalam mimpi) sujud diatas air dan tanah (yang becek) \". Kemudian langit tampak mendung pada malam itu lalu turunlah hujan hingga masjid bocor mengenai posisi tempat shalat Nabi shallallahu 'alaihi wasallam pada malam kedua puluh satu. Kemudian mataku memandang Rasulullah shallallahu 'alaihi wasallam, aku melihat Beliau setelah Shubuh dengan wajah Beliau yang penuh dengan tanah dan air\". "},"1880":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْتَمِسُوا حَدَّثَنِي مُحَمَّدٌ أَخْبَرَنَا عَبْدَةُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجَاوِرُ فِي الْعَشْرِ الْأَوَاخِرِ مِنْ رَمَضَانَ وَيَقُولُ تَحَرَّوْا لَيْلَةَ الْقَدْرِ فِي الْعَشْرِ الْأَوَاخِرِ مِنْ رَمَضَانَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] dari [Hisyam] berkata, telah mengabarkan kepada saya [bapakku] dari ['Aisyah radliallahu 'anha] dari Nabi shallallahu 'alaihi wasallam: \"Carilah\". Telah menceritakan kepada saya [Muhammad] telah mengabarkan kepada kami ['Abdah] dari [Hisyam bin 'Urwah] dari [bapakku] dari ['Aisyah radliallahu 'anha] berkata: Rasulullah shallallahu 'alaihi wasallam beri'tikaf pada sepuluh hari terakhir dari bulan Ramadhan dan bersabda: \"Carilah Lailatul Qadar pada sepuluh malam yang akhir dari Ramadhan\". "},"1881":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْتَمِسُوهَا فِي الْعَشْرِ الْأَوَاخِرِ مِنْ رَمَضَانَ لَيْلَةَ الْقَدْرِ فِي تَاسِعَةٍ تَبْقَى فِي سَابِعَةٍ تَبْقَى فِي خَامِسَةٍ تَبْقَىتَابَعَهُ عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam bersabda. Berkata, telah mengabarkan kepada saya bapakku dari 'Aisyah radliallahu 'anha dari Nabi shallallahu 'alaihi wasallam: \"Carilah Lailatul Qadar pada sepuluh malam yang akhir dari Ramadhan, pada sisa malam kesembilan, pada yang ketujuh, pada yang kelima\". Hadits ini dikuatkan pula oleh ['Abdul Wahhab] dari [Ayyub].:"},"1882":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي الْأَسْوَدِ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا عَاصِمٌ عَنْ أَبِي مِجْلَزٍ وَعِكْرِمَةَ قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هِيَ فِي الْعَشْرِ الْأَوَاخِرِ هِيَ فِي تِسْعٍ يَمْضِينَ أَوْ فِي سَبْعٍ يَبْقَيْنَ يَعْنِي لَيْلَةَ الْقَدْرِوَعَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ الْتَمِسُوا فِي أَرْبَعٍ وَعِشْرِينَ","id":"Telah menceritakan kepada kami ['Abdullah bin Abu Al Aswad] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami ['Ashim] dari [Abu MijlAz] dan ['Ikrimah] berkata, bahwa [Ibnu 'Abbas radliallahu 'anhuma] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dia terjadi pada sepuluh malam terakhir, juga pada sembilan hari yang terakhir atau pada yang ketujuh, yaitu terjadinya Lailatul Qadar\". Dan dari [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma]; \"Carilah pada malam kedua puluh empat\". "},"1883":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا حُمَيْدٌ حَدَّثَنَا أَنَسٌ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُخْبِرَنَا بِلَيْلَةِ الْقَدْرِ فَتَلَاحَى رَجُلَانِ مِنْ الْمُسْلِمِينَ فَقَالَ خَرَجْتُ لِأُخْبِرَكُمْ بِلَيْلَةِ الْقَدْرِ فَتَلَاحَى فُلَانٌ وَفُلَانٌ فَرُفِعَتْ وَعَسَى أَنْ يَكُونَ خَيْرًا لَكُمْ فَالْتَمِسُوهَا فِي التَّاسِعَةِ وَالسَّابِعَةِ وَالْخَامِسَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Humaid] telah menceritakan kepada kami [Anas] dari ['Ubadah bin Ash-Shamit] berkata; Nabi shallallahu 'alaihi wasallam keluar untuk memberitahukan kami tentang Lailatul Qadar. Tiba-tiba ada dua orang dari Kaum Muslimin yang membantah Beliau. Akhirnya Beliau berkata: \"Aku datang untuk memberitahukan kalian tentang waktu terjadinya Lailatul Qadar namun fulan dan fulan menyanggah aku sehingga kepastian waktunya diangkat (menjadi tidak diketahui). Namun semoga kejadian ini menjadi kebaikan buat kalian, maka carilah pada malam yang kesembilan, ketujuh dan kelima (pada sepuluh malam akhir dari Ramadhan) \". "},"1884":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي يَعْفُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ الْعَشْرُ شَدَّ مِئْزَرَهُ وَأَحْيَا لَيْلَهُ وَأَيْقَظَ أَهْلَهُ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari [Abu Ya'fur] dari [Abu Adh-Dhuha] dari [Masruq] dari ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam bila memasuki sepuluh akhir (dari bulan Ramadhan), Beliau mengencangkan sarung Beliau, menghidupkan malamnya dengan ber'ibadah dan membangunkan keluarga Beliau\"."},"1885":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ أَنَّ نَافِعًا أَخْبَرَهُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْتَكِفُ الْعَشْرَ الْأَوَاخِرَ مِنْ رَمَضَانَ","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] berkata, telah menceritakan kepada saya [Ibnu Wahab] dari [Yunus] bahwa [Nafi'] mengabarkannya dari ['Abdullah bin 'Umar radliallahu 'anhua] berkata: \" Rasulullah shallallahu 'alaihi wasallam beri'tikaf pada sepuluh hari yang akhir dari Ramadhan\". "},"1886":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَعْتَكِفُ الْعَشْرَ الْأَوَاخِرَ مِنْ رَمَضَانَ حَتَّى تَوَفَّاهُ اللَّهُ ثُمَّ اعْتَكَفَ أَزْوَاجُهُ مِنْ بَعْدِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] berkata, telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anha], isteri Nabi shallallahu 'alaihi wasallam bahwa Nabi shallallahu 'alaihi wasallam beri'tikaf pada sepuluh hari yang akhir dari Ramadhan hingga wafatnya kemudian isteri-isteri Beliau beri'tikaf setelah kepergian Beliau."},"1887":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَعْتَكِفُ فِي الْعَشْرِ الْأَوْسَطِ مِنْ رَمَضَانَ فَاعْتَكَفَ عَامًا حَتَّى إِذَا كَانَ لَيْلَةَ إِحْدَى وَعِشْرِينَ وَهِيَ اللَّيْلَةُ الَّتِي يَخْرُجُ مِنْ صَبِيحَتِهَا مِنْ اعْتِكَافِهِ قَالَ مَنْ كَانَ اعْتَكَفَ مَعِي فَلْيَعْتَكِفْ الْعَشْرَ الْأَوَاخِرَ وَقَدْ أُرِيتُ هَذِهِ اللَّيْلَةَ ثُمَّ أُنْسِيتُهَا وَقَدْ رَأَيْتُنِي أَسْجُدُ فِي مَاءٍ وَطِينٍ مِنْ صَبِيحَتِهَا فَالْتَمِسُوهَا فِي الْعَشْرِ الْأَوَاخِرِ وَالْتَمِسُوهَا فِي كُلِّ وِتْرٍ فَمَطَرَتْ السَّمَاءُ تِلْكَ اللَّيْلَةَ وَكَانَ الْمَسْجِدُ عَلَى عَرِيشٍ فَوَكَفَ الْمَسْجِدُ فَبَصُرَتْ عَيْنَايَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى جَبْهَتِهِ أَثَرُ الْمَاءِ وَالطِّينِ مِنْ صُبْحِ إِحْدَى وَعِشْرِينَ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Malik] dari [YAzid bin 'Abdullah bin Al Had] dari [Muhammad bin Ibrahim bin Al Harits At-Taimiy] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam 'i'tikaf pada sepuluh malam pertengahan bulan dari Ramadhan lalu orang-orang mengikutinya. Hingga ketika malam kedua puluh satu, yaitu malam ketika Beliau kembali ke tempat i'tikaf Beliau, Beliau berkata: \"Siapa yang telah beri'tilkaf bersamaku maka hendaklah dia beri'tikaf pada sepuluh malam-malam akhir. Sungguh aku telah diperlihatkan tentang malam Lailatul Qadar ini namun kemudian aku dilupakan waktunya yang pasti. Maka carilah pada malam sepuluh akhir dan carilah pada malam yang ganjil\". Kemudian pada malam itu langit menurunkan hujan. Pada waktu itu atap masjid masih terbuat dari dedaunan hingga air hujan mengalir masuk kedalam masjid. Kemudian mataku memandang Rasulullah shallallahu 'alaihi wasallam yang pada dahi Beliau ada sisa air dan tanah di waktu pagi pada hari kedua puluh satu\". "},"1888":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصْغِي إِلَيَّ رَأْسَهُ وَهُوَ مُجَاوِرٌ فِي الْمَسْجِدِ فَأُرَجِّلُهُ وَأَنَا حَائِضٌ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] dari [Hisyam] berkata, telah mengabarkan kepada saya [bapakku] dari ['Aisyah radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam menjulurkan kepala Beliau kepadaku ketika sedang beri'tikaf di masjid lalu aku menyisir rambut Beliau sedangkan aku saat itu sedang haidh\". "},"1889":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا لَيْثٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ وَعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْوَإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُدْخِلُ عَلَيَّ رَأْسَهُ وَهُوَ فِي الْمَسْجِدِ فَأُرَجِّلُهُ وَكَانَ لَا يَدْخُلُ الْبَيْتَ إِلَّا لِحَاجَةٍ إِذَا كَانَ مُعْتَكِفًا","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Laits] dari [Ibnu Syihab] dari ['Urwah] dan ['Amrah binti 'Abdurrahman] bahwa ['Aisyah radliallahu 'anha] isteri Nabi shallallahu 'alaihi wasallam berkata: \"Sungguh Nabi shallallahu 'alaihi wasallam pernah menjulurkan kepala Beliau kepadaku ketika sedang berada di masjid lalu aku menyisir rambut Beliau. Dan Beliau tidaklah masuk ke rumah kecuali ketika ada keperluan (buang hajat) apabila Beliau sedang beri'tikaf\". "},"1890":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُبَاشِرُنِي وَأَنَا حَائِضٌ وَكَانَ يُخْرِجُ رَأْسَهُ مِنْ الْمَسْجِدِ وَهُوَ مُعْتَكِفٌ فَأَغْسِلُهُ وَأَنَا حَائِضٌ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam pernah mencumbui aku ketika aku sedang haidh dan Beliau juga pernah mengeluarkan kepala Beliau dari masjid ketika sedang beri'tikaf lalu aku membasuh rambut Beliau sedangkan aku saat itu sedang haidh\". "},"1891":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ عُمَرَ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُنْتُ نَذَرْتُ فِي الْجَاهِلِيَّةِ أَنْ أَعْتَكِفَ لَيْلَةً فِي الْمَسْجِدِ الْحَرَامِ قَالَ فَأَوْفِ بِنَذْرِكَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] telah mengabarkan kepada saya [Nafi'] dari [Ibnu'Umar radliallahu 'anhuma] bahwa 'Umar bertanya kepada Nabi shallallahu 'alaihi wasallam, katanya: \"Aku pernah bernadzar di zaman Jahiliyyah untuk beri'tikaf dalam satu malam di Al Masjidil Haram\". Maka Beliau berkata: \"Tunaikanlah nadzarmu itu\". "},"1892":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا يَحْيَى عَنْ عَمْرَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْتَكِفُ فِي الْعَشْرِ الْأَوَاخِرِ مِنْ رَمَضَانَ فَكُنْتُ أَضْرِبُ لَهُ خِبَاءً فَيُصَلِّي الصُّبْحَ ثُمَّ يَدْخُلُهُ فَاسْتَأْذَنَتْ حَفْصَةُ عَائِشَةَ أَنْ تَضْرِبَ خِبَاءً فَأَذِنَتْ لَهَا فَضَرَبَتْ خِبَاءً فَلَمَّا رَأَتْهُ زَيْنَبُ ابْنَةُ جَحْشٍ ضَرَبَتْ خِبَاءً آخَرَ فَلَمَّا أَصْبَحَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى الْأَخْبِيَةَ فَقَالَ مَا هَذَا فَأُخْبِرَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَالْبِرَّ تُرَوْنَ بِهِنَّ فَتَرَكَ الِاعْتِكَافَ ذَلِكَ الشَّهْرَ ثُمَّ اعْتَكَفَ عَشْرًا مِنْ شَوَّالٍ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Yahya] dari ['Amrah] dari ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam beri'tikaf pada sepuluh hari terakhir dari bulan Ramadhan dan aku membuatkan tenda khusus untuk Beliau, dan setiap beliau selesai dari shalat Shubuh Beliau masuk ke dalam tenda tersebut. Kemudian Hafshah meminta izin kepada 'Aisyah untuk juga membuat tenda, maka 'Aisyah mengizinkannya, lalu Hafshah membuatnya. Ketika Zainab putri dari Jahsy melihatnya ia pun membuat tenda yang lain buatnya. Pada pagi harinya Nabi shallallahu 'alaihi wasallam melihat tenda-tenda tersebut lalu berkata: \"Apa ini?\" Lalu Beliau diberitahu. Maka Nabi shallallahu 'alaihi wasallam berkata: \"Apakah kalian melihat kebaikan ada padanya (dengan membuat tenda-tenda ini)?\" Akhirnya Beliau meninggalkan i'tikaf pada bulan itu lalu Beliau ber'tikaf sepuluh hari pada bulan Syawal. "},"1893":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَادَ أَنْ يَعْتَكِفَ فَلَمَّا انْصَرَفَ إِلَى الْمَكَانِ الَّذِي أَرَادَ أَنْ يَعْتَكِفَ إِذَا أَخْبِيَةٌ خِبَاءُ عَائِشَةَ وَخِبَاءُ حَفْصَةَ وَخِبَاءُ زَيْنَبَ فَقَالَ أَالْبِرَّ تَقُولُونَ بِهِنَّ ثُمَّ انْصَرَفَ فَلَمْ يَعْتَكِفْ حَتَّى اعْتَكَفَ عَشْرًا مِنْ شَوَّالٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Yahya bin Sa'id] dari ['Amrah binti 'Abdurrahman] dari ['Aisyah radliallahu 'anha] berkata: \"Nabi shallallahu 'alaihi wasallam hendak beri'tikaf. Ketika Beliau menuju tempat khusus untuk i'tikaf Beliau, Beliau melihat ada tenda-tenda, yaitu tendanya 'Aisyah, Hafshah dan Zainab. Maka Beliau berkata: \"Apakah kalian melihat kebaikan ada padanya (dengan membuat tenda-tenda ini)?\" Akhirnya Beliau pergi dan tidak jadi i'tikaf. Kemudian Beliau ber'tikaf sepuluh hari pada bulan Syawal. "},"1894":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَلِيُّ بْنُ الْحُسَيْنِ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ صَفِيَّةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ أَنَّهَاجَاءَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزُورُهُ فِي اعْتِكَافِهِ فِي الْمَسْجِدِ فِي الْعَشْرِ الْأَوَاخِرِ مِنْ رَمَضَانَ فَتَحَدَّثَتْ عِنْدَهُ سَاعَةً ثُمَّ قَامَتْ تَنْقَلِبُ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهَا يَقْلِبُهَا حَتَّى إِذَا بَلَغَتْ بَابَ الْمَسْجِدِ عِنْدَ بَابِ أُمِّ سَلَمَةَ مَرَّ رَجُلَانِ مِنْ الْأَنْصَارِ فَسَلَّمَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى رِسْلِكُمَا إِنَّمَا هِيَ صَفِيَّةُ بِنْتُ حُيَيٍّ فَقَالَا سُبْحَانَ اللَّهِ يَا رَسُولَ اللَّهِ وَكَبُرَ عَلَيْهِمَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّيْطَانَ يَبْلُغُ مِنْ الْإِنْسَانِ مَبْلَغَ الدَّمِ وَإِنِّي خَشِيتُ أَنْ يَقْذِفَ فِي قُلُوبِكُمَا شَيْئًا","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya ['Ali bin a-Husain radliallahu 'anhuma] bahwa [Shafiyah] isteri Nabi shallallahu 'alaihi wasallam mengabarkan kepadanya bahwa dia datang mengunjungi Rasulullah shallallahu 'alaihi wasallam dalam masa-masa i'tikaf Beliau di masjid pada sepuluh hari terakhir dari bulan Ramadhan, dia berbicara sejenak dengan Beliau lalu dia berdiri untuk pulang. Maka Nabi shallallahu 'alaihi wasallam pun berdiri untuk mengantarnya hingga ketika sampai di pintu masjid yang berhadapan dengan pintu rumah Ummu Salamah, ada dua orang dari kaum Anshar yang lewat lalu keduanya memberi salam kepada Rasulullah shallallahu 'alaihi wasallam. Maka Nabi shallallahu 'alaihi wasallam berkata kepada keduanya: \"Kalian tenang saja. Sungguh wanita ini adalah Shafiyah binti Huyay\". Maka keduanya berkata: \"Maha suci Allah, wahai Rasulullah\". Kejadian ini menjadikan berat bagi keduanya. Lalu Nabi shallallahu 'alaihi wasallam berkata: \"Sesungguhnya setan mendatangi manusia lewat aliran darah dan aku khawatir setan telah memasukkan sesuatu pada hati kalian berdua\"."},"1895":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مُنِيرٍ سَمِعَ هَارُونَ بْنَ إِسْمَاعِيلَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ سَمِعْتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ قَالَ سَأَلْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ رَضِيَ اللَّهُ عَنْهُ قُلْتُهَلْ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُ لَيْلَةَ الْقَدْرِ قَالَ نَعَمِ اعْتَكَفْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَشْرَ الْأَوْسَطَ مِنْ رَمَضَانَ قَالَ فَخَرَجْنَا صَبِيحَةَ عِشْرِينَ قَالَ فَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَبِيحَةَ عِشْرِينَ فَقَالَ إِنِّي أُرِيتُ لَيْلَةَ الْقَدْرِ وَإِنِّي نُسِّيتُهَا فَالْتَمِسُوهَا فِي الْعَشْرِ الْأَوَاخِرِ فِي وِتْرٍ فَإِنِّي رَأَيْتُ أَنِّي أَسْجُدُ فِي مَاءٍ وَطِينٍ وَمَنْ كَانَ اعْتَكَفَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْيَرْجِعْ فَرَجَعَ النَّاسُ إِلَى الْمَسْجِدِ وَمَا نَرَى فِي السَّمَاءِ قَزَعَةً قَالَ فَجَاءَتْ سَحَابَةٌ فَمَطَرَتْ وَأُقِيمَتْ الصَّلَاةُ فَسَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الطِّينِ وَالْمَاءِ حَتَّى رَأَيْتُ أَثَرَ الطِّينِ فِي أَرْنَبَتِهِ وَجَبْهَتِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Munir] dia mendengar [Harun bin Isma'il] telah menceritakan kepada kami ['Ali bin AL Mubarak] berkata, telah menceritakan kepada saya [Yahya bin Abu Katsir] berkata, aku mendengar [Abu Salamah bin 'Abdurrahman] berkata; Aku pernah bertanya kepada [Abu Sa'id Al Khudriy], aku katakan: \"Apakah kamu pernah mendengar Rasulullah shallallahu 'alaihi wasallam memberitahukan tentang Lailatul Qadar?\" Dia menjawab: \"Ya pernah, kami pernah ber'i'tikaf bersama Rasulullah shallallahu 'alaihi wasallam pada sepuluh malam pertengahan dari bulan Ramadhan. Dia berkata: \"Kemudian kami keluar pada pagi hari kedua puluh. Dia berkata: \"Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan khuthbah kepada kami pada pagi hari kedua puluh dan berkata: \"Sungguh aku diperlihatkan (dalam mimpi) tentang Lailatul Qadar namun aku dilupakan waktunya yang pasti. Maka carilah pada sepuluh malam-malam akhir dan pada malam yang ganjil. Sungguh aku melihat dalam mimpi, bahwa aku sujud diatas tanah dan air (yang becek). Oleh karena itu siapa yang sudah beri'tikaf bersama Rasulullah shallallahu 'alaihi wasallam maka kembalilah beri'tikaf\". Maka orang-orang kembali ke masjid. Dan saai itu tidaklah kami melihat awan yang tipis sekalipun di langit hingga kemudian tiba-tiba datang awan yang banyak lalu hujan turun. Kemudian shalat didirikan, Rasulullah shallallahu 'alaihi wasallam sujud diatas tanah yang becek dan air hingga aku melihat sisa-sisa tanah pada ujung hidung dan dahi Beliau. "},"1896":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاعْتَكَفَتْ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةٌ مِنْ أَزْوَاجِهِ مُسْتَحَاضَةٌ فَكَانَتْ تَرَى الْحُمْرَةَ وَالصُّفْرَةَ فَرُبَّمَا وَضَعْنَا الطَّسْتَ تَحْتَهَا وَهِيَ تُصَلِّي","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Khalid] dari ['Ikrimah] dari ['Aisyah radliallahu 'anha] berkata; Ada seorang dari isteri-isteri Beliau yang ikut beri'tikaf bersama Rasulullah shallallahu 'alaihi wasallam dalam keadaan mengalami istihadhah. 'Aisyah radliallahu 'anha melihat ada darah berwarna merah dan kekuningan sedangkan di bawahnya diletakkan baskom sementara dia mengerjakan shalat\"."},"1897":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ صَفِيَّةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ ح حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ الْحُسَيْنِكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ وَعِنْدَهُ أَزْوَاجُهُ فَرُحْنَ فَقَالَ لِصَفِيَّةَ بِنْتِ حُيَيٍّ لَا تَعْجَلِي حَتَّى أَنْصَرِفَ مَعَكِ وَكَانَ بَيْتُهَا فِي دَارِ أُسَامَةَ فَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَهَا فَلَقِيَهُ رَجُلَانِ مِنْ الْأَنْصَارِ فَنَظَرَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ أَجَازَا وَقَالَ لَهُمَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَعَالَيَا إِنَّهَا صَفِيَّةُ بِنْتُ حُيَيٍّ قَالَا سُبْحَانَ اللَّهِ يَا رَسُولَ اللَّهِ قَالَ إِنَّ الشَّيْطَانَ يَجْرِي مِنْ الْإِنْسَانِ مَجْرَى الدَّمِ وَإِنِّي خَشِيتُ أَنْ يُلْقِيَ فِي أَنْفُسِكُمَا شَيْئًا","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] berkata, telah menceritakan kepada saya [Al Laits] berkata, telah menceritakan kepada saya ['Abdurrahman bin Khalid] dari [Ibnu Syihab] dari ['Ali bin Al Husain radliallahu 'anhuma] bahwa [Shafiyah] isteri Nabi shallallahu 'alaihi wasallam mengabarkan kepadanya. Dan diriwayatkan pula, telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam bin Yusuf] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] dari ['Ali bin Al Husain radliallahu 'anhuma]; Nabi shallallahu 'alaihi wasallam berada di dalam masjid sedangkan isteri-isteri Beliau bersama Beliau dalam keadaan bergembira. Beliau berkata kepada Shafiyah binti Huyyay: \"Janganlah kamu tergesa-gesa hendak pulang, tunggulah hingga aku keluar bersamamu\". Rumah Shafiyah berada di perkampungan Usamah. Maka Nabi shallallahu 'alaihi wasallam keluar bersama Shafiyah. Kemudian di jalan ada dua orang dari Kaum Anshar yang berjumpa dengan Beliau lalu keduanya memandang Nabi shallallahu 'alaihi wasallam sesaat lalu keduanya meneruskan perjalanannya. Nabi shallallahu 'alaihi wasallam berkata kepada keduanya: \"Kemarilah kalian, ini adalah Shafiyah binti Huyay\". Maka keduanya berkata: \"Maha suci Allah, wahai Rasulullah\". Lalu Beliau shallallahu 'alaihi wasallam berkata: \"Sesungguhnya syetan berjalan pada diri manusia lewat aliran darah dan aku khawatir telah timbul suatu perasaan pada diri kalian berdua\"."},"1898":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ أَخْبَرَنِي أَخِي عَنْ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ أَبِي عَتِيقٍ عَنْ ابْنِ شِهَابٍ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ رَضِيَ اللَّهُ عَنْهُمَا أَنَّ صَفِيَّةَ بِنْتَ حُيَيٍّ أَخْبَرَتْهُ ح و حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْتُ الزُّهْرِيَّ يُخْبِرُ عَنْ عَلِيِّ بْنِ الْحُسَيْنِ أَنَّ صَفِيَّةَ رَضِيَ اللَّهُ عَنْهَاأَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ مُعْتَكِفٌ فَلَمَّا رَجَعَتْ مَشَى مَعَهَا فَأَبْصَرَهُ رَجُلٌ مِنْ الْأَنْصَارِ فَلَمَّا أَبْصَرَهُ دَعَاهُ فَقَالَ تَعَالَ هِيَ صَفِيَّةُ وَرُبَّمَا قَالَ سُفْيَانُ هَذِهِ صَفِيَّةُ فَإِنَّ الشَّيْطَانَ يَجْرِي مِنْ ابْنِ آدَمَ مَجْرَى الدَّمِقُلْتُ لِسُفْيَانَ أَتَتْهُ لَيْلًا قَالَ وَهَلْ هُوَ إِلَّا لَيْلٌ","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] berkata, telah mengabarkan kepada saya [saudaraku] dari [Sulaiman] dari [Muhammad bin Abu 'Atiq] dari [Ibnu Syihab] dari ['Ali bin Al Husain radliallahu 'anhuma] bahwa [Shafiyah] isteri Nabi shallallahu 'alaihi wasallam mengabarkan kepadanya. Dan diriwayatkan pula, telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] aku mendengar [Az Zuhriy] dari ['Ali bin Al Husain radliallahu 'anhuma] bahwa Shafiyah radliallahu 'anhu menemui Nabi shallallahu 'alaihi wasallam ketika Beliau sedang i'tikaf. Ketika dia kembali Beliau berjalan mendampinginya. Kemudian ada seorang dari Kaum Anshar yang melihat Beliau. Setelah Beliau melihatnya, Beliau memanggil orang itu lalu berkata: \"Dia adalah Shafiyah\". Sufyan beranggapan, Beliau shallallahu 'alaihi wasallam berkata: \"Ini adalah Shafiyah. Sesungguhnya syetan berjalan pada diri manusia lewat aliran darah\". Aku bertanya kepada Sufyan: \"Apakah Shafiyah radliallahu 'anha menemui Beliau shallallahu 'alaihi wasallam pada malam hari?\" Sufyan berkata: Memang, tidak lain kecuali di malam hari\". "},"1899":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ جُرَيْجٍ عَنْ سُلَيْمَانَ الْأَحْوَلِ خَالِ ابْنِ أَبِي نَجِيحٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ ح قَالَ سُفْيَانُ وَحَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ ح قَالَ وَأَظُنُّ أَنَّ ابْنَ أَبِي لَبِيدٍ حَدَّثَنَا عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ قَالَاعْتَكَفْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَشْرَ الْأَوْسَطَ فَلَمَّا كَانَ صَبِيحَةَ عِشْرِينَ نَقَلْنَا مَتَاعَنَا فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ اعْتَكَفَ فَلْيَرْجِعْ إِلَى مُعْتَكَفِهِ فَإِنِّي رَأَيْتُ هَذِهِ اللَّيْلَةَ وَرَأَيْتُنِي أَسْجُدُ فِي مَاءٍ وَطِينٍ فَلَمَّا رَجَعَ إِلَى مُعْتَكَفِهِ وَهَاجَتْ السَّمَاءُ فَمُطِرْنَا فَوَالَّذِي بَعَثَهُ بِالْحَقِّ لَقَدْ هَاجَتْ السَّمَاءُ مِنْ آخِرِ ذَلِكَ الْيَوْمِ وَكَانَ الْمَسْجِدُ عَرِيشًا فَلَقَدْ رَأَيْتُ عَلَى أَنْفِهِ وَأَرْنَبَتِهِ أَثَرَ الْمَاءِ وَالطِّينِ","id":"Telah menceritakan kepada kami ['Abdurrahman bin Bisyir] telah menceritakan kepada kami [Sufyan] dari [Ibnu Juraij] dari [Sulaiman Al Ahwal] pamannya Ibnu Abu Najih dari [Abu Salamah] dari [Abu Sa'id]. Dan diriwayatkan pula, [Sufyan] berkata, telah menceritakan kepada kami [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Sa'id]. Dan diriwayatkan pula, aku menduga bahwa [Ibnu Abu Labid] telah menceritakan kepada kami [Abu Salamah] dari [Abu Sa'id Al Khudriy radliallahu 'anhu] berkata: \"Kami pernah ber'i'tikaf bersama Rasulullah shallallahu 'alaihi wasallam pada sepuluh malam pertengahan. Ketika pagi pada hari kedua puluh kami memindahkan (membawa pulang) perlengkapan kami lalu kami menemui Rasulullah shallallahu 'alaihi wasallam. Maka Beliau berkata: \"Siapa yang sudah beri'tikaf kembalilah ke tempatnya beri'tikaf. Sungguh aku diperlihatkan (dalam mimpi) tentang malam ini, aku melihat aku sujud diatas air dan tanah. Ketika Beliau kembali ketempat i'tikaf Beliau, langit nampak mendung lalu hujan turun. Abu Sa'id Al Khudriy radliallahu 'anhu berkata: \"Demi Dzat yang telah mengutus Beliau dengan haq, sungguh langit menurunkan hujan sejak akhir (sore) hari itu. Masjid saat itu atapnya terbuat dari dedaunan dan sungguh aku melihat sisa-sisa tanah pada ujung hidung dan dahi Beliau. "},"1900":{"ar":"حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ سَلَامٍ أَخْبَرَنَا مُحَمَّدُ بْنُ فُضَيْلِ بْنِ غَزْوَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْتَكِفُ فِي كُلِّ رَمَضَانٍ وَإِذَا صَلَّى الْغَدَاةَ دَخَلَ مَكَانَهُ الَّذِي اعْتَكَفَ فِيهِ قَالَ فَاسْتَأْذَنَتْهُ عَائِشَةُ أَنْ تَعْتَكِفَ فَأَذِنَ لَهَا فَضَرَبَتْ فِيهِ قُبَّةً فَسَمِعَتْ بِهَا حَفْصَةُ فَضَرَبَتْ قُبَّةً وَسَمِعَتْ زَيْنَبُ بِهَا فَضَرَبَتْ قُبَّةً أُخْرَى فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْغَدَاةِ أَبْصَرَ أَرْبَعَ قِبَابٍ فَقَالَ مَا هَذَا فَأُخْبِرَ خَبَرَهُنَّ فَقَالَ مَا حَمَلَهُنَّ عَلَى هَذَا آلْبِرُّ انْزِعُوهَا فَلَا أَرَاهَا فَنُزِعَتْ فَلَمْ يَعْتَكِفْ فِي رَمَضَانَ حَتَّى اعْتَكَفَ فِي آخِرِ الْعَشْرِ مِنْ شَوَّالٍ","id":"Telah menceritakan kepada kami [Muhammad] dia adalah Ibnu Salam telah mengabarkan kepada kami [Muhammad bin Fudhail bin Ghozwan] dari [Yahya bin Sa'id] dari ['Amrah binti 'Abdurrahman] dari ['Aisyah radliallahu 'anha] berkata: Rasulullah shallallahu 'alaihi wasallam selalu beri'tikaf pada bulan Ramadhan. Apabila selesai dari shalat Shubuh Beliau masuk ke tempat khusus i'tikaf Beliau. Dia (Yahya bin Sa'id) berkata: Kemudian 'Aisyah radliallahu 'anha meminta izin untuk bisa beri'tikaf bersama Beliau, maka Beliau mengizinkannya. Lalu 'Aisyah radliallahu 'anha membuat tenda khusus. Kemudian hal ini didengar oleh Hafshah, maka diapun membuat tenda serupa. Begitu juga hal ini kemudian didengar oleh Zainab maka dia pun membuat tenda yang serupa. Ketika Beliau selesai dari shalat Shubuh Beliau melihat tenda-tenda tersebut, maka Beliau berkata: \"Apa ini?\" Lalu Beliau diberitahu dengan apa yang telah diperbuat oleh mereka (para isteri beliau). Maka Beliau bersabda: \"Apa yang mendorong mereka sehingga beranggapan bahwa tenda-tenda ini adalah jalan kebajikan? Bongkarlah tenda-tenda itu, aku tidak mau melihatnya\". Maka tenda-tenda itu dibongkar dan Beliau tidak meneruskan i'tikaf Ramadhan hingga kemudian Beliau melaksanakannya pada sepuluh akhir dari bulan Syawal."},"1901":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ عَنْ أَخِيهِ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ أَنَّهُ قَالَيَا رَسُولَ اللَّهِ إِنِّي نَذَرْتُ فِي الْجَاهِلِيَّةِ أَنْ أَعْتَكِفَ لَيْلَةً فِي الْمَسْجِدِ الْحَرَامِ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْفِ نَذْرَكَ فَاعْتَكَفَ لَيْلَةً","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] dari [saudaranya] dari [Sulaiman bin Bilal] dari ['Ubaidullah bin 'Umar] dari [Nafi'] dari ['Abdullah bin 'Umar] dari ['Umar bin Al Khaththob radliallahu 'anhu] bahwa dia berkata: \"Wahai Rasulullah, aku pernah bernadzar di zaman Jahiliyyah untuk beri'tikaf satu malam di Al Masjidil Haram\". Maka Nabi shallallahu 'alaihi wasallam berkata kepadanya: \"Tunaikanlah nadzarmu itu\". Maka kemudian 'Umar bin Al Khaththob radliallahu 'anhu melaksanakan i'tikafnya pada suatu malam."},"1902":{"ar":"حَدَّثَنَا عُبَيْدُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ عُمَرَ رَضِيَ اللَّهُ عَنْهُ نَذَرَ فِي الْجَاهِلِيَّةِ أَنْ يَعْتَكِفَ فِي الْمَسْجِدِ الْحَرَامِ قَالَ أُرَاهُ قَالَ لَيْلَةً قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْفِ بِنَذْرِكَ","id":"Telah menceritakan kepada kami ['Ubaid bin Isma'il] telah menceritakan kepada kami [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa 'Umar radliallahu 'anhu bernadzar di zaman Jahiliyyah untuk beri'tikaf di Al Masjidil Haram. Dia ('Ubaid) berkata: \"Aku menduga dia berkata: Untuk satu malam\". Maka Rasulullah shallallahu 'alaihi wasallam berkata, kepadanya: \"Tunaikanlah nadzarmu itu\". "},"1903":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ أَبِي حَصِينٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْتَكِفُ فِي كُلِّ رَمَضَانٍ عَشْرَةَ أَيَّامٍ فَلَمَّا كَانَ الْعَامُ الَّذِي قُبِضَ فِيهِ اعْتَكَفَ عِشْرِينَ يَوْمًا","id":"Telah menceritakan kepada kami ['Abdullah bin Abu Syaibah] telah menceritakan kepada kami [Abu Bakar] dari [Abu Hashin] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam selalu beri'tikaf pada bulan Ramadhan selama sepuluh hari. Namun pada tahun wafatnya, Beliau beri'tikaf selama dua puluh hari\". "},"1904":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَبُو الْحَسَنِ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَتْنِي عَمْرَةُ بِنْتُ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ أَنْ يَعْتَكِفَ الْعَشْرَ الْأَوَاخِرَ مِنْ رَمَضَانَ فَاسْتَأْذَنَتْهُ عَائِشَةُ فَأَذِنَ لَهَا وَسَأَلَتْ حَفْصَةُ عَائِشَةَ أَنْ تَسْتَأْذِنَ لَهَا فَفَعَلَتْ فَلَمَّا رَأَتْ ذَلِكَ زَيْنَبُ ابْنَةُ جَحْشٍ أَمَرَتْ بِبِنَاءٍ فَبُنِيَ لَهَا قَالَتْ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى انْصَرَفَ إِلَى بِنَائِهِ فَبَصُرَ بِالْأَبْنِيَةِ فَقَالَ مَا هَذَا قَالُوا بِنَاءُ عَائِشَةَ وَحَفْصَةَ وَزَيْنَبَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَالْبِرَّ أَرَدْنَ بِهَذَا مَا أَنَا بِمُعْتَكِفٍ فَرَجَعَ فَلَمَّا أَفْطَرَ اعْتَكَفَ عَشْرًا مِنْ شَوَّالٍ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Abu Al Hasan] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Al Awza'iy] berkata, telah menceritakan kepada saya [Yahya bin Sa'id] berkata, telah menceritakan kepada saya ['Amrah binti 'Abdurrahman] dari ['Aisyah radliallahu 'anha] bahwa Rasulullah shallallahu 'alaihi wasallam memberitahu bahwa Beliau akan beri'tikaf pada sepuluh hari terakhir bulan Ramadhan. Lalu 'Aisyah radliallahu 'anha meminta izin kepada Beliau (untuk membuat bangunan (tenda) khusus) maka dia diijinkan. Kemudian Hafshah meminta 'Aisyah radliallahu 'anha agar memintakan izin kepada Beliau untuknya lalu dilakukan oleh 'Aisyah radliallahu 'anha. Ketika melihat hal itu, Zainab binti Jahsy memerintahkan pula untuk membuatkan tenda, maka tenda itu dibuat untuknya. 'Aisyah radliallahu 'anha berkata: Adalah Rasulullah shallallahu 'alaihi wasallam bila telah selesai dari shalat, Beliau kembali ke tempat khusus i'tikaf. Maka Beliau melihat ada banyak tenda, lalu berkata: \"Apa ini?\" Mereka menjawab: \"Ini tenda-tenda milik 'Aisyah, Hafshah dan Zainab\". Maka Beliau bersabda: \"Apakah mereka mengharapkan kebajikan dengan tenda-tenda ini?. Aku tidak akan beri'tikaf\". Maka Beliau pulang ke rumah. Setelah Lebaran 'Iedul Fithri Beliau i'tikaf sepuluh hari di bulan Syawal. "},"1905":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا هِشَامُ بْنُ يُوسُفَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّهَا كَانَتْ تُرَجِّلُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ حَائِضٌ وَهُوَ مُعْتَكِفٌ فِي الْمَسْجِدِ وَهِيَ فِي حُجْرَتِهَا يُنَاوِلُهَا رَأْسَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Hisyam binYusuf] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhriy] dari ['Urwah] dari ['Aisyah radliallahu 'anha] bahwa dia menyisir rambut Nabi shallallahu 'alaihi wasallam saat sedang haidh ketika Beliau sedang i'tikaf di masjid, ketika itu Beliau menjulurkan kepala Beliau kepadanya. "},"1906":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَإِنَّكُمْ تَقُولُونَ إِنَّ أَبَا هُرَيْرَةَ يُكْثِرُ الْحَدِيثَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَقُولُونَ مَا بَالُ الْمُهَاجِرِينَ وَالْأَنْصَارِ لَا يُحَدِّثُونَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ أَبِي هُرَيْرَةَ وَإِنَّ إِخْوَتِي مِنْ الْمُهَاجِرِينَ كَانَ يَشْغَلُهُمْ صَفْقٌ بِالْأَسْوَاقِ وَكُنْتُ أَلْزَمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مِلْءِ بَطْنِي فَأَشْهَدُ إِذَا غَابُوا وَأَحْفَظُ إِذَا نَسُوا وَكَانَ يَشْغَلُ إِخْوَتِي مِنْ الْأَنْصَارِ عَمَلُ أَمْوَالِهِمْ وَكُنْتُ امْرَأً مِسْكِينًا مِنْ مَسَاكِينِ الصُّفَّةِ أَعِي حِينَ يَنْسَوْنَ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَدِيثٍ يُحَدِّثُهُ إِنَّهُ لَنْ يَبْسُطَ أَحَدٌ ثَوْبَهُ حَتَّى أَقْضِيَ مَقَالَتِي هَذِهِ ثُمَّ يَجْمَعَ إِلَيْهِ ثَوْبَهُ إِلَّا وَعَى مَا أَقُولُ فَبَسَطْتُ نَمِرَةً عَلَيَّ حَتَّى إِذَا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقَالَتَهُ جَمَعْتُهَا إِلَى صَدْرِي فَمَا نَسِيتُ مِنْ مَقَالَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ مِنْ شَيْءٍ","id":"Telah menceritakan kepada kami [Abu Al Yaman] telah menceritakan kepada kami [Syu'aib] dari [Az Zuhriy] berkata, telah mengabarkan kepada saya [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] bahwa [Abu Hurairah radliallahu 'anhu] berkata; \"Sesunggungnya kalian telah mengatakan bahwa Abu Hurairah adalah orang yang paling banyak menyampaikan hadits dari Rasulullah shallallahu 'alaihi wasallam dan kalian juga mengatakan tentang sahabat Muhajirin dan Anshar yang menyampaikan hadits dari Rasulullah shallallahu 'alaihi wasallam dengan tidak sebanyak yang disampaikan oleh Abu Hurairah. Sungguh saudara-saudaraku dari kalangan Muhajirin mereka disibukkan dengan berdagang di pasar-pasar sedangkan aku selalu mendampingi (mulazamah) Rasulullah shallallahu 'alaihi wasallam dalam keadaan perutku hanya terisi makanan pokok sehingga aku hadir saat mereka tidak hadir dan aku dapat menghafal hadits ketika mereka lupa. Sedangkan saudara-saudaraku dari kalangan Anshar mereka disibukkan dengan pekerjaan mereka dalam mengurus harta mereka sedangkan aku saat itu adalah salah satu orang miskin dari kalangan orang-orang miskin Ahlush Shuffah sehingga aku dapat mengingat hadits saat mereka lupa, dan sungguh Rasulullah shallallahu 'alaihi wasallam telah bersabda dalam suatu hadits yang Beliau sampaikan kepadaku yaitu: \"Tidaklah seseorang menggelar kainnya hingga aku selesaikan sabdaku ini diatas kainnya itu lalu dia menampung dan mengambilnya kembali melainkan dia akan dapat menjaga (menghafal dan memahami) apa yang aku sabdakan\". Maka aku menggelar kainku yang bermotif (bergaris) hingga ketika Beliau telah menyelesaikan sabda Belliau aku ambil kain tersebut lalu aku peluk di dadaku. Maka setelah itu tidaklah aku lupa sedikitpun dari sabda-sabda Rasulullah shallallahu 'alaihi wasallam \". "},"1907":{"ar":"حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَالَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ رَضِيَ اللَّهُ عَنْهُلَمَّا قَدِمْنَا الْمَدِينَةَ آخَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنِي وَبَيْنَ سَعْدِ بْنِ الرَّبِيعِ فَقَالَ سَعْدُ بْنُ الرَّبِيعِ إِنِّي أَكْثَرُ الْأَنْصَارِ مَالًا فَأَقْسِمُ لَكَ نِصْفَ مَالِي وَانْظُرْ أَيَّ زَوْجَتَيَّ هَوِيتَ نَزَلْتُ لَكَ عَنْهَا فَإِذَا حَلَّتْ تَزَوَّجْتَهَا قَالَ فَقَالَ لَهُ عَبْدُ الرَّحْمَنِ لَا حَاجَةَ لِي فِي ذَلِكَ هَلْ مِنْ سُوقٍ فِيهِ تِجَارَةٌ قَالَ سُوقُ قَيْنُقَاعٍ قَالَ فَغَدَا إِلَيْهِ عَبْدُ الرَّحْمَنِ فَأَتَى بِأَقِطٍ وَسَمْنٍ قَالَ ثُمَّ تَابَعَ الْغُدُوَّ فَمَا لَبِثَ أَنْ جَاءَ عَبْدُ الرَّحْمَنِ عَلَيْهِ أَثَرُ صُفْرَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجْتَ قَالَ نَعَمْ قَالَ وَمَنْ قَالَ امْرَأَةً مِنْ الْأَنْصَارِ قَالَ كَمْ سُقْتَ قَالَ زِنَةَ نَوَاةٍ مِنْ ذَهَبٍ أَوْ نَوَاةً مِنْ ذَهَبٍ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah menceritakan kepada kami ['Abdul 'Aziz bin 'Abdullah] telah menceritakan kepada kami [Ibrahim bin Sa'ad] dari [bapaknya] dari [kakeknya] berkata; ['Abdurrahman bin 'Auf] radliallahu 'anhu berkata, ketika kami sampai di Madinah; Rasulullah shallallahu 'alaihi wasallam mempersaudarakan antara aku dengan Saad bin ar-Rabi', lalu Saad bin ar-Rabi' berkata; \"Aku adalah orang Anshar yang paling banyak hartanya, maka aku beri separuh hartaku untukmu, kemudian lihatlah diantara kedua isteriku siapa yang engkau suka nanti akan aku ceraikan untukmu, jika ia telah halal maka nikahilah\". Perawi berkata; \"Maka 'Abdurrahman berkata kepadanya; \"Aku tidak membutuhkan itu. Begini saja, apakah ada pasar yang sedang berlangsung transaksi jual beli saat ini?\" Sa'ad menjawab: \"Pasar Qainuqa'\". Perawi berkata; \"Lalu Abdur Rahman pergi kesana, ia membawa keju dan minyak samin. Perawi berkata lagi; \"Dia melakukan hal itu pada hari-hari berikutnya. 'Abdurrahman tetap berdagang disana hingga akhirnya ia datang dengan mengenakan pakaian yang bagus dan penuh aroma wewangian. Maka Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apakah engkau sudah menikah?\" Dia menjawab; \"Ya, sudah\". Lalu beliau bertanya lagi: \"Dengan siapa?\" Dia menjawab; \"Dengan seorang wanita Anshar\". Beliau bertanya lagi: \"Dengan mahar apa engkau melakukan akad nikah?\" Dia menjawab; \"Dengan perhiasan sebiji emas, atau sebiji emas\". Lalu Nabi shallallahu 'alaihi wasallam berkata, kepadanya: \"Adakanlah walimah (resepsi) walau hanya dengan seekor kambing\"."},"1908":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَدِمَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ الْمَدِينَةَ فَآخَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُ وَبَيْنَ سَعْدِ بْنِ الرَّبِيعِ الْأَنْصَارِيِّ وَكَانَ سَعْدٌ ذَا غِنًى فَقَالَ لِعَبْدِ الرَّحْمَنِ أُقَاسِمُكَ مَالِي نِصْفَيْنِ وَأُزَوِّجُكَ قَالَ بَارَكَ اللَّهُ لَكَ فِي أَهْلِكَ وَمَالِكَ دُلُّونِي عَلَى السُّوقِ فَمَا رَجَعَ حَتَّى اسْتَفْضَلَ أَقِطًا وَسَمْنًا فَأَتَى بِهِ أَهْلَ مَنْزِلِهِ فَمَكَثْنَا يَسِيرًا أَوْ مَا شَاءَ اللَّهُ فَجَاءَ وَعَلَيْهِ وَضَرٌ مِنْ صُفْرَةٍ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْيَمْ قَالَ يَا رَسُولَ اللَّهِ تَزَوَّجْتُ امْرَأَةً مِنْ الْأَنْصَارِ قَالَ مَا سُقْتَ إِلَيْهَا قَالَ نَوَاةً مِنْ ذَهَبٍ أَوْ وَزْنَ نَوَاةٍ مِنْ ذَهَبٍ قَالَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Humaid] dari [Anas radliallahu 'anhu] berkata; 'Abdurrahman bin 'Auf radliallahu 'anhu tiba di Madinah, lalu Rasulullah shallallahu 'alaihi wasallam mempersaudarakannya dengan Saad bin Ar-Rabi' Al Anshariy. Saat itu Sa'ad adalah seorang yang kaya, lalu dia berkata, kepada 'Abdurrahman: \"Aku akan membagi untukmu separuh dari hartaku dan menikahkanmu (dengan salah seorang dari isteriku) \". 'Abdurrahman berkata: \"Semoga Allah memberkahimu dalam keluarga dan hartamu. Bagiku darimu cukup tunjukkanlah pasar kepadaku\". Maka dia tidak kembali melainkan pergi ke pasar dengan membawa keju dan minyak samin lalu membawa keuntungannya untuk keluarganya lalu tinggal sejenak atau sesuai apa yang Allah kehendaki. Kemudian dia datang dengan baju yang penuh arama wewangian. Lalu Nabi shallallahu 'alaihi wasallam bertanya kepadanya: \"Apakah engkau sudah menikah?\" Dia menjawab: \"Ya, aku sudah menikah dengan seorang wanita Anshar\". Beliau bertanya lagi: \"Dengan mahar apa engkau melakukan akad nikah?\" Dia menjawab: \"Dengan perhiasan sebiji emas, atau sebiji emas\". Lalu Nabi shallallahu 'alaihi wasallam berkata, kepadanya: \"Adakanlah walimah walau dengan seekor kambing\"."},"1909":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ عُكَاظٌ وَمَجَنَّةُ وَذُو الْمَجَازِ أَسْوَاقًا فِي الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ فَكَأَنَّهُمْ تَأَثَّمُوا فِيهِ فَنَزَلَتْ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ قَرَأَهَا ابْنُ عَبَّاسٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Muhammad] telah menceritakan kepada kami [Sufyan] dari ['Amru] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"'Ukazh, Majannah dan Dzul Majaz adalah nama-nama pasar di zaman Jahiliyyah. Ketika Islam datang mereka seakan-akan merasa berdosa bila tetap berdagang di pasar-pasar tersebut. Maka turunlah firman Allah Ta'ala QS Al Baqarah ayat 198 yang artinya: (\"Tidak ada dosa bagi kalian jika mencari karunia rezeqi Rabb kalian…..\"). Ini dilakukan selama musim hajji, menurut pendapat Ibnu 'Abbas radliallahu 'anhuma."},"1910":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ الشَّعْبِيِّ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ رَضِيَ اللَّهُ عَنْهُ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا ابْنُ عُيَيْنَةَ حَدَّثَنَا أَبُو فَرْوَةَ عَنْ الشَّعْبِيِّ قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ أَبِي فَرْوَةَ سَمِعْتُ الشَّعْبِيَّ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ رَضِيَ اللَّهُ عَنْهُمَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي فَرْوَةَ عَنْ الشَّعْبِيِّ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَلَالُ بَيِّنٌ وَالْحَرَامُ بَيِّنٌ وَبَيْنَهُمَا أُمُورٌ مُشْتَبِهَةٌ فَمَنْ تَرَكَ مَا شُبِّهَ عَلَيْهِ مِنْ الْإِثْمِ كَانَ لِمَا اسْتَبَانَ أَتْرَكَ وَمَنْ اجْتَرَأَ عَلَى مَا يَشُكُّ فِيهِ مِنْ الْإِثْمِ أَوْشَكَ أَنْ يُوَاقِعَ مَا اسْتَبَانَ وَالْمَعَاصِي حِمَى اللَّهِ مَنْ يَرْتَعْ حَوْلَ الْحِمَى يُوشِكُ أَنْ يُوَاقِعَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adiy] dari [Ibnu 'Aun] dari [Asy-Sa'biy] aku mendengar [An-Nu'man bin Basyir radliallahu 'anhuma] aku mendengar Nabi shallallahu 'alaihi wasallam. Dan diriwayatkan pula, telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Ibnu 'Uyainah] telah menceritakan kepada kami [Abu Farwah] dari [Asy-Sa'biy] berkata, aku mendengar [An-Nu'man bin Basyir] telah menceritakan kepada kami berkata, aku mendengar Nabi shallallahu 'alaihi wasallam. Dan diriwayatkan pula ['Abdullah bin Muhammad] dari [Ibnu 'Uyainah] dari [Abu Farwah] aku mendengar [Asy-Sa'biy] aku mendengar [An-Nu'man bin Basyir radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam. Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Abu Farwah] dari [Asy-Sa'biy] dari [An-Nu'man bin Basyir radliallahu 'anhu] berkata, telah bersabda Nabi shallallahu 'alaihi wasallam: \"Yang halal sudah jelas dan yang haram juga sudah jelas. Namun diantara keduanya ada perkara yang syubhat (samar). Maka barangsiapa yang meninggalkan perkara yang samar karena khawatir mendapat dosa, berarti dia telah meninggalkan perkara yang jelas keharamannya dan siapa yang banyak berdekatan dengan perkara samar maka dikhawatirkan dia akan jatuh pada perbuatan yang haram tersebut. Maksiat adalah larangan-larangan Allah. Maka siapa yang berada di dekat larangan Allah itu dikhawatirkan dia akan jatuh pada larangan tersebut\"."},"1911":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ أَبِي حُسَيْنٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ رَضِيَ اللَّهُ عَنْهُأَنَّ امْرَأَةً سَوْدَاءَ جَاءَتْ فَزَعَمَتْ أَنَّهَا أَرْضَعَتْهُمَا فَذَكَرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْرَضَ عَنْهُ وَتَبَسَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَيْفَ وَقَدْ قِيلَ وَقَدْ كَانَتْ تَحْتَهُ ابْنَةُ أَبِي إِهَابٍ التَّمِيمِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] telah mengabarkan kepada kami ['Abdullah bin 'Abdurrahman bin Abu Husain] telah menceritakan kepada kami ['Abdullah bin Abu Mulaikah] dari ['Uqbah bin Al Harits radliallahu 'anhu] bahwa ada seorang wanita kulit hitam datang dan mengaku bahwa dia pernah menyusui keduanya. Kejadian ini kemudian diceritakan kepada Nabi shallallahu 'alaihi wasallam. Maka Beliau berpaling dan tersenyum kepadanya seraya berkata: \"Bagaimana lagi, sedangkan dia sudah mengatakannya\". Saat itu yang menjadi mempelai puteri adalah anak perempuan Abu Ihab At-Taymiy."},"1912":{"ar":"حَدَّثَنَا يَحْيَى بْنُ قَزَعَةَ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ عُتْبَةُ بْنُ أَبِي وَقَّاصٍ عَهِدَ إِلَى أَخِيهِ سَعْدِ بْنِ أَبِي وَقَّاصٍ أَنَّ ابْنَ وَلِيدَةِ زَمْعَةَ مِنِّي فَاقْبِضْهُ قَالَتْ فَلَمَّا كَانَ عَامَ الْفَتْحِ أَخَذَهُ سَعْدُ بْنُ أَبِي وَقَّاصٍ وَقَالَ ابْنُ أَخِي قَدْ عَهِدَ إِلَيَّ فِيهِ فَقَامَ عَبْدُ بْنُ زَمْعَةَ فَقَالَ أَخِي وَابْنُ وَلِيدَةِ أَبِي وُلِدَ عَلَى فِرَاشِهِ فَتَسَاوَقَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَعْدٌ يَا رَسُولَ اللَّهِ ابْنُ أَخِي كَانَ قَدْ عَهِدَ إِلَيَّ فِيهِ فَقَالَ عَبْدُ بْنُ زَمْعَةَ أَخِي وَابْنُ وَلِيدَةِ أَبِي وُلِدَ عَلَى فِرَاشِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ لَكَ يَا عَبْدُ بْنَ زَمْعَةَ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ ثُمَّ قَالَ لِسَوْدَةَ بِنْتِ زَمْعَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجِبِي مِنْهُ لِمَا رَأَى مِنْ شَبَهِهِ بِعُتْبَةَ فَمَا رَآهَا حَتَّى لَقِيَ اللَّهَ","id":"Telah menceritakan kepada kami [Yahya bin Qaza'ah] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Aisyah radliallahu 'anha] berkata; 'Utbah bin Abu Waqash berpesan kepada saudaranya Sa'ad bin Abu Waqash yang isinya 'Anak laki-laki dari hamba sahaya Zam'ah adalah anakku maka ambillah. 'Aisyah radliallahu 'anha berkata; Ketika tahun Pembebasan Makkah, Sa'ad bin Abu Waqash mengambilnya, seraya berkata; Itu anak laki-laki saudaraku, yang ia berpesan kepadaku untuk mengambil anak ini. Maka 'Abd bin Zam'ah berdiri lalu berkata: Oh tidak, karena saudaraku dan anak laki-laki hamba sahaya ayahku dilahirkan di tempat tidurnya. Lalu keduanya mengadukan masalah ini kepada Nabi shallallahu 'alaihi wasallam. Sa'ad berkata: \"Wahai Rasulullah, ini adalah anak saudaraku, yang saudaraku telah berpesan kepadaku untuk mengambilnya. Lalu 'Abd bin Zam'ah berkata: \"Saudaraku dan anak laki-laki dari hamba sahaya ayahku dilahirkan pada tempat tidurnya\". Lantas Rasulullah shallallahu 'alaihi wasallam berkata: \"Dia itu milikmu wahai 'Abd bin Zam'ah. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Anak itu milik pemilik kasur (suami) sedangkan lelaki pezina baginya adalah batu (dirajam). Kemudian Beliau berkata kepada Saudah binti Zam'ah isteri Nabi shallallahu 'alaihi wasallam: \"Berhijablah engkau daripadanya wahai Saudah, yang demikian karena ada kemiripannya dengan 'Utbah\". Maka anak laki-laki dari hamba sahaya Zam'ah itu tidak pernah melihat Saudah selama-lamanya hingga Saudah berjumpa dengan Allah. "},"1913":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمِعْرَاضِ فَقَالَ إِذَا أَصَابَ بِحَدِّهِ فَكُلْ وَإِذَا أَصَابَ بِعَرْضِهِ فَقَتَلَ فَلَا تَأْكُلْ فَإِنَّهُ وَقِيذٌ قُلْتُ يَا رَسُولَ اللَّهِ أُرْسِلُ كَلْبِي وَأُسَمِّي فَأَجِدُ مَعَهُ عَلَى الصَّيْدِ كَلْبًا آخَرَ لَمْ أُسَمِّ عَلَيْهِ وَلَا أَدْرِي أَيُّهُمَا أَخَذَ قَالَ لَا تَأْكُلْ إِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى الْآخَرِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] berkata, telah mengabarkan kepada saya ['Abdullah bin Abu As-Safar] dari [Asy-Sya'by] dari ['Adiy bin Hatim radliallahu 'anhu] berkata: Aku bertanya kepada Nabi shallallahu 'alaihi wasallam tentang anak panah yang mengenai hewan buruan, maka Beliau menjawab: \"Jika panah itu mengenai hewan buruan dengan ujung besinya yang tajam maka makanlah dan jika terkena oleh bagian pinggirnya lalu hewan buruan itu mati maka janganlah kamu makan karena dia berarti bangkai karena tidak terbunuh dengan ujung panah yang tajam\". Aku katakan: \"Wahai Rasulullah, aku melepas anjing buruanku dengan mengucapkan basmalah lalu aku dapatkan ada anjing lain pada hewan buruan itu yang aku tidak membaca basmalah dan aku tidak tahu yang mana dari dua anjing itu yang membunuh hewan buruan itu\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Jangan kamu makan, karena kamu membaca basmalah untuk anjingmu dan tidak untuk anjing yang lain\"."},"1914":{"ar":"حَدَّثَنَا قَب��يصَةُ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ طَلْحَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَمَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَمْرَةٍ مَسْقُوطَةٍ فَقَالَ لَوْلَا أَنْ تَكُونَ مِنْ صَدَقَةٍ لَأَكَلْتُهَاوَقَالَ هَمَّامٌ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَجِدُ تَمْرَةً سَاقِطَةً عَلَى فِرَاشِي","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Tholhah] dari [Anas radliallahu 'anhu] berkata: Nabi shallallahu 'alaihi wasallam berjalan melewati buah-buah kurma yang jatuh, lalu Beliau berkata: \"Seandainya kurma-kurma ini padanya tidak ada kewajiban shadaqah (zakat) tentu aku sudah memakannya\". Dan berkata, [Hammam] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Aku menemukan kurma yang jatuh di atas tempat tidurku\"."},"1915":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِ قَالَشُكِيَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّجُلُ يَجِدُ فِي الصَّلَاةِ شَيْئًا أَيَقْطَعُ الصَّلَاةَ قَالَ لَا حَتَّى يَسْمَعَ صَوْتًا أَوْ يَجِدَ رِيحًاوَقَالَ ابْنُ أَبِي حَفْصَةَ عَنْ الزُّهْرِيِّ لَا وُضُوءَ إِلَّا فِيمَا وَجَدْتَ الرِّيحَ أَوْ سَمِعْتَ الصَّوْتَ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhriy] dari ['Abbad bin Tamim] dari [pamannya] berkata; Nabi shallallahu 'alaihi wasallam diadukan tentang seorang laki-laki yang mendapatkan sesuatu yang nggak beres ketika sedang shalat, apakah aku harus memutuskan shalat atau melanjutkannya?\" Maka Beliau bersabda: \"Tidak, hingga dia mendengar suara atau tercium baunya\". Dan berkata, [Ibnu Abu Hafshah] dari [Az Zuhriy]: \"Tidak ada kewajiban berwudhu' kecuali bila engkau mencium bau atau mendengar suara\". "},"1916":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ الْمِقْدَامِ الْعِجْلِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الطُّفَاوِيُّ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ قَوْمًا قَالُوا يَا رَسُولَ اللَّهِ إِنَّ قَوْمًا يَأْتُونَنَا بِاللَّحْمِ لَا نَدْرِي أَذَكَرُوا اسْمَ اللَّهِ عَلَيْهِ أَمْ لَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمُّوا اللَّهَ عَلَيْهِ وَكُلُوهُ","id":"Telah menceritakan kepada saya [Ahmad bin Al Miqdam Al 'Ijliy] telah menceritakan kepada kami [Muhammad bin 'Abdurrahman Ath-Thofawiy] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah radliallahu 'anha]; Bahwa orang-orang berkata: \"Wahai Rasululloh, ada suatu kaum yang mendatangi kami dengan daging yang kami tidak tahu apakah mereka menyebutkan nama Allah ketika menyembelihnya atau tidak\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebutlah nama Allah, lalu makanlah\"."},"1917":{"ar":"حَدَّثَنَا طَلْقُ بْنُ غَنَّامٍ حَدَّثَنَا زَائِدَةُ عَنْ حُصَيْنٍ عَنْ سَالِمٍ قَالَ حَدَّثَنِي جَابِرٌ رَضِيَ اللَّهُ عَنْهُ قَالَبَيْنَمَا نَحْنُ نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ أَقْبَلَتْ مِنْ الشَّأْمِ عِيرٌ تَحْمِلُ طَعَامًا فَالْتَفَتُوا إِلَيْهَا حَتَّى مَا بَقِيَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا اثْنَا عَشَرَ رَجُلًا فَنَزَلَتْ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا }","id":"Telah menceritakan kepada kami [Tholq bin Ghonnam] telah menceritakan kepada kami [Za'idah] dari [Hushain] dari [Salim] berkata, telah menceritakan kepada saya [Jabir radliallahu 'anhu] berkata: \"Ketika kami sedang shalat bersama Nabi shallallahu 'alaihi wasallam, tiba-tiba datang rombongan dagang dari negeri Syam yang membawa makanan. Maka orang-orang melirik (dan berhamburan pergi) mendatangi rambongan tersebut, hingga tidak ada orang yang tersisa bersama Nabi shallallahu 'alaihi wasallam kecuali hanya dua belas orang. Maka turunlah ayat ini (QS. Al Jumu'ah ayat 12) yang artinya.: (\"Dan apabila mereka melihat perdagangan atau permainan, maka mereka bubar untuk menuju kepadanya dan mereka meninggalkan kamu ketika kamu sedang berdiri menyampaikan berkhuthbah\". "},"1918":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَأْتِي عَلَى النَّاسِ زَمَانٌ لَا يُبَالِي الْمَرْءُ مَا أَخَذَ مِنْهُ أَمِنَ الْحَلَالِ أَمْ مِنْ الْحَرَامِ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Ibnu Abu Dza'bi] telah menceritakan kepada kami [Sa'id Al Maqbariy] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Akan datang suatu zaman pada manusia yang ketika itu seseorang tidak peduli lagi tentang apa yang didapatnya apakah dari barang halal ataukah haram\"."},"1919":{"ar":"حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ عَنْ أَبِي الْمِنْهَالِ قَالَ كُنْتُ أَتَّجِرُ فِي الصَّرْفِ فَسَأَلْتُ زَيْدَ بْنَ أَرْقَمَ رَضِيَ اللَّهُ عَنْهُ فَقَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنِي الْفَضْلُ بْنُ يَعْقُوبَ حَدَّثَنَا الْحَجَّاجُ بْنُ مُحَمَّدٍ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ وَعَامِرُ بْنُ مُصْعَبٍ أَنَّهُمَا سَمِعَا أَبَا الْمِنْهَالِ يَقُولُ سَأَلْتُ الْبَرَاءَ بْنَ عَازِبٍ وَزَيْدَ بْنَ أَرْقَمَعَنْ الصَّرْفِ فَقَالَا كُنَّا تَاجِرَيْنِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّرْفِ فَقَالَ إِنْ كَانَ يَدًا بِيَدٍ فَلَا بَأْسَ وَإِنْ كَانَ نَسَاءً فَلَا يَصْلُحُ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Amru bin Dinar] dari [Abu Al Minhal] berkata: \"Aku berdagang penukaran uang lalu aku bertanya kepada [Zaid bin Arqam radliallahu 'anhu], maka dia berkata, bahwa Nabi shallallahu 'alaihi wasallam telah bersabda\". Dan diriwayatkan pula, telah menceritakan kepada saya [Al Fadhal bin Ya'qub] telah menceritakan kepada kami [Al Hajjaj bin Muhamamd] telah berkata, [Ibnu Juraij] telah mengabarkan kepada saya ['Amru bin Dinar] dan ['Amir bin Mush'ab] bahwa keduanya mendengar [Abu Al Minhal] berkata; Aku bertanya kepada [Al Bara' bin 'Azib] dan [Zaid bin Arqam] tentang pertukaran uang, maka dia berkata: \"Kami dahulu adalah para pedagang di zaman Rasulullah shallallahu 'alaihi wasallam dan kami pernah pula bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang pertukaran uang, maka Beliau bersabda: \"Jika transaksi langsung (cash) tidak mengapa namun bila tunda (penangguhan di belakang) maka tidak boleh\"."},"1920":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَلَامٍ أَخْبَرَنَا مَخْلَدُ بْنُ يَزِيدَ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ أَنَّ أَبَا مُوسَى الْأَشْعَرِيَّاسْتَأْذَنَ عَلَى عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ فَلَمْ يُؤْذَنْ لَهُ وَكَأَنَّهُ كَانَ مَشْغُولًا فَرَجَعَ أَبُو مُوسَى فَفَرَغَ عُمَرُ فَقَالَ أَلَمْ أَسْمَعْ صَوْتَ عَبْدِ اللَّهِ بْنِ قَيْسٍ ائْذَنُوا لَهُ قِيلَ قَدْ رَجَعَ فَدَعَاهُ فَقَالَ كُنَّا نُؤْمَرُ بِذَلِكَ فَقَالَ تَأْتِينِي عَلَى ذَلِكَ بِالْبَيِّنَةِ فَانْطَلَقَ إِلَى مَجْلِسِ الْأَنْصَارِ فَسَأَلَهُمْ فَقَالُوا لَا يَشْهَدُ لَكَ عَلَى هَذَا إِلَّا أَصْغَرُنَا أَبُو سَعِيدٍ الْخُدْرِيُّ فَذَهَبَ بِأَبِي سَعِيدٍ الْخُدْرِيِّ فَقَالَ عُمَرُ أَخَفِيَ هَذَا عَلَيَّ مِنْ أَمْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلْهَانِي الصَّفْقُ بِالْأَسْوَاقِ يَعْنِي الْخُرُوجَ إِلَى تِجَارَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Salam] telah mengabarkan kepada kami [Makhlad bin Yazid] telah mengabarkan kepada kami [Ibnu Juraij] berkata, telah mengabarkan kepada saya ['Atho'] dari ['Ubaid bin 'Umair] bahwa [Abu Musa Al Anshariy] meminta izin kepada 'Umar bin Al Khaththob radliallahu 'anhu namun tidak diizinkan karena nampaknya dia sedang sibuk. Lalu Abu Musa kembali sedangkan 'Umar telah pula selesai dari pekerjaannya lalu dia berkata: \"Tidakkah tadi aku mendengar suara 'Abdullah bin Qais?, Berilah izin kepadanya\". Umar diberitahu bahwa Abu Musa telah pulang. Maka 'Umar memanggilnya, lalu Abu Musa berkata: \"Kami diperintahkan hal yang demikian (kembali pulang bila salam minta izin tiga kali tidak dijawab) \". Maka dia berkata: \"Berikanlah kepadaku alasan yang jelas tentang masalah ini\". Maka Abu Musa pergi menemui majelis Kaum Anshar lalu dia bertanya kepada mereka. Kaum Anshar berkata: \"Tidak ada yang menjadi saksi (mengetahui) perkara ini kecuali anak kecil kami yaitu Abu Sa'id Al Khudriy\". Maka Abu Musa berangkat bersama [Abu Sa'id Al Khudriy] menemui 'Umar, maka 'Umar berkata: \"Kenapa aku bisa tidak tahu urusan Rasulullah shallallahu 'alaihi wasallam. Sungguh aku telah dilalaikan oleh hiruk pikik pasar\". Maksudnya kegiatan berdagang."},"1921":{"ar":"وَقَالَ اللَّيْثُ حَدَّثَنِي جَعْفَرُ بْنُ رَبِيعَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُذَكَرَ رَجُلًا مِنْ بَنِي إِسْرَائِيلَ خَرَجَ إِلَى الْبَحْرِ فَقَضَى حَاجَتَهُ وَسَاقَ الْحَدِيثَحَدَّثَنِي عَبْدُ اللَّهِ بْنُ صَالِحٍ قَالَ حَدَّثَنِي اللَّيْثُ بِهَذَا","id":"Dan berkata, [Al Laits] telah menceritakan kepada saya [Ja'far bin Rabi'ah] dari ['Abdurrahman bin Hurmuz] dari [Abu Hurairah radliallahu 'anhu] dari Rasulullah shallallahu 'alaihi wasallam bahwa Beliau menceritakan tentang seorang dari Bani Isra'il yang pergi ke laut lalu menuunaikan hajatnya. Lalu dia menyebutkan hadits ini, telah menceritakan kepada saya ['Abdullah bin Shalih] berkata, telah menceritakan kepada saya [Al Laits] seperti hadits ini."},"1922":{"ar":"حَدَّثَنِي مُحَمَّدٌ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حُصَيْنٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَأَقْبَلَتْ عِيرٌ وَنَحْنُ نُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ فَانْفَضَّ النَّاسُ إِلَّا اثْنَيْ عَشَرَ رَجُلًا فَنَزَلَتْ هَذِهِ الْآيَةُ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }","id":"Telah menceritakan kepada saya [Muhammad] berkata, telah menceritakan kepada saya [Muhammad bin Fudhail] dari [Hushain] dari [Salim bin Abu Al Ja'di] dari [Jabir radliallahu 'anhu] berkata: \"Ketika kami sedang shalat Jum'at bersama Nabi shallallahu 'alaihi wasallam, tiba-tiba datang rambongan dagang. Maka orang-orang melirik (dan berhamburan pergi) kecuali hanya dua belas orang. Maka kemudian turunlah ayat ini (QS. Al Jumu'ah ayat 12) yang artinya.: (\"Dan apabila mereka melihat perdagangan atau permainan, maka mereka bubar untuk menuju kepadanya dan mereka meninggalkan kamu ketika kamu sedang berdiri menyampaikan berkhuthbah\". "},"1923":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَنْفَقَتْ الْمَرْأَةُ مِنْ طَعَامِ بَيْتِهَا غَيْرَ مُفْسِدَةٍ كَانَ لَهَا أَجْرُهَا بِمَا أَنْفَقَتْ وَلِزَوْجِهَا بِمَا كَسَبَ وَلِلْخَازِنِ مِثْلُ ذَلِكَ لَا يَنْقُصُ بَعْضُهُمْ أَجْرَ بَعْضٍ شَيْئًا","id":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa'il] dari [Masruq] dari ['Aisyah radliallahu 'anha] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang isteri menginfaqkan (bershadaqah) makanan keluarganya yang tujuannya bukan mencari kerusakan maka baginya pahala dari apa yang diinfaqkan itu dan begitu juga pahala bagi suaminya dari harta hasil usahanya itu. Dan begitu juga seorang penjaga gudang akan mendapatkan pahala tanpa dikurangi sedikitpun pahala masing-masingnya\". "},"1924":{"ar":"حَدَّثَنِي يَحْيَى بْنُ جَعْفَرٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنْ هَمَّامٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَنْفَقَتْ الْمَرْأَةُ مِنْ كَسْبِ زَوْجِهَا عَنْ غَيْرِ أَمْرِهِ فَلَهُ نِصْفُ أَجْرِهِ","id":"Telah menceritakan kepada saya [Yahya bin Ja'far] telah menceritakan kepada kami ['Abdur Razzaq] dari [Ma'mar] dari [Hammam] berkata, aku mendengar [Abu Hurairah radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Jika seorang isteri menginfaqkan (bershadaqah) harta hasil usaha suaminya tanpa perintah suaminya maka bagi suaminya separuh pahalanya.\""},"1925":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي يَعْقُوبَ الْكِرْمَانِيُّ حَدَّثَنَا حَسَّانُ حَدَّثَنَا يُونُسُ قَالَ مُحَمَّدٌ هُوَ الزُّهْرِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ سَرَّهُ أَنْ يُبْسَطَ لَهُ فِي رِزْقِهِ أَوْ يُنْسَأَ لَهُ فِي أَثَرِهِ فَلْيَصِلْ رَحِمَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Ya'qub AL Karmaniy] telah menceritakan kepada kami [Hassan] telah menceritakan kepada kami [Yunus] berkata, [Muhammad, dia adalah Az Zuhriy] dari [Anas bin Malik radliallahu 'anhu] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa ang ingin diluaskan rezeqinya atau meninggalkan nama sebagai orang baik setelah kematiannya hendaklah dia menyambung silaturrahim\"."},"1926":{"ar":"حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا الْأَعْمَشُ قَالَ ذَكَرْنَا عِنْدَ إِبْرَاهِيمَ الرَّهْنَ فِي السَّلَمِ فَقَالَ حَدَّثَنِي الْأَسْوَدُ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرَى طَعَامًا مِنْ يَهُودِيٍّ إِلَى أَجَلٍ وَرَهَنَهُ دِرْعًا مِنْ حَدِيدٍ","id":"Telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Al A'masy] berkata; Kami membicarakan tentang gadai dalam jual beli kredit (Salam) di hadapan [Ibrahim] maka dia berkata, telah menceritakan kepada saya [Al Aswad] dari ['Aisyah radliallahu 'anha] bahwa Nabi shallallahu 'alaihi wasallam pernah membeli makanan dari orang Yahuid yang akan dibayar Beliau pada waktu tertentu di kemudian hari dan Beliau menjaminkannya (gadai) dengan baju besi."},"1927":{"ar":"حَدَّثَنَا مُسْلِمٌ حَدَّثَنَا هِشَامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ ح حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ حَوْشَبٍ حَدَّثَنَا أَسْبَاطٌ أَبُو الْيَسَعِ الْبَصْرِيُّ حَدَّثَنَا هِشَامٌ الدَّسْتَوَائِيُّ عَنْ قَتَادَةَ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُأَنَّهُ مَشَى إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِخُبْزِ شَعِيرٍ وَإِهَالَةٍ سَنِخَةٍ وَلَقَدْ رَهَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِرْعًا لَهُ بِالْمَدِينَةِ عِنْدَ يَهُودِيٍّ وَأَخَذَ مِنْهُ شَعِيرًا لِأَهْلِهِ وَلَقَدْ سَمِعْتُهُ يَقُولُ مَا أَمْسَى عِنْدَ آلِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَاعُ بُرٍّ وَلَا صَاعُ حَبٍّ وَإِنَّ عِنْدَهُ لَتِسْعَ نِسْوَةٍ","id":"Telah menceritakan kepada kami [Muslim] telah menceritakan kepada kami [Hisyam] telah menceritakan kepada kami [Qatadah] dari [Anas]. Dan diriwayatkan pula, telah menceritakan kepada saya [Muhammad bin 'Abdullah bin Hawsyab] telah menceritakan kepada kami [Asbath Abu Al Yasa' Al Bashriy] telah menceritakan kepada kami [Hisyam Ad-Dastawa'iy] dari [Qatadah] dari [Anas radliallahu 'anhu] bahwa dia pernah di sore hari bersama Nabi shallallahu 'alaihi wasallam dengan hidangan rati terbuat dari gandum dan sayur yang sudah basi. Sungguh Nabi shallallahu 'alaihi wasallam telah menggadaikan baju besi Beliau kepada seorang Yahudi untuk mendapatkan makanan di Madinah lalu dengan itu Beliau mendapatkan gandum untuk keluarga Beliau. Dan sungguh aku mendengar Beliau bersabda: \"Tidaklah ada satu malampun yang berlalu pada keluarga Muhammad dimana ada satu sha' dari gandum atau satu sha' rati\". Padahal Beliau memelilki sembilan isteri. "},"1928":{"ar":"حَدَّثَ��َا إِسْمَاعِيلُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا اسْتُخْلِفَ أَبُو بَكْرٍ الصِّدِّيقُ قَالَ لَقَدْ عَلِمَ قَوْمِي أَنَّ حِرْفَتِي لَمْ تَكُنْ تَعْجِزُ عَنْ مَئُونَةِ أَهْلِي وَشُغِلْتُ بِأَمْرِ الْمُسْلِمِينَ فَسَيَأْكُلُ آلُ أَبِي بَكْرٍ مِنْ هَذَا الْمَالِ وَيَحْتَرِفُ لِلْمُسْلِمِينَ فِيهِ","id":"Telah menceritakan kepada kami [Isma'il bin 'Abdullah] berkata, telah menceritakan kepada saya [Ibnu Wahab] dari [Yunus] dari [Ibnu Syihab] berkata, telah menceritakan kepada saya ['Urwah bin Az Zubair] bahwa ['Aisyah Radliallahu 'anha] berkata: Ketika Abu Bakar Sh-Shiddiq diangkat menjadi khalifah ia berkata: \"Kaumku telah mengetahui bahwa pekerjaanku mencari nafkah tidak akan melemahkan urusanku terhadap keluargaku, semenrtara aku juga disibukkan dengan urusan kaum muslimin. Maka keluarga Abu Bakar akan makan dari harta yang aku usahakan ini sedangkan dia juga bersungguh bekerja untuk urusan Kaum Muslimin."},"1929":{"ar":"حَدَّثَنِي مُحَمَّدٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدٌ قَالَ حَدَّثَنِي أَبُو الْأَسْوَدِ عَنْ عُرْوَةَ قَالَ قَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَاكَانَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمَّالَ أَنْفُسِهِمْ وَكَانَ يَكُونُ لَهُمْ أَرْوَاحٌ فَقِيلَ لَهُمْ لَوْ اغْتَسَلْتُمْرَوَاهُ هَمَّامٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ","id":"Telah menceritakan kepada saya [Muhammad] telah menceritakan kepada kami ['Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id] berkata, telah menceritakan kepada saya [Abu Al Aswad] dari ['Urwah] berkata,, ['Aisyah radliallahu 'anha] berkata: \"Para sahabat Rasulullah shallallahu 'alaihi wasallam adalah para pekerja yang pada suatu hari mereka hadir ke masjid dalam keadaan lusuh dan kotor sehingga dikatakan kepada mereka seandainya kalian mandi lebih dahulu\". [Hammam] meriwayatkan dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha]."},"1930":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى أَخْبَرَنَا عِيسَى بْنُ يُونُسَ عَنْ ثَوْرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ الْمِقْدَامِ رَضِيَ اللَّهُ عَنْهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَكَلَ أَحَدٌ طَعَامًا قَطُّ خَيْرًا مِنْ أَنْ يَأْكُلَ مِنْ عَمَلِ يَدِهِ وَإِنَّ نَبِيَّ اللَّهِ دَاوُدَ عَلَيْهِ السَّلَام كَانَ يَأْكُلُ مِنْ عَمَلِ يَدِهِ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah mengabarkan kepada kami ['Isa bin Yunus] dari [Tsaur] dari [Khalid bin Ma'dan] dari [Al Miqdam radliallahu 'anhu] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada seorang yang memakan satu makananpun yang lebih baik dari makanan hasil usaha tangannya sendiri. Dan sesungguhnya Nabi Allah Daud AS memakan makanan dari hasil usahanya sendiri\"."},"1931":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ حَدَّثَنَا أَبُو هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ دَاوُدَ النَّبِيَّ عَلَيْهِ السَّلَام كَانَ لَا يَأْكُلُ إِلَّا مِنْ عَمَلِ يَدِهِ","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami ['Abdur Razzaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] telah menceritakan kepada kami [Abu Hurairah radliallahu 'anhu] dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bahwa Nabi Allah Daud AS tidak memakan makanan kecuali hasil usahanya sendiri\"."},"1932":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي عُبَيْدٍ مَوْلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَحْتَطِبَ أَحَدُكُمْ حُزْمَةً عَلَى ظَهْرِهِ خَيْرٌ لَهُ مِنْ أَنْ يَسْأَلَ أَحَدًا فَيُعْطِيَهُ أَوْ يَمْنَعَهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Abu 'Ubaid] sahayanya 'Abdurrahman bin 'Auf bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] berkata; \"Sungguh, seorang dari kalian yang memanggul kayu bakar dan dibawa dengan punggungnya lebih baik baginya daripada dia meminta kepada orang lain, baik orang lain itu memberinya atau menolaknya\"."},"1933":{"ar":"حَدَّثَنَا يَحْيَى بْنُ مُوسَى حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ الزُّبَيْرِ بْنِ الْعَوَّامِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَنْ يَأْخُذَ أَحَدُكُمْ أَحْبُلَهُ","id":"Telah menceritakan kepada kami [Yahya bin Musa] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [bapaknya] dari [Az Zubair bin Al 'Awam radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: Sungguh seseorang dari kalian yang mengambil talinya\"."},"1934":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو غَسَّانَ مُحَمَّدُ بْنُ مُطَرِّفٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَحِمَ اللَّهُ رَجُلًا سَمْحًا إِذَا بَاعَ وَإِذَا اشْتَرَى وَإِذَا اقْتَضَى","id":"Telah menceritakan kepada kami ['Ali bin 'Ayyasy] telah menceritakan kepada kami [Abu Ghossan Muhammad bin Muthorrif] berkata, telah menceritakan kepada saya [Muhammad bin Al Munkadir] dari [Jabir bin 'Abdullah radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah merahmati orang yang memudahkan ketika menjual dan ketika membeli dan juga orang yang meminta haknya\"."},"1935":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مَنْصُورٌ أَنَّ رِبْعِيَّ بْنَ حِرَاشٍ حَدَّثَهُ أَنَّ حُذَيْفَةَ رَضِيَ اللَّهُ عَنْهُ حَدَّثَهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَلَقَّتْ الْمَلَائِكَةُ رُوحَ رَجُلٍ مِمَّنْ كَانَ قَبْلَكُمْ قَالُوا أَعَمِلْتَ مِنْ الْخَيْرِ شَيْئًا قَالَ كُنْتُ آمُرُ فِتْيَانِي أَنْ يُنْظِرُوا وَيَتَجَاوَزُوا عَنْ الْمُوسِرِ قَالَ قَالَ فَتَجَاوَزُوا عَنْهُقَالَ أَبُو عَبْد اللَّهِ وَقَالَ أَبُو مَالِكٍ عَنْ رِبْعِيٍّ كُنْتُ أُيَسِّرُ عَلَى الْمُوسِرِ وَأُنْظِرُ الْمُعْسِرَ وَتَابَعَهُ شُعْبَةُ عَنْ عَبْدِ الْمَلِكِ عَنْ رِبْعِيٍّ وَقَالَ أَبُو عَوَانَةَ عَنْ عَبْدِ الْمَلِكِ عَنْ رِبْعِيٍّ أُنْظِرُ الْمُوسِرَ وَأَتَجَاوَزُ عَنْ الْمُعْسِرِ وَقَالَ نُعَيْمُ بْنُ أَبِي هِنْدٍ عَنْ رِبْعِيٍّ فَأَقْبَلُ مِنْ الْمُوسِرِ وَأَتَجَاوَزُ عَنْ الْمُعْسِرِ","id":"Telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Manshur] bahwa [Rib'iy bin Hirasy] menceritakan kepadanya bahwa [Hudzaiah radliallahu 'anhu] menceritakan kepadanya dan berkata; Nabi shallallahu 'alaihi wasallam bersabda: Para Malaikat akan mendatangi ruh seseorang dari orang-orang sebelum kalian (saat menjelang ajalnya) lalu bertanya: \"Apakah kamu pernah berbuat suatu kebaikan?\" Orang itu menjawab: \"Aku dahulu memerintahkan para pembantuku untuk memneri tangguh dan menagih orang-orang yang memeliki kelapangan\". Dia berkata; Beliau shallallahu 'alaihi wasallam bersabda: \"Maka orang-orang itu memenuhi kewajibannya\". Berkata, Abu 'Abdullah Al Bukhariy; dan berkata, [Abu Malik] dari [Rib'iy]: \"Aku biasa memudahkan urusan orang yang sedang mmiliki kelapangan dan memberi waktu bagi yang sedang kesulitan\". Dan Hadits ini dikuatkan pula oleh [Syu'bah] dari ['Abdul Malik] dari [Rab'iy]. Dan berkata, [Abu 'Awanah] dari ['Abdul Malik] dari [Rib'iy]: \"Aku memberi waktu untuk orang ang sedang memiliki kemudahan dan menagih untuk orang yang sedang kesulitan\". Dan berkata, [Nu'aim bin Abu Hind] dari [Rab'iy]: \"Maka aku menerima dari yang sedang memiliki kemudahan dan menagih dari orang yang sedang kesulitan\"."},"1936":{"ar":"حَدَّثَنَا هِشَامُ بْنُ عَمَّارٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنَا الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ تَاجِرٌ يُدَايِنُ النَّاسَ فَإِذَا رَأَى مُعْسِرًا قَالَ لِفِتْيَانِهِ تَجَاوَزُوا عَنْهُ لَعَلَّ اللَّهَ أَنْ يَتَجَاوَزَ عَنَّا فَتَجَاوَزَ اللَّهُ عَنْهُ","id":"Telah menceritakan kepada kami [Hisyam bin 'Ammar] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepada kami [Az Zubaidiy] dari [Az Zuhriy] dari ['Ubaidullah bin 'Abdullah] bahwa dia mendengar [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Ada seorang pedagang yang memberi pinjaman kepada manusia sehingga jika ia melihat mereka dalam kesulitan dia berkata, kepada para pembantunya: \"Berilah dia tempo hingga mendapatkan kemudahan semoga Allah memudahkan urusan kita. Maka kemudianAllah memudahkan urusan pedagang tersebut\"."},"1937":{"ar":"حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ صَالِحٍ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ رَفَعَهُ إِلَى حَكِيمِ بْنِ حِزَامٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا أَوْ قَالَ حَتَّى يَتَفَرَّقَا فَإِنْ صَدَقَا وَبَيَّنَا بُورِكَ لَهُمَا فِي بَيْعِهِمَا وَإِنْ كَتَمَا وَكَذَبَا مُحِقَتْ بَرَكَةُ بَيْعِهِمَا","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Shalih Abu AL Khalil] dari ['Abdullah bin Al Harits] yang dinisbatkannya kepada [Hakim bin Hizam radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang melakukan jual beli boleh melakukan khiyar (pilihan untuk melangsungkan atau membatalkan jual beli) selama keduanya belum berpisah\", Atau sabda Beliau: \"hingga keduanya berpisah. Jika keduanya jujur dan menampakkan dagangannya maka keduanya diberkahi dalam jual belinya dan bila menyembunyikan dan berdusta maka akan dimusnahkan keberkahan jual belinya\"."},"1938":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ قَالَكُنَّا نُرْزَقُ تَمْرَ الْجَمْعِ وَهُوَ الْخِلْطُ مِنْ التَّمْرِ وَكُنَّا نَبِيعُ صَاعَيْنِ بِصَاعٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَاعَيْنِ بِصَاعٍ وَلَا دِرْهَمَيْنِ بِدِرْهَمٍ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syaiban] dari [Yahya] dari [Abu Salamah] dari [Abu Sa'id radliallahu 'anhu] berkata: \"Kami diberikan kurma yang bercampur (antara yang baik dan yang jelek) dan kami menjual dua sha' dengan satu sha'\". Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak boleh menjual dua sha' dibayar satu sha' dan dua dirham dengan satu dirham\"."},"1939":{"ar":"حَدَّثَنَا عُمَرُ بْنُ حَفْصٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ قَالَ حَدَّثَنِي شَقِيقٌ عَنْ أَبِي مَسْعُودٍ قَالَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ يُكْنَى أَبَا شُعَيْبٍ فَقَالَ لِغُلَامٍ لَهُ قَصَّابٍ اجْعَلْ لِي طَعَامًا يَكْفِي خَمْسَةً فَإِنِّي أُرِيدُ أَنْ أَدْعُوَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَامِسَ خَمْسَةٍ فَإِنِّي قَدْ عَرَفْتُ فِي وَجْهِهِ الْجُوعَ فَدَعَاهُمْ فَجَاءَ مَعَهُمْ رَجُلٌ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا قَدْ تَبِعَنَا فَإِنْ شِئْتَ أَنْ تَأْذَنَ لَهُ فَأْذَنْ لَهُ وَإِنْ شِئْتَ أَنْ يَرْجِعَ رَجَعَ فَقَالَ لَا بَلْ قَدْ أَذِنْتُ لَهُ","id":"Telah menceritakan kepada kami ['Umar bin Hafsh] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] berkata, telah menceritakan kepadaku [Syaqiq] dari [Abu Mas'ud] berkata: \"Ada seorang Anshar yang biasa dipanggil dengan Abu Syu'aib datang dan berkata, kepada seorang pembantunya yang tukang jagal: \"Buatkan aku makanan untuk lima orang, karena aku ingin mengundang Nabi shallallahu 'alaihi wasallam sebagai tamu kelimaku. Sungguh aku melihat rasa lapar dari raut muka Beliau\". Lalu ia mengundang mereka, kemudian datanglah seseorang bersama mereka, lalu Nabi shallallahu 'alaihi wasallam berkata: \"Sesungguhnya orang ini mengikuti kami, jika engkau mau mengizinkan maka izinkanlah dan jika engkau ingin agar dia pulang maka ia akan pulang\". Lalu Abu Syu'aib berkata: \"Iya, bahkan aku telah mengizinkannya\"."},"1940":{"ar":"حَدَّثَنَا بَدَلُ بْنُ الْمُحَبَّرِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَبَا الْخَلِيلِ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ حَكِيمِ بْنِ حِزَامٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا أَوْ قَالَ حَتَّى يَتَفَرَّقَا فَإِنْ صَدَقَا وَبَيَّنَا بُورِكَ لَهُمَا فِي بَيْعِهِمَا وَإِنْ كَتَمَا وَكَذَبَا مُحِقَتْ بَرَكَةُ بَيْعِهِمَا","id":"Telah menceritakan kepada kami [Badal bin Al Muhabbar] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] berkata, aku mendengar [Abu Al Khalil] menceritakan dari ['Abdullah bin Al Harits] dari [Hakim bin Hizam radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Dua orang yang melakukan jual beli boleh melakukan khiyar (pilihan untuk melangsungkan atau membatalkan jual beli) selama keduanya belum berpisah\", Atau sabda Beliau: \"hingga keduanya berpisah. Jika keduanya jujur dan menampakkan cacat dagangannya maka keduanya diberkahi dalam jual belinya dan bila menyembunyikan cacat dan berdusta maka akan dimusnahkan keberkahan jual belinya\"."},"1941":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ حَدَّثَنَا سَعِيدٌ الْمَقْبُرِيُّ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَأْتِيَنَّ عَلَى النَّاسِ زَمَانٌ لَا يُبَالِي الْمَرْءُ بِمَا أَخَذَ الْمَالَ أَمِنْ حَلَالٍ أَمْ مِنْ حَرَامٍ","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Ibnu Abu Dza'bi] telah menceritakan kepada kami [Sa'id Al Maqbariy] dari [Abu Hurairah radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh pasti akan datang suatu jaman pada manusia yang ketika itu seseorang tidak peduli lagi tentang apa yang didapatnya apakah dari barang halal ataukah haram\"."},"1942":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا غُنْدَرٌ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَمَّا نَزَلَتْ آخِرُ الْبَقَرَةِ قَرَأَهُنَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهِمْ فِي الْمَسْجِدِ ثُمَّ حَرَّمَ التِّجَارَةَ فِي الْخَمْرِ","id":"Telah menceritakan kepada kami [Muhammad bion Basysyar] telah menceritakan kepada kami [Ghundar] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Abu Adh-Dhuha] dari [Masruq] dari ['Aisyah radliallahu 'anha] berkata: \"Ketika turun ayat-ayat terakhir dari surah Al Baqarah, Nabi shallallahu 'alaihi wasallam menerima ayat-ayat tersebut ketika sedang berada di masjid maka kemudian Beliau mengharamkan jual beli didalam masjid\"."},"1943":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا أَبُو رَجَاءٍ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُ اللَّيْلَةَ رَجُلَيْنِ أَتَيَانِي فَأَخْرَجَانِي إِلَى أَرْضٍ مُقَدَّسَةٍ فَانْطَلَقْنَا حَتَّى أَتَيْنَا عَلَى نَهَرٍ مِنْ دَمٍ فِيهِ رَجُلٌ قَائِمٌ وَعَلَى وَسَطِ النَّهَرِ رَجُلٌ بَيْنَ يَدَيْهِ حِجَارَةٌ فَأَقْبَلَ الرَّجُلُ الَّذِي فِي النَّهَرِ فَإِذَا أَرَادَ الرَّجُلُ أَنْ يَخْرُجَ رَمَى الرَّجُلُ بِحَجَرٍ فِي فِيهِ فَرَدَّهُ حَيْثُ كَانَ فَجَعَلَ كُلَّمَا جَاءَ لِيَخْرُجَ رَمَى فِي فِيهِ بِحَجَرٍ فَيَرْجِعُ كَمَا كَانَ فَقُلْتُ مَا هَذَا فَقَالَ الَّذِي رَأَيْتَهُ فِي النَّهَرِ آكِلُ الرِّبَا","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Abu Raja'] dari [Samrah bin Jundub radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Pada suatu malam aku bermimpi dua orang menemuiku lalu keduanya membawa aku keluar menuju tanah suci. Kemudian kami berangkat hingga tiba di suatu sungai yang airnya dari darah. Disana ada seorang yang berdiri di tengah sungai dan satu orang lagi berada (di tepinya) memegang batu. Maka laki-laki yang berada di tengah sungai menghampirinya dan setiap kali dia hendak keluar dari sungai maka laki-laki yang memegang batu melemparnya dengan batu kearah mulutnya hingga dia kembali ke tempatnya semula di tengah sungai dan terjadilah seterusnya yang setiap dia hendak keluar dari sungai, akan dilempar dengan batu sehingga kembali ke tempatnya semula. Aku bertanya: \"Apa maksudnya ini?\" Maka orang yang aku lihat dalam mimpiku itu berkata: \"Orang yang kamu lihat dalam sungai adalah pemakan riba'\"."},"1944":{"ar":"حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ قَالَ رَأَيْتُ أَبِياشْتَرَى عَبْدًا حَجَّامًا فَسَأَلْتُهُ فَقَالَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَمَنِ الْكَلْبِ وَثَمَنِ الدَّمِ وَنَهَى عَنْ الْوَاشِمَةِ وَالْمَوْشُومَةِ وَآكِلِ الرِّبَا وَمُوكِلِهِ وَلَعَنَ الْمُصَوِّرَ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari ['Aun bin Abu Juhaifah] berkata, aku melihat [bapakku] membeli seorang budak sebagai tukang bekam lalu aku tanyakan kepadanya maka dia berkata; Nabi shallallahu 'alaihi wasallam telah melarang harga (uang hasil jual beli) anjing, darah dan melarang orang yang membuat tato dan yang minta ditato dan pemakan riba' dan yang meminjam riba serta melaknat pembuat patung\"."},"1945":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ ابْنُ الْمُسَيَّبِ إِنَّ أَبَا هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْحَلِفُ مُنَفِّقَةٌ لِلسِّلْعَةِ مُمْحِقَةٌ لِلْبَرَكَةِ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] berkata, [Ibnu Al Musayyab] bahwa [Abu Hurairah radliallahu 'anhu] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sumpah itu melariskan dagangan jual beli namun menghilangkan barakah\"."},"1946":{"ar":"حَدَّثَنَا عَمْرُو بْنُ مُحَمَّدٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا الْعَوَّامُ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى رَضِيَ اللَّهُ عَنْهُأَنَّ رَجُلًا أَقَامَ سِلْعَةً وَهُوَ فِي السُّوقِ فَحَلَفَ بِاللَّهِ لَقَدْ أَعْطَى بِهَا مَا لَمْ يُعْطِ لِيُوقِعَ فِيهَا رَجُلًا مِنْ الْمُسْلِمِينَ فَنَزَلَتْ{ إِنَّ الَّذِينَ يَشْتَرُونَ بِعَهْدِ اللَّهِ وَأَيْمَانِهِمْ ثَمَنًا قَلِيلًا }الْآيَةَ","id":"Telah menceritakan kepada kami ['Amru bin Muhammad] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Al 'Awwam] dari [Ibrahim bin 'Abdurrahman] dari ['Abdullah bin Abi Aufa radliallahu 'anhu] bahwa ada seseorang menyiapkan barang dagangan dipasar, lalu ia bersumpah atas nama Allah, sesungguhnya ia telah memberikan barang tersebut dengan apa yang tidak ada padanya kepada seseorang dari kaum muslimin, lalu turunlah ayat: (\"Sesungguhnya orang-orang yang menukar janjinya dengan Allah dan sumpah-sumpah mereka dengan harga yang sedikit\"). (QS Al 'Imran: 77). "},"1947":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَلِيُّ بْنُ حُسَيْنٍ أَنَّ حُسَيْنَ بْنَ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُمَا أَخْبَرَهُ أَنَّ عَلِيًّا عَلَيْهِ السَّلَام قَالَكَانَتْ لِي شَارِفٌ مِنْ نَصِيبِي مِنْ الْمَغْنَمِ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطَانِي شَارِفًا مِنْ الْخُمْسِ فَلَمَّا أَرَدْتُ أَنْ أَبْتَنِيَ بِفَاطِمَةَ بِنْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاعَدْتُ رَجُلًا صَوَّاغًا مِنْ بَنِي قَيْنُقَاعَ أَنْ يَرْتَحِلَ مَعِي فَنَأْتِيَ بِإِذْخِرٍ أَرَدْتُ أَنْ أَبِيعَهُ مِنْ الصَّوَّاغِينَ وَأَسْتَعِينَ بِهِ فِي وَلِيمَةِ عُرُسِي","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Yunus] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya ['Ali bin Husain] bahwa [Husain bin 'Ali] radliallahu 'anhuma mengabarkan kepadanya bahwa ['Ali Alaihissalam] berkata: \"Aku memiliki unta yang bagus dari bagianku hasil ghonimah (rampasan perang) yang diberikan oleh Rasulullah shallallahu 'alaihi wasallam dari jatah seperlima. Ketika aku hendak menikahi Fathimah binti Rasulullah shallallahu 'alaihi wasallam aku menyuruh seorang laki-laki sebagai pembuat emas dari suku Bani Qainuqa agar berkeliling bersamaku. Maka kami datang dengan membawa wewangian dari daun idzkhir dan aku tukar dengan emas lalu aku gunakan sebagai mahar dalam pesta perkawinanku\"."},"1948":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ خَالِدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ حَرَّمَ مَكَّةَ وَلَمْ تَحِلَّ لِأَحَدٍ قَبْلِي وَلَا لِأَحَدٍ بَعْدِي وَإِنَّمَا حَلَّتْ لِي سَاعَةً مِنْ نَهَارٍ لَا يُخْتَلَى خَلَاهَا وَلَا يُعْضَدُ شَجَرُهَا وَلَا يُنَفَّرُ صَيْدُهَا وَلَا يُلْتَقَطُ لُقْطَتُهَا إِلَّا لِمُعَرِّفٍ وَقَالَ عَبَّاسُ بْنُ عَبْدِ الْمُطَّلِبِ إِلَّا الْإِذْخِرَ لِصَاغَتِنَا وَلِسُقُفِ بُيُوتِنَا فَقَالَ إِلَّا الْإِذْخِرَفَقَالَ عِكْرِمَةُ هَلْ تَدْرِي مَا يُنَفَّرُ صَيْدُهَا هُوَ أَنْ تُنَحِّيَهُ مِنْ الظِّلِّ وَتَنْزِلَ مَكَانَهُ قَالَ عَبْدُ الْوَهَّابِ عَنْ خَالِدٍ لِصَاغَتِنَا وَقُبُورِنَا","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Khalid bin 'Abdullah] dari [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah telah mengharamkan kota Makkah, maka tidak dihalalkan buat seorangpun sebelum dan tidak dihalalkan pula buat seorangpun susudahku. Sesungguhnya pernah dihalalkan buatku sesaat dalam suatu hari. Bumi Makkah tidak boleh disingkirkan durinya dan tidak boleh ditebang pohonnya dan tidak boleh diburu hewan buruannya dan tidak ditemukan satupun barang temuan kecuali harus dikembalikan kepada yng mengenalnya (pemiliknya) \". Berkata, 'Abbas bin 'Abdul Muththolib: \"Kecuali pohon idzkhir (pohon yang harum baunya) yang berguna untuk proses pembutan emas dan wewangian di atap-atap rumah kami. Maka Beliau bersabda: \"Ya, kecuali pohon idzkhir\". Lalu ['Ikrimah]: \"Apakah kamu mengerti yang dimaksud dengan dilarang memburu binatang buruan? Yaitu mengusirnya dari tempat tinggalnya dan kamu jadikan untuk persinggahan\". Berkata, ['Abdul Wahhab] dari [Khalid]: \"Idkhir, Untuk wewangain pengerjaan pembuatan emas kami dan Kubur-Kubur kami\"."},"1949":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ خَبَّابٍ قَالَكُنْتُ قَيْنًا فِي الْجَاهِلِيَّةِ وَكَانَ لِي عَلَى الْعَاصِ بْنِ وَائِلٍ دَيْنٌ فَأَتَيْتُهُ أَتَقَاضَاهُ قَالَ لَا أُعْطِيكَ حَتَّى تَكْفُرَ بِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَا أَكْفُرُ حَتَّى يُمِيتَكَ اللَّهُ ثُمَّ تُبْعَثَ قَالَ دَعْنِي حَتَّى أَمُوتَ وَأُبْعَثَ فَسَأُوتَى مَالًا وَوَلَدًا فَأَقْضِيكَ فَنَزَلَتْ{ أَفَرَأَيْتَ الَّذِي كَفَرَ بِآيَاتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا أَطَّلَعَ الْغَيْبَ أَمْ اتَّخَذَ عِنْدَ الرَّحْمَنِ عَهْدًا }","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Ibnu Abu 'Adiy] dari [Syu'bah] dari [Sulaiman] dari [Abu Adh-Dhuha] dari [Masruq] dari [Khabbab] berkata: \"Pada masa Jahiliyyah aku adalah seorang tukang besi dan emas dan Al 'Ash bin Wa'il pernah punya hutang kepadaku lalu aku datang menemuinya untuk menagihnya. Dia berkata: \"Aku tidak akan bayar kecuali kamu mau mengingkari (kufur) Muhammad shallallahu 'alaihi wasallam \". Aku katakan: \"Aku tidak akan kufur sampai kamu dimatikan oleh Allah Ta'ala lalu kamu dibangkitkan. Dia berkata: \"Biarkanlah aku sampai aku mati lalu dibangkitkan dan aku diberikan harta dan anak lalu aku bayar hutangku kepadamu\". Maka turunlah QS Maryam ayat 49 yang artinya: (\" Maka apakah kamu telah melihat orang yang kafir kepada ayat-ayat kami dan ia mengatakan: \"Pasti Aku akan diberi harta dan anak\". Adakah ia melihat yang ghaib atau ia telah membuat perjanjian di sisi Tuhan yang Maha Pemurah?\")."},"1950":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ يَقُولُإِنَّ خَيَّاطًا دَعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ صَنَعَهُ قَالَ أَنَسُ بْنُ مَالِكٍ فَذَهَبْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى ذَلِكَ الطَّعَامِ فَقَرَّبَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُبْزًا وَمَرَقًا فِيهِ دُبَّاءٌ وَقَدِيدٌ فَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَتَبَّعُ الدُّبَّاءَ مِنْ حَوَالَيْ الْقَصْعَةِ قَالَ فَلَمْ أَزَلْ أُحِبُّ الدُّبَّاءَ مِنْ يَوْمِئِذٍ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ishaq bin 'Abdullah bin Abu Tholhah] bahwa dia mendengar [Anas bin Malik radliallahu 'anhu] berkata: \"Ada seorang tukang jahit yang mengundang makan Rasulullah shallallahu 'alaihi wasallam dengan makanan yang dibuatnya sendiri\". Anas bin Malik berkata: \"Maka aku ikut pergi bersama Rasulullah shallallahu 'alaihi wasallam menghadiri undangan jamuan makan tersebut. Maka disuguhkan kepada Rasulullah shallallahu 'alaihi wasallam roti, sayur sop berisi labu dan daging asin yang sudah dikeringkan. Aku melihat Nabi shallallahu 'alaihi wasallam mencari-cari labu tersebut dari pinggir-pinggir baskom. Beliau berkata: \" Sejak hari itu aku selalu suka dengan labu\". "},"1951":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا يَعْقُوبُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي حَازِمٍ قَالَ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَتْ امْرَأَةٌ بِبُرْدَةٍ قَالَ أَتَدْرُونَ مَا الْبُرْدَةُ فَقِيلَ لَهُ نَعَمْ هِيَ الشَّمْلَةُ مَنْسُوجٌ فِي حَاشِيَتِهَا قَالَتْ يَا رَسُولَ اللَّهِ إِنِّي نَسَجْتُ هَذِهِ بِيَدِي أَكْسُوكَهَا فَأَخَذَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُحْتَاجًا إِلَيْهَا فَخَرَجَ إِلَيْنَا وَإِنَّهَا إِزَارُهُ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ يَا رَسُولَ اللَّهِ اكْسُنِيهَا فَقَالَ نَعَمْ فَجَلَسَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَجْلِسِ ثُمَّ رَجَعَ فَطَوَاهَا ثُمَّ أَرْسَلَ بِهَا إِلَيْهِ فَقَالَ لَهُ الْقَوْمُ مَا أَحْسَنْتَ سَأَلْتَهَا إِيَّاهُ لَقَدْ عَلِمْتَ أَنَّهُ لَا يَرُدُّ سَائِلًا فَقَالَ الرَّجُلُ وَاللَّهِ مَا سَأَلْتُهُ إِلَّا لِتَكُونَ كَفَنِي يَوْمَ أَمُوتُ قَالَ سَهْلٌ فَكَانَتْ كَفَنَهُ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Ya'qub bin 'Abdurrahman] dari [Abu Hazim] berkata, aku mendengar [Sahal bin Sa'ad radliallahu 'anhu] berkata; Ada seorang wanita mendatangi Nabi shallallahu 'alaihi wasallam dengan membawa burdah. (Sahal) berkata; \"Tahukah kamu apa yang dimaksud dengan burdah?\" Dikatakan kepadanya lalu dia mengatakan: \"Ya benar, itu adalah kain selimut yang pinggirnya berjahit?\" Wanita itu berkata: \"Wahai Rasulullah, aku menjahitnya dengan tanganku sendiri, dan aku membuatnya untuk memakaikannya kepada anda\". Maka Nabi shallallahu 'alaihi wasallam mengambilnya karena Beliau memerlukannya. Kemudian Beliau menemui kami dengan mengenakan kain tersebut. Kemudian ada seseorang dari suatu kaum yang berkata: \"Wahai Rasulullah, pakaikanlah kain itu untukku\". Beliau menawab: \"Ya\". lalui Nabi shallallahu 'alaihi wasallam duduk dalam suatu majelis lalu kembali dan melipat kain tersebut kemudian memberikannya kepada orang itu. Orang-orang berkata, kepada orang itu: \"Tidak baik apa yang telah kamu minta kepada Beliau. Bukankah kamu tahu bahwa Beliau tidak akan menolak (permintaan orang). Maka orang itu menjawab: \"Demi Allah, sungguh aku tidak memintanya melainkan untuk aku jadikan sebagai kain kafanku pada hari kematianku\". Sahal berkata: \"Akhirnya memang kain itu yang jadi kain kafannya\". "},"1952":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ أَبِي حَازِمٍ قَالَ أَتَى رِجَالٌ إِلَى سَهْلِ بْنِ سَعْدٍيَسْأَلُونَهُ عَنْ الْمِنْبَرِ فَقَالَ بَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى فُلَانَةَ امْرَأَةٍ قَدْ سَمَّاهَا سَهْلٌ أَنْ مُرِي غُلَامَكِ النَّجَّارَ يَعْمَلُ لِي أَعْوَادًا أَجْلِسُ عَلَيْهِنَّ إِذَا كَلَّمْتُ النَّاسَ فَأَمَرَتْهُ يَعْمَلُهَا مِنْ طَرْفَاءِ الْغَابَةِ ثُمَّ جَاءَ بِهَا فَأَرْسَلَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَا فَأَمَرَ بِهَا فَوُضِعَتْ فَجَلَسَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami ['Abdul 'Aziz] dari [Abu Hazim] berkata, bahwa ada orang-orang mendatangi [Sahal bin Sa'ad] lalu bertanya tentang mimbar? Maka dia (Sahal) berkata: \"Rasulullah shallallahu 'alaihi wasallam mengutus orang untuk menemui seorang wanita yang namanya sudah disebutkan oleh Sahal, lalu berkata: \"Perintahkanlah anakmu yang tukang kayu itu untuk membuat mimbar bertangga yang aku jadikan tempat duduk saat aku berbicara dengan orang banyak\". Kemudian wanita itu memerintahkan anaknya membuat mimbar yang terbuat dari batang kayu pohon hutan. Setelah minbar itu jadi, diberikan kepada wanita tersebut. Lalu wanita tersebut mengirimnya untuk Rasulullah shallallahu 'alaihi wasallam, Maka beliau perintahkan orang untuk meletakkan mimbar tersebut dan beliau pergunakan untuk duduk."},"1953":{"ar":"حَدَّثَنَا خَلَّادُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ أَيْمَنَ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ امْرَأَةً مِنْ الْأَنْصَارِ قَالَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا رَسُولَ اللَّهِ أَلَا أَجْعَلُ لَكَ شَيْئًا تَقْعُدُ عَلَيْهِ فَإِنَّ لِي غُلَامًا نَجَّارًا قَالَ إِنْ شِئْتِ قَالَ فَعَمِلَتْ لَهُ الْمِنْبَرَ فَلَمَّا كَانَ يَوْمُ الْجُمُعَةِ قَعَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ الَّذِي صُنِعَ فَصَاحَتْ النَّخْلَةُ الَّتِي كَانَ يَخْطُبُ عِنْدَهَا حَتَّى كَادَتْ تَنْشَقُّ فَنَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَخَذَهَا فَضَمَّهَا إِلَيْهِ فَجَعَلَتْ تَئِنُّ أَنِينَ الصَّبِيِّ الَّذِي يُسَكَّتُ حَتَّى اسْتَقَرَّتْ قَالَ بَكَتْ عَلَى مَا كَانَتْ تَسْمَعُ مِنْ الذِّكْرِ","id":"Telah menceritakan kepada kami [Khallad bin Yahya] telah menceritakan kepada kami ['Abdul Wahid bin Ayman] dari [bapaknya] dari [Jabir bin 'Abdullah radliallahu 'anhu] bahwa ada seorang wanita kaum Anshar berkata, kepada Rasulullah shallallahu 'alaihi wasallam: \"Tidakah sebaiknya aku buatkan sesuatu yang bisa baginda pergunakan untuk karena aku punya anak yang pekerjaannya sebagai tukang kayu?\" Beliau menjawab: \"Silakan bila kamu kehendaki\". Sahal berkata: \"Maka wanita itu membuatkan mimbar. Ketika hari Jum'at Nabi shallallahu 'alaihi wasallam duduk diatas mimbar yang telah dibuat tersebut. Lalu batang pohon kurma yang biasanya beliau berkhathbah di atasnya berteriak hingga hampir-hampir batang pohon itu terbelah. Maka Nabi shallallahu 'alaihi wasallam turun menghampiri batang kayu tersebut lalu memegang dan memeluknya hingga akhirnya batang kayu tersebut merintih dengan perlahan seperti bayi hingga akhirnya berhenti dan menjadi tenang. Beliau berkata: \"Batang kayu itu menangis karena dzikir yang pernah didengarnya \". "},"1954":{"ar":"حَدَّثَنَا يُوسُفُ بْنُ عِيسَى حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاشْتَرَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ يَهُودِيٍّ طَعَامًا بِنَسِيئَةٍ وَرَهَنَهُ دِرْعَهُ","id":"Telah menceritakan kepada kami [Yusuf bin 'Isa] telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Ibrahim] dari [Al aswad] dari ['Aisyah radliallahu 'anha] berkata: \"Rasulullah shallallahu 'alaihi wasallam membeli makanan dari orang Yahudi secara angsuran dan menjaminnya dengan menggadaikan baju besi Beliau\"."},"1955":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا عَبْدُ الْوَهَّابِ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ فَأَبْطَأَ بِي جَمَلِي وَأَعْيَا فَأَتَى عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ جَابِرٌ فَقُلْتُ نَعَمْ قَالَ مَا شَأْنُكَ قُلْتُ أَبْطَأَ عَلَيَّ جَمَلِي وَأَعْيَا فَتَخَلَّفْتُ فَنَزَلَ يَحْجُنُهُ بِمِحْجَنِهِ ثُمَّ قَالَ ارْكَبْ فَرَكِبْتُ فَلَقَدْ رَأَيْتُهُ أَكُفُّهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَزَوَّجْتَ قُلْتُ نَعَمْ قَالَ بِكْرًا أَمْ ثَيِّبًا قُلْتُ بَلْ ثَيِّبًا قَالَ أَفَلَا جَارِيَةً تُلَاعِبُهَا وَتُلَاعِبُكَ قُلْتُ إِنَّ لِي أَخَوَاتٍ فَأَحْبَبْتُ أَنْ أَتَزَوَّجَ امْرَأَةً تَجْمَعُهُنَّ وَتَمْشُطُهُنَّ وَتَقُومُ عَلَيْهِنَّ قَالَ أَمَّا إِنَّكَ قَادِمٌ فَإِذَا قَدِمْتَ فَالْكَيْسَ الْكَيْسَ ثُمَّ قَالَ أَتَبِيعُ جَمَلَكَ قُلْتُ نَعَمْ فَاشْتَرَاهُ مِنِّي بِأُوقِيَّةٍ ثُمَّ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلِي وَقَدِمْتُ بِالْغَدَاةِ فَجِئْنَا إِلَى الْمَسْجِدِ فَوَجَدْتُهُ عَلَى بَابِ الْمَسْجِدِ قَالَ أَالْآنَ قَدِمْتَ قُلْتُ نَعَمْ قَالَ فَدَعْ جَمَلَكَ فَادْخُلْ فَصَلِّ رَكْعَتَيْنِ فَدَخَلْتُ فَصَلَّيْتُ فَأَمَرَ بِلَالًا أَنْ يَزِنَ لَهُ أُوقِيَّةً فَوَزَنَ لِي بِلَالٌ فَأَرْجَحَ لِي فِي الْمِيزَانِ فَانْطَلَقْتُ حَتَّى وَلَّيْتُ فَقَالَ ادْعُ لِي جَابِرًا قُلْتُ الْآنَ يَرُدُّ عَلَيَّ الْجَمَلَ وَلَمْ يَكُنْ شَيْءٌ أَبْغَضَ إِلَيَّ مِنْهُ قَالَ خُذْ جَمَلَكَ وَلَكَ ثَمَنُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami ['Abdul Wahhab] telah menceritakan kepada kami ['Ubaidullah] dari [Wahab bin Kaisan] dari [Jabir bin 'Abdullah radliallahu 'anhu] berkata: \"Aku pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu peperangan lalu untaku berjalan lambat hingga aku kelelahan. Kemudian Nabi shallallahu 'alaihi wasallam menemuiku\". Jabir berkata: Aku katakan kepada Beliau (setelah bertanya kepadaku): \"Iya\". Beliau bertanya: Apa sebabnya?\" Aku katakan: \"Untaku berjalan sangat lambat hingga aku kelelahan dan tertinggal. Kemudian Beliau berhenti turun dan memukul untaku dengan tongkat Beliau lalu berkata: \"Kendarailah\". Maka aku mengendarainya. Sungguh aku melihat unta itu mengikuti Rasulullah shallallahu 'alaihi wasallam. Beliau bertanya kepadaku: \"Apakah kamu sudah menikah?\" Aku jawab: \"Sudah\". Beliau bertanya lagi: \"Dengan seorang gadis atau janda?\" Aku jawab: \"Janda\". Beliau berkata: \"Mengapa tidak dengan seorang gadis sehingga kamu dapat bersenda gurau dengannya dan dia bisa bersenda gurau denganmu\". Aku katakan: \"Sesungguhnya aku punya saudara-saudara perempuan. Aku ingin jika aku menikahi seorang wanita dia adalah orang yang akan tetap dapat menyatukan saudara-saudara perempuanku itu, menyisir dan membimbing mereka\". Beliau berkata: \"Sungguh kamu sudah terlambat maka jika kamu bisa mendahului maka kamu akan menjadi orang yang hebat\". Kemudian Beliau berkata: \"Apakah kamu akan menjual untamu?\" Aku jawab: \"Ya\". Maka Beliau membeli untaku dengan satu 'uqiyah, lalu Rasulullah shallallahu 'alaihi wasallam tiba sebelum aku tiba, aku tiba setelah tengah hari. Lalu kami datang ke masjid dan aku dapati Beliau di pintu masjid, lalu Beliau berkata: \"Baru sekarang kamu tiba?\" Aku jawab: \"Ya\". Maka beliau berkata: \"Biarkanlah untamu itu\". Maka Beliau masuk ke dalam masjid lalu shalat dua raka'at, dan akupun masuk ke masjid lalu shalat. Kemudian Beliau memerintahkan Bilal untuk menimbang baginya satu 'uqiyah. Lalu Bilal menimbang satu 'uqiyah untukku dengan timbangan yang akurat. Kemudian aku pergi hingga berpaling meninggalkan Beliau. Kemudian Beliau berkata: \"Panggilah Jabir untuk menemuiku\". Aku katakan: Sekarang Beliau mengembalikan unta itu kepadaku padahal tidak ada yang lebih aku benci kecuali unta itu\". Beliau berkata: \"Ambillah untamu dan harga jaulnya tetap buatmu\". "},"1956":{"ar":"حَدَّثَنَا عَلِيُّ بْن�� عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَكَانَتْ عُكَاظٌ وَمَجَنَّةُ وَذُو الْمَجَازِ أَسْوَاقًا فِي الْجَاهِلِيَّةِ فَلَمَّا كَانَ الْإِسْلَامُ تَأَثَّمُوا مِنْ التِّجَارَةِ فِيهَا فَأَنْزَلَ اللَّهُ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَبْتَغُوا فَضْلًا مِنْ رَبِّكُمْ }فِي مَوَاسِمِ الْحَجِّ قَرَأَ ابْنُ عَبَّاسٍ كَذَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Dinar] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"'Ukazh, Majannah dan Dzul Majaz adalah nama-nama pasar di zaman Jahiliyyah. Ketika Islam datang mereka seakan merasa berdosa bila tetap berdagang di pasar-pasar tersebut. Maka turunlah firman Allah Ta'ala QS Al Baqarah ayat 198 yang artinya: (\"Tidak ada dosa bagi kalian jika mencari karunia rezeqi Rabb kalian…..\"). Ini dilakukan selama musim hajji, menurut pendapat Ibnu 'Abbas radliallahu 'anhuma."},"1957":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ قَالَ عَمْرٌو كَانَ هَا هُنَا رَجُلٌ اسْمُهُ نَوَّاسٌ وَكَانَتْ عِنْدَهُ إِبِلٌ هِيمٌ فَذَهَبَ ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَافَاشْتَرَى تِلْكَ الْإِبِلَ مِنْ شَرِيكٍ لَهُ فَجَاءَ إِلَيْهِ شَرِيكُهُ فَقَالَ بِعْنَا تِلْكَ الْإِبِلَ فَقَالَ مِمَّنْ بِعْتَهَا قَالَ مِنْ شَيْخٍ كَذَا وَكَذَا فَقَالَ وَيْحَكَ ذَاكَ وَاللَّهِ ابْنُ عُمَرَ فَجَاءَهُ فَقَالَ إِنَّ شَرِيكِي بَاعَكَ إِبِلًا هِيمًا وَلَمْ يَعْرِفْكَ قَالَ فَاسْتَقْهَا قَالَ فَلَمَّا ذَهَبَ يَسْتَاقُهَا فَقَالَ دَعْهَا رَضِينَا بِقَضَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا عَدْوَىسَمِعَ سُفْيَانُ عَمْرًا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] berkata, ['Amru] berkata: \"Dahulu disini ada seseorang yang bernama Nawas, ia memiliki unta yang sakit. Lalu [Ibnu 'Umar radliallahu 'anhuma] datang untuk membeli unta tersebut melalui seorang temannya, lalu temannya itu berkata: \"Kami telah menjual unta itu\". Ia (Nawas) bertanya: \"Kepada siapa kamu menjualnya?. Ia menjawab: \"Kepada seorang syeikh begini dan begitu\". Ia (Ibnu 'Umar) berkata: \"Celaka engkau, demi Allah orang itu adalah Ibnu 'Umar\". Lalu iapun menemuinya dan berkata: \"Sesungguhnya temanku telah menjual kepadamu unta yang sakit sedangkan ia tidak menjelaskannya kepadamu\". Kata (Ibnu 'Umar): \"Kalau begitu, ambil saja untamu\". Ketika Nawas akan mengambilnya, Ibnu 'Umar berkata: \"Biarkanlah, kami ridha dengan keputusan Rasulullah shallallahu 'alaihi wasallam yang beliau bersabda 'Sesungguhnya tidak penyakit yang menular dengan sendiri \". Sufyan mendengar ini dari 'Amru."},"1958":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عُمَرَ بْنِ كَثِيرِ بْنِ أَفْلَحَ عَنْ أَبِي مُحَمَّدٍ مَوْلَى أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَ رَضِيَ اللَّهُ عَنْهُ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ حُنَيْنٍ فَأَعْطَاهُ يَعْنِي دِرْعًا فَبِعْتُ الدِّرْعَ فَابْتَعْتُ بِهِ مَخْرَفًا فِي بَنِي سَلِمَةَ فَإِنَّهُ لَأَوَّلُ مَالٍ تَأَثَّلْتُهُ فِي الْإِسْلَامِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Yahya bin Sa'id] dari ['Umar bin Katsir bin Aflah] dari [Abu Muhammad] sahayanya Abu Qatadah dari [Abu Qatadah radliallahu 'anhu] berkata: \"Kami pergi bersama Rasulullah shallallahu 'alaihi wasallam pada tahun perang Hunain, lalu Beliau memberiku baju besi. Kemudian baju besi itu aku jual lalu uangnya aku gunakan untuk membeli sebuah kebun di kampung Bani Salamah. Maka kebun itulah yang kemudian menjadi harta pertamaku (modal awal) dalam Islam\"."},"1959":{"ar":"حَدَّثَنِي مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا أَبُو بُرْدَةَ بْنُ عَبْدِ اللَّهِ قَالَ سَمِعْتُ أَبَا بُرْدَةَ بْنَ أَبِي مُوسَى عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْجَلِيسِ الصَّالِحِ وَالْجَلِيسِ السَّوْءِ كَمَثَلِ صَاحِبِ الْمِسْكِ وَكِيرِ الْحَدَّادِ لَا يَعْدَمُكَ مِنْ صَاحِبِ الْمِسْكِ إِمَّا تَشْتَرِيهِ أَوْ تَجِدُ رِيحَهُ وَكِيرُ الْحَدَّادِ يُحْرِقُ بَدَنَكَ أَوْ ثَوْبَكَ أَوْ تَجِدُ مِنْهُ رِيحًا خَبِيثَةً","id":"Telah menceritakan kepada saya [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul Wahid] telah menceritakan kepada kami [Abu Burdah bin 'Abdullah] berkata; Aku mendengar [Abu Burdah bin Abu Musa] dari [bapaknya radliallahu 'anhu] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan orang yang bergaul dengan orang shalih dan orang yang bergaul dengan orang buruk seperti penjual minyak wangi dan tukang tempa besi, Pasti kau dapatkan dari pedagang minyak wangi apakah kamu membeli minyak wanginya atau sekedar mendapatkan bau wewangiannya, sedangkan dari tukang tempa besi akan membakar badanmu atau kainmu atau kamu akan mendapatkan bau yang tidak sedap\"."},"1960":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ حُمَيْدٍ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَحَجَمَ أَبُو طَيْبَةَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ لَهُ بِصَاعٍ مِنْ تَمْرٍ وَأَمَرَ أَهْلَهُ أَنْ يُخَفِّفُوا مِنْ خَرَاجِهِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Humaid] dari [Anas bin Malik radliallahu 'anhu] berkata; Abu Thoybah membekam Rasulullah shallallahu 'alaihi wasallam lalu Beliau membayar dia dengan satu sha' kurma dan memerintahkan keluarganya untuk meringankan pajaknya\"."},"1961":{"ar":"حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا خَالِدٌ هُوَ ابْنُ عَبْدِ اللَّهِ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا قَالَاحْتَجَمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَعْطَى الَّذِي حَجَمَهُ وَلَوْ كَانَ حَرَامًا لَمْ يُعْطِهِ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Khalid] dia adalah putra dari 'Abdullah telah menceritakan kepada kami [Khalid] dari ['Ikrimah] dari [Ibnu 'Abbas radliallahu 'anhuma] berkata; \"Rasulullah shallallahu 'alaihi wasallam berbekam dan membayar orang yang membekamnya. Seandainya berbekam itu haram, tentu Beliau tidak akan memberi upah\". "},"1962":{"ar":"حَدَّثَنَا آدَمُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو بَكْرِ بْنُ حَفْصٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَأَرْسَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عُمَرَ رَضِيَ اللَّهُ عَنْهُ بِحُلَّةِ حَرِيرٍ أَوْ سِيَرَاءَ فَرَآهَا عَلَيْهِ فَقَالَ إِنِّي لَمْ أُرْسِلْ بِهَا إِلَيْكَ لِتَلْبَسَهَا إِنَّمَا يَلْبَسُهَا مَنْ لَا خَلَاقَ لَهُ إِنَّمَا بَعَثْتُ إِلَيْكَ لِتَسْتَمْتِعَ بِهَا يَعْنِي تَبِيعَهَا","id":"Telah menceritakan kepada kami [Adam] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Bakar bij Hafsh] dari [Salim bin 'Abdullah bin 'Umar] dari [bapaknya] berkata: \"Nabi shallallahu 'alaihi wasallam memberikan kepada 'Umar radliallahu 'anhu baju atau pakaian bergaris terbuat dari sutera kemudian Beliau melihat 'Umar memakainya, maka Beliau berkata: \"Aku memberikannya bukan untuk kamu pakai. Sesungguhnya orang yang memakai pakaian seperti ini tidak akan mendapat bagian di akhirat. Aku memberikannya untukmu agar kamu untuk memperoleh kesenangan yaitu menjualnya\". "},"1963":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ رَضِيَ اللَّهُ عَنْهَا أَنَّهَا أَخْبَرَتْهُأَنَّهَا اشْتَرَتْ نُمْرُقَةً فِيهَا تَصَاوِيرُ فَلَمَّا رَآهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ عَلَى الْبَابِ فَلَمْ يَدْخُلْهُ فَعَرَفْتُ فِي وَجْهِهِ الْكَرَاهِيَةَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتُوبُ إِلَى اللَّهِ وَإِلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاذَا أَذْنَبْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَالُ هَذِهِ النُّمْرُقَةِ قُلْتُ اشْتَرَيْتُهَا لَكَ لِتَقْعُدَ عَلَيْهَا وَتَوَسَّدَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَصْحَابَ هَذِهِ الصُّوَرِ يَوْمَ الْقِيَامَةِ يُعَذَّبُونَ فَيُقَالُ لَهُمْ أَحْيُوا مَا خَلَقْتُمْ وَقَالَ إِنَّ الْبَيْتَ الَّذِي فِيهِ الصُّوَرُ لَا تَدْخُلُهُ الْمَلَائِكَةُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari [Al Qasim bin Muhammad] dari ['Aisyah Ummul Mu'minin radliallahu 'anhuma] dia mengabarkan kepadanya bahwa dia telah membeli bantal yang ada gambarnya. Ketika Rasulullah shallallahu 'alaihi wasallam melihatnya Beliau berdiri di pintu dan tidak masuk ke dalam rumah, Maka aku mengerti betapa dari wajah Beliau nampak ketidak sukaan. Maka aku katakan: \"Wahai Rasulullah, aku bertaubat kepada Allah dan kepada Rasul-Nya shallallahu 'alaihi wasallam, dosa apa yan telah aku perbuat?\" Maka Rasulullah shallallahu 'alaihi wasallam berkata: \"Mengapa bantal ini ada disini\". Aku berkata; \"Aku membelinya untuk anda agar anda dapat duduk dan bersandar di atasnya\". Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya orang yang membuat gambar ini akan disiksa pada hari qiyamat dan akan dikatakan kepada mereka; \"hidupkanlah apa yang telah kalian ciptakan\". Dan Beliau juga bersabda: \"Sesungguhnya rumah yang berisi gambar-gambar tidak akan dimasuki oleh Malaikat\". "},"1964":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بَنِي النَّجَّارِ ثَامِنُونِي بِحَائِطِكُمْ وَفِيهِ خِرَبٌ وَنَخْلٌ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami ['Abdul Warits] dari [Abu At-Tayyah] dari [Anas radliallahu 'anhu] berkata; Nabi shallallahu 'alaihi wasallam berkata: \"Wahai Banu Najar, juallah kepadaku berapa harga (kebun kalian) \". Didalam kebun tersebut terdapat reruntuhan bangunan dan pohon-pohon kurma. "},"1965":{"ar":"حَدَّثَنَا صَدَقَةُ أَخْبَرَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ قَالَ سَمِعْتُ نَافِعًا عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمُتَبَايِعَيْنِ بِالْخِيَارِ فِي بَيْعِهِمَا مَا لَمْ يَتَفَرَّقَا أَوْ يَكُونُ الْبَيْعُ خِيَارًاقَالَ نَافِعٌ وَكَانَ ابْنُ عُمَرَ إِذَا اشْتَرَى شَيْئًا يُعْجِبُهُ فَارَقَ صَاحِبَهُ","id":"Telah menceritakan kepada kami [Shadaqah] telah mengabarkan kepada kami ['Abdul Wahhab] berkata, aku mendengar [Yahya bin Sa'id] berkata, aku mendengar [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Dua orang yang melakukan jual beli boleh melakukan khiyar (pilihan untuk melangsungkan atau membatalkan) dalam jual beli selama keduanya belum berpisah, atau jual beli menjadi khiyar (terjadi dengan pilihan) \". Nafi' berkata: \"Adalah Ibnu 'Umar radliallahu 'anhuma bila membeli sesuatu, baru menganggapnya telah terjadi jual beli bila sudah berpisah dari penjualnya\". "},"1966":{"ar":"حَدَّثَنَا حَفْصُ بْنُ عُمَرَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ حَكِيمِ بْنِ حِزَامٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَفْتَرِقَاوَزَادَ أَحْمَدُ حَدَّثَنَا بَهْزٌ قَالَ قَالَ هَمَّامٌ فَذَكَرْتُ ذَلِكَ لِأَبِي التَّيَّاحِ فَقَالَ كُنْتُ مَعَ أَبِي الْخَلِيلِ لَمَّا حَدَّثَهُ عَبْدُ اللَّهِ بْنُ الْحَارِثِ بِهَذَا الْحَدِيثِ","id":"Telah menceritakan kepada kami [Hafsh bin 'Umar] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Abu Al Khalil] dari ['Abdullah bin Al Harits] dari [Hakim bin Hizam radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Dua orang yang melakukan jual beli boleh melakukan khiyar (pilihan untuk melangsungkan atau membatalkan) dalam jual beli selama keduanya belum berpisah\". [Ahmad] menambahkan, telah menceritakan kepada kami [Bahaz] berkata,, [Hammam] berkata: \"Kemudian hal ini aku ceritakan kepada [Abu At-Tayyah], maka dia berkata: \"Aku pernah bersama [Abu Al Khalil] ketika ['Abdullah bin Al Harits] menceritakan kepadanya tentang hadits ini\". "},"1967":{"ar":"حَدَّثَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا أَوْ يَقُولُ أَحَدُهُمَا لِصَاحِبِهِ اخْتَرْ وَرُبَّمَا قَالَ أَوْ يَكُونُ بَيْعَ خِيَارٍ","id":"Telah menceritakan kepada kami [Abu An-Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Dua orang yang melakukan jual beli boleh melakukan khiyar (pilihan untuk melangsungkan atau membatalkan) dalam jual beli selama keduanya belum berpisah\". Atau Beliau bersabda: \"(Selama belum berpisah) seorang dari rekannya\". Atau Beliau bersabda: \"Jual beli menjadi khiyar (terjadi dengan pilihan) \"."},"1968":{"ar":"حَدَّثَنِي إِسْحَاقُ أَخْبَرَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا شُعْبَةُ قَالَ قَتَادَةُ أَخْبَرَنِي عَنْ صَالِحٍ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَ سَمِعْتُ حَكِيمَ بْنَ حِزَامٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا فَإِنْ صَدَقَا وَبَيَّنَا بُورِكَ لَهُمَا فِي بَيْعِهِمَا وَإِنْ كَذَبَا وَكَتَمَا مُحِقَتْ بَرَكَةُ بَيْعِهِمَا","id":"Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Habban bin Hilal] telah menceritakan kepada kami [Syu'bah] berkata, [Qatadah] mengabarkan kepadaku dari [Shalih Abu Al Khalil] dari ['Abdullah bin Al Harits] berkata, aku mendengar [Hakim bin Hizam radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Dua orang yang melakukan jual beli boleh melakukan khiyar (pilihan untuk melangsungkan atau membatalkan jual beli) selama keduanya belum berpisah\", Atau sabda Beliau: \"hingga keduanya berpisah. Jika keduanya jujur dan menampakkan cacat dagangannya maka keduanya diberkahi dalam jual belinya dan bila menyembunyikan cacatnya dan berdusta maka akan dimusnahkan keberkahan jual belinya\"."},"1969":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُتَبَايِعَانِ كُلُّ وَاحِدٍ مِنْهُمَا بِالْخِيَارِ عَلَى صَاحِبِهِ مَا لَمْ يَتَفَرَّقَا إِلَّا بَيْعَ الْخِيَارِ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang melakukan jual beli, masing-masing punya hak pilihan atas teman jual belinya selama keduanya belum berpisah, kecuali jual beli yang tidak membutuhkan berpisah.\" "},"1970":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا تَبَايَعَ الرَّجُلَانِ فَكُلُّ وَاحِدٍ مِنْهُمَا بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا وَكَانَا جَمِيعًا أَوْ يُخَيِّرُ أَحَدُهُمَا الْآخَرَ فَتَبَايَعَا عَلَى ذَلِكَ فَقَدْ وَجَبَ الْبَيْعُ وَإِنْ تَفَرَّقَا بَعْدَ أَنْ يَتَبَايَعَا وَلَمْ يَتْرُكْ وَاحِدٌ مِنْهُمَا الْبَيْعَ فَقَدْ وَجَبَ الْبَيْعُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] dari Rasulullah shallallahu 'alaihi wasallam bahwa Beliau bersabda: \"Jika dua orang melakukan jual beli maka masing-masingnya punya hak khiyar (pilihan) atas jual belinya selama keduanya belum berpisah. Jika keduanya sepakat atau salah satu dari keduanya memilih lalu dilakukan transaksi maka berarti jual beli telah terjadi dengan sah, dan seandainya keduanya berpisah setelah transaksi sedangkan salah seorang dari keduanya tidak membatalkan transaksi maka jual beli sudah sah\". "},"1971":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ بَيِّعَيْنِ لَا بَيْعَ بَيْنَهُمَا حَتَّى يَتَفَرَّقَا إِلَّا بَيْعَ الْخِيَارِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari ['Abdullah bin Dinar] dari [Ibnu 'Umar radliallahu 'anhuma] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Setiap dua orang yang melakukan jual beli dianggap tidak terjadi transaksi sah jual beli hingga keduanya berpisah, kecuali jual beli yang tidak membutuhkan perpisahan\"."},"1972":{"ar":"حَدَّثَنَا إِسْحَاقُ حَدَّثَنَا حَبَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ حَكِيمِ بْنِ حِزَامٍ رَضِيَ اللَّهُ عَنْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْبَيِّعَانِ بِالْخِيَارِ مَا لَمْ يَتَفَرَّقَا قَالَ هَمَّامٌ وَجَدْتُ فِي كِتَابِي يَخْتَارُ ثَلَاثَ مِرَارٍ فَإِنْ صَدَقَا وَبَيَّنَا بُورِكَ لَهُمَا فِي بَيْعِهِمَا وَإِنْ كَذَبَا وَكَتَمَا فَعَسَى أَنْ يَرْبَحَا رِبْحًا وَيُمْحَقَا بَرَكَةَ بَيْعِهِمَاقَالَ وَحَدَّثَنَا هَمَّامٌ حَدَّثَنَا أَبُو التَّيَّاحِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ الْحَارِثِ يُحَدِّثُ بِهَذَا الْحَدِيثِ عَنْ حَكِيمِ بْنِ حِزَامٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ishaq] telah menceritakan kepada kami [Habban] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Abu Al Khalil] dari ['Abdullah bin Al Harits] dari [Hakim bin Hizam radliallahu 'anhu] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Dua orang yang melakukan jual beli boleh melakukan khiyar (pilihan untuk melangsungkan atau membatalkan jual beli) selama keduanya belum berpisah\". Hammam berkata: \"Aku dapatkan dalam catatanku (Beliau bersabda): \"Dia boleh memilih dengan kesempatan hingga tiga kali. Jika keduanya jujur dan menampakkan cacat dagangannya maka keduanya diberkahi dalam jual belinya dan bila menyembunyikan cacat dan berdusta maka mungkin keduanya akan mendapatkan untung namun akan hilang keberkahan jual beli keduanya\". Hibban berkata; Dan telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Abu At-Tayyah] bahwa dia mendengar ['Abdullah bin Al Harits] menceritakan tentang hadits ini dari [Hakim bin Hizam radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam. "},"1973":{"ar":"وَقَالَ لَنَا الْحُمَيْدِيُّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَكُنْتُ عَلَى بَكْرٍ صَعْبٍ لِعُمَرَ فَكَانَ يَغْلِبُنِي فَيَتَقَدَّمُ أَمَامَ الْقَوْمِ فَيَزْجُرُهُ عُمَرُ وَيَرُدُّهُ ثُمَّ يَتَقَدَّمُ فَيَزْجُرُهُ عُمَرُ وَيَرُدُّهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعُمَرَ بِعْنِيهِ قَالَ هُوَ لَكَ يَا رَسُولَ اللَّهِ قَالَ بِعْنِيهِ فَبَاعَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ لَكَ يَا عَبْدَ اللَّهِ بْنَ عُمَرَ تَصْنَعُ بِهِ مَا شِئْتَقَالَ أَبُو عَبْد اللَّهِ وَقَالَ اللَّيْثُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَ بِعْتُ مِنْ أَمِيرِ الْمُؤْمِنِينَ عُثْمَانَ بْنِ عَفَّانَ مَالًا بِالْوَادِي بِمَالٍ لَهُ بِخَيْبَرَ فَلَمَّا تَبَايَعْنَا رَجَعْتُ عَلَى عَقِبِي حَتَّى خَرَجْتُ مِنْ بَيْتِهِ خَشْيَةَ أَنْ يُرَادَّنِي الْبَيْعَ وَكَانَتْ السُّنَّةُ أَنَّ الْمُتَبَايِعَيْنِ بِالْخِيَارِ حَتَّى يَتَفَرَّقَا قَالَ عَبْدُ اللَّهِ فَلَمَّا وَجَبَ بَيْعِي وَبَيْعُهُ رَأَيْتُ أَنِّي قَدْ غَبَنْتُهُ بِأَنِّي سُقْتُهُ إِلَى أَرْضِ ثَمُودَ بِثَلَاثِ لَيَالٍ وَسَاقَنِي إِلَى الْمَدِينَةِ بِثَلَاثِ لَيَالٍ","id":"Dan berkata, kepada kami [Al Humaidiy] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru] dari [Ibnu 'Umar radliallahu 'anhuma] berkata: \"Kami pernah bersama Nabi shallallahu 'alaihi wasallam pada suatu perjalanan yang ketika itu aku menunggang anak unta yang masih liar milik 'Umar. Anak unta itu selalu mendahulukanku (membawaku paling depan). Maka ia berjalan pada barisan paling depan, lalu 'Umar membentaknya dan mengembalikannya ke belakang. Namun ia kembali maju paling depan dan 'Umarpun kembali membentak dan mengembalikannya ke belakang. Kemudian Nabi shallallahu 'alaihi wasallam berkata, kepada 'Umar: \"Juallah anak unta itu kepadaku\". 'Umar menjawab: \"Ia untukmu wahai Rasulullah\". Beliau bersabda: \"Juallah kepadaku\". Maka 'Umarpun menjualnya kepada Rasulullah shallallahu 'alaihi wasallam kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sekarang anak unta itu untukmu wahai 'Abdullah bin 'Umar kamu dapat berbuat dengannya sesukamu\". Dan Abu 'Abdullah Al Bukhariy berkata: \"Dan Laits berkata, telah mengabarkan kepada saya 'Abdurrahman bin Khalid dari Ibnu Syihab dari Salim bin 'Abdullah dari Abdulloh bin 'Umar radliallahu 'anhu berkata: \"Aku menjual (dengan cara barter) kepada amirul Mukminin 'Utsman bin 'Affan hartaku berupa tanah yang ada lembahnya dengan harta dia berupa tanah yang terletak di Khaibar. Setelah kami bertransaksi aku kembali ketempatku semula dan aku keluar dari rumahnya karena khawatir jika ia akan membatalkan transaksi, karena termasuk dari sunnah adalah bahwasanya dua orang yang bertransaksi mempunyai hak pilih hingga mereka berpisah. 'Abdullah berkata: \"Ketika jual beli antara aku dan dia telah sah terjadi, aku merasa bahwa aku telah mendhaliminya, bahwa aku telah membawanya (mendekatkannya) ke daerah Tsamud yang jaraknya selama tiga malam, dan ia membawaku (mendekatkan) ke Madinah yang jaraknya selama tiga malam. "},"1974":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَجُلًا ذَكَرَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ يُخْدَعُ فِي الْبُيُوعِ فَقَالَ إِذَا بَايَعْتَ فَقُلْ لَا خِلَابَةَ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari ['Abdullah bin Dinar] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa ada seorang laki-laki menceritakan kepada Nabi shallallahu 'alaihi wasallam bahwa dia tertipu dalam berjual beli. Maka Beliau bersabda: \"Jika kamu berjual beli katakanlah \"Maaf, namun jangan ada penipuan\"."},"1975":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الصَّبَّاحِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ زَكَرِيَّاءَ عَنْ مُحَمَّدِ بْنِ سُوقَةَ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ قَالَ حَدَّثَتْنِي عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَغْزُو جَيْشٌ الْكَعْبَةَ فَإِذَا كَانُوا بِبَيْدَاءَ مِنْ الْأَرْضِ يُخْسَفُ بِأَوَّلِهِمْ وَآخِرِهِمْ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ يُخْسَفُ بِأَوَّلِهِمْ وَآخِرِهِمْ وَفِيهِمْ أَسْوَاقُهُمْ وَمَنْ لَيْسَ مِنْهُمْ قَالَ يُخْسَفُ ��ِأَوَّلِهِمْ وَآخِرِهِمْ ثُمَّ يُبْعَثُونَ عَلَى نِيَّاتِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ash-Shabbah] telah menceritakan kepada kami [Ima'il bin Zakariya] dari [Muhammad bin Suqah] dari [Nafi' bin Jubair bin Muth'im] berkata, telah menceritakan kepada saya ['Aisyah radliallahu 'anha] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ada sepasukan tentara yang akan menyerang Ka'bah. Ketika mereka sampai di Baida' di suatu bumi, mereka ditenggelamkan seluruhnya mulai orang yang pertama hingga yang terakhir\". 'Aisyah radliallahu 'anha berkata; Aku bertanya: \"Wahai Rasulullah, bagaimana mereka ditenggelamkan seluruhnya mulai orang yang pertama hingga yang terakhir sedangkan didalamnya ada pasukan perang mereka dan yang bukan dari golongan mereka (yang tidak punya maksud sama)?\" Beliau menjawab: \"Mereka akan ditenggelamkan seluruhnya mulai orang yang pertama hingga yang terakhir kemudian mereka akan dibangkitkan pada hari qiyamat sesuai dengan niat mereka masing-masing\". "},"1976":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ أَحَدِكُمْ فِي جَمَاعَةٍ تَزِيدُ عَلَى صَلَاتِهِ فِي سُوقِهِ وَبَيْتِهِ بِضْعًا وَعِشْرِينَ دَرَجَةً وَذَلِكَ بِأَنَّهُ إِذَا تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ أَتَى الْمَسْجِدَ لَا يُرِيدُ إِلَّا الصَّلَاةَ لَا يَنْهَزُهُ إِلَّا الصَّلَاةُ لَمْ يَخْطُ خَطْوَةً إِلَّا رُفِعَ بِهَا دَرَجَةً أَوْ حُطَّتْ عَنْهُ بِهَا خَطِيئَةٌ وَالْمَلَائِكَةُ تُصَلِّي عَلَى أَحَدِكُمْ مَا دَامَ فِي مُصَلَّاهُ الَّذِي يُصَلِّي فِيهِ اللَّهُمَّ صَلِّ عَلَيْهِ اللَّهُمَّ ارْحَمْهُ مَا لَمْ يُحْدِثْ فِيهِ مَا لَمْ يُؤْذِ فِيهِ وَقَالَ أَحَدُكُمْ فِي صَلَاةٍ مَا كَانَتْ الصَّلَاةُ تَحْبِسُهُ","id":"Telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah radliallahu 'anhu] berkata: Telah bersabda Rasulullah shallallahu 'alaihi wasallam: \"Shalat seseorang dari kalian dengan berjama'ah akan ditambahkan pahalanya dibanding shalatnya di pasarnya atau di rumahnya dengan lebih dua puluh derajat. Yang demikian itu karena bila dia berwudhu' dengan menyempurnakan wudhu'nya lalu menuju ke masjid, yang dia tidak keluar kecuali untuk melaksanakan shalat jamaah, tidak bergerak kecuali untuk shalat (berjama'ah), maka tidak ada satu langkahpun dari langkahnya kecuali akan ditinggikan satu derajat baginya atau akan dihapuskan satu kesalahannya. Dan Malaikat akan mendo'akan salah seorang dari kalian selama dia masih pada tempat shalatnya yang dia dijadikannya sebagai tempat shalatnya, (do'a malaikat tersebut): \"Ya Allah, berilah shalawat untuknya. Ya Allah, rahmatilah dia, selama dia belum berhadats dan tidak menyakiti orang lain disana \". Dan Beliau bersabda: \" Salah seorang diantara kalian sudah dianggap mendirikan shalat, ketika menunggu waktu shalat didirikan\". "},"1977":{"ar":"حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ حَدَّثَنَا شُعْبَةُ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السُّوقِ فَقَالَ رَجُلٌ يَا أَبَا الْقَاسِمِ فَالْتَفَتَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا دَعَوْتُ هَذَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمُّوا بِاسْمِي وَلَا تَكَنَّوْا بِكُنْيَتِي","id":"Telah menceritakan kepada kami [Adam bin Abu Iyas] telah menceritakan kepada kami [Syu'bah] dari [Humaid Ath-Thowil] dari [Anas bin Malik radliallahu 'anhu] berkata: \"Nabi shallallahu 'alaihi wasallam pernah berada dalam suatu pasar tiba-tiba ada seorang lelaki yang memanggil Beliau: \"Wahai Abu Al Qasim!\". Maka Nabi shallallahu 'alaihi wasallam menoleh kepada orang itu lalu dia berkata: \"Aku yang memanggil dengan panggilan tadi\". Maka Nabi shallallahu 'alaihi wasallam berkata: \"Panggillah dengan menyebut namaku dan jangan memanggil dengan nama kuniyahku (panggilan atau julukan) \"."},"1978":{"ar":"حَدَّثَنَا مَالِكُ بْنُ إِسْمَاعِيلَ حَدَّثَنَا زُهَيْرٌ عَنْ حُمَيْدٍ عَنْ أَنَسٍ رَضِيَ اللَّهُ عَنْهُدَعَا رَجُلٌ بِالبَقِيعِ يَا أَبَا الْقَاسِمِ فَالْتَفَتَ إِلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَمْ أَعْنِكَ قَالَ سَمُّوا بِاسْمِي وَلَا تَكْتَنُوا بِكُنْيَتِي","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Zuhair] dari [Humaid] dari [Anas radliallahu 'anhu] berkata: \"Ada seorang lelaki di Baqi' yang memanggil \"Wahai Abu Al Qasim!\". Lalu Nabi shallallahu 'alaihi wasallam menoleh kepada orang itu lalu dia berkata: \"Bukan anda yang aku panggil\". Maka Nabi shallallahu 'alaihi wasallam: \"Panggillah dengan menyebut namaku dan jangan memanggil dengan nama kuniyahku (panggilan atau julukan) \"."},"1979":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ أَبِي هُرَيْرَةَ الدَّوْسِيِّ رَضِيَ اللَّهُ عَنْهُ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي طَائِفَةِ النَّهَارِ لَا يُكَلِّمُنِي وَلَا أُكَلِّمُهُ حَتَّى أَتَى سُوقَ بَنِي قَيْنُقَاعَ فَجَلَسَ بِفِنَاءِ بَيْتِ فَاطِمَةَ فَقَالَ أَثَمَّ لُكَعُ أَثَمَّ لُكَعُ فَحَبَسَتْهُ شَيْئًا فَظَنَنْتُ أَنَّهَا تُلْبِسُهُ سِخَابًا أَوْ تُغَسِّلُهُ فَجَاءَ يَشْتَدُّ حَتَّى عَانَقَهُ وَقَبَّلَهُ وَقَالَ اللَّهُمَّ أَحْبِبْهُ وَأَحِبَّ مَنْ يُحِبُّهُقَالَ سُفْيَانُ قَالَ عُبَيْدُ اللَّهِ أَخْبَرَنِي أَنَّهُ رَأَى نَافِعَ بْنَ جُبَيْرٍ أَوْتَرَ بِرَكْعَةٍ","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah bin Abu Yazid] dari [Nafi' bin Jubair bin Muth'im] dari [Abu Hurairah Ad-Dawsiy radliallahu 'anhu] berkata: Nabi shallallahu 'alaihi wasallam keluar pada waktu siang hari dan Beliau tidak berbicara kepadaku dan akupun juga tidak berbicara kepada Beliau hingga sampai di pasar Bani Qainuqa'. (Setelah keluar dari pasar) maka Beliau duduk di halaman rumah Fathimah lalu berkata: \"Mana anak kecil itu. Mana anak kecil itu? (maksudnya Hasan bin 'Ali) \". Rupanya Fathimah yang menahan anak kecil itu karena suatu keperluan, seingatku Fathimah memasangkan ikat leher yang sering dipakainya atau memandikannya, lalu Beliau datang dengan tergesa hingga Beliau bentangkan tangannya untuk memeluk dan menciumnya, lalu Beliau berdoa: Ya Allah, cintailah dia dan cintailah orang yang mencintainya\". Telah berkata, Sufyan berkata, 'Ubaidullah telah mengabarkan kepada saya bahwa dia memandang Nafi' bin Jubair membolehkan witir dengan satu raka'at saja\"."},"1980":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْمُنْذِرِ حَدَّثَنَا أَبُو ضَمْرَةَ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ حَدَّثَنَا ابْنُ عُمَرَأَنَّهُمْ كَانُوا يَشْتَرُونَ الطَّعَامَ مِنْ الرُّكْبَانِ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَبْعَثُ عَلَيْهِمْ مَنْ يَمْنَعُهُمْ أَنْ يَبِيعُوهُ حَيْثُ اشْتَرَوْهُ حَتَّى يَنْقُلُوهُ حَيْثُ يُبَاعُ الطَّعَامُقَالَ وَحَدَّثَنَا ابْنُ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَ نَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُبَاعَ الطَّعَامُ إِذَا اشْتَرَاهُ حَتَّى يَسْتَوْفِيَهُ","id":"Telah menceritakan kepada kami [Ibrahim bin Al Mundzir] telah menceritakan kepada kami [Abu Dhamrah] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] telah menceritakan kepada kami [Ibnu 'Umar radliallahu 'anhuma], sudah menjadi kebiasaan di zaman Nabi shallallahu 'alaihi wasallam mereka membeli makanan dari hewan-hewan pengangkut dagangan, kemudian datanglah kepada mereka seseorang yang melarang mereka menjual dangannya di tempat mereka membeli, hingga mereka pindahkan ditempat makanan biasa dijual. Berkata Nafi': dan telah menceritakan kepada kami Ibnu 'Umar radliallahu 'anhuma yang berkata: Nabi shallallahu 'alaihi wasallam melarang seseorang menjual makanan yang sudah dibeli hingga telah menjadi haknya secara sempurna\""},"1981":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سِنَانٍ حَدَّثَنَا فُلَيْحٌ حَدَّثَنَا هِلَالٌ عَنْ عَطَاءِ بْنِ يَسَارٍ قَالَ لَقِيتُ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ الْعَاصِ رَضِيَ اللَّهُ عَنْهُمَا قُلْتُأَخْبِرْنِي عَنْ صِفَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي التَّوْرَاةِ قَالَ أَجَلْ وَاللَّهِ إِنَّهُ لَمَوْصُوفٌ فِي التَّوْرَاةِ بِبَعْضِ صِفَتِهِ فِي الْقُرْآنِ{ يَا أَيُّهَا النَّبِيُّ إِنَّا أَرْسَلْنَاكَ شَاهِدًا وَمُبَشِّرًا وَنَذِيرًا }وَحِرْزًا لِلْأُمِّيِّينَ أَنْتَ عَبْدِي وَرَسُولِي سَمَّيْتُكَ المتَوَكِّلَ لَيْسَ بِفَظٍّ وَلَا غَلِيظٍ وَلَا سَخَّابٍ فِي الْأَسْوَاقِ وَلَا يَدْفَعُ بِالسَّيِّئَةِ السَّيِّئَةَ وَلَكِنْ يَعْفُو وَيَغْفِرُ وَلَنْ يَقْبِضَهُ اللَّهُ حَتَّى يُقِيمَ بِهِ الْمِلَّةَ الْعَوْجَاءَ بِأَنْ يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ وَيَفْتَحُ بِهَا أَعْيُنًا عُمْيًا وَآذَانًا صُمًّا وَقُلُوبًا غُلْفًاتَابَعَهُ عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ عَنْ هِلَالٍ وَقَالَ سَعِيدٌ عَنْ هِلَالٍ عَنْ عَطَاءٍ عَنْ ابْنِ سَلَامٍ{ غُلْفٌ }كُلُّ شَيْءٍ فِي غِلَافٍ سَيْفٌ أَغْلَفُ وَقَوْسٌ غَلْفَاءُ وَرَجُلٌ أَغْلَفُ إِذَا لَمْ يَكُنْ مَخْتُونًا","id":"Telah menceritakan kepada kami [Muhammad bin Sinan] telah menceritakan kepada kami [Fulaih] telah menceritakan kepada kami [Hilal] dari ['Atho' bin Yasar] berkata; Aku bertemu dengan ['Abdullah bin 'Amru bin Al 'Ash radliallahu 'anhuma] lalu aku katakan: \"Kabarkan kepadaku tentang sifat Rasulullah shallallahu 'alaihi wasallam di dalam kitab At-Taurah?\" Dia berkata: \"Baik. Demi Allah, sungguh Beliau telah disebutkan dalam kitab At-Taurah sebagian dari sifat-sifat Beliau seperti yang disebutkan dalam Al Qur'an (Wahai Nabi, sesungguhnya kami mengutus engkau sebagai saksi, pemberi kabar gembira dan pemberi peringatan), menjaga para ummiyyin (kaum yang tidak baca tulis). Engkau adalah hambaKu dan RasulKu, Aku memberimu nama Al Mutawakkil, bukan orang yang bersifat kasar lagi keras tidak suka berteriak-teriak di pasar dan tidak membalas keburukan dengan keburukan tetapi memaafkan dan mengampuni, dan Allah tidak akan mematikannya hingga Beliau meluruskan agama-agama yang bengkok agar hanya mengucapkan Laa ilaaha illallah yang dengannya akan membuka mata yang buta, telinga yang tuli dan hati yang tertutup\". Hadits ini dikuatkan pula oleh ['Abdul 'Aziz bin Abu Salamah] dari [Hilal]. Dan berkata, [Sa'id] dari [Hilal] dari ['Atho'] dari [Ibu Salam]: Arti ghulf adalah tertutup atau segala sesuatu yang masih mempunyai penutup, saif aghlaf artinya pedang yang tersimpan dalam sarung, qaus ghulafa' artinya anak panah yang tertutup (tersimpan dalam sarungnya). Dan seorang laki-laki dikatakan aghlaf bila dia belum dikhitan (kemaluannya belum dikhitan) \"."},"1982":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَسْتَوْفِيَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang membeli makanan janganlah dia menjualnya sebelum menjadi haknya secara sempurna\". "},"1983":{"ar":"حَدَّثَنَا عَبْدَانُ أَخْبَرَنَا جَرِيرٌ عَنْ مُغِيرَةَ عَنْ الشَّعْبِيِّ عَنْ جَابِرٍ رَضِيَ اللَّهُ عَنْهُ قَالَتُوُفِّيَ عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ حَرَامٍ وَعَلَيْهِ دَيْنٌ فَاسْتَعَنْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى غُرَمَائِهِ أَنْ يَضَعُوا مِنْ دَيْنِهِ فَطَلَبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَيْهِمْ فَلَمْ يَفْعَلُوا فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَصَنِّفْ تَمْرَكَ أَصْنَافًا الْعَجْوَةَ عَلَى حِدَةٍ وَعَذْقَ زَيْدٍ عَلَى حِدَةٍ ثُمَّ أَرْسِلْ إِلَيَّ فَفَعَلْتُ ثُمَّ أَرْسَلْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ فَجَلَسَ عَلَى أَعْلَاهُ أَوْ فِي وَسَطِهِ ثُمَّ قَالَ كِلْ لِلْقَوْمِ فَكِلْتُهُمْ حَتَّى أَوْفَيْتُهُمْ الَّذِي لَهُمْ وَبَقِيَ تَمْرِي كَأَنَّهُ لَمْ يَ��ْقُصْ مِنْهُ شَيْءٌوَقَالَ فِرَاسٌ عَنْ الشَّعْبِيِّ حَدَّثَنِي جَابِرٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا زَالَ يَكِيلُ لَهُمْ حَتَّى أَدَّاهُ وَقَالَ هِشَامٌ عَنْ وَهْبٍ عَنْ جَابِرٍ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جُذَّ لَهُ فَأَوْفِ لَهُ","id":"Telah menceritakan kepada kami ['Abdan] telah mengabarkan kepada kami [Jarir] dari [Mughirah] dari [Asy-Sya'biy] dari [Jabir radliallahu 'anhu] berkata; 'Abdullah bin 'Amru in Haram wafat dengan meninggalkan hutang lalu aku meminta tolong kepada Nabi shallallahu 'alaihi wasallam untuk meminta para piutangnya agar mereka mau membebaskan hutang tersebut. Maka Nabi shallallahu 'alaihi wasallam meminta kepada mereka namun mereka tidak mengabulkannya. Maka Nabi shallallahu 'alaihi wasallam berkata, kepadaku: \"Pergilah dan pisahkan kurmamu sesuai jenisnya, kurma jenis 'ajwah dipisahkan, kurma jenis 'Adzq zaid tolong pisahkan, lalu kirimlah kepadaku\". Kemudian aku melaksanakan lalu aku kirim kepada Nabi shallallahu 'alaihi wasallam. Maka Beliau datang lalu duduk diatasnya atau di tengahnya kemudian berkata: \"Timbanglah untuk orang-orang\". Maka akupun menimbangnya hingga aku tunaikan apa yang menjadi hak mereka dan yang tinggal adalah kurma milikku dan seolah tidak ada yang kurang sedikitpun dari kurma-kurna tersebut\". Dan berkata, [Firas] dari [Asy-Sya'biy] telah menceritakan kepada saya [Jabir] dari Nabi shallallahu 'alaihi wasallam: \"Dan senantiasa Beliau terus menimbang kurma tersebut untuk masyarakat hingga selesai\". Dan berkata, [Hisyam] dari [Wahab] dari [Jabir] bahwa Nabi shallallahu 'alaihi wasallam berkata: \"Potonglah tangkainya buat dia lalu genapkanlah timbangannya\"."},"1984":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا الْوَلِيدُ عَنْ ثَوْرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كِيلُوا طَعَامَكُمْ يُبَارَكْ لَكُمْ","id":"Telah menceritakan kepada kami [Ibrahim bin Musa] telah menceritakan kepada kami [Al Walid] dari [Tsaur] dari [Khalid bin Ma'dan] dari [Al Miqdam bin Ma'diy Karib radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam bersabda: \"Timbanglah makanan kalian niscaya kalian diberkahi\"."},"1985":{"ar":"حَدَّثَنَا مُوسَى حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَمْرُو بْنُ يَحْيَى عَنْ عَبَّادِ بْنِ تَمِيمٍ الْأَنْصَارِيِّ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ رَضِيَ اللَّهُ عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ إِبْرَاهِيمَ حَرَّمَ مَكَّةَ وَدَعَا لَهَا وَحَرَّمْتُ الْمَدِينَةَ كَمَا حَرَّمَ إِبْرَاهِيمُ مَكَّةَ وَدَعَوْتُ لَهَا فِي مُدِّهَا وَصَاعِهَا مِثْلَ مَا دَعَا إِبْرَاهِيمُ عَلَيْهِ السَّلَام لِمَكَّةَ","id":"Telah menceritakan kepada kami [Musa] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami ['Amru bin Yahya] dari ['Abbad bin Tamim Al Anshariy] dari ['Abdullah bin Zaid radliallahu 'anhu] dari Nabi shallallahu 'alaihi wasallam: \"Nabi Ibrahim 'alaihissalam telah mengharamkan (mensucikan) Makkah dan berdoa untuknya dan aku telah mengharamkan Madinah sebagaimana Ibrahim mengharamkan Makkah dan berdo'a untuknya dalam hal mud dan sha'nya sebagaimana Ibrahim berdo'a untuk Makkah\"."},"1986":{"ar":"حَدَّثَنِي عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ عَنْ مَالِكٍ عَنْ إِسْحَاقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَضِيَ اللَّهُ عَنْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ بَارِكْ لَهُمْ فِي مِكْيَالِهِمْ وَبَارِكْ لَهُمْ فِي صَاعِهِمْ وَمُدِّهِمْ يَعْنِي أَهْلَ الْمَدِينَةِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] dari [Malik] dari [Ishaq bin 'Abdullah bin Abu tholhah] dari [Anas bin Malik radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah berkahilah mereka dalam timbangan mereka dan berkahilah pula dalam sha' dan mud mereka, yakni penduduk Madinah\". "},"1987":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ رَضِيَ اللَّهُ عَنْهُ قَالَرَأَيْتُ الَّذِينَ يَشْتَرُونَ الطَّعَامَ مُجَازَفَةً يُضْرَبُونَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعُوهُ حَتَّى يُؤْوُوهُ إِلَى رِحَالِهِمْ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Al Walid bin Muslim] dari [Al Awza'iy] dari [Az Zuhriy] dari [Salim] dari [bapaknya radliallahu 'anhu] berkata; \"Aku melihat orang-orang yang membeli makanan yang tanpa ditimbang di zaman Rasulullah shallallahu 'alaihi wasallam akan dipukul bila menjualnya kembali, hingga mereka mengangkutnya kepada kendaraan angkut mereka\"."},"1988":{"ar":"حَدَّثَنَا مُوسَى بْنُ إِسْمَاعِيلَ حَدَّثَنَا وُهَيْبٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يَبِيعَ الرَّجُلُ طَعَامًا حَتَّى يَسْتَوْفِيَهُ قُلْتُ لِابْنِ عَبَّاسٍ كَيْفَ ذَاكَ قَالَ ذَاكَ دَرَاهِمُ بِدَرَاهِمَ وَالطَّعَامُ مُرْجَأٌ قَالَ أَبُو عَبْد اللَّهِ{ مُرْجَئُونَ }مُؤَخَّرُونَ","id":"Telah menceritakan kepada kami [Musa bin Isma'il] telah menceritakan kepada kami [Wuhaib] dari [Ibnu Thawus] dari [bapaknya] dari [Ibnu 'Abbas radliallahu 'anhuma] bahwa Rasulullah shallallahu 'alaihi wasallam melarang seseorang menjual makanan (yang dibelinya) hingga telah menjadi miliknya secara sah. Aku bertanya kepada Ibnu 'Abbas: \"Bagaimana maksudnya?\" Dia menjawab: \"Hal itu bila dirham dengan dirham dan pembayaran makanannya ditangguhkan\". Abu 'Abdullah Al Bukhariy berkata: Murjauna maknanya sama dengan mu\"akhkhoruuna, artinya ditangguhkan\". "},"1989":{"ar":"حَدَّثَنِي أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ دِينَارٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَقْبِضَهُ","id":"Telah menceritakan kepada saya [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami ['Abdullah bin Dinar] berkata; Aku mendengar [Ibnu 'Umar radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang membeli makanan janganlah dia menjualnya sebelum dia memegangnya (berada ditangannya secara sah) \". "},"1990":{"ar":"حَدَّثَنَا عَلِيٌّ حَدَّثَنَا سُفْيَانُ كَانَ عَمْرُو بْنُ دِينَارٍ يُحَدِّثُهُ عَنْ الزُّهْرِيِّ عَنْ مَالِكِ بْنِ أَوْسٍ أَنَّهُ قَالَ مَنْ عِنْدَهُ صَرْفٌ فَقَالَ طَلْحَةُ أَنَا حَتَّى يَجِيءَ خَازِنُنَا مِنْ الْغَابَةِ قَالَ سُفْيَانُ هُوَ الَّذِي حَفِظْنَاهُ مِنْ الزُّهْرِيِّ لَيْسَ فِيهِ زِيَادَةٌ فَقَالَ أَخْبَرَنِي مَالِكُ بْنُ أَوْسِ بْنِ الْحَدَثَانِ سَمِعَ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يُخْبِرُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الذَّهَبُ بِالذَّهَبِ رِبًا إِلَّا هَاءَ وَهَاءَ وَالْبُرُّ بِالْبُرِّ رِبًا إِلَّا هَاءَ وَهَاءَ وَالتَّمْرُ بِالتَّمْرِ رِبًا إِلَّا هَاءَ وَهَاءَ وَالشَّعِيرُ بِالشَّعِيرِ رِبًا إِلَّا هَاءَ وَهَاءَ","id":"Telah menceritakan kepada saya ['Ali] telah menceritakan kepada kami [Sufyan] bahwa ['Amru bin Dinar] menceritakan kepadanya dari [Az Zuhriy] dari [Malik bin Aus] bahwa dia berkata: \"Siapa yang memiliki barang dagangan?\" Tholhah berkata: \"Saya, hingga tukang gudang kami datang dari hutan\" Sufyan berkata: \"Begitulah yang kami ingat dari Az Zuhriy tanpa ada tambahan sedikitpun didalamnya\". Maka dia berkata, telah mengabarkan kepada saya Malik bin Aus bin Al Hadatsan dia mendengar ['Umar bin Al Khaththob radliallahu 'anhu] mengabarkan dari Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jual beli emas dengan emas adalah riba' kecuali begini-begini (maksudnya secara kontan), beras dengan beras adalah riba' kecuali begini-begini (maksudnya secara kontan), kurma dengan kurma adalah riba' kecuali begini-begini (maksudnya secara kontan), gandum dengan gandum adalah riba' kecuali begini-begini (maksudnya secara kontan) \". "},"1991":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ قَالَ الَّذِي حَفِظْنَاهُ مِنْ عَمْرِو بْنِ دِينَارٍ سَمِعَ طَاوُسًا يَقُولُ سَمِعْتُ ابْنَ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُمَا يَقُولُأَمَّا الَّذِي نَهَى عَنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَهُوَ الطَّعَامُ أَنْ يُبَاعَ حَتَّى يُقْبَضَقَالَ ابْنُ عَبَّاسٍ وَلَا أَحْسِبُ كُلَّ شَيْءٍ إِلَّا مِثْلَهُ","id":"Telah menceritakan kepada saya ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] berkata: \"Yang kami ingat dari ['Amru bin Dinar] bahwa dia mendengar [Thawus] berkata; Aku mendengar [Ibnu 'Abbas radliallahu 'anhuma] berkata: \"Yang dilarang oleh Nabi shallallahu 'alaihi wasallam adalah makanan yang dijual kembali kecuali telah dipegangnya (berada ditangannya secara sah) \". Ibnu 'Abbas radliallahu 'anhuma: \"Aku memandang segala sesuatu tidak lain kecuali seperti itu\". "},"1992":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَسْتَوْفِيَهُزَادَ إِسْمَاعِيلُ مَنْ ابْتَاعَ طَعَامًا فَلَا يَبِعْهُ حَتَّى يَقْبِضَهُ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang membeli makanan janganlah dia menjualnya sebelum menjadi haknya secara sempurna\". [Isma'il] menambahkan: \"Siapa yang membeli makanan janganlah dia menjualnya sebelum dia memegangnya (berada ditangannya secara sah) \". "},"1993":{"ar":"حَدَّثَنَا يَحْيَى بْنُ بُكَيْرٍ حَدَّثَنَا اللَّيْثُ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ ابْنَ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَلَقَدْ رَأَيْتُ النَّاسَ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْتَاعُونَ جِزَافًا يَعْنِي الطَّعَامَ يُضْرَبُونَ أَنْ يَبِيعُوهُ فِي مَكَانِهِمْ حَتَّى يُؤْوُوهُ إِلَى رِحَالِهِمْ","id":"Telah menceritakan kepada kami [Yahya bin Bukair] telah menceritakan kepada kami [Al Laits] dari [Yunus] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya [Salim bin 'Abdullah] bahwa [Ibnu 'Umar radliallahu 'anhuma] berkata; \"Sungguh aku melihat orang-orang yang membeli makanan yang tanpa ditimbang di zaman Rasulullah shallallahu 'alaihi wasallam akan dipukul bila menjualnya kembali di tempat membelinya hingga mereka mengangkutnya kepada kendaraan angkut mereka\"."},"1994":{"ar":"حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْلَقَلَّ يَوْمٌ كَانَ يَأْتِي عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا يَأْتِي فِيهِ بَيْتَ أَبِي بَكْرٍ أَحَدَ طَرَفَيْ النَّهَارِ فَلَمَّا أُذِنَ لَهُ فِي الْخُرُوجِ إِلَى الْمَدِينَةِ لَمْ يَرُعْنَا إِلَّا وَقَدْ أَتَانَا ظُهْرًا فَخُبِّرَ بِهِ أَبُو بَكْرٍ فَقَالَ مَا جَاءَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي هَذِهِ السَّاعَةِ إِلَّا لِأَمْرٍ حَدَثَ فَلَمَّا دَخَلَ عَلَيْهِ قَالَ لِأَبِي بَكْرٍ أَخْرِجْ مَنْ عِنْدَكَ قَالَ يَا رَسُولَ اللَّهِ إِنَّمَا هُمَا ابْنَتَايَ يَعْنِي عَائِشَةَ وَأَسْمَاءَ قَالَ أَشَعَرْتَ أَنَّهُ قَدْ أُذِنَ لِي فِي الْخُرُوجِ قَالَ الصُّحْبَةَ يَا رَسُولَ اللَّهِ قَالَ الصُّحْبَةَ قَالَ يَا رَسُولَ اللَّهِ إِنَّ عِنْدِي نَاقَتَيْنِ أَعْدَدْتُهُمَا لِلْخُرُوجِ فَخُذْ إِحْدَاهُمَا قَالَ قَدْ أَخَذْتُهَا بِالثَّمَنِ","id":"Telah menceritakan kepada kami [Farwah bin Abu Al Maghra'] telah mengabarkan kepada kami ['Ali bin Mushir] dari [Hisyam] dari [bapaknya] dari ['Aisyah radliallahu 'anha] berkata; \"Sangat jarang tiba sebuah hari selain di hari tersebut beliau shallallahu 'alaihi wasallam menemui rumah Abu Bakar pada dua ujung siang. Maka ketika Beliau diizinkan untuk berhijrah ke Madinah, tidaklah Beliau meninggalkan kami melainkan Beliau mendatangi kami ketika zhuhur, lalu Abu Bakar diberitahu tentang kedatangan beliau shallallahu 'alaihi wasallam. Maka Abu Bakar berkata: \"Tidaklah Nabi shallallahu 'alaihi wasallam menemui kami pada saat seperti ini melainkan pasti karena ada suatu peristiwa yang terjadi\". Ketika Beliau telah menemui Abu Bakar, Beliau berkata: \"Keluarkanlah orang orang yang ada di rumahmu!\". Abu bakar berkata: \"Wahai Rasulullah, kedua orang itu adalah dua anak puteriku, yaitu 'Aisyah dan Asma'\". Beliau bertanya: \"Apakah kamu sudah tahu bahwa aku telah diizinkan untuk keluar (berhijrah)?\" Abu Bakar berkata: Ash-Shuhbah (kita berangkat bersama) wahai Rasulullah\". Beliau bertanya: \"Benar, kita berangkat bersama\". Abu bakar berkata: \"Wahai Rasulullah, sesungguhnya aku punya dua ekor unta yang telah aku siapkan keduanya untuk keluar hijrah maka ambillah salah satunya\". Maka Beliau berkata: \"Aku sudah mengambil salah satunya dan kamu terima harga jualnya\"."},"1995":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَ��فِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَبِيعُ بَعْضُكُمْ عَلَى بَيْعِ أَخِيهِ","id":"Telah menceritakan kepada kami [Isma'il] berkata, telah menceritakan kepada saya [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seagian dari kalian membeli apa yang dibeli (sedang ditawar) oleh saudaranya\"."},"1996":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُقَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعَ حَاضِرٌ لِبَادٍ وَلَا تَنَاجَشُوا وَلَا يَبِيعُ الرَّجُلُ عَلَى بَيْعِ أَخِيهِ وَلَا يَخْطُبُ عَلَى خِطْبَةِ أَخِيهِ وَلَا تَسْأَلُ الْمَرْأَةُ طَلَاقَ أُخْتِهَا لِتَكْفَأَ مَا فِي إِنَائِهَا","id":"Telah menceritakan kepada kami ['Ali bin 'Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhriy] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah radliallahu 'anhu] berkata: Rasulullah shallallahu 'alaihi wasallam melarang orang kota menjual untuk orang desa, dan melarang meninggikan penawaran barang (yang sedang ditawar orang lain dengan maksud menipu), dan melarang seseorang membeli apa yang dibeli (sedang ditawar) oleh saudaranya, melarang pula seseorang meminang (wanita) pinangan saudaranya dan melarang seorang wanita meminta suaminya agar menceraikan isteri lainnya (madunya) dengan maksud periuknya sajalah yang dipenuhi (agar belanja dirinya lebih banyak) \". "},"1997":{"ar":"حَدَّثَنَا بِشْرُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدُ اللَّهِ أَخْبَرَنَا الْحُسَيْنُ الْمُكْتِبُ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَجُلًا أَعْتَقَ غُلَامًا لَهُ عَنْ دُبُرٍ فَاحْتَاجَ فَأَخَذَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ يَشْتَرِيهِ مِنِّي فَاشْتَرَاهُ نُعَيْمُ بْنُ عَبْدِ اللَّهِ بِكَذَا وَكَذَا فَدَفَعَهُ إِلَيْهِ","id":"Telah menceritakan kepada kami [Bisyir bin Muhammad] telah mengabarkan kepada kami ['Abdullah] telah mengabarkan kepada kami [Al Husain Al Muktib] dari ['Atho' bin Abu Ribah] dari [Jabir bin 'Abdullah radliallahu 'anhu] bahwa ada seorang laki-laki membebaskan seorang budak dengan syarat asalkan dirnya telah meninggal (mudabbar),. Maka budak tersebut diambil oleh Nabi shallallahu 'alaihi wasallam lalu Beliau berkata: \"Siapa yang mau membeli dariku\". Maka budak itu kemudian dibeli oleh Nu'aim bin 'Abdullah seharga segini segini lalu Beliau memberikan uang itu kepada orang laki-laki tadi\". "},"1998":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا قَالَنَهَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النَّجْشِ","id":"Telah menceritakan kepada kami ['Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu 'Umar radliallahu 'anhuma] berkata; Nabi shallallahu 'alaihi wasallam melarang dari menambahkan harga barang dagangan yang menganudng unsur penipuan terhadap orang lain."},"1999":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ بَيْعِ حَبَلِ الْحَبَلَةِ وَكَانَ بَيْعًا يَتَبَايَعُهُ أَهْلُ الْجَاهِلِيَّةِ كَانَ الرَّجُلُ يَبْتَاعُ الْجَزُورَ إِلَى أَنْ تُنْتَجَ النَّاقَةُ ثُمَّ تُنْتَجُ الَّتِي فِي بَطْنِهَا","id":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar radliallahu 'anhu] bahwa Rasulullah shallallahu 'alaihi wasallam melarang menjual (anak) yang dikandung dalam perut unta. Cara itu merupakan jual beli orang-orang jahiliyyah, yang seseorang membeli sesuatu yang ada di dalam kandungan unta, hingga unta itu melahirkan, lalu anak unta tersebut melahirkan kembali\"."},"2000":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَامِرُ بْنُ سَعْدٍ أَنَّ أَبَا سَعِيدٍ رَضِيَ اللَّهُ عَنْهُ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُنَابَذَةِ وَهِيَ طَرْحُ الرَّجُلِ ثَوْبَهُ بِالْبَيْعِ إِلَى الرَّجُلِ قَبْلَ أَنْ يُقَلِّبَهُ أَوْ يَنْظُرَ إِلَيْهِ وَنَهَى عَنْ الْمُلَامَسَةِ وَالْمُلَامَسَةُ لَمْسُ الثَّوْبِ لَا يَنْظُرُ إِلَيْهِ","id":"Telah menceritakan kepada kami [Sa'id bin 'Ufair] berkata, telah menceritakan kepada saya [Al Laits] berkata, telah menceritakan kepada saya ['Uqail] dari [Ibnu Syihab] berkata, telah mengabarkan kepada saya ['Amir bin Sa'ad] bahwa [Abu Sa'id radliallahu 'anhu] mengabarkannya bahwa Rasulullah shallallahu 'alaihi wasallam melarang munaabadzah, yaitu seseorang melempar pakaiannya sebagai bukti pembelian harus terjadi (dengan mengatakan bila kamu sentuh berarti terjadi transaksi) sebelum orang lain itu menerimanya atau melihatnya dan Beliau juga melarang mulaamasah, yaitu menjual kain dengan hanya menyentuh kain tersebut tanpa melihatnya (yaitu dengan suatu syarat misalnya kalau kamu sentuh berarti kamu harus membeli) \"."}};
